// Bio/Biochem quizzes — bb01 through bb70
export const BIO_BIOCHEM_QUIZZES = [
  {
    id:'bb01', cat:'Bio/Biochem', title:'Enzyme Kinetics & Michaelis-Menten', diff:'Hard',
    qs:[
      { q:`What does the Michaelis constant (Km) represent?`, ch:[`Substrate concentration at half-maximal velocity`,`Maximum reaction velocity`,`Total enzyme concentration`,`Rate constant for product release`], ans:0, exp:`Km is the substrate concentration [S] at which reaction velocity = Vmax/2. A lower Km indicates higher enzyme affinity for its substrate.` },
      { q:`Competitive inhibition causes which kinetic change?`, ch:[`Decreased Vmax only`,`Decreased Vmax and increased Km`,`Increased Vmax and Km`,`Increased apparent Km only`], ans:3, exp:`Competitive inhibitors compete with substrate for the active site, increasing apparent Km. Vmax is unchanged because excess substrate can overcome the inhibition.` },
      { q:`On a Lineweaver-Burk plot, the y-intercept equals:`, ch:[`Km`,`-1/Km`,`1/Vmax`,`Vmax`], ans:2, exp:`The Lineweaver-Burk plot graphs 1/v vs 1/[S]. Y-intercept = 1/Vmax; x-intercept = -1/Km, allowing graphical determination of kinetic constants.` },
      { q:`An uncompetitive inhibitor decreases:`, ch:[`Vmax only`,`Km only`,`Neither Vmax nor Km`,`Both apparent Vmax and Km`], ans:3, exp:`Uncompetitive inhibitors bind only the ES complex, decreasing both apparent Vmax and Km proportionally. Lineweaver-Burk lines are parallel to the uninhibited line.` },
      { q:`Catalytic efficiency is best represented by:`, ch:[`Vmax alone`,`Km alone`,`kcat/Km (specificity constant)`,`kcat alone`], ans:2, exp:`The specificity constant kcat/Km measures how efficiently an enzyme converts substrate at low [S]. Values near 10^8 M⁻¹s⁻¹ indicate a near-perfect enzyme.` },
      { q:`Pure noncompetitive inhibition affects:`, ch:[`Km only`,`Vmax only`,`Both Km and Vmax`,`Neither`], ans:1, exp:`A pure noncompetitive inhibitor binds an allosteric site independent of substrate, reducing Vmax without changing Km.` },
      { q:`Which inhibitor produces parallel lines on a Lineweaver-Burk plot?`, ch:[`Competitive`,`Noncompetitive`,`Uncompetitive`,`Mixed`], ans:2, exp:`Uncompetitive inhibition decreases both Vmax and Km by the same factor, giving parallel lines on the Lineweaver-Burk plot.` },
      { q:`Allosteric enzymes differ from Michaelis-Menten enzymes by exhibiting:`, ch:[`Sigmoidal v vs [S] curves`,`Hyperbolic v vs [S] curves`,`Linear v vs [S] curves`,`No regulation`], ans:0, exp:`Allosteric enzymes show sigmoidal kinetics due to cooperativity between subunits. Binding at one site changes affinity at other sites.` },
      { q:`A Hill coefficient greater than 1 indicates:`, ch:[`Competitive inhibition`,`Positive cooperativity`,`Negative cooperativity`,`Irreversible inhibition`], ans:1, exp:`n > 1 indicates positive cooperativity — binding of one ligand increases affinity for subsequent ligands. Hemoglobin has Hill coefficient ~2.8.` },
      { q:`Feedback inhibition is best described as:`, ch:[`A product inhibiting an upstream enzyme in its own pathway`,`An activator stimulating an early enzyme`,`Covalent modification of the active site`,`Irreversible substrate analog binding`], ans:0, exp:`Feedback inhibition: a downstream metabolite inhibits an earlier committed-step enzyme, preventing overproduction and conserving resources.` },
      { q:`Vmax is directly proportional to:`, ch:[`Km`,`Substrate concentration`,`Total enzyme concentration [E]t`,`Inhibitor concentration`], ans:2, exp:`Vmax = kcat × [E]total. Doubling enzyme concentration doubles Vmax. Km is an intrinsic property unaffected by enzyme amount.` },
      { q:`An enzyme with Km = 0.05 mM has __ affinity vs one with Km = 5 mM:`, ch:[`Lower`,`Higher`,`Equal`,`Cannot be determined`], ans:1, exp:`Lower Km = higher affinity. The enzyme with Km = 0.05 mM reaches half-maximal velocity at 100-fold lower substrate concentration.` },
      { q:`Organophosphates inhibit acetylcholinesterase by:`, ch:[`Competing with acetylcholine`,`Allosteric binding reversibly`,`Increasing the Km for acetylcholine`,`Forming irreversible covalent bonds with the active-site serine`], ans:3, exp:`Organophosphates irreversibly phosphorylate the active-site serine, permanently inactivating the enzyme and causing acetylcholine accumulation at synapses.` },
      { q:`The induced-fit model proposes that:`, ch:[`Substrate binding induces conformational changes in the enzyme`,`The active site is rigid and complementary to the substrate`,`Only one substrate stereoisomer can bind`,`Enzymes never change shape`], ans:0, exp:`The induced-fit model (Koshland, 1958): substrate binding causes conformational changes that optimize the active site geometry for catalysis.` },
      { q:`If enzyme concentration is doubled, what happens to Km?`, ch:[`Km doubles`,`Km is unchanged`,`Km halves`,`Km increases by √2`], ans:1, exp:`Km is an intrinsic property of the enzyme-substrate interaction and is independent of enzyme concentration. Only Vmax changes with [E]total.` },
    ]
  },
  {
    id:'bb02', cat:'Bio/Biochem', title:'Glycolysis & Gluconeogenesis', diff:'Hard',
    qs:[
      { q:`What is the net ATP yield from glycolysis of one glucose?`, ch:[`2`,`1`,`4`,`6`], ans:0, exp:`Glycolysis produces 4 ATP but consumes 2 (at hexokinase and PFK-1), giving net 2 ATP per glucose, plus 2 NADH and 2 pyruvate.` },
      { q:`PFK-1 is activated by:`, ch:[`AMP and fructose-2,6-bisphosphate`,`ATP and citrate`,`Glucagon and cAMP`,`High glucose-6-phosphate`], ans:0, exp:`PFK-1 is activated by AMP (low energy) and fructose-2,6-bisphosphate (insulin-stimulated). It is inhibited by ATP, citrate, and H⁺.` },
      { q:`Which enzyme is bypassed in gluconeogenesis by PEPCK?`, ch:[`Aldolase`,`Phosphoglycerate kinase`,`Pyruvate kinase`,`Enolase`], ans:2, exp:`Pyruvate kinase (PEP → pyruvate + ATP) is irreversible. Gluconeogenesis bypasses it using pyruvate carboxylase then PEPCK.` },
      { q:`Under anaerobic conditions, pyruvate is converted to lactate to:`, ch:[`Produce more ATP`,`Store energy as lactate`,`Feed into the TCA cycle`,`Regenerate NAD+ so glycolysis can continue`], ans:3, exp:`Lactate dehydrogenase regenerates NAD+ from NADH, allowing glycolysis to continue when the ETC cannot accept electrons. No additional ATP is produced.` },
      { q:`2,3-BPG in red blood cells functions to:`, ch:[`Activate PFK-1`,`Stabilize deoxyhemoglobin and reduce oxygen affinity`,`Generate ATP as a glycolytic intermediate`,`Inhibit lactate dehydrogenase`], ans:1, exp:`2,3-BPG stabilizes deoxyhemoglobin (T-state), shifting the O2 dissociation curve rightward, promoting O2 unloading to tissues.` },
      { q:`Gluconeogenesis occurs primarily in:`, ch:[`Liver (and kidney during prolonged fasting)`,`Skeletal muscle`,`Heart`,`Brain`], ans:0, exp:`The liver provides ~90% of glucose during fasting via gluconeogenesis. Muscle cannot export glucose (lacks glucose-6-phosphatase). Kidney contributes ~10-20% during prolonged starvation.` },
      { q:`Which enzyme is unique to gluconeogenesis?`, ch:[`Enolase`,`Aldolase`,`Fructose-1,6-bisphosphatase`,`Phosphoglycerate mutase`], ans:2, exp:`Fructose-1,6-bisphosphatase converts F-1,6-BP → F-6-P, bypassing the irreversible PFK-1 step. The other bypasses use pyruvate carboxylase, PEPCK, and glucose-6-phosphatase.` },
      { q:`The Cori cycle describes:`, ch:[`Ketone body production and brain utilization`,`Glycogen synthesis and breakdown in muscle`,`Glucose-alanine cycling between muscle and liver`,`Lactate shuttling from muscle to liver, where it is reconverted to glucose`], ans:3, exp:`In the Cori cycle, exercising muscle produces lactate (anaerobic glycolysis), which travels to the liver for gluconeogenesis and is released back to muscle.` },
      { q:`Hexokinase differs from glucokinase in that hexokinase:`, ch:[`Has a lower Km and is inhibited by glucose-6-phosphate`,`Has a higher Km and is not inhibited by G-6-P`,`Requires glucagon for activation`,`Is found only in the liver`], ans:0, exp:`Hexokinase has low Km (~0.1 mM) and is product-inhibited by G-6-P. Glucokinase has high Km (~10 mM) and is not inhibited by G-6-P, allowing the liver to buffer post-meal glucose.` },
      { q:`Which substrate CANNOT be converted to glucose in mammals?`, ch:[`Alanine`,`Acetyl-CoA`,`Lactate`,`Glycerol`], ans:1, exp:`Acetyl-CoA cannot be converted to glucose because the PDH reaction is irreversible and mammals lack the glyoxylate cycle. Fatty acid catabolism cannot contribute to net glucose synthesis.` },
      { q:`Insulin stimulates glycolysis primarily through:`, ch:[`Direct phosphorylation of pyruvate kinase`,`Inhibiting glucokinase`,`Stimulating glucose-6-phosphatase`,`Activating PFK-2, raising fructose-2,6-bisphosphate levels`], ans:3, exp:`Insulin activates protein phosphatase 2A which dephosphorylates (activates) PFK-2. Elevated F-2,6-BP is the most potent allosteric activator of PFK-1.` },
      { q:`The first ATP-generating reaction in glycolysis is:`, ch:[`Hexokinase`,`Aldolase`,`Phosphoglycerate kinase`,`Pyruvate kinase`], ans:2, exp:`Phosphoglycerate kinase (step 7) catalyzes the first substrate-level phosphorylation: 1,3-BPG + ADP → 3-PG + ATP. This occurs twice per glucose.` },
      { q:`The committed step of glycolysis is:`, ch:[`Hexokinase`,`PFK-1`,`Phosphoglucose isomerase`,`Aldolase`], ans:1, exp:`PFK-1 catalyzes F-6-P → F-1,6-BP, the committed and most heavily regulated step of glycolysis.` },
      { q:`Pyruvate dehydrogenase is inhibited by:`, ch:[`NAD+ and CoA-SH`,`AMP and ADP`,`NADH and acetyl-CoA`,`Insulin and glucose`], ans:2, exp:`PDH is product-inhibited by NADH and acetyl-CoA, and by ATP. It is activated by NAD+, CoA, AMP, and Ca2+.` },
      { q:`Glucose-6-phosphate can enter all of the following EXCEPT:`, ch:[`Glycolysis`,`Pentose phosphate pathway`,`Glycogen synthesis`,`Glycolysis and gluconeogenesis simultaneously`], ans:3, exp:`G-6-P is a major metabolic junction entering glycolysis, PPP, and glycogen synthesis. It cannot simultaneously enter both glycolysis and gluconeogenesis in the same cell.` },
    ]
  },
  {
    id:'bb03', cat:'Bio/Biochem', title:'TCA Cycle & Electron Transport Chain', diff:'Expert',
    qs:[
      { q:`How many NADH are produced per TCA cycle turn?`, ch:[`3`,`1`,`2`,`4`], ans:0, exp:`Each TCA cycle turn produces 3 NADH (isocitrate DH, α-KG DH, malate DH), plus 1 FADH2, 1 GTP, and 2 CO2.` },
      { q:`Citrate synthase condenses acetyl-CoA with:`, ch:[`Malate`,`Fumarate`,`Oxaloacetate`,`Succinate`], ans:2, exp:`Citrate synthase combines acetyl-CoA (2C) with oxaloacetate (4C) to form citrate (6C) + CoA-SH. This condensation is essentially irreversible.` },
      { q:`Alpha-ketoglutarate dehydrogenase is analogous to pyruvate dehydrogenase because it:`, ch:[`Uses the same substrates`,`Catalyzes an oxidative decarboxylation using the same cofactors`,`Is found in the cytoplasm`,`Is activated by NADH`], ans:1, exp:`Both complexes catalyze oxidative decarboxylation using identical cofactors: TPP, lipoic acid, FAD, NAD+, and CoA.` },
      { q:`The approximate ATP yield from one acetyl-CoA through TCA + oxidative phosphorylation is:`, ch:[`2`,`5`,`16`,`~10`], ans:3, exp:`1 acetyl-CoA yields 3 NADH (×2.5 ATP) + 1 FADH2 (×1.5 ATP) + 1 GTP = ~10 ATP (using updated P/O ratios of 2.5 and 1.5).` },
      { q:`Which TCA enzyme performs substrate-level phosphorylation?`, ch:[`Succinyl-CoA synthetase`,`Citrate synthase`,`Isocitrate dehydrogenase`,`Succinate dehydrogenase`], ans:0, exp:`Succinyl-CoA synthetase converts succinyl-CoA → succinate, coupling this to GTP synthesis. This is the only substrate-level phosphorylation in the TCA cycle.` },
      { q:`Which is NOT a major regulatory TCA enzyme?`, ch:[`Isocitrate dehydrogenase`,`Alpha-ketoglutarate dehydrogenase`,`Citrate synthase`,`Fumarase`], ans:3, exp:`Fumarase (fumarate → malate) is not a major regulatory point. The three key regulatory enzymes are citrate synthase, isocitrate DH, and α-KG DH.` },
      { q:`Complex I transfers electrons from NADH to:`, ch:[`Cytochrome c`,`Ubiquinone (CoQ)`,`Cytochrome a3`,`Molecular oxygen`], ans:1, exp:`Complex I oxidizes NADH and reduces ubiquinone (CoQ → CoQH2), simultaneously pumping 4H+ across the inner mitochondrial membrane.` },
      { q:`The modern P/O ratio for NADH oxidation is approximately:`, ch:[`2.5`,`1.0`,`1.5`,`2.0`], ans:0, exp:`Modern experimental measurements give P/O ratios of ~2.5 for NADH and ~1.5 for FADH2, replacing older textbook values of 3 and 2.` },
      { q:`Complex III transfers electrons from:`, ch:[`NADH to cytochrome c`,`Cytochrome c to O2`,`CoQH2 to cytochrome c`,`Succinate to CoQ`], ans:2, exp:`Complex III accepts electrons from ubiquinol (CoQH2) and transfers them to cytochrome c via the Q cycle, pumping 4H+ across the inner membrane.` },
      { q:`ATP synthase synthesizes ATP by:`, ch:[`Direct substrate-level phosphorylation`,`Accepting electrons from cytochrome c`,`Oxidizing FADH2`,`Using proton flow to drive rotational catalysis`], ans:3, exp:`ATP synthase uses the electrochemical proton gradient (chemiosmosis). H+ flow through Fo drives rotation of the γ subunit, inducing conformational changes in F1 β subunits that catalyze ATP synthesis.` },
      { q:`Cyanide kills by:`, ch:[`Inhibiting Complex I`,`Inhibiting cytochrome c oxidase (Complex IV), blocking O2 reduction`,`Uncoupling oxidative phosphorylation`,`Inhibiting ATP synthase directly`], ans:1, exp:`CN- binds to Fe3+ in cytochrome a3 of Complex IV, blocking electron transfer to O2. The entire ETC backs up, NADH accumulates, and ATP production halts.` },
      { q:`UCP-1 (thermogenin) in brown adipose tissue allows protons to:`, ch:[`Leak across the inner mitochondrial membrane, dissipating energy as heat`,`Enter the matrix via ATP synthase, boosting ATP`,`Be exported from the matrix`,`Enter the intermembrane space from the matrix`], ans:0, exp:`UCP-1 bypasses ATP synthase, dissipating the proton gradient as heat (thermogenesis). Essential for non-shivering thermogenesis in newborns and cold-adapted mammals.` },
      { q:`Fluorocitrate blocks the TCA cycle by inhibiting:`, ch:[`Citrate synthase`,`Succinate dehydrogenase`,`Aconitase`,`Malate dehydrogenase`], ans:2, exp:`Fluoroacetate is converted to fluorocitrate, a potent aconitase inhibitor (citrate → isocitrate). This causes citrate accumulation and halts the TCA cycle.` },
      { q:`Pyruvate carboxylase is anaplerotic because it:`, ch:[`Converts pyruvate to acetyl-CoA`,`Converts pyruvate to oxaloacetate, replenishing TCA intermediates`,`Converts OAA to PEP for gluconeogenesis`,`Decarboxylates pyruvate to acetaldehyde`], ans:1, exp:`Pyruvate carboxylase (biotin-dependent) converts pyruvate + CO2 → OAA, replenishing TCA intermediates. It is activated by acetyl-CoA.` },
      { q:`Succinate dehydrogenase is unique among TCA enzymes because it:`, ch:[`Uses NAD+ as electron acceptor`,`Produces CO2 as a product`,`Requires CoA as a cofactor`,`Is directly embedded in the inner mitochondrial membrane and doubles as Complex II`], ans:3, exp:`Succinate dehydrogenase is both a TCA enzyme and ETC Complex II. It is the only TCA enzyme embedded in the inner mitochondrial membrane and uses FAD as electron acceptor.` },
    ]
  },
  {
    id:'bb04', cat:'Bio/Biochem', title:'Molecular Biology & Genetics', diff:'Hard',
    qs:[
      { q:`Which enzyme synthesizes RNA from a DNA template?`, ch:[`DNA polymerase III`,`Reverse transcriptase`,`Primase`,`RNA polymerase`], ans:3, exp:`RNA polymerase reads the template strand (3'→5') and synthesizes RNA (5'→3'). Eukaryotes have RNA pol I (rRNA), II (mRNA), and III (tRNA, 5S rRNA).` },
      { q:`The lac operon is maximally induced when:`, ch:[`Lactose is present and glucose is absent`,`Glucose is abundant and lactose is absent`,`Only glucose is present`,`Neither glucose nor lactose is present`], ans:0, exp:`The lac operon requires both: allolactose relieves repressor binding (lactose present) and cAMP-CAP activator is active (glucose absent).` },
      { q:`Okazaki fragments are synthesized on the:`, ch:[`Leading strand in the 3'→5' direction`,`Lagging strand in the 5'→3' direction`,`Both strands simultaneously`,`Template strand by DNA pol I`], ans:1, exp:`The lagging strand is synthesized discontinuously in 5'→3' Okazaki fragments because DNA pol can only add nucleotides to a 3'-OH. Fragments are joined by DNA ligase.` },
      { q:`Insertion/deletion of a non-multiple-of-3 nucleotides causes:`, ch:[`Missense mutation`,`Nonsense mutation`,`Frameshift mutation`,`Silent mutation`], ans:2, exp:`A frameshift shifts the reading frame, causing all downstream codons to be misread, typically producing truncated or nonfunctional proteins.` },
      { q:`The Shine-Dalgarno sequence in prokaryotes:`, ch:[`Codes for the start methionine`,`Is the promoter -10 sequence`,`Is a termination signal for transcription`,`Is an mRNA sequence that aligns the ribosome at the start codon`], ans:3, exp:`The Shine-Dalgarno sequence (~5-10 nt upstream of AUG) base-pairs with 16S rRNA of the 30S subunit, positioning the ribosome for translation initiation.` },
      { q:`Eukaryotic RNA processing includes all EXCEPT:`, ch:[`Removal of Shine-Dalgarno sequence`,`5' cap addition`,`3' poly-A tail addition`,`Splicing of introns`], ans:0, exp:`Eukaryotic pre-mRNA processing includes 5' capping, 3' polyadenylation, and splicing. The Shine-Dalgarno sequence is a prokaryotic element not found in eukaryotic mRNA.` },
      { q:`47,XXY is:`, ch:[`Turner syndrome`,`Down syndrome`,`Klinefelter syndrome`,`Patau syndrome`], ans:2, exp:`Klinefelter syndrome (47,XXY) is the most common sex chromosome aneuploidy in males (~1/600). Features include tall stature, testicular atrophy, infertility, and gynecomastia.` },
      { q:`DNA replication is semiconservative because:`, ch:[`Both strands of parental DNA are degraded`,`Each daughter DNA has one new and one original (parental) strand`,`Both new strands are synthesized simultaneously`,`Only one strand is used as template`], ans:1, exp:`Meselson and Stahl (1958) demonstrated semiconservative replication using 15N/14N density labeling. Each daughter molecule retains one parental strand.` },
      { q:`The TATA box is:`, ch:[`Part of the core promoter where TFIID (TBP) binds`,`A transcription termination signal`,`An enhancer element`,`The polyadenylation signal`], ans:0, exp:`The TATA box (~25-30 bp upstream of TSS) is recognized by TFIID (TBP), positioning RNA polymerase II for accurate initiation.` },
      { q:`Genomic imprinting refers to:`, ch:[`Random X-chromosome inactivation in females`,`Mutations caused by radiation`,`Gene expression dependent on parent of origin due to epigenetic marks`,`Homologous recombination during meiosis`], ans:2, exp:`Genomic imprinting: monoallelic gene expression based on parental origin. Imprinted genes are silenced by DNA methylation or histone modifications on one allele.` },
      { q:`Thymine dimers from UV radiation are corrected by:`, ch:[`Mismatch repair`,`Base excision repair`,`Direct repair (photoreactivation)`,`Nucleotide excision repair`], ans:3, exp:`NER removes bulky lesions like thymine dimers — ~25 nucleotides around the lesion are excised then resynthesized. Defects in NER genes cause xeroderma pigmentosum.` },
      { q:`Alternative splicing is significant because it:`, ch:[`Increases the mutation rate`,`Allows one gene to produce multiple protein isoforms`,`Removes exons permanently from the genome`,`Only occurs in prokaryotes`], ans:1, exp:`Alternative splicing generates protein isoforms from one gene. Humans have ~20,000 genes but can produce >100,000 proteins through alternative splicing.` },
      { q:`Blood type AB has genotype:`, ch:[`IAIB`,`IAIA or IAi`,`IBIB or IBi`,`ii`], ans:0, exp:`Blood type AB results from IAIB genotype — co-dominance of both A and B alleles. This locus demonstrates both co-dominance and multiple alleles.` },
      { q:`PCR requires all of the following EXCEPT:`, ch:[`Two oligonucleotide primers`,`Thermostable DNA polymerase (e.g., Taq)`,`dNTPs`,`RNA polymerase and a promoter sequence`], ans:3, exp:`PCR amplifies DNA using primers, Taq polymerase, dNTPs, and thermal cycling. RNA polymerase is not involved — PCR is a DNA amplification technique.` },
      { q:`Telomerase is necessary because:`, ch:[`It repairs double-strand DNA breaks`,`It removes RNA primers from Okazaki fragments`,`It extends telomeres, preventing end-replication shortening`,`It methylates cytosine residues in CpG islands`], ans:2, exp:`DNA polymerase cannot replicate the 5' end of linear chromosomes (end-replication problem). Telomerase uses its own RNA template to add TTAGGG repeats, preventing progressive shortening.` },
    ]
  },
  {
    id:'bb05', cat:'Bio/Biochem', title:'Cell Organelles & Functions', diff:'Easy',
    qs:[
      { q:`Which organelle is the site of aerobic cellular respiration?`, ch:[`Nucleus`,`Mitochondria`,`Endoplasmic reticulum`,`Lysosome`], ans:1, exp:`The mitochondria are the site of the TCA cycle and oxidative phosphorylation, producing the majority of cellular ATP. They have a double membrane with inner cristae that house the ETC.` },
      { q:`The rough endoplasmic reticulum differs from smooth ER because it:`, ch:[`Produces lipids`,`Contains ribosomes on its surface`,`Stores calcium`,`Is found only in muscle cells`], ans:1, exp:`Rough ER has ribosomes attached to its cytoplasmic surface, making it the site of synthesis for proteins destined for secretion or membrane insertion. Smooth ER lacks ribosomes and is involved in lipid synthesis and detoxification.` },
      { q:`Lysosomes primarily function to:`, ch:[`Synthesize proteins`,`Generate ATP`,`Digest cellular debris and macromolecules via hydrolytic enzymes`,`Modify proteins for secretion`], ans:2, exp:`Lysosomes contain ~50 different acid hydrolases (active at pH ~5) that degrade macromolecules from phagocytosis, endocytosis, or autophagy. They are the cell's digestive compartment.` },
      { q:`The Golgi apparatus is responsible for:`, ch:[`DNA replication`,`Post-translational modification, sorting, and packaging of proteins`,`ATP synthesis`,`Protein synthesis`], ans:1, exp:`The Golgi modifies proteins arriving from the ER (glycosylation, phosphorylation), sorts them, and packages them into vesicles for their final destinations (secretion, lysosomes, or plasma membrane).` },
      { q:`The cell nucleus contains:`, ch:[`Ribosomes for protein synthesis`,`The cell's genetic information (DNA) and is the site of transcription`,`Enzymes for lipid metabolism`,`The machinery for ATP synthesis`], ans:1, exp:`The nucleus houses chromosomal DNA and is the primary site of transcription and DNA replication. It is bounded by the nuclear envelope with nuclear pores for selective transport.` },
      { q:`Which structure is NOT found in animal cells?`, ch:[`Mitochondria`,`Cell wall`,`Endoplasmic reticulum`,`Golgi apparatus`], ans:1, exp:`Cell walls are found in plant cells (cellulose), bacteria (peptidoglycan), and fungi (chitin), but NOT in animal cells. Animal cells are bounded only by the plasma membrane.` },
      { q:`Peroxisomes function primarily in:`, ch:[`Protein synthesis`,`ATP production via glycolysis`,`Oxidation of fatty acids and detoxification of hydrogen peroxide`,`DNA repair`], ans:2, exp:`Peroxisomes contain oxidases that break down fatty acids and amino acids, producing H2O2, which is then neutralized by catalase (H2O2 → H2O + O2). They are important in liver and kidney for detoxification.` },
      { q:`The cytoskeleton provides cells with:`, ch:[`Genetic information storage`,`Structural support, cell movement, and intracellular transport`,`Energy through ATP synthesis`,`A site for protein glycosylation`], ans:1, exp:`The cytoskeleton consists of microfilaments (actin), intermediate filaments, and microtubules. It maintains cell shape, enables cell movement (cilia, flagella), and facilitates intracellular transport.` },
      { q:`Ribosomes are the sites of:`, ch:[`DNA replication`,`Protein synthesis (translation)`,`RNA synthesis (transcription)`,`Lipid synthesis`], ans:1, exp:`Ribosomes translate mRNA sequences into polypeptide chains. Eukaryotic ribosomes (80S) consist of 60S and 40S subunits. They can be free in the cytoplasm or attached to the rough ER.` },
      { q:`The inner mitochondrial membrane contains:`, ch:[`DNA polymerase`,`The electron transport chain and ATP synthase`,`Ribosomes for mitochondrial protein synthesis`,`Hydrolytic enzymes for digestion`], ans:1, exp:`The inner mitochondrial membrane houses the ETC complexes (I-IV) and ATP synthase (Complex V). Its extensive folding into cristae maximizes surface area for ATP production.` },
      { q:`Which organelle is responsible for photosynthesis in plant cells?`, ch:[`Mitochondria`,`Nucleus`,`Chloroplast`,`Vacuole`], ans:2, exp:`Chloroplasts are the sites of photosynthesis, containing chlorophyll and other photosynthetic pigments. They have an outer membrane, inner membrane, and thylakoid stacks (grana) in the stroma.` },
      { q:`Endosomes function in:`, ch:[`Protein synthesis`,`Sorting material arriving from endocytosis before delivery to lysosomes`,`ATP production`,`DNA repair`], ans:1, exp:`Early endosomes sort internalized material — some is recycled back to the membrane, while the rest moves to late endosomes and ultimately lysosomes for degradation.` },
      { q:`The smooth endoplasmic reticulum is the primary site for:`, ch:[`Protein synthesis and folding`,`Lipid synthesis and detoxification reactions`,`mRNA transcription`,`Ribosome assembly`], ans:1, exp:`Smooth ER lacks ribosomes and specializes in lipid (phospholipid, steroid) synthesis, drug detoxification (CYP450 enzymes), and calcium ion storage (especially in muscle cells).` },
      { q:`Which organelle is responsible for the secretory pathway?`, ch:[`Lysosome → Endosome → Golgi → ER`,`ER → Golgi → secretory vesicles`,`Mitochondria → ER → Golgi`,`Nucleus → ER → Lysosome`], ans:1, exp:`The secretory pathway: proteins are synthesized on rough ER ribosomes → transported to ER lumen → packaged in vesicles → sent to Golgi for modification → secreted or sent to final destinations.` },
      { q:`The nuclear envelope contains nuclear pores that:`, ch:[`Prevent all molecular traffic between nucleus and cytoplasm`,`Allow selective bidirectional transport of molecules between nucleus and cytoplasm`,`Are the site of ribosome synthesis`,`Produce mRNA directly`], ans:1, exp:`Nuclear pores (NPC, ~30 MDa each) allow selective passage of molecules: mRNA and ribosomes export from nucleus, while proteins like transcription factors and DNA/RNA polymerases are imported.` },
    ]
  },
  {
    id:'bb06', cat:'Bio/Biochem', title:'Cell Membrane Structure & Transport', diff:'Easy',
    qs:[
      { q:`The fluid mosaic model describes the cell membrane as:`, ch:[`A rigid bilayer of phospholipids with fixed proteins`,`A fluid phospholipid bilayer with embedded and associated proteins that can move laterally`,`A single layer of lipids and proteins`,`A solid structure that controls all membrane transport`], ans:1, exp:`The fluid mosaic model (Singer & Nicolson, 1972): the membrane is a fluid phospholipid bilayer in which proteins are embedded (integral) or attached (peripheral) and can move laterally.` },
      { q:`Phospholipids in the membrane are oriented with:`, ch:[`Hydrophilic heads facing inward`,`Hydrophobic tails facing outward`,`Hydrophilic heads facing outward and hydrophobic tails facing inward (facing each other)`,`Random orientation without a pattern`], ans:2, exp:`In aqueous environments, phospholipid bilayers form spontaneously with hydrophilic phosphate heads facing outward (toward water) and hydrophobic fatty acid tails facing inward away from water.` },
      { q:`Simple diffusion across the membrane requires:`, ch:[`A protein carrier`,`ATP energy`,`A concentration gradient (high to low) and a lipid-soluble molecule`,`Vesicles`], ans:2, exp:`Simple diffusion requires no carrier or energy. Lipid-soluble (nonpolar) molecules like O2, CO2, and steroids cross directly down their concentration gradient.` },
      { q:`Facilitated diffusion differs from simple diffusion in that it:`, ch:[`Requires ATP energy`,`Moves molecules against their concentration gradient`,`Uses protein channels or carriers but still moves molecules down their gradient`,`Is only used for water molecules`], ans:2, exp:`Facilitated diffusion uses protein channels (e.g., aquaporins) or carrier proteins (e.g., GLUT transporters) to allow larger or charged molecules to cross the membrane without requiring ATP.` },
      { q:`Primary active transport directly uses:`, ch:[`A concentration gradient`,`ATP hydrolysis to move molecules against their gradient`,`An electrochemical gradient established by another pump`,`Osmotic pressure`], ans:1, exp:`Primary active transport (e.g., Na+/K+ ATPase) directly uses ATP hydrolysis to move molecules against their concentration/electrochemical gradient, maintaining cellular homeostasis.` },
      { q:`The Na+/K+ ATPase pump moves:`, ch:[`3 Na+ in, 2 K+ out per ATP`,`2 Na+ out, 3 K+ in per ATP`,`3 Na+ out, 2 K+ in per ATP`,`Equal amounts of Na+ and K+ in opposite directions`], ans:2, exp:`The Na+/K+ ATPase exports 3 Na+ out of the cell and imports 2 K+ into the cell per ATP hydrolyzed, maintaining the resting membrane potential and cellular osmolarity.` },
      { q:`Osmosis is best defined as:`, ch:[`The movement of solutes from high to low concentration`,`The movement of water through a semipermeable membrane from low to high solute concentration`,`Active transport of water molecules`,`The equilibration of solute concentrations across a membrane`], ans:1, exp:`Osmosis: water moves through semipermeable membranes from regions of lower solute concentration (higher water activity) to higher solute concentration (lower water activity) until equilibrium.` },
      { q:`Cholesterol in the cell membrane:`, ch:[`Increases membrane fluidity at all temperatures`,`Is found only in the outer leaflet`,`Modulates membrane fluidity, preventing extremes of rigidity or fluidity`,`Acts as a channel for small molecules`], ans:2, exp:`Cholesterol inserts between phospholipids, reducing fluidity at high temperatures (limiting motion) but preventing crystallization at low temperatures. It modulates membrane fluidity and is essential for proper membrane function.` },
      { q:`Endocytosis involves:`, ch:[`Membrane fusion to release molecules outside the cell`,`The cell engulfing extracellular material by membrane invagination`,`Water transport through aquaporins`,`Protein synthesis at the membrane surface`], ans:1, exp:`Endocytosis: the plasma membrane invaginates and pinches off to form an intracellular vesicle containing extracellular material. Types include phagocytosis (large particles), pinocytosis (fluid), and receptor-mediated endocytosis.` },
      { q:`Integral membrane proteins differ from peripheral membrane proteins in that integral proteins:`, ch:[`Are only found on the extracellular surface`,`Are attached to the membrane by non-covalent interactions`,`Span the membrane or are embedded within the lipid bilayer`,`Are not made of amino acids`], ans:2, exp:`Integral (intrinsic) membrane proteins are embedded within or span the phospholipid bilayer, often held by hydrophobic interactions. Peripheral proteins are associated with the membrane surface via electrostatic interactions.` },
      { q:`Aquaporins facilitate:`, ch:[`Na+ and K+ transport`,`Glucose transport into cells`,`Rapid water transport across cell membranes`,`Vesicle formation`], ans:2, exp:`Aquaporins (AQPs) are channel proteins that allow rapid, selective transport of water across membranes. AQP2 in collecting duct cells is regulated by ADH/vasopressin to control water reabsorption.` },
      { q:`Exocytosis is used for:`, ch:[`Breaking down proteins within lysosomes`,`Releasing secretory vesicle contents to the extracellular space by membrane fusion`,`Importing nutrients into the cell`,`Moving proteins from ER to Golgi`], ans:1, exp:`Exocytosis: secretory vesicles fuse with the plasma membrane and release their contents extracellularly. Used for hormone secretion, neurotransmitter release, and secretion of extracellular matrix proteins.` },
      { q:`Secondary active transport (cotransport) differs from primary active transport in that it:`, ch:[`Directly uses ATP`,`Moves only one molecule at a time`,`Uses the electrochemical gradient of one ion (established by a pump) to drive movement of another molecule`,`Does not require membrane proteins`], ans:2, exp:`Secondary active transport uses the Na+ gradient (established by Na+/K+ ATPase) to drive cotransport of other molecules. The SGLT1 glucose transporter uses Na+ entry to cotransport glucose against its gradient.` },
      { q:`The resting membrane potential of a typical neuron is approximately:`, ch:[`+70 mV`,`0 mV`,`-70 mV`,`-120 mV`], ans:2, exp:`The resting membrane potential of neurons is approximately -70 mV (inside negative), maintained primarily by the Na+/K+ ATPase and K+ leak channels. The electrochemical gradient is essential for nerve impulse transmission.` },
      { q:`Receptor-mediated endocytosis is selective because:`, ch:[`It uses more ATP than phagocytosis`,`Specific ligands bind to membrane receptors that cluster in clathrin-coated pits before internalization`,`It is faster than phagocytosis`,`It only occurs in specialized immune cells`], ans:1, exp:`In receptor-mediated endocytosis, ligands (LDL, hormones, vitamins) bind specific receptors that cluster in clathrin-coated pits. The coated pit invaginates and pinches off to form a coated vesicle.` },
    ]
  },
  {
    id:'bb07', cat:'Bio/Biochem', title:'Carbohydrate Classification & Structure', diff:'Easy',
    qs:[
      { q:`Monosaccharides are classified by their:`, ch:[`Molecular weight only`,`Number of carbon atoms and presence of an aldehyde or ketone group`,`Whether they are sweet-tasting`,`Their solubility in water`], ans:1, exp:`Monosaccharides are classified by carbon number (triose=3C, pentose=5C, hexose=6C) and functional group: aldoses contain an aldehyde group (-CHO); ketoses contain a ketone group (C=O).` },
      { q:`Glucose is an:`, ch:[`Aldoketose`,`Ketopentose`,`Aldohexose`,`Ketohexose`], ans:2, exp:`Glucose is an aldohexose: it has 6 carbons and an aldehyde functional group at C1. Fructose, in contrast, is a ketohexose (6 carbons, ketone at C2).` },
      { q:`The glycosidic bond in disaccharides is:`, ch:[`A hydrogen bond between two monosaccharides`,`A covalent bond formed between the anomeric carbon of one monosaccharide and a hydroxyl of another`,`A phosphodiester bond`,`An ionic interaction`], ans:1, exp:`Glycosidic bonds form between the anomeric carbon (C1 of aldoses) of one sugar and a hydroxyl group of another. The orientation (α or β) determines the bond type and affects digestibility.` },
      { q:`Lactose is composed of:`, ch:[`Glucose + Fructose`,`Glucose + Galactose`,`Glucose + Glucose`,`Galactose + Fructose`], ans:1, exp:`Lactose (milk sugar) is a disaccharide of glucose + galactose linked by a β(1→4) glycosidic bond. Lactase enzyme cleaves this bond; lactase deficiency causes lactose intolerance.` },
      { q:`Starch and glycogen are both:`, ch:[`Disaccharides made of glucose`,`Lipid-carbohydrate hybrids`,`Polysaccharides composed of glucose with α-glycosidic bonds`,`Polysaccharides composed of glucose with β-glycosidic bonds`], ans:2, exp:`Both starch (amylose/amylopectin) and glycogen are α-glucose polysaccharides. α(1→4) bonds form the linear backbone; α(1→6) bonds create branch points. Glycogen is more highly branched.` },
      { q:`Cellulose differs from starch in that it contains:`, ch:[`β(1→4) glycosidic bonds between glucose units`,`α(1→4) glycosidic bonds between glucose units`,`Fructose instead of glucose`,`No glycosidic bonds`], ans:0, exp:`Cellulose has β(1→4) glycosidic bonds, creating straight chains that hydrogen-bond with neighboring chains for structural rigidity. Humans lack β-glucosidase (cellulase) and cannot digest cellulose.` },
      { q:`An epimer is:`, ch:[`A stereoisomer that is a mirror image`,`A stereoisomer that differs only at a single carbon other than the anomeric carbon`,`A sugar that cannot be metabolized`,`Two sugars with the same molecular formula but different connectivity`], ans:1, exp:`Epimers are diastereomers that differ in configuration at only one carbon (other than C1). Glucose and galactose are C4 epimers; glucose and mannose are C2 epimers.` },
      { q:`The anomeric carbon of a sugar refers to:`, ch:[`The terminal carbon of the carbon chain`,`The carbon bearing the carbonyl group that becomes the site of ring formation`,`The carbon with the most hydroxyl groups`,`The carbon involved in phosphorylation`], ans:1, exp:`When a monosaccharide forms a ring, the carbonyl carbon (C1 in aldoses, C2 in ketoses) becomes the anomeric carbon. The two ring configurations (α/β) differ in -OH orientation at this carbon.` },
      { q:`Which sugar is found in DNA nucleotides?`, ch:[`Ribose`,`Glucose`,`Galactose`,`Deoxyribose`], ans:3, exp:`DNA contains 2'-deoxyribose (a pentose missing the 2'-OH group). RNA contains ribose (with the 2'-OH intact). This structural difference affects the stability and function of each nucleic acid.` },
      { q:`Sucrose (table sugar) consists of:`, ch:[`Glucose + Glucose`,`Glucose + Fructose`,`Glucose + Galactose`,`Fructose + Galactose`], ans:1, exp:`Sucrose is a disaccharide of glucose (α-1) + fructose (β-2), linked at both anomeric carbons — making it a non-reducing sugar. Sucrase cleaves this bond in the small intestine.` },
      { q:`A reducing sugar is one that:`, ch:[`Contains only α-glycosidic bonds`,`Has a free anomeric -OH that can be oxidized (donate electrons to other molecules)`,`Is found only in plant cells`,`Cannot be metabolized`], ans:1, exp:`Reducing sugars (e.g., glucose, fructose, lactose, maltose) have a free anomeric -OH group that can act as a reducing agent. Sucrose is non-reducing because both anomeric carbons are locked in the glycosidic bond.` },
      { q:`Hexokinase phosphorylates glucose to form:`, ch:[`Glucose-1-phosphate`,`Glucose-6-phosphate`,`Fructose-6-phosphate`,`Glucose-2-phosphate`], ans:1, exp:`Hexokinase (or glucokinase in liver) phosphorylates glucose at the 6-position using ATP, producing glucose-6-phosphate. This traps glucose inside the cell and commits it to metabolism.` },
      { q:`The Haworth projection of glucose shows:`, ch:[`A linear chain`,`The 3D conformation of the chair form`,`The planar ring structure with -OH groups above or below the ring`,`The hydrogen bonds between glucose molecules`], ans:2, exp:`Haworth projections show the closed ring (pyranose or furanose) with substituents drawn above or below the ring plane. For β-D-glucose, all large groups are equatorial in the chair conformation.` },
      { q:`Glycoproteins are proteins that:`, ch:[`Have lipid groups attached to them`,`Are found only in the nucleus`,`Have carbohydrate chains (oligosaccharides) covalently attached to them`,`Are only found on the intracellular side of the membrane`], ans:2, exp:`Glycoproteins have oligosaccharides covalently attached at asparagine (N-linked) or serine/threonine (O-linked). They are important for cell-cell recognition, immune function, and blood group antigens.` },
      { q:`Which of the following is a pentose sugar essential for nucleotide structure?`, ch:[`Glucose`,`Galactose`,`Fructose`,`Ribose`], ans:3, exp:`Ribose (and deoxyribose) are pentoses (5-carbon sugars) that form the backbone of nucleotides. Ribose is in RNA and ATP; deoxyribose is in DNA.` },
    ]
  },
  {
    id:'bb08', cat:'Bio/Biochem', title:'Amino Acid Properties & Classification', diff:'Easy',
    qs:[
      { q:`Which amino acid contains a sulfhydryl (-SH) group that can form disulfide bonds?`, ch:[`Methionine`,`Valine`,`Cysteine`,`Serine`], ans:2, exp:`Cysteine has a thiol (-SH) group that can be oxidized to form disulfide (-S-S-) bonds with other cysteine residues. These bonds are important for protein structure stabilization (e.g., insulin, immunoglobulins).` },
      { q:`At physiological pH (~7.4), a basic amino acid would carry:`, ch:[`A negative charge`,`No charge`,`A positive charge`,`A variable charge depending on concentration`], ans:2, exp:`Basic amino acids (lysine, arginine, histidine) have pKa values above 7.4, meaning they are mostly protonated (positively charged) at physiological pH. Histidine (pKa ~6) is partially protonated.` },
      { q:`Proline is unique among amino acids because:`, ch:[`It contains a sulfur atom`,`Its side chain forms a covalent bond with its own backbone nitrogen, creating a cyclic structure`,`It is the only nonpolar amino acid`,`It cannot be incorporated into proteins`], ans:1, exp:`Proline's side chain cyclizes back onto its own amino nitrogen, creating a rigid pyrrolidine ring. This limits backbone rotation, introducing kinks in α-helices and is enriched in collagen's unusual secondary structure.` },
      { q:`Which amino acid has an aromatic side chain with a hydroxyl group, giving it weak acid properties?`, ch:[`Phenylalanine`,`Tryptophan`,`Tyrosine`,`Histidine`], ans:2, exp:`Tyrosine has a phenol group (aromatic ring + -OH) with pKa ~10. It can be phosphorylated by tyrosine kinases (signal transduction), and is a precursor for thyroid hormones and catecholamines.` },
      { q:`The isoelectric point (pI) of an amino acid is the pH at which:`, ch:[`The amino acid has maximum solubility`,`The net charge of the amino acid is zero`,`The amino acid has maximum negative charge`,`Only the carboxyl group is ionized`], ans:1, exp:`The pI is the pH at which the net charge is zero (the zwitterion form predominates). Below pI, the amino acid is positively charged; above pI, it is negatively charged. Used in isoelectric focusing separation.` },
      { q:`Essential amino acids are those that:`, ch:[`Can be synthesized by the body in sufficient amounts`,`Must be obtained from the diet because the body cannot synthesize them in adequate quantities`,`Are needed only during childhood`,`Are found only in animal proteins`], ans:1, exp:`The 9 essential amino acids (His, Ile, Leu, Lys, Met, Phe, Thr, Trp, Val) cannot be synthesized de novo in adequate amounts by humans and must be obtained from diet. Conditionally essential (Arg, Gln) are required during stress/illness.` },
      { q:`Glycine is the smallest amino acid and is unique because:`, ch:[`It has the largest side chain`,`It is the only amino acid that is not chiral (has two H atoms as its side chain)`,`It cannot be incorporated into peptide bonds`,`It is always positively charged`], ans:1, exp:`Glycine has -H as its side chain (R group), making the alpha carbon have two identical substituents — no chirality. This gives it maximum conformational flexibility, and it is enriched in turns and collagen (every third residue).` },
      { q:`Acidic amino acids have side chains that:`, ch:[`Carry positive charges at pH 7`,`Carry negative charges at pH 7 due to carboxyl groups with low pKa values`,`Are uncharged at all pH values`,`Contain nitrogen groups`], ans:1, exp:`Aspartate (Asp) and glutamate (Glu) are acidic amino acids with carboxyl side chains (pKa ~4). They are negatively charged at physiological pH and often participate in enzyme active sites and ion pairs.` },
      { q:`Which amino acid is the precursor to serotonin and melatonin?`, ch:[`Phenylalanine`,`Tyrosine`,`Histidine`,`Tryptophan`], ans:3, exp:`Tryptophan is hydroxylated and decarboxylated to produce serotonin (5-hydroxytryptamine). Serotonin is then acetylated and methylated in the pineal gland to produce melatonin.` },
      { q:`The peptide bond is:`, ch:[`A bond between two carboxyl groups`,`A bond between the carboxyl group of one amino acid and the amino group of the next, with loss of water`,`A bond between two amino groups`,`A hydrogen bond between neighboring amino acids`], ans:1, exp:`Peptide bonds form by condensation (dehydration synthesis) between the -COOH of one amino acid and the -NH2 of the next, releasing water. The peptide bond has partial double-bond character due to resonance, restricting rotation.` },
      { q:`Histidine is the only amino acid whose side chain can serve as both an acid and base near physiological pH because:`, ch:[`It has two sulfur atoms`,`Its imidazole ring has a pKa of ~6, allowing it to donate or accept protons near pH 7`,`It has both a carboxyl and an amino group in the side chain`,`Its aromatic ring can be protonated at pH 7`], ans:1, exp:`Histidine's imidazole ring (pKa ~6) is ~50% protonated at pH 7, making it an excellent buffer at physiological pH. It acts as a proton shuttle in many enzyme active sites (e.g., serine proteases, carbonic anhydrase).` },
      { q:`Leucine, isoleucine, and valine are classified as:`, ch:[`Polar, uncharged amino acids`,`Negatively charged amino acids`,`Aromatic amino acids`,`Branched-chain amino acids (BCAAs) with nonpolar aliphatic side chains`], ans:3, exp:`BCAAs (Leu, Ile, Val) have branched aliphatic side chains that are hydrophobic. They are metabolized primarily in skeletal muscle (not liver) and are important for muscle protein synthesis and energy during exercise.` },
      { q:`Serine, threonine, and tyrosine are important in cell signaling because:`, ch:[`They can form disulfide bonds`,`Their hydroxyl groups can be phosphorylated by protein kinases`,`They are the most abundant amino acids in proteins`,`Their side chains are always charged`], ans:1, exp:`Protein kinases phosphorylate the -OH groups of Ser, Thr, and Tyr, adding a negatively charged phosphate group that changes protein conformation and activity. Phosphatases remove these groups, making phosphorylation a reversible regulatory switch.` },
      { q:`Glutamine and asparagine differ from glutamate and aspartate by having:`, ch:[`An extra carbon atom`,`A phosphate group instead of a carboxyl`,`An amide group (-CONH2) instead of a carboxyl group (-COOH), making them polar but uncharged`,`A thiol group in place of the carboxyl`], ans:2, exp:`Glutamine (from glutamate) and asparagine (from aspartate) have amide (-CONH2) side chains rather than carboxyl groups, making them polar but uncharged at physiological pH. Gln is the most abundant free amino acid in blood.` },
      { q:`Which property of the alpha helix contributes most to its stability?`, ch:[`Disulfide bonds between adjacent residues`,`Hydrogen bonds between the C=O of one residue and the N-H of the residue 4 positions later`,`Ionic bonds between charged side chains`,`Hydrophobic interactions between aromatic rings`], ans:1, exp:`α-Helices are stabilized primarily by intrachain hydrogen bonds between the backbone C=O of residue n and the N-H of residue n+4. The helix turns every 3.6 residues, and all backbone groups participate in hydrogen bonding.` },
    ]
  },
  {
    id:'bb09', cat:'Bio/Biochem', title:'Protein Structure: Primary Through Quaternary', diff:'Easy',
    qs:[
      { q:`Primary protein structure refers to:`, ch:[`The 3D folded shape of a protein`,`The sequence of amino acids in the polypeptide chain`,`The arrangement of multiple polypeptide subunits`,`Local regular repeating structures like helices`], ans:1, exp:`Primary structure is the linear sequence of amino acids connected by peptide bonds. This sequence is determined by the gene and dictates all higher-order structures.` },
      { q:`Secondary protein structure is stabilized primarily by:`, ch:[`Disulfide bonds`,`Hydrogen bonds between backbone carbonyl and amide groups`,`Ionic interactions between side chains`,`Hydrophobic interactions between nonpolar side chains`], ans:1, exp:`Secondary structures (α-helices and β-sheets) are stabilized by hydrogen bonds between backbone C=O and N-H groups. These are NOT between side chains — side chains participate in tertiary structure stabilization.` },
      { q:`The beta-sheet is a secondary structure where:`, ch:[`The polypeptide chain coils into a helix`,`Adjacent polypeptide chains (or segments) are held together by hydrogen bonds between backbone groups, forming a pleated sheet`,`Multiple subunits are held together by non-covalent bonds`,`Proline residues create rigid kinks`], ans:1, exp:`β-Sheets consist of β-strands arranged laterally, connected by backbone hydrogen bonds. Parallel strands run in the same direction; antiparallel strands run in opposite directions. β-Sheets are flatter than α-helices.` },
      { q:`Tertiary protein structure refers to:`, ch:[`The linear amino acid sequence`,`The local regular repeating structures`,`The overall 3D folding of a single polypeptide chain`,`The association of multiple subunits`], ans:2, exp:`Tertiary structure is the complete 3D conformation of a polypeptide, including all the ways secondary structure elements pack together. It is stabilized by hydrophobic interactions, H-bonds, ionic bonds, and disulfide bonds between side chains.` },
      { q:`Quaternary protein structure refers to:`, ch:[`The first amino acid in the chain`,`The 3D shape of a single polypeptide`,`The arrangement and interactions of multiple polypeptide subunits in a multi-subunit protein`,`The secondary structural elements`], ans:2, exp:`Quaternary structure is the association of two or more polypeptide subunits (e.g., hemoglobin = 2α + 2β subunits). Subunits are held together by non-covalent interactions and sometimes disulfide bonds.` },
      { q:`Protein denaturation involves:`, ch:[`Cleavage of peptide bonds`,`Loss of 3D structure while primary sequence remains intact`,`Permanent destruction of the amino acid sequence`,`Glycosylation of the protein`], ans:1, exp:`Denaturation disrupts non-covalent interactions maintaining 3D structure (heat, pH, detergents), causing unfolding. The primary structure (peptide bonds) remains intact. Some proteins can renature when conditions are restored.` },
      { q:`Chaperone proteins function by:`, ch:[`Degrading misfolded proteins`,`Assisting correct protein folding and preventing aggregation of unfolded proteins`,`Synthesizing proteins at ribosomes`,`Adding sugar chains to glycoproteins`], ans:1, exp:`Molecular chaperones (Hsp70, Hsp90, chaperonins like GroEL) prevent misfolding and aggregation by transiently binding to exposed hydrophobic regions, providing a protected environment for proper folding.` },
      { q:`Hydrophobic interactions in protein folding:`, ch:[`Occur primarily on the protein surface`,`Are strongest at low temperatures`,`Drive nonpolar side chains to the interior of the protein, away from water`,`Involve charged side chains`], ans:2, exp:`The hydrophobic effect is the primary thermodynamic driving force for protein folding. Nonpolar side chains cluster in the hydrophobic core, minimizing contact with water and maximizing the entropy of surrounding water molecules.` },
      { q:`Disulfide bonds in proteins are:`, ch:[`Hydrogen bonds between cysteine residues`,`Covalent bonds between the sulfur atoms of two cysteine residues`,`Found mainly inside the cytoplasm`,`Formed by phenylalanine residues`], ans:1, exp:`Disulfide bonds (-S-S-) form by oxidation of two cysteine -SH groups. They are covalent bonds that stabilize extracellular proteins (e.g., antibodies, insulin). The reducing environment of the cytoplasm prevents their formation there.` },
      { q:`The Anfinsen experiment demonstrated that:`, ch:[`Protein sequence determines tertiary structure`,`Chaperones are essential for all protein folding`,`All proteins contain disulfide bonds`,`Denaturation is always irreversible`], ans:0, exp:`Anfinsen showed that denatured ribonuclease A spontaneously refolded to its native conformation when denaturing conditions were removed, demonstrating that primary sequence encodes all information needed for correct folding.` },
      { q:`Alpha helices have a characteristic rise of:`, ch:[`2.3 Å per residue`,`3.6 Å per residue`,`5.4 Å per residue`,`1.0 Å per residue`], ans:0, exp:`Each residue in an α-helix advances the helix 1.5 Å along the axis, and with 3.6 residues per turn, each turn spans 5.4 Å (1.5 × 3.6). The repeat unit is 3.6 residues and the rise per residue is 1.5 Å.` },
      { q:`Which amino acids are least commonly found in α-helices?`, ch:[`Alanine and leucine`,`Glycine and proline`,`Valine and isoleucine`,`Lysine and glutamate`], ans:1, exp:`Glycine is too flexible (no R group to stabilize helix) and proline cannot participate in helix hydrogen bonding (no NH group) and introduces a kink. Both are helix-breakers.` },
      { q:`Collagen's unique triple helix structure requires:`, ch:[`High proportion of phenylalanine`,`Glycine at every third position (Gly-X-Y repeat) and hydroxyproline for stability`,`Disulfide bonds between all three chains`,`An α-helical secondary structure`], ans:1, exp:`Collagen's Gly-X-Y repeat (where X is often proline, Y is often hydroxyproline) allows three left-handed polyproline II helices to wind together. Glycine's small size fits in the interior. Hydroxyproline forms H-bonds between chains, requiring vitamin C for its synthesis.` },
      { q:`Motor proteins like myosin and kinesin:`, ch:[`Synthesize proteins at ribosomes`,`Convert chemical energy (ATP) into mechanical movement along cytoskeletal filaments`,`Are responsible for cell membrane transport`,`Degrade misfolded proteins`], ans:1, exp:`Motor proteins use ATP hydrolysis to generate force and movement. Myosin moves along actin filaments (muscle contraction). Kinesin and dynein move cargo along microtubules toward (+) and (-) ends, respectively.` },
      { q:`Proteomics is the large-scale study of:`, ch:[`The complete set of genes in an organism`,`The complete set of proteins expressed by a cell, tissue, or organism at a given time`,`The 3D structure of a single protein`,`mRNA expression patterns`], ans:1, exp:`Proteomics characterizes the entire protein complement (proteome) of a cell/tissue/organism. Unlike the genome (static), the proteome is dynamic — changing with cell type, developmental stage, and environment.` },
    ]
  },
  {
    id:'bb10', cat:'Bio/Biochem', title:'Lipid Classification & Structure', diff:'Easy',
    qs:[
      { q:`Fatty acids are characterized by:`, ch:[`Short chains of amino acids`,`Long hydrocarbon chains with a carboxyl group (-COOH) at one end`,`Rings of carbon atoms`,`Short glucose polymers`], ans:1, exp:`Fatty acids consist of a long hydrocarbon chain (usually 12-20 carbons) with a carboxyl group at the alpha end. They may be saturated (no double bonds) or unsaturated (one or more double bonds).` },
      { q:`A saturated fatty acid:`, ch:[`Has at least one carbon-carbon double bond`,`Has no carbon-carbon double bonds`,`Is liquid at room temperature`,`Contains phosphate groups`], ans:1, exp:`Saturated fatty acids (e.g., palmitic acid, 16:0) have all C-C single bonds, allowing tight packing and high melting points. They are solid at room temperature and are abundant in animal fats.` },
      { q:`Phospholipids are important as:`, ch:[`Energy storage molecules`,`The primary structural components of cell membranes`,`Enzymatic cofactors`,`Signaling molecules only`], ans:1, exp:`Phospholipids (glycerol + 2 fatty acids + phosphate head group) are the primary structural lipids of cell membranes. Their amphipathic nature drives spontaneous bilayer formation.` },
      { q:`Triglycerides (triacylglycerols) store energy as:`, ch:[`Polysaccharide chains`,`Three fatty acids esterified to a glycerol backbone`,`Cholesterol with attached fatty acids`,`Phospholipid bilayers`], ans:1, exp:`Triglycerides = glycerol + 3 fatty acids linked by ester bonds. They store more energy per gram than carbohydrates (~9 kcal/g vs ~4 kcal/g) because fatty acid carbons are more reduced.` },
      { q:`Cholesterol is a:`, ch:[`Fatty acid`,`Triglyceride`,`Steroid with a four-ring structure`,`Phospholipid`], ans:2, exp:`Cholesterol is a sterol (steroid alcohol) with a fused four-ring (cyclopentanoperhydrophenanthrene) structure. It is a precursor for steroid hormones, bile acids, and vitamin D, and modulates membrane fluidity.` },
      { q:`Cis double bonds in unsaturated fatty acids:`, ch:[`Allow tighter packing of fatty acid chains`,`Introduce a bend (kink) that prevents tight packing, lowering the melting point`,`Increase the melting point of the fatty acid`,`Are found in trans fats`], ans:1, exp:`Cis double bonds create ~30° kinks in the fatty acid chain, preventing tight packing and decreasing melting point. This is why vegetable oils (polyunsaturated) are liquid at room temperature while saturated animal fats are solid.` },
      { q:`Sphingolipids are structurally distinct from phospholipids because they use:`, ch:[`Glycerol as their backbone`,`Sphingosine (a long-chain amino alcohol) as their backbone`,`Three fatty acid chains`,`No polar head group`], ans:1, exp:`Sphingolipids (sphingomyelin, cerebrosides, gangliosides) have sphingosine as their backbone instead of glycerol. Sphingosine + fatty acid = ceramide (the core building block). They are abundant in nervous tissue.` },
      { q:`Eicosanoids are derived from:`, ch:[`Cholesterol`,`20-carbon polyunsaturated fatty acids, especially arachidonic acid`,`Glycerol`,`Sphingosine`], ans:1, exp:`Eicosanoids (prostaglandins, thromboxanes, leukotrienes) are signaling molecules derived from C20 fatty acids, primarily arachidonic acid (20:4, ω-6). Cyclooxygenase (COX) produces prostaglandins; lipoxygenase produces leukotrienes.` },
      { q:`Waxes function primarily as:`, ch:[`Energy storage in animals`,`Protective waterproof coatings on plant leaves and animal fur/feathers`,`Components of cell membranes`,`Signaling molecules`], ans:1, exp:`Waxes (long-chain fatty acid esterified to a long-chain alcohol) are highly hydrophobic and serve as waterproof protective coatings. Examples: beeswax, plant cuticle wax, ear wax (cerumen).` },
      { q:`The omega (ω) classification of fatty acids indicates:`, ch:[`The total length of the fatty acid chain`,`The position of the last double bond counting from the methyl (omega) end`,`The degree of branching`,`The melting point of the fatty acid`], ans:1, exp:`Omega numbering counts from the methyl (omega) end: ω-3 (fish oil, ALA) have the first double bond at C3; ω-6 (linoleic acid) at C6. These are essential fatty acids humans cannot synthesize.` },
      { q:`Bile acids are derived from:`, ch:[`Phospholipids`,`Cholesterol`,`Triglycerides`,`Sphingolipids`], ans:1, exp:`Bile acids (cholic acid, deoxycholic acid) are synthesized from cholesterol in the liver and stored in the gallbladder. They emulsify dietary fats in the small intestine, facilitating lipase access and lipid absorption.` },
      { q:`Lipid droplets in adipocytes store lipids primarily as:`, ch:[`Phospholipids`,`Cholesterol esters`,`Glycolipids`,`Triglycerides`], ans:3, exp:`Adipocytes store energy primarily as triglycerides within cytoplasmic lipid droplets coated by perilipin proteins. Lipolysis by hormone-sensitive lipase releases fatty acids for energy during fasting/exercise.` },
      { q:`Trans fatty acids differ from cis fatty acids in that they:`, ch:[`Have more double bonds`,`Have the same melting point as saturated fats`,`Have a trans double bond configuration that allows more linear chain packing`,`Are found only in fish oil`], ans:2, exp:`Trans fats (partially hydrogenated oils) have a trans configuration at the double bond, allowing chain packing more similar to saturated fats. They raise LDL cholesterol and lower HDL, increasing cardiovascular disease risk.` },
      { q:`Gangliosides are glycolipids that:`, ch:[`Are found exclusively in cell nuclei`,`Are abundant in neuronal cell membranes and contain sialic acid in their head groups`,`Function as energy storage molecules`,`Are the primary structural lipid in red blood cells`], ans:1, exp:`Gangliosides (e.g., GM1, GM2, GM3) are complex sphingolipids with oligosaccharide head groups containing one or more sialic acid residues. They are abundant in neuron plasma membranes and are important for cell recognition.` },
      { q:`Lipid-soluble vitamins are stored in:`, ch:[`Red blood cells`,`The kidney`,`Fatty tissues and liver`,`The plasma`], ans:2, exp:`Fat-soluble vitamins (A, D, E, K) are stored in adipose tissue and the liver because they associate with lipids. Unlike water-soluble vitamins, they can accumulate to toxic levels with excessive supplementation (fat-soluble vitamin toxicity).` },
    ]
  },
  {
    id:'bb11', cat:'Bio/Biochem', title:'Nucleotide Structure & DNA Basics', diff:'Easy',
    qs:[
      { q:`A nucleotide consists of:`, ch:[`A sugar, a phosphate group, and a nitrogenous base`,`Two amino acids and a sugar`,`A fatty acid, glycerol, and a phosphate`,`A sugar and a nitrogenous base only`], ans:0, exp:`Nucleotides have three components: a pentose sugar (ribose in RNA, deoxyribose in DNA), a phosphate group, and a nitrogenous base (purine or pyrimidine). A nucleoside lacks the phosphate.` },
      { q:`Which bases are purines?`, ch:[`Cytosine and thymine`,`Adenine and guanine`,`Uracil and cytosine`,`Adenine and cytosine`], ans:1, exp:`Purines (adenine and guanine) have a double-ring structure (fused pyrimidine + imidazole rings). Pyrimidines (cytosine, thymine, uracil) have a single ring. Mnemonic: PURe As Gold = Purines: Adenine, Guanine.` },
      { q:`In DNA, adenine pairs with thymine using:`, ch:[`One hydrogen bond`,`Two hydrogen bonds`,`Three hydrogen bonds`,`A covalent bond`], ans:1, exp:`A-T base pairs form 2 hydrogen bonds; G-C base pairs form 3 hydrogen bonds. Higher G-C content increases DNA melting temperature because 3 H-bonds require more energy to disrupt than 2.` },
      { q:`The sugar in DNA is:`, ch:[`Ribose`,`Glucose`,`Deoxyribose`,`Galactose`], ans:2, exp:`DNA contains 2'-deoxyribose (missing the 2'-OH of ribose). This makes DNA more stable than RNA because the 2'-OH in RNA can participate in hydrolysis reactions.` },
      { q:`DNA strands are antiparallel, meaning:`, ch:[`They have the same sequence`,`One strand runs 5'→3' while the complementary strand runs 3'→5'`,`Both strands are single-stranded`,`They are identical in sequence`], ans:1, exp:`The two strands of a DNA double helix run in opposite directions: one 5'→3' and the other 3'→5'. This antiparallel orientation is essential for complementary base pairing and replication.` },
      { q:`RNA differs from DNA in that RNA:`, ch:[`Uses deoxyribose instead of ribose`,`Is usually double-stranded`,`Contains uracil instead of thymine and uses ribose`,`Contains thymine instead of uracil`], ans:2, exp:`RNA uses ribose (vs. deoxyribose in DNA) and uracil instead of thymine. RNA is typically single-stranded. The 2'-OH in ribose makes RNA more chemically reactive and less stable than DNA.` },
      { q:`The 5' end of a DNA/RNA strand has:`, ch:[`A free 3'-OH group`,`A free phosphate group`,`A nitrogenous base only`,`A methyl group`], ans:1, exp:`The 5' end has a free 5'-phosphate group (or triphosphate in the original nucleotide). The 3' end has a free hydroxyl group (-OH). Nucleic acid synthesis always occurs 5'→3' (adding nucleotides to the 3'-OH).` },
      { q:`The central dogma of molecular biology states:`, ch:[`RNA → DNA → Protein`,`DNA → RNA → Protein`,`Protein → DNA → RNA`,`DNA → Protein directly`], ans:1, exp:`The central dogma (Crick, 1958): DNA is transcribed to RNA, which is translated into protein. Exceptions include reverse transcription (RNA→DNA by retroviruses) and RNA replication by RNA viruses.` },
      { q:`A codon is:`, ch:[`A sequence of 3 nucleotides in mRNA that specifies an amino acid`,`A sequence of 3 nucleotides in tRNA`,`The entire mRNA sequence`,`A regulatory sequence in the promoter`], ans:0, exp:`Codons are triplets of mRNA nucleotides (read 5'→3') that specify a particular amino acid or stop signal. With 4 bases and triplet code, there are 4³=64 codons for 20 amino acids — the code is degenerate (multiple codons per amino acid).` },
      { q:`A gene is best defined as:`, ch:[`All the DNA in a cell`,`A segment of DNA that encodes a functional RNA or protein product`,`Only the protein-coding portions of the genome`,`The regulatory regions of chromosomes`], ans:1, exp:`A gene is a segment of DNA encoding a functional product — either a protein (via mRNA) or a functional RNA (rRNA, tRNA, miRNA, etc.). Human genome has ~20,000-25,000 protein-coding genes.` },
      { q:`Chromosomes are composed of:`, ch:[`DNA only`,`RNA and protein`,`DNA wrapped around histone proteins, forming chromatin`,`Protein only`], ans:2, exp:`Chromosomes are made of chromatin = DNA tightly wound around histone octamers (nucleosomes), further condensed into higher-order structures. Eukaryotic human cells have 23 pairs (46 total) of chromosomes.` },
      { q:`Which type of RNA carries amino acids to the ribosome during translation?`, ch:[`mRNA`,`rRNA`,`tRNA`,`snRNA`], ans:2, exp:`tRNA (transfer RNA) has an anticodon that base-pairs with the mRNA codon, and carries the corresponding amino acid at its 3'-CCA end. Aminoacyl-tRNA synthetases charge tRNA with the correct amino acid.` },
      { q:`The promoter region of a gene:`, ch:[`Codes for the first amino acid of the protein`,`Is a DNA sequence where RNA polymerase binds to initiate transcription`,`Is the stop codon`,`Is found at the 3' end of the gene`], ans:1, exp:`The promoter is a DNA sequence upstream (5') of the transcription start site where RNA polymerase and transcription factors bind to initiate transcription. In prokaryotes, key elements are the -10 and -35 sequences.` },
      { q:`Introns differ from exons in that introns:`, ch:[`Code for protein and are retained in mature mRNA`,`Are non-coding sequences removed from pre-mRNA during splicing`,`Are found only in prokaryotes`,`Form the ribosome structure`], ans:1, exp:`Introns (intervening sequences) are removed from pre-mRNA by the spliceosome. Exons (expressed sequences) are retained and ligated together to form mature mRNA. Most human genes contain many introns.` },
      { q:`The genetic code is said to be degenerate because:`, ch:[`Different organisms use different codons`,`Most amino acids are encoded by more than one codon`,`Some codons encode multiple amino acids`,`The code changes during development`], ans:1, exp:`The genetic code is degenerate: most of the 20 amino acids have more than one codon. For example, leucine has 6 codons. This redundancy often allows silent mutations that don't change the amino acid.` },
    ]
  },
  {
    id:'bb12', cat:'Bio/Biochem', title:'Mitosis & Meiosis Fundamentals', diff:'Easy',
    qs:[
      { q:`During which phase of mitosis do chromosomes align at the cell's equator?`, ch:[`Prophase`,`Metaphase`,`Anaphase`,`Telophase`], ans:1, exp:`Metaphase: chromosomes align at the metaphase plate (cell equator), attached to spindle fibers via kinetochores. This alignment ensures equal distribution of chromosomes to daughter cells.` },
      { q:`Meiosis produces:`, ch:[`2 identical diploid cells`,`4 genetically unique haploid cells`,`2 haploid cells`,`4 identical diploid cells`], ans:1, exp:`Meiosis produces 4 haploid (n) cells from one diploid (2n) parent cell. Genetic variation arises from crossing over (prophase I) and independent assortment of homologs.` },
      { q:`Crossing over during meiosis occurs in:`, ch:[`Metaphase I`,`Anaphase II`,`Prophase I`,`Telophase II`], ans:2, exp:`Crossing over (homologous recombination) occurs during prophase I of meiosis when homologous chromosomes pair up (synapsis) and exchange genetic segments at chiasmata. This creates recombinant chromosomes increasing genetic diversity.` },
      { q:`Sister chromatids are:`, ch:[`Homologous chromosomes from opposite parents`,`Identical copies of a chromosome joined at the centromere after DNA replication`,`The haploid cells produced after meiosis II`,`Chromosomes from different species`], ans:1, exp:`Sister chromatids are exact copies of a chromosome held together at the centromere. They form during S phase (DNA replication) and separate during anaphase of mitosis (or anaphase II of meiosis).` },
      { q:`The cell cycle phase in which DNA is replicated is:`, ch:[`G1 phase`,`S phase`,`G2 phase`,`M phase`], ans:1, exp:`DNA replication occurs in S (synthesis) phase. The cell cycle: G1 (growth, preparation) → S (DNA synthesis) → G2 (growth, preparation for division) → M (mitosis/meiosis).` },
      { q:`Nondisjunction refers to:`, ch:[`Normal chromosome separation during meiosis`,`Failure of chromosomes or chromatids to separate properly during cell division, resulting in aneuploidy`,`Crossing over at incorrect positions`,`Failure of cytokinesis`], ans:1, exp:`Nondisjunction: chromosomes fail to separate properly, producing gametes with extra or missing chromosomes (n+1 or n-1). Results in trisomy (e.g., Down syndrome, trisomy 21) or monosomy.` },
      { q:`Cytokinesis refers to:`, ch:[`DNA replication`,`Chromosome condensation`,`Division of the cytoplasm to form two daughter cells following nuclear division`,`The checkpoint before DNA replication`], ans:2, exp:`Cytokinesis divides the cytoplasm after nuclear division is complete. In animal cells, a cleavage furrow (actin-myosin ring) pinches the cell in two. In plant cells, a cell plate forms between daughter cells.` },
      { q:`A diploid organism has:`, ch:[`One copy of each chromosome (n)`,`Two copies of each chromosome (2n)`,`Four copies of each chromosome (4n)`,`An indeterminate number of chromosomes`], ans:1, exp:`Diploid cells (2n) contain two complete sets of chromosomes — one from each parent. Human somatic cells are 2n=46. Haploid cells (n=23) are produced by meiosis and found in gametes.` },
      { q:`Meiosis I is unique because it:`, ch:[`Separates sister chromatids`,`Is the phase where cytokinesis occurs`,`Separates homologous chromosome pairs (reduces chromosome number from 2n to n)`,`Is identical to mitosis`], ans:2, exp:`Meiosis I is the reductional division: homologous chromosomes (bivalents) separate, reducing the cell from 2n to n. This is fundamentally different from mitosis, which separates sister chromatids and maintains ploidy.` },
      { q:`The spindle apparatus is composed of:`, ch:[`Actin microfilaments`,`Microtubules (tubulin polymers) that attach to chromosomes via kinetochores`,`Intermediate filaments`,`DNA strands connecting chromosomes`], ans:1, exp:`Spindle fibers are microtubules (α/β tubulin polymers) that extend from centrosomes (MTOC). They attach to chromosomes at kinetochores during prometaphase and pull chromosomes apart during anaphase.` },
      { q:`G2/M checkpoint primarily monitors:`, ch:[`Whether DNA replication has occurred correctly`,`Whether nutrients are available for cell division`,`Whether the cell has grown large enough`,`Whether mitosis is complete`], ans:0, exp:`The G2/M checkpoint checks for complete and accurate DNA replication before entering mitosis. If DNA damage or replication errors are detected, the checkpoint halts cell cycle progression until repairs are made.` },
      { q:`The number of chromosomes in a human gamete is:`, ch:[`46`,`92`,`23`,`48`], ans:2, exp:`Human gametes (sperm and eggs) are haploid: n=23 chromosomes (one from each homologous pair). Fertilization restores the diploid number: 23+23=46 chromosomes in the zygote.` },
      { q:`Mitosis results in:`, ch:[`4 genetically unique haploid cells`,`2 genetically identical diploid cells`,`2 haploid cells with random genetic combinations`,`4 identical haploid cells`], ans:1, exp:`Mitosis produces 2 daughter cells genetically identical to the parent cell (barring mutation). Used for growth, tissue repair, and asexual reproduction. Maintains the diploid chromosome number.` },
      { q:`Telomeres function to:`, ch:[`Initiate DNA replication`,`Code for ribosomal RNA`,`Protect chromosome ends from degradation and inappropriate fusion`,`Serve as centromere attachment sites`], ans:2, exp:`Telomeres are repetitive DNA sequences (TTAGGG in humans) at chromosome ends that protect against degradation and fusion. They shorten with each cell division; critically short telomeres trigger senescence or apoptosis.` },
      { q:`During anaphase of mitosis:`, ch:[`Chromosomes condense and become visible`,`The nuclear envelope breaks down`,`Sister chromatids separate and are pulled to opposite poles`,`The nuclear envelope reforms`], ans:2, exp:`During anaphase, cohesins are cleaved by separase, releasing sister chromatid connections. Spindle fibers pull the separated chromatids (now individual chromosomes) to opposite poles of the cell.` },
    ]
  },
  {
    id:'bb13', cat:'Bio/Biochem', title:'Mendelian Genetics', diff:'Easy',
    qs:[
      { q:`The law of segregation states that:`, ch:[`Genes on different chromosomes are inherited together`,`Two alleles for each trait separate during gamete formation, so each gamete receives one allele`,`Dominant alleles always mask recessive alleles`,`Crossing over shuffles gene combinations`], ans:1, exp:`Mendel's first law: the two alleles for each trait segregate (separate) during gamete formation. Each gamete receives one allele, and they reunite randomly at fertilization.` },
      { q:`In a monohybrid cross between two heterozygotes (Aa × Aa), the phenotypic ratio is:`, ch:[`1:1`,`1:2:1`,`3:1`,`9:3:3:1`], ans:2, exp:`Aa × Aa produces offspring: 1 AA : 2 Aa : 1 aa (genotypic ratio 1:2:1). Since A is dominant, 3 show the dominant phenotype (AA + Aa) and 1 shows recessive (aa) → 3:1 phenotypic ratio.` },
      { q:`A test cross is performed by crossing an unknown genotype with:`, ch:[`Another heterozygote`,`A homozygous dominant individual`,`A homozygous recessive individual`,`An individual with the same phenotype`], ans:2, exp:`A test cross (with homozygous recessive, aa) reveals the genotype of an individual with the dominant phenotype. If offspring are all dominant → homozygous dominant (AA); if 1:1 dominant:recessive → heterozygous (Aa).` },
      { q:`Incomplete dominance results in:`, ch:[`One allele completely masking the other`,`The heterozygote expressing an intermediate phenotype between the two homozygotes`,`Both alleles being fully expressed simultaneously`,`Offspring having a different trait than either parent`], ans:1, exp:`In incomplete dominance (e.g., red × white → pink snapdragons), neither allele is completely dominant, and the heterozygote shows an intermediate phenotype. The 3:1 phenotypic ratio changes to 1:2:1.` },
      { q:`The ABO blood group demonstrates:`, ch:[`Simple dominance`,`Incomplete dominance`,`Codominance and multiple alleles`,`X-linked inheritance`], ans:2, exp:`ABO involves multiple alleles (IA, IB, i) and codominance: IA and IB are both fully expressed when present together (type AB), while i is recessive. This is the classic example of codominance.` },
      { q:`A carrier of an autosomal recessive disease is:`, ch:[`Homozygous dominant (AA)`,`Homozygous recessive (aa) — affected`,`Heterozygous (Aa) — unaffected but can pass the allele`,`Only females can be carriers`], ans:2, exp:`A carrier is heterozygous (Aa): they carry one recessive disease allele but are phenotypically unaffected because the dominant allele compensates. Two carriers have a 25% chance of producing an affected (aa) child.` },
      { q:`The law of independent assortment states that:`, ch:[`All genes segregate together`,`Alleles of different genes on different chromosome pairs assort independently during gamete formation`,`Linked genes always separate`,`Dominant alleles are passed more frequently`], ans:1, exp:`Mendel's second law: alleles of genes on different chromosomes segregate independently of each other during meiosis. This produces all possible combinations. Linked genes (on the same chromosome) do NOT follow this law.` },
      { q:`In X-linked recessive inheritance, the trait:`, ch:[`Affects males and females equally`,`Is more common in females`,`Is more common in males, who need only one copy of the allele`,`Skips generations in both sexes equally`], ans:2, exp:`Males (XY) need only one copy of the X-linked recessive allele to be affected (hemizygous). Females (XX) require two copies. This explains why X-linked recessive diseases (hemophilia, color blindness) are far more common in males.` },
      { q:`Which genotypic ratio results from a dihybrid cross (AaBb × AaBb)?`, ch:[`1:2:1`,`3:1`,`9:3:3:1`,`1:1:1:1`], ans:2, exp:`A dihybrid cross AaBb × AaBb yields a 9:3:3:1 phenotypic ratio (9 A_B_ : 3 A_bb : 3 aaB_ : 1 aabb) when both genes assort independently and one allele is dominant at each locus.` },
      { q:`Penetrance in genetics refers to:`, ch:[`The number of alleles a person has`,`The proportion of individuals with a given genotype who actually show the expected phenotype`,`The severity of a disease phenotype`,`Whether a trait is dominant or recessive`], ans:1, exp:`Penetrance is the proportion of individuals with a genotype who express the associated phenotype. Complete penetrance = 100% of carriers are affected. Reduced/incomplete penetrance means some carriers show no phenotype.` },
      { q:`Hemophilia A is caused by:`, ch:[`An autosomal recessive mutation`,`An autosomal dominant mutation`,`An X-linked recessive mutation in the Factor VIII gene`,`A mitochondrial mutation`], ans:2, exp:`Hemophilia A is an X-linked recessive disorder caused by deficiency of clotting Factor VIII. Males with the mutation on their single X chromosome are affected; carrier females are mostly unaffected.` },
      { q:`Pedigree analysis uses which symbol for an affected female?`, ch:[`Open circle`,`Filled circle`,`Open square`,`Filled square`], ans:1, exp:`Pedigree conventions: circles = females, squares = males. Filled shapes = affected individuals; open shapes = unaffected. Carriers are sometimes shown with half-filled symbols or a dot inside.` },
      { q:`If two parents are carriers of cystic fibrosis (Aa × Aa), what is the probability their child will have cystic fibrosis?`, ch:[`50%`,`75%`,`25%`,`100%`], ans:2, exp:`Aa × Aa produces 1/4 AA, 2/4 Aa, 1/4 aa. Cystic fibrosis is autosomal recessive (aa), so there is a 1/4 = 25% probability that a child will be affected.` },
      { q:`Genomic imprinting causes:`, ch:[`Random mutation of genes`,`Differential expression of a gene depending on whether it was inherited from the mother or father`,`Identical twins to have different phenotypes`,`Genes to be expressed equally from both parents`], ans:1, exp:`Genomic imprinting: some genes are expressed monoallelically based on parental origin due to epigenetic marks. Example: Angelman syndrome (maternal allele affected) vs. Prader-Willi syndrome (paternal allele affected) — same chromosome region, different disorders.` },
      { q:`Epistasis is when:`, ch:[`Two genes are found on the same chromosome`,`One gene masks the expression of another gene at a different locus`,`A gene has multiple phenotypic effects`,`Two alleles at the same locus interact`], ans:1, exp:`Epistasis: one gene (epistatic gene) masks the expression of another gene (hypostatic gene) at a different locus. This can produce modified ratios in dihybrid crosses (e.g., 9:7, 12:3:1, 15:1 instead of 9:3:3:1).` },
    ]
  },
  {
    id:'bb14', cat:'Bio/Biochem', title:'Cell Signaling & Second Messengers', diff:'Easy',
    qs:[
      { q:`Which second messenger is produced by adenylyl cyclase when stimulated by G-protein alpha subunit?`, ch:[`IP3`,`DAG`,`cAMP`,`Ca2+`], ans:2, exp:`Adenylyl cyclase converts ATP → cAMP (cyclic AMP) when activated by the Gαs subunit (stimulatory G-protein). cAMP activates Protein Kinase A (PKA), which phosphorylates target proteins to alter cell function.` },
      { q:`GPCRs (G protein-coupled receptors) work by:`, ch:[`Directly phosphorylating target proteins`,`Activating G proteins that regulate effector proteins like adenylyl cyclase or phospholipase C`,`Forming ion channels when ligand binds`,`Dimerizing and activating intrinsic kinase domains`], ans:1, exp:`GPCRs are 7-transmembrane receptors that couple to heterotrimeric G proteins (Gα, Gβ, Gγ). Ligand binding causes GDP→GTP exchange on Gα, activating effectors (adenylyl cyclase, phospholipase C) until GTP is hydrolyzed.` },
      { q:`Phospholipase C (PLC) generates which second messengers?`, ch:[`cAMP and PKA`,`cGMP and PKG`,`IP3 and diacylglycerol (DAG)`,`Arachidonic acid and thromboxane`], ans:2, exp:`PLC cleaves PIP2 into IP3 (inositol trisphosphate) and DAG. IP3 triggers Ca2+ release from the ER; DAG activates Protein Kinase C (PKC). This is the Gαq signaling pathway.` },
      { q:`Receptor tyrosine kinases (RTKs) are activated by:`, ch:[`GPCRs`,`Ligand binding causing receptor dimerization and autophosphorylation of tyrosine residues`,`cAMP binding`,`Ion channel opening`], ans:1, exp:`RTKs (e.g., insulin receptor, EGF receptor): ligand binding induces receptor dimerization and trans-autophosphorylation of tyrosine residues, creating docking sites for downstream signaling proteins (Ras, PI3K, PLCγ).` },
      { q:`Calcium ions act as second messengers by:`, ch:[`Directly phosphorylating proteins`,`Binding calmodulin and other calcium-binding proteins to activate downstream effectors`,`Activating adenylyl cyclase directly`,`Inhibiting G-protein activity`], ans:1, exp:`Ca2+ binds calmodulin (CaM), causing conformational changes that allow Ca2+-CaM to activate many enzymes including CaM kinase II (CaMKII), myosin light chain kinase (MLCK), and calcineurin.` },
      { q:`Signal amplification in cell signaling occurs because:`, ch:[`Each receptor can only activate one G protein`,`Activated enzymes catalytically produce many second messenger molecules, and kinase cascades amplify the signal at each step`,`Signals are transmitted at the speed of light`,`All signaling proteins are always in the active state`], ans:1, exp:`Cascades amplify: one receptor activates many G proteins → each adenylyl cyclase produces many cAMP molecules → each PKA phosphorylates many targets. A single hormone molecule can activate millions of downstream events.` },
      { q:`The JAK-STAT pathway is activated by:`, ch:[`Steroid hormones`,`Cytokines and growth factors that bind receptors lacking intrinsic kinase activity`,`Receptor tyrosine kinases only`,`cAMP`], ans:1, exp:`Cytokine receptors (e.g., for interferon, EPO, IL-6) lack intrinsic kinase activity but associate with JAK (Janus kinase). Ligand binding activates JAK, which phosphorylates STAT proteins that dimerize and translocate to the nucleus to activate transcription.` },
      { q:`Steroid hormones exert their effects primarily by:`, ch:[`Binding membrane receptors and activating second messengers`,`Binding intracellular receptors that directly regulate gene transcription`,`Opening ion channels`,`Activating adenylyl cyclase`], ans:1, exp:`Steroid hormones (cortisol, estrogen, testosterone) are lipid-soluble and cross the plasma membrane to bind intracellular receptors. The hormone-receptor complex then acts as a transcription factor, directly regulating gene expression.` },
      { q:`Phosphodiesterase (PDE) regulates signaling by:`, ch:[`Generating cAMP from ATP`,`Activating G proteins`,`Degrading cAMP and cGMP, terminating the signal`,`Phosphorylating GPCR receptors`], ans:2, exp:`PDEs hydrolyze cAMP → AMP and cGMP → GMP, terminating cAMP/cGMP signals. Caffeine is a PDE inhibitor, prolonging cAMP action. Sildenafil (Viagra) inhibits PDE5, which breaks down cGMP in penile smooth muscle.` },
      { q:`Negative feedback in signaling pathways serves to:`, ch:[`Amplify the original signal`,`Maintain or prolong signaling`,`Limit or terminate signaling, maintaining homeostasis`,`Cause desensitization of all receptors`], ans:2, exp:`Negative feedback loops limit signal duration and magnitude. For example, PKA phosphorylates and desensitizes the β-adrenergic receptor; β-arrestin promotes receptor internalization, terminating the signal.` },
      { q:`The MAPK (ERK) pathway is primarily involved in:`, ch:[`Apoptosis exclusively`,`Regulating cell proliferation, differentiation, and survival in response to growth factors`,`Ca2+ release from the ER`,`Direct activation of ATP synthase`], ans:1, exp:`The MAPK cascade (Ras → Raf → MEK → ERK) is activated by RTKs and growth factors. Activated ERK phosphorylates transcription factors (Fos, Jun, Myc) to regulate genes for cell growth and differentiation.` },
      { q:`Insulin signaling activates which pathway to promote glucose uptake?`, ch:[`cAMP/PKA pathway`,`PI3K/Akt/mTOR pathway, leading to GLUT4 translocation`,`JAK/STAT pathway`,`Notch signaling`], ans:1, exp:`Insulin → insulin receptor (RTK) → IRS proteins → PI3K → PIP3 → Akt (PKB) phosphorylation → GLUT4-containing vesicles translocate to cell surface, increasing glucose uptake. mTOR activated downstream promotes protein synthesis.` },
      { q:`Receptor downregulation involves:`, ch:[`Increased synthesis of new receptors`,`Internalization and degradation of receptors following prolonged ligand exposure`,`Receptor movement to the nucleus`,`Receptor phosphorylation that activates them`], ans:1, exp:`Prolonged agonist exposure causes receptor desensitization: phosphorylation by GRK and β-arrestin binding trigger clathrin-mediated endocytosis. Internalized receptors are either recycled to the membrane or degraded in lysosomes.` },
      { q:`Nitric oxide (NO) acts as a signaling molecule by:`, ch:[`Binding cell surface receptors`,`Diffusing across membranes and activating soluble guanylyl cyclase to produce cGMP`,`Acting as a kinase directly`,`Activating PLC`], ans:1, exp:`NO (produced by NOS from arginine) is a gas that diffuses freely across membranes. It activates soluble guanylyl cyclase → cGMP → PKG activation → smooth muscle relaxation (vasodilation). Nitroglycerin works by generating NO.` },
      { q:`Protein kinases phosphorylate target proteins on:`, ch:[`Lysine and arginine residues`,`Serine, threonine, or tyrosine residues`,`Proline residues only`,`Glycine and alanine residues`], ans:1, exp:`Most protein kinases transfer γ-phosphate from ATP to hydroxyl groups of serine (Ser/Thr kinases) or tyrosine (Tyr kinases). Phosphorylation changes protein conformation, altering activity, localization, or protein-protein interactions.` },
    ]
  },
  {
    id:'bb15', cat:'Bio/Biochem', title:'Water-Soluble Vitamins', diff:'Easy',
    qs:[
      { q:`Thiamine (Vitamin B1) deficiency causes:`, ch:[`Pellagra`,`Scurvy`,`Beriberi and Wernicke-Korsakoff syndrome`,`Rickets`], ans:2, exp:`Thiamine (B1) is essential as TPP (thiamine pyrophosphate) cofactor for pyruvate dehydrogenase, α-KG dehydrogenase, and transketolase. Deficiency causes beriberi (peripheral neuropathy, heart failure) and Wernicke's encephalopathy in alcoholics.` },
      { q:`Niacin (Vitamin B3) is a precursor for:`, ch:[`FAD and FMN`,`NAD+ and NADP+`,`CoA`,`Pyridoxal phosphate`], ans:1, exp:`Niacin (nicotinic acid or nicotinamide) is used to synthesize NAD+ and NADP+, essential electron carriers in metabolism. Deficiency causes pellagra (the "4 Ds": dermatitis, diarrhea, dementia, death).` },
      { q:`Riboflavin (Vitamin B2) is a precursor for:`, ch:[`NAD+ and NADP+`,`TPP`,`FAD and FMN`,`Biotin`], ans:2, exp:`Riboflavin forms FAD (flavin adenine dinucleotide) and FMN (flavin mononucleotide), which accept 2 electrons as hydride. They function in the ETC (Complex I, II), fatty acid oxidation, and TCA cycle.` },
      { q:`Vitamin C (ascorbic acid) is required for:`, ch:[`Calcium absorption`,`Collagen synthesis — hydroxylation of proline and lysine residues`,`Coagulation of blood`,`Synthesis of thyroid hormones`], ans:1, exp:`Vitamin C is a cofactor for prolyl and lysyl hydroxylase enzymes that hydroxylate proline and lysine in collagen. Deficiency causes scurvy: impaired collagen formation → bleeding gums, poor wound healing, perifollicular hemorrhages.` },
      { q:`Folate (Vitamin B9) is essential for:`, ch:[`Protein catabolism`,`One-carbon metabolism, including synthesis of purines and thymidylate`,`Fatty acid oxidation`,`Glycolysis regulation`], ans:1, exp:`Folate (as THF = tetrahydrofolate) carries one-carbon groups essential for purine synthesis and thymidylate synthesis (dTMP). Deficiency causes megaloblastic anemia and neural tube defects (especially early pregnancy — hence folate supplementation).` },
      { q:`Vitamin B12 (cobalamin) deficiency causes:`, ch:[`Pellagra`,`Megaloblastic anemia and subacute combined degeneration of the spinal cord`,`Beriberi`,`Scurvy`], ans:1, exp:`B12 is required for methionine synthase (methionine synthesis, also recycling THF) and methylmalonyl-CoA mutase (odd-chain FA oxidation). Deficiency causes megaloblastic anemia and neurologic degeneration. B12 is found only in animal products.` },
      { q:`Intrinsic factor is required for absorption of:`, ch:[`Vitamin C`,`Folate`,`Vitamin B12`,`Vitamin B6`], ans:2, exp:`Intrinsic factor (IF), secreted by gastric parietal cells, binds B12 and allows its absorption in the terminal ileum. Pernicious anemia = autoimmune destruction of parietal cells → B12 deficiency → megaloblastic anemia and neurologic damage.` },
      { q:`Biotin serves as a cofactor for:`, ch:[`Oxidoreductases`,`Aminotransferases`,`Carboxylases (enzymes that add CO2 to substrates)`,`Phosphatases`], ans:2, exp:`Biotin is covalently attached to carboxylases: pyruvate carboxylase, acetyl-CoA carboxylase, propionyl-CoA carboxylase, and methylcrotonyl-CoA carboxylase. Avidin in raw egg whites avidly binds and inactivates biotin.` },
      { q:`Pyridoxine (Vitamin B6) is required for:`, ch:[`TCA cycle reactions`,`Transamination reactions and amino acid metabolism`,`Nucleotide synthesis`,`Fatty acid elongation`], ans:1, exp:`B6 (as PLP = pyridoxal phosphate) is a cofactor for aminotransferases (transamination), decarboxylases (neurotransmitter synthesis: GABA, serotonin, dopamine), and glycogen phosphorylase.` },
      { q:`Pantothenic acid (Vitamin B5) is a component of:`, ch:[`FAD`,`Coenzyme A (CoA)`,`NAD+`,`Thiamine pyrophosphate`], ans:1, exp:`Pantothenic acid is a precursor for Coenzyme A (CoA) and acyl carrier protein (ACP). CoA is essential for acetyl-CoA (TCA cycle, FA synthesis), succinyl-CoA (heme synthesis), and many other metabolic reactions.` },
      { q:`Which B vitamin is synthesized by intestinal bacteria and is also found in eggs?`, ch:[`Thiamine`,`Niacin`,`Biotin`,`Folate`], ans:2, exp:`Biotin is synthesized by gut bacteria in small amounts and found in eggs (yolk), liver, and nuts. Raw egg white contains avidin, which binds biotin with extremely high affinity, preventing its absorption.` },
      { q:`Niacin can be synthesized from which amino acid?`, ch:[`Methionine`,`Tryptophan`,`Phenylalanine`,`Lysine`], ans:1, exp:`Niacin (B3) can be synthesized endogenously from tryptophan, but at low efficiency (~60 mg Trp = 1 mg niacin). Adequate dietary niacin intake is still required to prevent pellagra, especially when protein/Trp intake is low.` },
      { q:`Which vitamin requires the cofactor MTHFR for its metabolism and, when deficient, raises homocysteine levels?`, ch:[`Vitamin B12 and folate`,`Thiamine and riboflavin`,`Niacin and vitamin B6`,`Vitamin C and biotin`], ans:0, exp:`Both folate (as 5-MTHF) and B12 are required for remethylation of homocysteine to methionine. Deficiency of either raises homocysteine, a cardiovascular risk factor. MTHFR polymorphisms affect folate metabolism.` },
      { q:`The RDA (Recommended Dietary Allowance) for vitamin C in adults is approximately:`, ch:[`5 mg/day`,`90 mg/day`,`500 mg/day`,`1000 mg/day`], ans:1, exp:`The RDA for vitamin C is ~75-90 mg/day for adults (higher for smokers). Scurvy manifests after ~4-6 weeks of severe deficiency. Excess vitamin C (>2 g/day) can cause osmotic diarrhea and increases oxalate kidney stone risk.` },
      { q:`Folate supplementation is especially critical:`, ch:[`In postmenopausal women`,`During the first trimester of pregnancy to prevent neural tube defects`,`In athletes for energy metabolism`,`Only in individuals with renal failure`], ans:1, exp:`Neural tube closure occurs during weeks 3-4 of embryonic development, often before pregnancy is confirmed. Adequate folate intake (400-800 μg/day) before and during early pregnancy dramatically reduces risk of spina bifida and anencephaly.` },
    ]
  },
  {
    id:'bb16', cat:'Bio/Biochem', title:'Fat-Soluble Vitamins', diff:'Easy',
    qs:[
      { q:`The fat-soluble vitamins are:`, ch:[`A, B, C, D`,`A, D, E, K`,`C, D, E, K`,`A, B12, D, K`], ans:1, exp:`Fat-soluble vitamins (A, D, E, K) are absorbed with dietary fat and stored in adipose tissue and liver. Unlike water-soluble vitamins, they can accumulate to toxic levels with excess supplementation.` },
      { q:`Vitamin A (retinol) is essential for:`, ch:[`Blood clotting`,`Vision (retinal is part of rhodopsin) and epithelial cell differentiation`,`Calcium absorption`,`Antioxidant protection of cell membranes`], ans:1, exp:`Vitamin A (as retinal) combines with opsin to form rhodopsin in rod cells, essential for low-light vision. As retinoic acid, it regulates gene expression for epithelial differentiation. Deficiency → night blindness and xerophthalmia.` },
      { q:`Vitamin D is unique among vitamins because:`, ch:[`It is found only in plants`,`It can be synthesized endogenously in skin from 7-dehydrocholesterol upon UV exposure`,`It acts as an electron carrier`,`It cannot be stored in the body`], ans:1, exp:`UV-B radiation converts 7-dehydrocholesterol in skin to previtamin D3 → vitamin D3 (cholecalciferol). D3 is hydroxylated in liver (25-OH-D3) then kidney (1,25-OH-D3 = calcitriol, the active form).` },
      { q:`The active form of vitamin D (calcitriol) regulates:`, ch:[`Glycolysis rate`,`Calcium and phosphate absorption in the small intestine, promoting bone mineralization`,`Blood glucose by stimulating insulin release`,`Heme synthesis`], ans:1, exp:`Calcitriol (1,25-dihydroxyvitamin D3) acts as a steroid hormone: binds intracellular receptors → induces calbindin synthesis → increases Ca2+ absorption in the gut. Deficiency causes rickets (children) or osteomalacia (adults).` },
      { q:`Vitamin K is essential for:`, ch:[`Night vision`,`Activation of clotting factors II, VII, IX, X via gamma-carboxylation of glutamate residues`,`Red blood cell production`,`Antioxidant protection`], ans:1, exp:`Vitamin K (phylloquinone from plants; menaquinone from bacteria) is required for γ-glutamyl carboxylase, which carboxylates glutamate residues in clotting factors (II, VII, IX, X) and proteins C, S. Deficiency → bleeding disorders.` },
      { q:`Warfarin anticoagulates blood by:`, ch:[`Directly inhibiting thrombin`,`Activating fibrinolyis`,`Inhibiting vitamin K epoxide reductase, preventing recycling of active vitamin K`,`Blocking platelet aggregation`], ans:2, exp:`Warfarin inhibits vitamin K epoxide reductase (VKOR), blocking regeneration of active vitamin K hydroquinone. This depletes the cofactor needed for γ-carboxylation of clotting factors II, VII, IX, X, reducing clotting.` },
      { q:`Vitamin E (tocopherol) functions primarily as:`, ch:[`A procoagulant`,`A fat-soluble antioxidant that protects cell membranes from lipid peroxidation`,`A calcium-binding protein`,`A precursor for steroid hormones`], ans:1, exp:`Vitamin E (α-tocopherol) is the primary lipid-soluble antioxidant in cell membranes. It scavenges free radicals (especially peroxyl radicals), preventing propagation of lipid peroxidation. Vitamin C regenerates oxidized vitamin E.` },
      { q:`Vitamin A toxicity (hypervitaminosis A) is characterized by:`, ch:[`Rickets and poor bone mineralization`,`Headache, hepatotoxicity, teratogenicity, and bone abnormalities`,`Scurvy-like symptoms`,`Pellagra`], ans:1, exp:`Excess vitamin A (>10,000 IU/day) causes toxicity: headache, nausea, hepatotoxicity, bone resorption, and is strongly teratogenic (causes birth defects). Isotretinoin (Accutane) — a vitamin A analog — carries strict pregnancy warnings.` },
      { q:`Vitamin D deficiency in children causes:`, ch:[`Scurvy`,`Rickets — softening and weakening of bones due to inadequate mineralization`,`Pellagra`,`Beriberi`], ans:1, exp:`Rickets: inadequate vitamin D leads to reduced Ca2+/phosphate absorption → elevated PTH → impaired bone mineralization → soft, deformable bones (bowed legs, enlarged fontanelle, costochondral beading/rachitic rosary).` },
      { q:`Beta-carotene is important because:`, ch:[`It is the active form of vitamin D`,`It is a provitamin that can be converted to vitamin A and is also an antioxidant`,`It is a precursor for vitamin K`,`It serves as a coenzyme in glycolysis`], ans:1, exp:`β-Carotene (orange pigment in carrots, sweet potatoes) is a provitamin A — two molecules of vitamin A (retinol) can be formed from one β-carotene. It also acts as an antioxidant quenching singlet oxygen.` },
      { q:`Newborns are routinely given vitamin K injection at birth because:`, ch:[`They cannot absorb fat-soluble vitamins`,`They have sterile guts (no bacteria) and low vitamin K stores, putting them at risk for hemorrhagic disease`,`Vitamin K stimulates brain development`,`Their kidneys cannot activate vitamin D`], ans:1, exp:`Neonates have low vitamin K stores, minimal placental transfer, and a sterile gut (no bacterial menaquinone synthesis). Without prophylactic K injection, they risk vitamin K deficiency bleeding (VKDB) — serious intracranial hemorrhage.` },
      { q:`Which vitamin is synthesized by intestinal bacteria and is important for blood clotting?`, ch:[`Vitamin A`,`Vitamin D`,`Vitamin E`,`Vitamin K`], ans:3, exp:`Gut bacteria (bacteroides, E. coli) synthesize menaquinone (vitamin K2), which contributes to vitamin K status. This is why broad-spectrum antibiotics can cause vitamin K deficiency and clotting abnormalities.` },
      { q:`The recommended safe upper limit for vitamin D intake in adults is approximately:`, ch:[`400 IU/day`,`1000 IU/day`,`4000 IU/day`,`10,000 IU/day`], ans:2, exp:`The tolerable upper limit for vitamin D is ~4000 IU/day for adults. Hypervitaminosis D causes hypercalcemia (nausea, weakness, polyuria, nephrocalcinosis). Because it is fat-soluble, excess supplementation can accumulate to toxic levels.` },
      { q:`The main dietary sources of vitamin K include:`, ch:[`Citrus fruits and strawberries`,`Dairy products and fortified cereals`,`Green leafy vegetables (spinach, kale) and fermented foods`,`Red meat and eggs`], ans:2, exp:`Vitamin K1 (phylloquinone) is found in green leafy vegetables (kale, spinach, Brussels sprouts) and vegetable oils. Vitamin K2 (menaquinone) is found in fermented foods (natto, cheese) and produced by gut bacteria.` },
      { q:`Retinol-binding protein (RBP) transports:`, ch:[`Vitamin D in the blood`,`Vitamin A (retinol) in the blood from liver stores to target tissues`,`Vitamin E in lymph`,`Vitamin K to the liver`], ans:1, exp:`Retinol is transported from liver stores bound to RBP (retinol-binding protein) in complex with transthyretin. Vitamin D is transported bound to vitamin D-binding protein (VDBP). Fat-soluble vitamins require specific carrier proteins since they are insoluble in blood.` },
    ]
  },
  {
    id:'bb17', cat:'Bio/Biochem', title:'Introduction to Metabolism', diff:'Easy',
    qs:[
      { q:`Catabolism refers to:`, ch:[`Building complex molecules from simple ones`,`The breakdown of complex molecules to release energy`,`The storage of glucose as glycogen`,`Synthesis of proteins from amino acids`], ans:1, exp:`Catabolism: degradative pathways that break down complex molecules (carbohydrates, fats, proteins) into simpler ones, releasing energy captured as ATP, NADH, and FADH2.` },
      { q:`Anabolism refers to:`, ch:[`The breakdown of complex molecules`,`Energy release through oxidation`,`The synthesis of complex molecules from simpler precursors using energy`,`The conversion of pyruvate to lactate`], ans:2, exp:`Anabolism: biosynthetic pathways that build complex molecules (proteins, glycogen, fatty acids) from simpler precursors. These processes consume ATP and reducing equivalents (NADPH).` },
      { q:`The primary energy currency of cells is:`, ch:[`NADH`,`Glucose`,`ATP (adenosine triphosphate)`,`Glycogen`], ans:2, exp:`ATP is the universal energy currency of cells. The free energy of ATP hydrolysis (ΔG = ~-30.5 kJ/mol) drives nearly all endergonic cellular reactions. ATP is regenerated from ADP + Pi by substrate-level phosphorylation and oxidative phosphorylation.` },
      { q:`NADH and FADH2 are important in metabolism because they:`, ch:[`Directly phosphorylate ADP to ATP`,`Are electron carriers that donate electrons to the ETC for ATP production`,`Directly store energy as chemical bonds`,`Activate enzymes through allosteric regulation`], ans:1, exp:`NADH and FADH2 are reduced electron carriers generated in glycolysis, TCA cycle, and β-oxidation. They donate electrons to the mitochondrial ETC, driving ATP synthesis via chemiosmosis. Each NADH yields ~2.5 ATP; FADH2 yields ~1.5 ATP.` },
      { q:`The metabolic state after a meal (fed state) is characterized by:`, ch:[`Gluconeogenesis and lipolysis`,`Glycolysis, glycogen synthesis, and lipogenesis (fat storage)`,`Ketogenesis and protein catabolism`,`Mobilization of fat stores`], ans:1, exp:`In the fed state, elevated insulin promotes: glucose uptake (GLUT4), glycolysis, glycogen synthesis (liver/muscle), and lipogenesis (liver → VLDL → adipose storage). Glucagon is low; anabolic pathways dominate.` },
      { q:`During fasting, the brain primarily uses which fuel after several days?`, ch:[`Glycogen`,`Fatty acids`,`Lactate`,`Ketone bodies`], ans:3, exp:`During prolonged fasting, the liver produces ketone bodies (acetoacetate, β-hydroxybutyrate) from acetyl-CoA derived from fatty acid β-oxidation. The brain adapts to use ketone bodies, reducing its glucose requirement and sparing muscle protein.` },
      { q:`Glucagon is secreted from the pancreas in response to:`, ch:[`High blood glucose`,`Low blood glucose (fasting)`,`High insulin levels`,`High dietary fat intake`], ans:1, exp:`Glucagon is secreted by pancreatic α-cells in response to low blood glucose. It activates glycogen breakdown (glycogenolysis) and gluconeogenesis in the liver via cAMP/PKA signaling, raising blood glucose.` },
      { q:`Insulin promotes all of the following EXCEPT:`, ch:[`Glucose uptake into muscle and adipose`,`Glycogen synthesis in liver and muscle`,`Gluconeogenesis in the liver`,`Fatty acid synthesis in the liver`], ans:2, exp:`Insulin promotes glucose storage and utilization: increases GLUT4 translocation (glucose uptake), stimulates glycogenesis and lipogenesis, inhibits gluconeogenesis and lipolysis. Gluconeogenesis is stimulated by glucagon, not insulin.` },
      { q:`The metabolic rate is measured by:`, ch:[`Blood glucose levels`,`Oxygen consumption rate — the amount of O2 consumed per unit time reflects energy expenditure`,`The rate of glycolysis only`,`The number of ATP molecules in a cell`], ans:1, exp:`Metabolic rate is measured by indirect calorimetry: O2 consumption and CO2 production reflect overall energy expenditure. Basal metabolic rate (BMR) is the energy needed at rest, influenced by body composition, age, and thyroid hormones.` },
      { q:`Phosphorylation potential in the cell refers to:`, ch:[`The concentration of glucose-6-phosphate`,`The ratio [ATP] / ([ADP][Pi]), indicating the cell's energy status`,`The activity of protein kinases`,`The number of phosphate bonds in NADH`], ans:1, exp:`Phosphorylation potential = [ATP]/([ADP][Pi]). High ratio = high energy charge; signals to inhibit catabolic pathways (glycolysis, TCA). Low ratio = low energy charge; activates catabolism to restore ATP.` },
      { q:`Acetyl-CoA is a central metabolic intermediate because it:`, ch:[`Is the first product of glycolysis`,`Links carbohydrate, fat, and protein catabolism to the TCA cycle`,`Is the primary fuel for the brain`,`Is stored in lysosomes`], ans:1, exp:`Acetyl-CoA (from glycolysis→PDH, fatty acid β-oxidation, and amino acid catabolism) feeds into the TCA cycle for complete oxidation. It is also the building block for fatty acid synthesis and cholesterol.` },
      { q:`The liver plays a central role in metabolism because it:`, ch:[`Is the only organ that can use fatty acids as fuel`,`Performs gluconeogenesis, ketogenesis, urea synthesis, lipoprotein assembly, and bile acid production`,`Is the primary site of protein synthesis for muscle`,`Stores the majority of the body's glycogen`], ans:1, exp:`The liver is the metabolic hub: produces glucose (gluconeogenesis), distributes fat (VLDL), detoxifies NH3 (urea cycle), makes ketone bodies (ketogenesis), synthesizes plasma proteins, and metabolizes xenobiotics.` },
      { q:`During exercise, skeletal muscle preferentially uses:`, ch:[`Only fatty acids`,`Only glucose`,`A mixture of fuels depending on exercise intensity: glucose/glycogen at high intensity, fat at low intensity`,`Only ketone bodies`], ans:2, exp:`Fuel use in muscle depends on exercise intensity. High-intensity exercise (>70% VO2max): primarily glucose (glycolysis + glycogen). Low-intensity sustained exercise: increasing fatty acid oxidation. The crossover point varies with fitness.` },
      { q:`Thermogenesis refers to:`, ch:[`ATP synthesis by oxidative phosphorylation`,`The production of body heat, especially by brown adipose tissue via UCP-1`,`The breakdown of glucose to pyruvate`,`The synthesis of thyroid hormones`], ans:1, exp:`Thermogenesis is heat production. Brown adipose tissue (BAT) contains UCP-1 (uncoupling protein), which dissipates the mitochondrial proton gradient as heat rather than making ATP — critical for temperature regulation in newborns.` },
      { q:`The AMP-activated protein kinase (AMPK) acts as a cellular energy sensor that:`, ch:[`Is activated by high ATP`,`Is activated when AMP:ATP ratio rises, stimulating catabolic pathways and inhibiting anabolic pathways`,`Promotes fatty acid synthesis when energy is low`,`Is activated by insulin signaling`], ans:1, exp:`AMPK is activated by high AMP:ATP (low energy). It phosphorylates and activates catabolic enzymes (ACC inactivated → less FA synthesis → more β-oxidation) and inhibits anabolic enzymes. AMPK is the target of metformin (diabetes drug).` },
    ]
  },
  {
    id:'bb18', cat:'Bio/Biochem', title:'Blood Cell Types & Functions', diff:'Easy',
    qs:[
      { q:`Red blood cells (erythrocytes) lack a nucleus primarily to:`, ch:[`Reduce immune detection`,`Maximize intracellular space for hemoglobin, increasing O2-carrying capacity`,`Enable them to divide rapidly`,`Allow them to cross the blood-brain barrier`], ans:1, exp:`Mature mammalian erythrocytes eject their nucleus during differentiation, maximizing space for ~270 million hemoglobin molecules per cell. This unique adaptation maximizes O2 transport but means they cannot repair themselves or divide.` },
      { q:`Hemoglobin is a tetramer consisting of:`, ch:[`4 identical alpha chains`,`2 alpha and 2 beta chains (in adult HbA)`,`2 alpha and 2 gamma chains`,`4 beta chains`], ans:1, exp:`Adult hemoglobin (HbA) = 2α + 2β subunits, each with a heme group containing Fe2+. HbF (fetal) = 2α + 2γ, with higher O2 affinity. HbA2 = 2α + 2δ, a minor adult form.` },
      { q:`Platelets (thrombocytes) function primarily in:`, ch:[`Transporting oxygen`,`Producing antibodies`,`Initiating blood clotting and primary hemostasis`,`Phagocytosis of bacteria`], ans:2, exp:`Platelets are small anucleate cell fragments (from megakaryocytes) that adhere to damaged vessel walls, aggregate, and release clotting factors initiating primary hemostasis. They express GPIb (binds vWF) and GPIIb/IIIa (binds fibrinogen).` },
      { q:`Neutrophils are the most abundant white blood cells and function as:`, ch:[`Antibody producers`,`First responders: phagocytosis of bacteria and release of antimicrobial enzymes (oxidative burst)`,`Long-lived memory cells`,`Natural killer cells`], ans:1, exp:`Neutrophils (50-70% of WBCs) are the first cells recruited to sites of bacterial infection. They phagocytose and kill bacteria via oxidative burst (NADPH oxidase, myeloperoxidase) and degranulation of antimicrobial enzymes.` },
      { q:`B lymphocytes (B cells) differentiate into plasma cells that:`, ch:[`Phagocytose pathogens directly`,`Secrete antibodies (immunoglobulins) specific to antigens`,`Kill virus-infected cells directly`,`Regulate T-cell activation`], ans:1, exp:`Upon antigen stimulation (with T-cell help), B cells differentiate into plasma cells — antibody factories secreting thousands of IgG/IgM/IgA molecules per second. Memory B cells persist for rapid responses to future exposures.` },
      { q:`T lymphocytes mature in:`, ch:[`The bone marrow`,`The thymus`,`The spleen`,`Lymph nodes`], ans:1, exp:`T cells originate from bone marrow stem cells but migrate to the thymus for maturation. In the thymus, they undergo positive selection (must recognize MHC) and negative selection (must not react to self-antigens), eliminating ~95% of precursors.` },
      { q:`Natural killer (NK) cells:`, ch:[`Require prior sensitization to kill target cells`,`Kill virus-infected and cancer cells without prior sensitization by recognizing missing MHC class I`,`Produce antibodies`,`Are the main cells in adaptive immunity`], ans:1, exp:`NK cells are innate lymphocytes that kill cells showing missing or reduced MHC class I (a sign of viral infection or cancer). They don't require prior exposure — they respond immediately. They use perforin/granzyme-mediated apoptosis.` },
      { q:`Monocytes circulate in blood and differentiate into __ in tissues:`, ch:[`Mast cells`,`Macrophages and dendritic cells`,`Natural killer cells`,`Plasma cells`], ans:1, exp:`Monocytes (large WBCs, ~5% of WBCs) circulate in blood and migrate into tissues where they differentiate into macrophages (phagocytosis, tissue homeostasis) or dendritic cells (antigen presentation). Kupffer cells in liver are tissue-resident macrophages.` },
      { q:`The hematocrit is the:`, ch:[`Concentration of hemoglobin in blood`,`Percentage of blood volume occupied by red blood cells`,`Number of white blood cells per μL`,`Oxygen saturation of hemoglobin`], ans:1, exp:`Hematocrit (Hct) = % of blood volume composed of RBCs. Normal: ~42-47% males, ~37-42% females. Elevated in polycythemia (dehydration, altitude adaptation). Decreased in anemia.` },
      { q:`Eosinophils are white blood cells that are elevated in:`, ch:[`Bacterial infections`,`Viral infections`,`Allergic reactions and parasitic infections`,`Autoimmune diseases`], ans:2, exp:`Eosinophils (~1-4% of WBCs) are recruited in allergic responses (IgE-mediated) and parasitic infections. They release cationic proteins from granules toxic to parasites. Elevated eosinophils on CBC suggest allergy, asthma, or helminth infection.` },
      { q:`The lifespan of a red blood cell is approximately:`, ch:[`7-10 days`,`120 days (about 4 months)`,`1 year`,`Several years`], ans:1, exp:`RBCs circulate for ~120 days. Old RBCs are phagocytosed by spleen and liver macrophages. Hemoglobin is broken down: globin → amino acids; heme → biliverdin → bilirubin (conjugated in liver, excreted in bile).` },
      { q:`Hematopoiesis (blood cell formation) primarily occurs in:`, ch:[`The thymus`,`The lymph nodes`,`The spleen`,`The red bone marrow`], ans:3, exp:`Red bone marrow (in sternum, ribs, vertebrae, pelvis) is the primary site of hematopoiesis in adults. All blood cells derive from pluripotent hematopoietic stem cells (HSCs). The liver and spleen are sites of fetal/extramedullary hematopoiesis.` },
      { q:`Basophils and mast cells release __ when activated:`, ch:[`Insulin`,`Antibodies`,`Histamine and heparin (from granules), mediating allergic/inflammatory responses`,`Complement proteins`], ans:2, exp:`Basophils (blood) and mast cells (tissues) contain granules packed with histamine, heparin, leukotrienes, and proteases. IgE cross-linking on their surface triggers degranulation, causing immediate hypersensitivity reactions (anaphylaxis, urticaria).` },
      { q:`Anemia is defined as:`, ch:[`Excess red blood cells`,`Elevated WBC count`,`Reduced hemoglobin or RBC count, reducing oxygen-carrying capacity`,`Elevated platelet count`], ans:2, exp:`Anemia = decreased RBC/Hb below normal → reduced O2 delivery to tissues. Causes: iron deficiency (most common), vitamin B12/folate deficiency (megaloblastic), hemolysis (sickle cell, G6PD deficiency), chronic disease, aplastic anemia.` },
      { q:`The ABO blood type antigens are expressed on:`, ch:[`White blood cells only`,`Platelets only`,`The surface of red blood cells`,`Plasma proteins`], ans:2, exp:`ABO antigens are glycolipids/glycoproteins expressed on the RBC surface. Type A has A antigens + anti-B antibodies; Type B has B antigens + anti-A; Type AB has both antigens, no antibodies; Type O has neither antigen, both antibodies.` },
    ]
  },
  {
    id:'bb19', cat:'Bio/Biochem', title:'Innate vs. Adaptive Immunity', diff:'Easy',
    qs:[
      { q:`The innate immune system differs from the adaptive immune system in that innate immunity:`, ch:[`Responds only after prior exposure`,`Produces antigen-specific antibodies`,`Responds immediately but non-specifically to conserved patterns on pathogens`,`Generates immunological memory`], ans:2, exp:`Innate immunity responds immediately (minutes-hours) but nonspecifically, recognizing conserved pathogen-associated molecular patterns (PAMPs) via pattern recognition receptors (PRRs like TLRs). Adaptive immunity is specific and develops over days.` },
      { q:`Pattern recognition receptors (PRRs) like Toll-like receptors (TLRs) recognize:`, ch:[`Specific antibodies`,`MHC molecules on host cells`,`Pathogen-associated molecular patterns (PAMPs) like LPS and viral RNA`,`Tumor antigens`], ans:2, exp:`TLRs recognize PAMPs: TLR4 → bacterial LPS; TLR3 → dsRNA (viruses); TLR9 → bacterial CpG DNA. PRR activation triggers NF-κB signaling, producing pro-inflammatory cytokines (TNF-α, IL-1β, IL-6) and type I interferons.` },
      { q:`The complement system is part of:`, ch:[`Adaptive immunity only`,`Innate immunity and also the effector phase of adaptive immunity`,`T cell-mediated immunity only`,`Antibody production`], ans:1, exp:`Complement (C1-C9) is a group of serum proteins activated by: classical pathway (antibody), lectin pathway (mannose), or alternative pathway (spontaneous). Functions: opsonization (C3b), chemotaxis (C5a), and membrane attack complex (MAC, C5b-9).` },
      { q:`MHC class I molecules present antigens to:`, ch:[`B cells`,`CD4+ T helper cells`,`CD8+ cytotoxic T cells`,`NK cells directly`], ans:2, exp:`MHC class I (on all nucleated cells) presents endogenous peptides (from cytoplasmic proteins including viral/tumor antigens) to CD8+ cytotoxic T cells. Recognition triggers killing of the infected/cancerous cell.` },
      { q:`MHC class II molecules present antigens to:`, ch:[`CD8+ cytotoxic T cells`,`CD4+ T helper cells`,`NK cells`,`B cells directly`], ans:1, exp:`MHC class II (on APCs: dendritic cells, macrophages, B cells) presents exogenous antigens (from endocytic pathway) to CD4+ T helper cells. T helper cells then activate B cells and cytotoxic T cells.` },
      { q:`Interferons (IFN-α, IFN-β) function in antiviral defense by:`, ch:[`Directly killing viruses`,`Activating macrophages to phagocytose bacteria`,`Signaling neighboring cells to upregulate antiviral defenses and restrict viral replication`,`Producing antibodies against viral proteins`], ans:2, exp:`Type I interferons (IFN-α from leukocytes, IFN-β from fibroblasts) are secreted by virus-infected cells. They signal neighboring cells via JAK-STAT to upregulate antiviral genes (Mx, PKR, 2',5'-OAS), restricting viral spread.` },
      { q:`The primary immune response differs from the secondary response in that the primary response:`, ch:[`Produces higher antibody titers faster`,`Is slower and produces lower antibody titers, but generates memory cells for future exposures`,`Does not involve B cells`,`Uses only IgG antibodies`], ans:1, exp:`Primary response (first exposure): slow (5-10 days), lower titer, mostly IgM. Secondary response (re-exposure): rapid (1-3 days), high titer, IgG dominates, due to memory B and T cells. Basis for vaccination.` },
      { q:`Opsonization refers to:`, ch:[`Direct cell killing by T cells`,`Coating pathogens with antibodies or complement (C3b) to enhance phagocytosis`,`Release of inflammatory mediators by mast cells`,`Production of interferons`], ans:1, exp:`Opsonins (IgG, C3b) coat pathogens, enhancing phagocytosis by macrophages and neutrophils that express Fc receptors and CR1 (C3b receptor). Opsonization bridges innate recognition with adaptive specificity.` },
      { q:`Dendritic cells are important because they:`, ch:[`Produce antibodies`,`Are the most effective antigen-presenting cells (APCs) that link innate and adaptive immunity`,`Kill virus-infected cells directly`,`Produce complement proteins`], ans:1, exp:`Dendritic cells (DCs) sample antigens in peripheral tissues, mature, migrate to lymph nodes, and present antigen via MHC I and II to naive T cells. They are the most potent APCs and essential initiators of adaptive immune responses.` },
      { q:`Regulatory T cells (Tregs) function to:`, ch:[`Enhance inflammation`,`Kill cancer cells`,`Suppress immune responses, preventing autoimmunity and excessive inflammation`,`Produce IgA antibodies`], ans:2, exp:`Foxp3+ Tregs (CD4+CD25+) secrete IL-10 and TGF-β, suppressing effector T cells and B cells. They maintain self-tolerance and prevent autoimmunity. Depletion of Tregs leads to multi-organ autoimmune disease in animal models.` },
      { q:`IgG antibodies are important for:`, ch:[`Mucosal immunity (secretory function)`,`First-line response before class switching`,`Long-term protection, placental transfer, and opsonization — the most abundant serum immunoglobulin`,`Mast cell sensitization in allergic reactions`], ans:2, exp:`IgG (4 subclasses) is the most abundant serum Ig (~75% of total). It provides long-term protection, crosses the placenta to provide neonatal immunity, opsonizes bacteria, activates complement (IgG1,3), and neutralizes toxins.` },
      { q:`Secretory IgA (sIgA) is primarily found in:`, ch:[`Blood serum`,`Bone marrow`,`Mucosal secretions: saliva, breast milk, gut, respiratory tract`,`Lymph nodes`], ans:2, exp:`sIgA is the dominant Ig in mucosal secretions, providing first-line defense at mucosal surfaces. It neutralizes pathogens and toxins without activating complement (preventing inflammation at sensitive mucosal sites). Breast milk IgA protects neonates.` },
      { q:`Vaccination works on the principle of:`, ch:[`Introducing live disease-causing organisms`,`Passively transferring antibodies`,`Priming the adaptive immune system with harmless antigen to generate memory cells`,`Boosting innate immunity only`], ans:2, exp:`Vaccines expose the immune system to antigens (killed/attenuated pathogens, protein subunits, mRNA) to stimulate primary immune responses and generate immunological memory. Subsequent exposure triggers rapid secondary response, preventing disease.` },
      { q:`Autoimmune disease results from:`, ch:[`Failure of the innate immune system`,`Loss of self-tolerance — the immune system attacks the body's own tissues`,`Insufficient antibody production`,`Overproduction of complement proteins`], ans:1, exp:`Autoimmunity occurs when central (thymic/bone marrow) or peripheral tolerance mechanisms fail, allowing autoreactive lymphocytes to survive and attack self-antigens. Examples: rheumatoid arthritis (joints), SLE (dsDNA antibodies), type 1 diabetes (islet cells).` },
      { q:`Which cytokine is known as the "pyrogen" that causes fever during infection?`, ch:[`IL-10`,`IL-4`,`TGF-β`,`IL-1β and IL-6`], ans:3, exp:`IL-1β, IL-6, and TNF-α are endogenous pyrogens produced by macrophages during infection. They signal the hypothalamus to increase the temperature set point via prostaglandin E2 synthesis. Aspirin/NSAIDs reduce fever by blocking prostaglandin synthesis.` },
    ]
  },
  // ── Medium ──────────────────────────────────────────────────────────────────
  {
    id:'bb20', cat:'Bio/Biochem', title:'Beta-Oxidation of Fatty Acids', diff:'Medium',
    qs:[
      { q:`Where does beta-oxidation of fatty acids primarily occur?`, ch:[`Cytoplasm`,`Smooth ER`,`Mitochondrial matrix`,`Peroxisome only`], ans:2, exp:`Beta-oxidation occurs mainly in the mitochondrial matrix. Very-long-chain fatty acids (>22C) are first shortened by peroxisomal beta-oxidation, but the bulk of energy-yielding oxidation happens in the mitochondria.` },
      { q:`Which cofactor is reduced during the first oxidation step of beta-oxidation?`, ch:[`NADH`,`FAD→FADH2`,`NADPH`,`CoASH`], ans:1, exp:`Step 1 (acyl-CoA dehydrogenase) removes two hydrogens from the alpha-beta carbons, reducing FAD to FADH2. This is unlike the TCA cycle dehydrations; FAD is used because the substrate lacks a hydroxyl group for NAD+ to act on.` },
      { q:`What is the net yield of one cycle of beta-oxidation of a saturated fatty acyl-CoA?`, ch:[`1 acetyl-CoA, 1 NADH, 1 FADH2`,`2 acetyl-CoA, 2 NADH, 2 FADH2`,`1 acetyl-CoA, 1 FADH2, 1 NADH, and a shortened acyl-CoA by 2C`,`2 ATP, 1 CO2`], ans:2, exp:`Each cycle produces: 1 acetyl-CoA (2-carbon), 1 FADH2 (step 1), 1 NADH (step 3), and the acyl-CoA shortened by 2 carbons. The cycle repeats until the entire chain is converted to acetyl-CoA units.` },
      { q:`Carnitine is required for beta-oxidation because:`, ch:[`It activates fatty acids in the cytoplasm`,`Long-chain fatty acids cannot cross the inner mitochondrial membrane without it`,`It is a cofactor for acyl-CoA dehydrogenase`,`It regenerates CoASH`], ans:1, exp:`Long-chain fatty acids (>12C) cannot freely cross the inner mitochondrial membrane. Carnitine palmitoyltransferase I (CPT-I) conjugates acyl-CoA to carnitine; the complex is transported in by CAT (carnitine-acylcarnitine translocase) and CPT-II reconverts it to acyl-CoA in the matrix.` },
      { q:`Malonyl-CoA inhibits CPT-I. What is the physiological significance of this?`, ch:[`It prevents fatty acid synthesis in the mitochondria`,`It prevents futile cycling: when fatty acid synthesis is active (malonyl-CoA is high), simultaneous breakdown is inhibited`,`It activates fatty acid oxidation during fasting`,`It stimulates carnitine synthesis`], ans:1, exp:`Malonyl-CoA is the first committed intermediate of fatty acid synthesis. High malonyl-CoA (fed state) inhibits CPT-I, preventing simultaneous synthesis and oxidation of fatty acids — preventing a futile metabolic cycle.` },
      { q:`For a 16-carbon saturated fatty acid (palmitate), how many rounds of beta-oxidation are required?`, ch:[`6`,`7`,`8`,`16`], ans:1, exp:`An n-carbon fatty acid requires (n/2 - 1) cycles. For palmitate (C16): 16/2 - 1 = 7 cycles, yielding 8 acetyl-CoA. Each cycle shortens the chain by 2 carbons, so starting at 16C: 14→12→10→8→6→4→2+2 (7 cuts, 8 acetyl-CoA).` },
      { q:`Oxidation of unsaturated fatty acids requires which additional enzymes compared to saturated FA oxidation?`, ch:[`Isomerase and/or reductase to handle double bonds at odd positions`,`Carboxylase to add carbon units`,`Phosphatase to remove phosphate groups`,`Extra rounds of CPT-I`], ans:0, exp:`Unsaturated FAs have cis double bonds that require enoyl-CoA isomerase (for monounsaturated) and 2,4-dienoyl-CoA reductase + isomerase (for polyunsaturated) to properly position double bonds for acyl-CoA dehydrogenase. This also yields less FADH2.` },
      { q:`Odd-chain fatty acid oxidation produces propionyl-CoA, which is converted to succinyl-CoA by:`, ch:[`Pyruvate dehydrogenase`,`Propionyl-CoA carboxylase (requires biotin) then methylmalonyl-CoA mutase (requires B12)`,`Acetyl-CoA carboxylase`,`Acyl-CoA dehydrogenase`], ans:1, exp:`Propionyl-CoA → methylmalonyl-CoA (propionyl-CoA carboxylase, biotin-dependent) → succinyl-CoA (methylmalonyl-CoA mutase, adenosylcobalamin/B12-dependent). Succinyl-CoA enters the TCA cycle. B12 deficiency impairs this, causing methylmalonyl acidemia.` },
      { q:`Why does beta-oxidation of fatty acids yield more ATP per carbon than oxidation of glucose?`, ch:[`Fatty acids have more oxygen atoms`,`Fatty acids are more reduced (have more C-H bonds), so oxidation yields more electrons (FADH2/NADH)`,`Fatty acids bypass substrate-level phosphorylation`,`Glucose requires more carrier proteins`], ans:1, exp:`Fatty acids are highly reduced hydrocarbons (average oxidation state ~-2 per carbon vs ~0 for glucose carbon). More C-H bonds per carbon means more electrons transferred to FADH2 and NADH during oxidation, yielding more ATP per gram than carbohydrates (~9 kcal/g vs ~4 kcal/g).` },
      { q:`In which condition is beta-oxidation maximally activated?`, ch:[`Fed state after a high-carbohydrate meal`,`Insulin-stimulated glucose uptake`,`Prolonged fasting or exercise when glucagon and epinephrine are elevated`,`After insulin injection`], ans:2, exp:`Beta-oxidation is activated during fasting/exercise: glucagon/epinephrine activate hormone-sensitive lipase → FFA release from adipose → enter circulation → taken up by muscle/liver. Insulin does the opposite, inhibiting lipolysis and promoting lipogenesis.` },
      { q:`MCAD (medium-chain acyl-CoA dehydrogenase) deficiency is dangerous because:`, ch:[`It increases ketone body production`,`It impairs beta-oxidation of C6-C12 fatty acids, causing hypoglycemia and hypoketosis during fasting`,`It causes hyperglycemia`,`It increases malonyl-CoA`], ans:1, exp:`MCAD deficiency (common fatty acid oxidation disorder) impairs medium-chain FA oxidation. During fasting, patients cannot generate energy from FA or ketones, causing hypoketotic hypoglycemia. Dicarboxylic acids accumulate. Diagnosis: acylcarnitine profile; treatment: avoid fasting.` },
      { q:`What happens to the acetyl-CoA produced by beta-oxidation in the liver during fasting?`, ch:[`It is used directly for ATP synthesis`,`It is converted to glucose via gluconeogenesis`,`It is converted to ketone bodies (acetoacetate and beta-hydroxybutyrate) for export to peripheral tissues`,`It is used for fatty acid synthesis`], ans:2, exp:`During fasting, the liver produces more acetyl-CoA from beta-oxidation than the TCA can handle (OAA is diverted to gluconeogenesis). Excess acetyl-CoA → ketone bodies (acetoacetate, beta-hydroxybutyrate), exported to brain/muscle as alternative fuel.` },
      { q:`Which enzyme is rate-limiting in beta-oxidation?`, ch:[`Thiolase`,`Enoyl-CoA hydratase`,`CPT-I (carnitine palmitoyltransferase I) at the transport step, or acyl-CoA dehydrogenase`,`3-hydroxyacyl-CoA dehydrogenase`], ans:2, exp:`CPT-I is the primary regulatory and rate-limiting step for long-chain fatty acid oxidation — inhibited by malonyl-CoA and activated by fasting. Acyl-CoA dehydrogenase is the first committed enzymatic step within beta-oxidation itself.` },
      { q:`The energy yield of complete oxidation of palmitate (C16:0) is approximately:`, ch:[`38 ATP`,`106 ATP`,`129 ATP`,`2520 kJ released as heat only`], ans:1, exp:`Palmitate (C16:0): 7 cycles → 8 acetyl-CoA + 7 FADH2 + 7 NADH. Total ATP: 8 acetyl-CoA x 10 = 80, plus 7 FADH2 x 1.5 = 10.5, plus 7 NADH x 2.5 = 17.5, minus 2 ATP activation = ~106 ATP net.` },
      { q:`Peroxisomal beta-oxidation differs from mitochondrial beta-oxidation in that:`, ch:[`Peroxisomes produce more ATP per cycle`,`Peroxisomes use FAD-linked oxidases that transfer electrons to O2, producing H2O2 instead of feeding the ETC`,`Peroxisomes activate fatty acids with GTP instead of ATP`,`Peroxisomes only oxidize even-chain fatty acids`], ans:1, exp:`Peroxisomal oxidation uses acyl-CoA oxidase (FAD-linked, produces H2O2 detoxified by catalase) and is not linked to the ETC directly — less efficient energetically. It handles very-long-chain FAs (>22C), branched-chain FAs (phytanic acid), and bile acid precursors.` },
    ]
  },
  {
    id:'bb21', cat:'Bio/Biochem', title:'Fatty Acid Synthesis', diff:'Medium',
    qs:[
      { q:`Fatty acid synthesis occurs in the:`, ch:[`Mitochondrial matrix`,`Cytoplasm/cytosol`,`Smooth endoplasmic reticulum only`,`Peroxisome`], ans:1, exp:`Fatty acid de novo synthesis occurs in the cytoplasm. Acetyl-CoA from the mitochondria is exported via the citrate shuttle (as citrate), then cleaved back to acetyl-CoA by ATP-citrate lyase in the cytoplasm.` },
      { q:`The committed step of fatty acid synthesis is catalyzed by:`, ch:[`Acetyl-CoA carboxylase (ACC)`,`Fatty acid synthase (FAS)`,`ATP-citrate lyase`,`Malonyl-CoA decarboxylase`], ans:0, exp:`Acetyl-CoA carboxylase (ACC) catalyzes acetyl-CoA + CO2 → malonyl-CoA (requires biotin, ATP). This is the rate-limiting, committed step. ACC is activated by citrate (fed state) and inhibited by palmitoyl-CoA (product) and malonyl-CoA.` },
      { q:`The reducing equivalents (NADPH) for fatty acid synthesis come primarily from:`, ch:[`NADH from glycolysis`,`Pentose phosphate pathway (PPP) and the malate-pyruvate cycle`,`Mitochondrial FADH2`,`Acetyl-CoA directly`], ans:1, exp:`Cytoplasmic NADPH for FA synthesis comes from: (1) pentose phosphate pathway (G6P dehydrogenase + 6-phosphogluconate dehydrogenase) and (2) the citrate shuttle-malate enzyme cycle. NADPH from these sources is distinct from mitochondrial NADH.` },
      { q:`How many carbons does malonyl-CoA contribute per elongation cycle of fatty acid synthesis?`, ch:[`1 carbon (the carboxylate CO2 is lost)`,`2 carbons (the carboxylate CO2 added by ACC is lost during condensation)`,`3 carbons`,`4 carbons`], ans:1, exp:`Malonyl-CoA (3C) donates 2 carbons per condensation reaction; the CO2 added by ACC is lost during the decarboxylative Claisen condensation catalyzed by beta-ketoacyl-ACP synthase (FAS). Net: +2C per cycle.` },
      { q:`Fatty acid synthase (FAS) in mammals is:`, ch:[`A multi-enzyme complex of 7 separate proteins`,`A single large multifunctional polypeptide with 7 catalytic domains`,`Only present in adipose tissue`,`Identical to bacterial FAS`], ans:1, exp:`Mammalian FAS (FASN) is a single polypeptide (~270 kDa) with 7 domains: MAT, KS, KR, DH, ER, ACP, and TE (thioesterase). It functions as a homodimer. Bacterial FAS is a dissociable multienzyme complex. FAS is overexpressed in many cancers.` },
      { q:`The product of de novo fatty acid synthesis by FAS is:`, ch:[`Acetyl-CoA`,`Palmitate (C16:0)`,`Stearate (C18:0)`,`Oleate (C18:1)`], ans:1, exp:`Mammalian FAS terminates synthesis at C16, releasing palmitate. The thioesterase domain cleaves the thioester bond after 7 elongation cycles (starting from acetyl-CoA primer + 7 malonyl-CoA). Longer-chain and unsaturated FAs require ER elongases and desaturases.` },
      { q:`Acetyl-CoA cannot cross the inner mitochondrial membrane directly. How is it transported to the cytoplasm?`, ch:[`Via the malate-aspartate shuttle`,`As carnitine-acetyl conjugate`,`As citrate (via citrate shuttle); ATP-citrate lyase regenerates acetyl-CoA + OAA in cytoplasm`,`As acetoacetate`], ans:2, exp:`The citrate shuttle: mitochondrial OAA + acetyl-CoA → citrate (citrate synthase), citrate exported via citrate carrier, then ATP-citrate lyase in cytoplasm cleaves citrate → OAA + acetyl-CoA. This also generates NADPH via the malic enzyme step.` },
      { q:`AMP-activated protein kinase (AMPK) inhibits fatty acid synthesis by:`, ch:[`Activating FAS`,`Phosphorylating and inactivating ACC, reducing malonyl-CoA production`,`Stimulating citrate export from mitochondria`,`Activating CPT-II`], ans:1, exp:`AMPK (activated by high AMP, low ATP — energy deficit) phosphorylates and inactivates ACC, reducing malonyl-CoA. Less malonyl-CoA also relieves CPT-I inhibition, promoting FA oxidation. AMPK thus simultaneously inhibits FA synthesis and activates FA oxidation.` },
      { q:`Insulin promotes fatty acid synthesis by:`, ch:[`Directly activating FAS transcription`,`Activating protein phosphatase that dephosphorylates (activates) ACC and increasing glucose flux through PPP for NADPH`,`Inhibiting citrate synthase`,`Decreasing GLUT4 expression`], ans:1, exp:`Insulin activates protein phosphatase (PP2A) → dephosphorylates ACC → active. Insulin also increases glucose uptake (GLUT4) → glycolysis + PPP for NADPH → supports FA synthesis. Insulin also induces SREBP-1c → FAS and ACC gene transcription.` },
      { q:`Biotin is a cofactor for ACC. What is biotin's role?`, ch:[`It carries the fatty acyl chain`,`It is the carboxyl carrier — CO2 is attached to biotin's nitrogen, then transferred to acetyl-CoA`,`It provides NADPH`,`It activates coenzyme A`], ans:1, exp:`Biotin in ACC acts as the carboxyl carrier: ATP + HCO3- → carboxybiotin-enzyme (biotin carboxylase domain), then the carboxyl group is transferred from biotin to acetyl-CoA → malonyl-CoA (carboxyl transferase domain). Avidin (in raw egg whites) binds biotin, causing deficiency.` },
      { q:`Which transcription factor is the master regulator of fatty acid synthesis genes?`, ch:[`PPAR-alpha`,`SREBP-1c (Sterol Regulatory Element-Binding Protein 1c)`,`FOXO1`,`HIF-1alpha`], ans:1, exp:`SREBP-1c (activated by insulin and LXR) transcriptionally upregulates ACC, FAS, SCD1, and other lipogenic genes. PPAR-alpha does the opposite — it activates fatty acid oxidation genes. FOXO1 is activated by fasting (promotes gluconeogenesis).` },
      { q:`Elongation of palmitate to stearate (C18) and longer FAs occurs in the:`, ch:[`Mitochondria`,`Cytoplasm via FAS`,`ER membrane, using elongases (ELOVLs)`,`Peroxisome`], ans:2, exp:`After FAS produces palmitate, elongation beyond C16 occurs on the cytoplasmic face of the ER. ELOVL (elongation of very-long-chain fatty acids) enzymes extend the chain using malonyl-CoA as the 2C donor. ELOVL1-7 have different substrate specificities.` },
      { q:`Desaturases add double bonds to fatty acids. Why can't humans synthesize linoleic acid (omega-6) or alpha-linolenic acid (omega-3)?`, ch:[`Humans lack all desaturases`,`Humans cannot desaturate beyond delta-9 (cannot place double bonds at omega-6 or omega-3 positions)`,`These fatty acids require peroxisomal synthesis`,`The fatty acid chain must be C22 or longer for desaturation`], ans:1, exp:`Human delta-9-desaturase (SCD1) can introduce a double bond at carbon 9, but humans lack delta-12 and delta-15 desaturases, which are needed to produce linoleate (18:2) and alpha-linolenate (18:3). These essential FAs must come from diet.` },
      { q:`The RQ (respiratory quotient) for fat metabolism is approximately:`, ch:[`1.0`,`0.85`,`0.70`,`1.3`], ans:2, exp:`RQ = CO2 produced / O2 consumed. For fat (tripalmitin), RQ is approximately 0.70. For carbohydrates: RQ = 1.0. RQ < 1 indicates fat oxidation; RQ > 1 indicates lipogenesis (more CO2 produced than O2 consumed).` },
      { q:`What is the product when acetoacetyl-ACP undergoes the complete reduction cycle in FAS?`, ch:[`A 4-carbon saturated acyl-ACP (butyryl-ACP)`,`A 4-carbon unsaturated acyl-ACP`,`Malonyl-ACP`,`Acetyl-ACP`], ans:0, exp:`After condensation of acetyl-CoA + malonyl-ACP → acetoacetyl-ACP, the full reduction cycle: (1) KR: ketoreduction → D-3-hydroxybutyryl-ACP; (2) DH: dehydration → crotonyl-ACP; (3) ER: reduction → butyryl-ACP (C4, saturated). This cycle repeats to extend the chain.` },
    ]
  },
  {
    id:'bb22', cat:'Bio/Biochem', title:'Cholesterol & Bile Acid Metabolism', diff:'Medium',
    qs:[
      { q:`The rate-limiting step of cholesterol synthesis is catalyzed by:`, ch:[`Squalene synthase`,`HMG-CoA reductase`,`HMG-CoA synthase`,`Lanosterol synthase`], ans:1, exp:`HMG-CoA reductase (3-hydroxy-3-methylglutaryl-CoA reductase) converts HMG-CoA to mevalonate. It is the rate-limiting, regulated step. Statins are competitive inhibitors of HMG-CoA reductase, reducing cholesterol synthesis.` },
      { q:`HMG-CoA reductase is regulated by:`, ch:[`Product inhibition by cholesterol (direct allosteric), insulin-mediated activation, and PCSK9-mediated degradation`,`Feedback activation by cholesterol`,`Covalent activation by AMP kinase`,`Allosteric activation by mevalonate`], ans:0, exp:`HMG-CoA reductase is regulated by: (1) sterol feedback via SREBP (cholesterol represses HMGCR gene expression); (2) phosphorylation by AMPK (inactivates); (3) dephosphorylation by insulin (activates); (4) proteasomal degradation accelerated by excess sterols.` },
      { q:`Statins lower LDL cholesterol by:`, ch:[`Blocking intestinal cholesterol absorption`,`Inhibiting HMG-CoA reductase, reducing hepatic cholesterol, upregulating LDL receptors, and increasing LDL clearance from blood`,`Activating lipoprotein lipase`,`Inhibiting cholesterol esterification`], ans:1, exp:`Statins inhibit hepatic HMG-CoA reductase → reduced cholesterol synthesis → decreased intracellular cholesterol → SREBP activated → LDL receptor gene upregulated → more LDL receptors on hepatocytes → LDL cleared from circulation. LDL-C drops 20-60%.` },
      { q:`Bile acids are synthesized from cholesterol in the:`, ch:[`Kidney`,`Adrenal cortex`,`Liver`,`Intestine`], ans:2, exp:`The liver converts cholesterol to primary bile acids (cholic acid and chenodeoxycholic acid) via a multi-step pathway involving cholesterol 7-alpha-hydroxylase (CYP7A1, the rate-limiting step). Bile acids are conjugated to glycine or taurine, stored in the gallbladder, and released into the intestine.` },
      { q:`Secondary bile acids (deoxycholate, lithocholate) are formed by:`, ch:[`Hepatic synthesis`,`Intestinal bacterial 7-alpha-dehydroxylation of primary bile acids`,`Pancreatic enzyme action`,`Adrenal conversion of cortisol`], ans:1, exp:`Primary bile acids (cholate, chenodeoxycholate) are deconjugated and dehydroxylated by gut bacteria (7-alpha-dehydroxylation) → secondary bile acids. Lithocholate is hepatotoxic; most is eliminated in feces.` },
      { q:`What is the enterohepatic circulation of bile acids?`, ch:[`Bile acid synthesis in the intestine and secretion into the liver`,`Recycling of bile acids: secreted into small intestine, absorbed in terminal ileum, returned to liver via portal blood, and re-secreted`,`Conversion of bile acids to cholesterol in the colon`,`Transport of bile acids in blood bound to albumin`], ans:1, exp:`95% of bile acids are efficiently recycled: jejunum/ileum absorption → portal vein → liver re-uptake → re-secreted into bile. The pool circulates 2-3x per meal; only ~5% is lost in feces (this is a major route of cholesterol excretion).` },
      { q:`Cholesterol 7-alpha-hydroxylase (CYP7A1) is regulated by:`, ch:[`PCSK9`,`Returning bile acids (negative feedback via FXR causing repression of CYP7A1 expression)`,`HMG-CoA reductase`,`LXR directly`], ans:1, exp:`FXR (farnesoid X receptor) is a bile acid-activated nuclear receptor. When bile acids return to the liver, they activate FXR → SHP (short heterodimer partner) → represses CYP7A1 transcription. This prevents overproduction of bile acids when the pool is adequate.` },
      { q:`What is the function of PCSK9?`, ch:[`Inhibits LDL synthesis`,`Binds LDL receptors and targets them for lysosomal degradation, reducing LDL clearance`,`Activates HMG-CoA reductase`,`Inhibits bile acid synthesis`], ans:1, exp:`PCSK9 binds the LDL receptor on hepatocytes and directs it to lysosomes for degradation instead of recycling to the surface. Loss-of-function PCSK9 mutations lead to very low LDL and cardioprotection. PCSK9 inhibitor antibodies are powerful LDL-lowering drugs.` },
      { q:`Cholesterol is transported in blood primarily as:`, ch:[`Free cholesterol bound to albumin`,`Cholesterol esters within lipoprotein particles (LDL, HDL, VLDL, chylomicrons)`,`Free fatty acid-cholesterol complexes`,`Bile salt-cholesterol micelles`], ans:1, exp:`Cholesterol is hydrophobic and is transported as cholesterol esters (CE) within lipoprotein particles. LCAT (lecithin-cholesterol acyltransferase) esterifies cholesterol in HDL. CETP (cholesteryl ester transfer protein) transfers CE from HDL to LDL/VLDL.` },
      { q:`Reverse cholesterol transport (RCT) refers to:`, ch:[`Delivery of dietary cholesterol from intestine to liver`,`Transport of cholesterol from peripheral tissues back to the liver via HDL for excretion`,`LDL delivering cholesterol to peripheral cells`,`Conversion of cholesterol to bile acids`], ans:1, exp:`RCT: ABCA1/ABCG1 on macrophages/peripheral cells → cholesterol efflux to nascent HDL (apoA-I) → LCAT esterifies → mature HDL → liver SR-BI uptake → cholesterol excreted as bile acids. This reverse transport is atheroprotective.` },
      { q:`Familial hypercholesterolemia (FH) is caused by:`, ch:[`Overproduction of HMG-CoA reductase`,`Defective LDL receptor (most common) or gain-of-function PCSK9 mutations`,`Deficiency of bile acid synthesis enzymes`,`Loss of CETP function`], ans:1, exp:`FH (autosomal dominant, most common severe genetic hypercholesterolemia) is caused by: (1) loss-of-function LDL receptor mutations; (2) gain-of-function PCSK9 mutations; (3) defective apoB-100. Results in LDL >300-500 mg/dL and premature atherosclerosis.` },
      { q:`Niemann-Pick type C disease involves impaired:`, ch:[`Bile acid synthesis`,`Intracellular cholesterol trafficking from lysosomes to ER/plasma membrane`,`HMG-CoA reductase activity`,`Fatty acid oxidation`], ans:1, exp:`NPC1 and NPC2 proteins mediate cholesterol transport from endosomes/lysosomes to ER and plasma membrane. NPC mutations → cholesterol and sphingolipid accumulation in lysosomes → progressive neurodegeneration and liver disease.` },
      { q:`Which lipoprotein is most strongly associated with increased cardiovascular disease risk?`, ch:[`HDL`,`VLDL`,`LDL (especially small dense LDL particles)`,`Chylomicrons`], ans:2, exp:`LDL delivers cholesterol to peripheral tissues and macrophages. Small dense LDL (pattern B) is more atherogenic than large buoyant LDL: more susceptible to oxidation, longer circulation time. Oxidized LDL is taken up by macrophage scavenger receptors → foam cells → plaques.` },
      { q:`Ezetimibe lowers cholesterol by:`, ch:[`Inhibiting HMG-CoA reductase in the liver`,`Inhibiting NPC1L1 in intestinal enterocytes, blocking dietary and biliary cholesterol absorption`,`Activating LDL receptors`,`Inhibiting CETP`], ans:1, exp:`Ezetimibe inhibits NPC1L1 (Niemann-Pick C1-Like 1) at the brush border of intestinal enterocytes, blocking cholesterol absorption from both dietary and biliary sources. Less cholesterol reaching the liver → SREBP-mediated upregulation of LDL receptors → lower plasma LDL-C.` },
      { q:`Bile acids emulsify dietary fats in the small intestine. Impaired bile acid secretion leads to:`, ch:[`Hyperglycemia`,`Fat malabsorption (steatorrhea) and deficiency of fat-soluble vitamins (A, D, E, K)`,`Elevated LDL only`,`Increased glycogen synthesis`], ans:1, exp:`Bile acid micelles are essential for emulsifying fat and fat-soluble vitamins for absorption. Biliary obstruction → steatorrhea (fatty stools), deficiencies of vitamins A, D, E, K, and essential fatty acids. Vitamin K deficiency causes coagulopathy (prolonged PT).` },
    ]
  },
  {
    id:'bb23', cat:'Bio/Biochem', title:'Amino Acid Catabolism & Urea Cycle', diff:'Medium',
    qs:[
      { q:`The first step in amino acid catabolism is typically:`, ch:[`Decarboxylation`,`Transamination or oxidative deamination to remove the amino group`,`Phosphorylation`,`Hydroxylation`], ans:1, exp:`Most AAs are catabolized by first transferring their amino group to alpha-ketoglutarate via aminotransferases (transaminases), producing glutamate + the corresponding alpha-keto acid. Glutamate then undergoes oxidative deamination (glutamate dehydrogenase) to release NH4+.` },
      { q:`Aminotransferases (transaminases) require which cofactor?`, ch:[`Thiamine (B1)`,`Pyridoxal phosphate (PLP, vitamin B6)`,`Riboflavin (B2)`,`Cobalamin (B12)`], ans:1, exp:`PLP (pyridoxal phosphate) is the coenzyme for all transaminases. PLP forms a Schiff base with the amino group of the substrate AA. ALT (GPT) and AST (GOT) require PLP. Elevated ALT/AST in liver disease reflects hepatocyte damage.` },
      { q:`Where does the urea cycle occur?`, ch:[`Kidney`,`Liver — partially in mitochondria, partially in cytoplasm`,`Skeletal muscle`,`Intestine`], ans:1, exp:`The urea cycle is in the liver. Steps 1-2 (carbamoyl phosphate synthesis and citrulline formation) occur in the mitochondrial matrix; steps 3-5 (citrulline → argininosuccinate → arginine → urea) occur in the cytoplasm. Urea is excreted by the kidneys.` },
      { q:`What is the fate of the two nitrogen atoms in urea?`, ch:[`Both come from glutamate`,`One comes from NH4+ (free ammonia) and one comes from aspartate`,`Both come from aspartate`,`One from aspartate, one from alanine`], ans:1, exp:`Urea (NH2-CO-NH2): N1 comes from NH4+ donated by carbamoyl phosphate (from glutamate dehydrogenase-released NH4+); N2 comes from aspartate (which carries the second nitrogen from transamination). The carbon comes from CO2.` },
      { q:`The rate-limiting enzyme of the urea cycle is:`, ch:[`Arginase`,`Argininosuccinate synthetase`,`Carbamoyl phosphate synthetase I (CPS-I) in the mitochondria`,`OTC (ornithine transcarbamylase)`], ans:2, exp:`CPS-I (carbamoyl phosphate synthetase I, mitochondrial) is the rate-limiting step. It is activated allosterically by N-acetylglutamate (NAG), which is synthesized by NAG synthase from glutamate + acetyl-CoA. CPS-I is induced by high-protein diets.` },
      { q:`N-acetylglutamate (NAG) is an obligatory allosteric activator of CPS-I. What stimulates NAG synthesis?`, ch:[`Glucose`,`Arginine (activates NAG synthase) and high amino acid load`,`Insulin`,`Glucagon`], ans:1, exp:`NAG synthase (NAGS) is activated by arginine and produces NAG from glutamate + acetyl-CoA. High amino acid intake → elevated glutamate + arginine → increased NAG → activates CPS-I → urea cycle runs faster. NAGS mutations cause hyperammonemia.` },
      { q:`OTC (ornithine transcarbamylase) deficiency causes:`, ch:[`Hyperglycemia`,`Hyperammonemia with elevated orotic acid in urine`,`Hyperuricemia`,`Organic acidemia only`], ans:1, exp:`OTC deficiency (X-linked) blocks ornithine + carbamoyl phosphate → citrulline. Carbamoyl phosphate accumulates → enters pyrimidine synthesis → orotic aciduria (key diagnostic marker distinguishing OTC from CPS-I deficiency). Hyperammonemia causes encephalopathy.` },
      { q:`Hyperammonemia causes encephalopathy primarily because:`, ch:[`Urea accumulates in the brain`,`NH3 combines with alpha-KG → glutamate → glutamine in astrocytes, depleting TCA intermediates and causing cerebral edema`,`Amino acids cannot cross the blood-brain barrier`,`Lactate accumulates`], ans:1, exp:`Ammonia in astrocytes is detoxified by glutamine synthetase. This depletes alpha-KG (impairs TCA cycle → less ATP) and accumulates glutamine (osmotic astrocyte swelling → cerebral edema). Hyperammonemia also depletes excitatory neurotransmitters.` },
      { q:`Alanine carries nitrogen from muscle to liver. In the liver, alanine undergoes:`, ch:[`Decarboxylation to form beta-alanine`,`Transamination with alpha-KG (ALT) → pyruvate + glutamate; glutamate undergoes GDH reaction; pyruvate → gluconeogenesis`,`Direct incorporation into urea`,`Oxidative phosphorylation`], ans:1, exp:`The glucose-alanine cycle: muscle protein → amino groups → alanine (via ALT) → blood → liver → ALT: alanine + alpha-KG → pyruvate + glutamate → gluconeogenesis (glucose back to muscle) + urea (nitrogen excretion). Non-toxic nitrogen transport from muscle to liver.` },
      { q:`Which amino acids are purely ketogenic (cannot contribute carbons to gluconeogenesis)?`, ch:[`Alanine and glutamine`,`Leucine and lysine`,`Phenylalanine and tyrosine`,`Isoleucine and threonine`], ans:1, exp:`Leucine and lysine are the only purely ketogenic AAs — they are degraded solely to acetyl-CoA or acetoacetate, which cannot be converted to glucose. All other AAs are either glucogenic or both glucogenic and ketogenic.` },
      { q:`Arginine is cleaved by arginase to produce:`, ch:[`Citrulline + NH3`,`Urea + ornithine`,`Aspartate + fumarate`,`Glutamate + succinate`], ans:1, exp:`Arginase (cytoplasm, last step of urea cycle) cleaves arginine → urea + ornithine. Ornithine is transported back to the mitochondria to accept another carbamoyl phosphate, continuing the cycle. Arginase 1 deficiency causes argininemia.` },
      { q:`During fasting, which organ is the major site of amino acid catabolism for gluconeogenesis?`, ch:[`Muscle`,`Brain`,`Liver`,`Kidney (during prolonged fasting)`], ans:2, exp:`The liver is the primary site of amino acid catabolism and gluconeogenesis during fasting. Skeletal muscle exports alanine and glutamine; the liver extracts these, deaminates them, and converts the carbon skeletons to glucose.` },
      { q:`Homocystinuria is caused by:`, ch:[`Cystathionine beta-synthase deficiency (most common) or methionine synthase deficiency`,`Excess methionine intake`,`Deficiency of methionine adenosyltransferase`,`Impaired urea cycle`], ans:0, exp:`Homocystinuria: (1) cystathionine beta-synthase (CBS) deficiency (B6-dependent) → homocysteine accumulates; (2) methylene-THF reductase (MTHFR) deficiency or B12/folate deficiency → impaired remethylation. Elevated homocysteine damages vascular endothelium.` },
      { q:`Maple syrup urine disease (MSUD) involves deficiency in:`, ch:[`Phenylalanine hydroxylase`,`Branched-chain alpha-keto acid dehydrogenase (BCKAD) — blocks catabolism of leucine, isoleucine, valine`,`Homogentisate oxidase`,`Glutamate dehydrogenase`], ans:1, exp:`MSUD: defect in BCKAD (thiamine-dependent) → accumulation of branched-chain amino acids (BCAA: leucine, isoleucine, valine) and their alpha-keto acids in blood and urine (maple syrup odor). Leucine accumulation causes severe neurotoxicity. Treatment: BCAA-restricted diet.` },
      { q:`Phenylketonuria (PKU) results from deficiency of:`, ch:[`Tyrosine transaminase`,`Phenylalanine hydroxylase (PAH), leading to phenylalanine accumulation and phenylpyruvate excretion`,`Homogentisate dioxygenase`,`Fumarylacetoacetase`], ans:1, exp:`PAH (requires tetrahydrobiopterin, BH4) converts phenylalanine → tyrosine. Deficiency → hyperphenylalaninemia → phenylpyruvate in urine (musty odor), intellectual disability. Newborn screening + low-Phe diet prevents neurological damage.` },
    ]
  },
  {
    id:'bb24', cat:'Bio/Biochem', title:'Nitrogen Metabolism', diff:'Medium',
    qs:[
      { q:`The primary route of nitrogen excretion in humans is:`, ch:[`Uric acid in urine`,`Urea in urine (synthesized by the liver)`,`Creatinine`,`Ammonia directly`], ans:1, exp:`Humans are ureotelic — nitrogen is excreted primarily as urea. Urea (synthesized in the liver) is filtered by the kidneys and excreted in urine. Creatinine (from creatine phosphate degradation) and uric acid (purine catabolism) are minor routes.` },
      { q:`Which enzyme catalyzes the reversible interconversion of glutamate and alpha-ketoglutarate?`, ch:[`Glutamine synthetase`,`Glutamate dehydrogenase (GDH)`,`Alanine aminotransferase (ALT)`,`Aspartate aminotransferase (AST)`], ans:1, exp:`GDH (mitochondrial) catalyzes glutamate + NAD+(NADP+) ↔ alpha-KG + NH4+ + NADH(NADPH). In catabolism: glutamate → alpha-KG + NH4+ (feeds urea cycle). GDH is activated by ADP/GDP and inhibited by GTP/ATP.` },
      { q:`Glutamine serves as:`, ch:[`Only a neurotransmitter`,`A major nitrogen carrier in the blood, nitrogen donor for nucleotide synthesis, and fuel for rapidly dividing cells`,`Only a structural protein component`,`A direct precursor to urea`], ans:1, exp:`Glutamine is the most abundant free AA in plasma. Functions: (1) nitrogen transport (2N per molecule) from muscle to liver/gut; (2) nitrogen donor for purine and pyrimidine synthesis; (3) major fuel for enterocytes and immune cells; (4) precursor to glutamate and alpha-KG.` },
      { q:`During protein catabolism, where does most of the nitrogen eventually end up before entering the urea cycle?`, ch:[`Directly as NH4+ in the cytoplasm`,`Collected as glutamate (via transamination), then as NH4+ via glutamate dehydrogenase`,`As aspartate directly`,`As alanine directly`], ans:1, exp:`Amino groups from AA catabolism are funneled to glutamate via transaminases (AA + alpha-KG → alpha-keto acid + glutamate). Glutamate then enters GDH reaction → NH4+ (for carbamoyl phosphate) or is transaminated with OAA → aspartate (for the second N in urea). Glutamate is the central nitrogen hub.` },
      { q:`Asparagine synthetase creates asparagine from:`, ch:[`Aspartate + CoA`,`Aspartate + glutamine (glutamine donates the amide group, hydrolyzing to glutamate)`,`Glutamate + pyruvate`,`Alanine + oxaloacetate`], ans:1, exp:`Asparagine synthetase: aspartate + glutamine + ATP → asparagine + glutamate + AMP + PPi. Glutamine is the nitrogen donor. L-asparaginase (cancer treatment for ALL) hydrolyzes asparagine → aspartate + NH4+, starving tumor cells that cannot synthesize asparagine.` },
      { q:`Orotic acid accumulates in urine when:`, ch:[`The urea cycle runs too fast`,`Carbamoyl phosphate accumulates (e.g., in OTC deficiency) and excess enters pyrimidine synthesis`,`Arginine is deficient`,`Glutamine synthetase is deficient`], ans:1, exp:`In OTC deficiency: carbamoyl phosphate (CP) cannot enter the urea cycle → CP leaves mitochondria → cytoplasmic pyrimidine synthesis → orotic acid accumulates (orotic aciduria). This distinguishes OTC deficiency from CPS-I deficiency (no orotic aciduria in CPS-I).` },
      { q:`Transamination requires the substrate to have:`, ch:[`A hydroxyl group`,`An alpha-amino group adjacent to a carboxylate (alpha-amino acid → alpha-keto acid)`,`A thiol group`,`A guanidino group`], ans:1, exp:`Transaminases (requiring PLP) transfer the alpha-amino group of an amino acid to alpha-ketoglutarate, producing the alpha-keto acid of the original amino acid and glutamate. Only alpha-amino acids are substrates.` },
      { q:`ALT and AST are diagnostically important because:`, ch:[`They are secreted into blood normally`,`They are cytoplasmic enzymes that leak into blood when hepatocytes are damaged, indicating hepatocellular injury`,`They measure kidney function`,`They are direct markers of urea cycle activity`], ans:1, exp:`ALT is primarily hepatic (more specific for liver); AST is in heart, liver, muscle, and other tissues. Elevated serum ALT/AST indicates hepatocellular damage (viral hepatitis, NAFLD, drug toxicity). ALT/AST >1000 suggests acute injury.` },
      { q:`Creatine is synthesized from which amino acids?`, ch:[`It is synthesized from arginine and glycine`,`It is derived from leucine and isoleucine`,`It is made from glutamate and alanine`,`It is synthesized from lysine alone`], ans:0, exp:`Creatine synthesis: glycine + arginine → guanidinoacetate (kidney) → creatine (liver, by SAM methylation). Creatine → creatine phosphate (creatine kinase) in muscle, serving as a rapid phosphate buffer. Creatine → creatinine (nonenzymatic, constant rate) excreted in urine.` },
      { q:`Uric acid is the end product of catabolism of:`, ch:[`Amino acids`,`Purines (adenine and guanine from nucleotides)`,`Pyrimidines`,`Fatty acids`], ans:1, exp:`Purine catabolism: AMP → IMP → hypoxanthine → xanthine → uric acid (xanthine oxidase). GMP → guanine → xanthine → uric acid. Uric acid is excreted in urine. Allopurinol inhibits xanthine oxidase, reducing uric acid production (gout treatment).` },
      { q:`Which vitamin deficiency impairs transamination reactions and causes elevated homocysteine?`, ch:[`Vitamin C`,`Vitamin B6 (pyridoxine)`,`Vitamin B12 (cobalamin)`,`Vitamin D`], ans:1, exp:`PLP (from B6) is required by all transaminases and also cystathionine beta-synthase (CBS), which converts homocysteine to cystathionine. B6 deficiency impairs transamination and homocysteine metabolism. B12 and folate deficiency also raise homocysteine via impaired remethylation.` },
      { q:`The liver is the main organ for amino acid catabolism primarily because:`, ch:[`It is the largest organ`,`It has the highest concentrations of urea cycle enzymes and transaminases, plus direct portal vein access to dietary amino acids`,`It contains the most mitochondria`,`It produces insulin`], ans:1, exp:`The liver has: (1) all 5 urea cycle enzymes (unique to liver); (2) high activity of transaminases and GDH; (3) direct portal blood supply with absorbed dietary AAs. The liver regulates plasma amino acid levels and converts excess AAs to glucose or ketone bodies.` },
      { q:`Muscle can use branched-chain amino acids (BCAAs) as a fuel source because:`, ch:[`Muscle has all urea cycle enzymes`,`Muscle has high BCKAD activity and can oxidize BCAA carbon skeletons directly`,`Muscle has glutamine synthetase`,`Muscle expresses phenylalanine hydroxylase`], ans:1, exp:`Unlike most AAs catabolized in the liver, BCAAs (Leu, Ile, Val) are primarily catabolized in skeletal muscle (high BCKAD expression). BCAA transaminase is active in muscle → BCAA carbon skeletons → succinyl-CoA, acetyl-CoA (energy).` },
      { q:`The glucose-alanine cycle functions to:`, ch:[`Provide glucose to the liver during feeding`,`Transport nitrogen (as alanine) from muscle to liver and return glucose from liver to muscle during fasting/exercise`,`Convert lactate to pyruvate in the liver`,`Synthesize glutamine in the kidney`], ans:1, exp:`Muscle proteolysis → AAs → transamination → pyruvate + glutamate → alanine (ALT) → blood → liver → ALT: alanine + alpha-KG → pyruvate + glutamate → gluconeogenesis (glucose back to muscle) + urea (nitrogen excretion). Non-toxic nitrogen transport.` },
      { q:`Why must the urea cycle be active continuously in humans (even if protein intake is low)?`, ch:[`Urea is needed for kidney function`,`There is constant endogenous protein turnover (~250-300 g/day), releasing amino groups that must be detoxified as urea`,`Urea inhibits ammonia toxicity independently of diet`,`The liver requires urea for gluconeogenesis`], ans:1, exp:`Even on a protein-free diet, endogenous protein turnover (synthesis and degradation of ~250 g body protein/day) releases amino groups. A fraction not recycled into protein synthesis must be excreted as urea. The urea cycle processes both dietary and endogenous nitrogen.` },
    ]
  },
  {
    id:'bb25', cat:'Bio/Biochem', title:'Pentose Phosphate Pathway', diff:'Medium',
    qs:[
      { q:`The pentose phosphate pathway (PPP) primarily generates:`, ch:[`ATP and pyruvate`,`NADPH and ribose-5-phosphate`,`Acetyl-CoA and FADH2`,`UDP-glucose and CO2`], ans:1, exp:`The PPP has two phases: (1) oxidative phase produces 2 NADPH + 1 CO2 per glucose-6-phosphate; (2) non-oxidative phase produces ribose-5-phosphate for nucleotide synthesis. The PPP does not produce ATP.` },
      { q:`The rate-limiting enzyme of the oxidative PPP is:`, ch:[`6-phosphogluconate dehydrogenase`,`Transketolase`,`Glucose-6-phosphate dehydrogenase (G6PD)`,`Phosphoglucose isomerase`], ans:2, exp:`G6PD (glucose-6-phosphate dehydrogenase) catalyzes G6P + NADP+ → 6-phosphoglucono-delta-lactone + NADPH. It is the rate-limiting and most important regulatory enzyme of the PPP. Inhibited by NADPH (product). G6PD deficiency is the most common human enzyme deficiency.` },
      { q:`NADPH produced by the PPP is critically important for:`, ch:[`Mitochondrial ATP synthesis`,`Reducing oxidized glutathione (GSSG → GSH) to protect red blood cells from oxidative damage`,`Gluconeogenesis directly`,`Urea cycle reactions`], ans:1, exp:`In RBCs, NADPH (only source via PPP since no mitochondria) keeps glutathione reduced (GSH). Glutathione peroxidase uses GSH to neutralize H2O2. Without NADPH (G6PD deficiency), oxidative stress → hemolysis. NADPH also used by NADPH oxidase (respiratory burst) and cytochrome P450s.` },
      { q:`G6PD deficiency causes hemolytic anemia triggered by:`, ch:[`Cold temperatures`,`Oxidative stressors: primaquine, dapsone, fava beans, infections`,`High-protein diet`,`Iron deficiency`], ans:1, exp:`G6PD deficiency (X-linked, common in malaria-endemic regions) → inadequate NADPH in RBCs → insufficient GSH → oxidative damage to Hb (Heinz bodies) and membranes → hemolysis triggered by oxidants. Provides some malaria protection.` },
      { q:`In the non-oxidative phase of the PPP, transketolase requires:`, ch:[`Biotin`,`Thiamine pyrophosphate (TPP)`,`PLP (pyridoxal phosphate)`,`Lipoic acid`], ans:1, exp:`Transketolase transfers a 2-carbon unit between sugar phosphates, requiring TPP (thiamine pyrophosphate) as cofactor. Thiamine (B1) deficiency impairs transketolase — the RBC transketolase assay is used to diagnose B1 deficiency.` },
      { q:`Which tissues have high PPP activity?`, ch:[`Skeletal muscle and brain`,`Liver, adrenal cortex, RBCs, mammary gland — tissues with high NADPH demand`,`Heart and kidney cortex`,`Adipose and lung only`], ans:1, exp:`Liver: NADPH for FA synthesis, P450 reactions. Adrenal cortex: NADPH for steroidogenesis. Mammary gland: NADPH for FA synthesis during lactation. RBCs: NADPH for antioxidant defense. Gonads: steroidogenesis. Skeletal muscle has low PPP activity.` },
      { q:`When cells need more NADPH than ribose-5-phosphate, the non-oxidative phase:`, ch:[`Converts ribose-5-phosphate back to G6P to cycle through the oxidative phase again`,`Directly converts ribose-5-P to NADPH`,`Shunts ribose-5-P into glycolysis as fructose-6-P and glyceraldehyde-3-P`,`Stores ribose-5-P as glycogen`], ans:2, exp:`When NADPH is the primary need, non-oxidative phase enzymes (transketolase, transaldolase) convert excess ribose-5-P → fructose-6-P + glyceraldehyde-3-P → glycolysis. When ribose-5-P is needed more, the flow can run in reverse from F6P and G3P.` },
      { q:`The PPP is especially important for rapidly proliferating cells (e.g., cancer cells) because:`, ch:[`It generates ATP faster than glycolysis`,`It provides ribose-5-phosphate for nucleotide synthesis needed for DNA replication`,`It produces acetyl-CoA for lipid synthesis`,`It generates lactate for the Warburg effect`], ans:1, exp:`Rapidly proliferating cells have high demand for ribose-5-P (for purine and pyrimidine nucleotides) to support DNA/RNA synthesis. Cancer cells often upregulate PPP flux. G6PD is frequently overexpressed in tumors and correlates with poor prognosis.` },
      { q:`In the complete oxidative phase of PPP, one molecule of glucose-6-phosphate produces:`, ch:[`1 NADPH and 1 ribose-5-P`,`2 NADPH, 1 CO2, and 1 ribulose-5-P`,`3 NADPH and 3 CO2`,`1 NADPH and 1 pyruvate`], ans:1, exp:`Oxidative phase: G6P + NADP+ → 6-phosphogluconolactone + NADPH (G6PD), then 6-phosphogluconate + NADP+ → ribulose-5-P + CO2 + NADPH (6-phosphogluconate dehydrogenase). Total per G6P: 2 NADPH + 1 CO2 + 1 ribulose-5-P.` },
      { q:`Transaldolase transfers:`, ch:[`A 1-carbon unit`,`A 2-carbon unit (like transketolase)`,`A 3-carbon dihydroxyacetone unit between sugar phosphates`,`A phosphate group`], ans:2, exp:`Transaldolase transfers a 3-carbon dihydroxyacetone unit from sedoheptulose-7-P to glyceraldehyde-3-P → fructose-6-P + erythrose-4-P. Unlike transketolase, transaldolase does NOT require TPP (it forms a Schiff base with lysine instead).` },
      { q:`Which reaction of the PPP produces CO2?`, ch:[`The G6PD reaction (step 1)`,`The 6-phosphogluconate dehydrogenase reaction (step 3) — oxidative decarboxylation`,`The transketolase reaction`,`The lactonase reaction (step 2)`], ans:1, exp:`Step 3: 6-phosphogluconate + NADP+ → ribulose-5-phosphate + CO2 + NADPH (catalyzed by 6-phosphogluconate dehydrogenase, an oxidative decarboxylation). This is the only CO2-producing step in the PPP.` },
      { q:`The PPP links to glycolysis via:`, ch:[`Pyruvate kinase`,`Fructose-6-phosphate and glyceraldehyde-3-phosphate (F6P and G3P)`,`Phosphofructokinase-1`,`Glucose-1-phosphate`], ans:1, exp:`The non-oxidative PPP produces F6P and G3P, which are intermediates of glycolysis. This connects the two pathways: surplus ribose-5-P → glycolytic intermediates (F6P, G3P). Conversely, G3P/F6P can flow in reverse into PPP when ribose-5-P is needed.` },
      { q:`Erythrose-4-phosphate (E4P) from the PPP is important as a precursor for:`, ch:[`Sedoheptulose-7-phosphate only`,`Aromatic compounds and sugar interconversions`,`Ribulose-5-phosphate`,`Ribose-1-phosphate`], ans:1, exp:`Erythrose-4-phosphate (E4P) from the PPP combines with PEP in bacteria and plants to form aromatic amino acids (shikimate pathway). In humans, E4P participates in sugar interconversions. PRPP (from ribose-5-P) is the direct precursor for purine and pyrimidine synthesis.` },
      { q:`NADPH generated by the PPP is used by NADPH oxidase in phagocytes to:`, ch:[`Reduce oxygen for ATP synthesis`,`Produce superoxide for the respiratory burst that kills pathogens`,`Synthesize fatty acids`,`Regenerate glutathione only`], ans:1, exp:`Phagocytes (neutrophils, macrophages) use NADPH oxidase to generate superoxide (NADPH + 2O2 → NADP+ + 2 O2-) during the respiratory burst → H2O2 → HOCl (via myeloperoxidase) to kill pathogens. Chronic granulomatous disease = NADPH oxidase deficiency → recurrent bacterial/fungal infections.` },
      { q:`In which metabolic state is PPP flux highest?`, ch:[`Fasting (glucagon-dominant)`,`Immediately after a carbohydrate-rich meal when G6P is abundant and biosynthetic demands (NADPH, ribose) are high`,`During intense aerobic exercise`,`During starvation`], ans:1, exp:`PPP is most active in the fed (anabolic) state: high G6P (abundant glucose) + high NADP+ (NADPH is consumed for biosynthesis). The liver (FA synthesis), adrenal cortex (steroidogenesis), and mammary gland (lactation) show highest fed-state PPP activity.` },
    ]
  },
  {
    id:'bb26', cat:'Bio/Biochem', title:'Glycogen Metabolism', diff:'Medium',
    qs:[
      { q:`Glycogen is a branched polymer of glucose connected primarily by:`, ch:[`beta-1,4 linkages with beta-1,6 branches`,`alpha-1,4 linkages with alpha-1,6 branches`,`alpha-1,2 linkages`,`beta-1,6 linkages throughout`], ans:1, exp:`Glycogen: linear glucose units joined by alpha-1,4 glycosidic bonds; branch points every 8-12 residues joined by alpha-1,6 bonds. Branches are important for: (1) increasing solubility; (2) providing multiple non-reducing ends for rapid simultaneous phosphorylase action.` },
      { q:`The primary storage sites for glycogen in the body are:`, ch:[`Brain and kidney`,`Liver and skeletal muscle`,`Heart and adipose`,`Bone and lung`], ans:1, exp:`Liver glycogen (~100g): primary glucose buffer for blood glucose homeostasis (glucose for export). Skeletal muscle glycogen (~400g): fuel for muscle contraction only (cannot export glucose — lacks glucose-6-phosphatase). Liver glycogen is depleted within 12-24 hours of fasting.` },
      { q:`Glycogen phosphorylase cleaves glycogen by:`, ch:[`Hydrolysis with water (adds H2O)`,`Phosphorolysis (adds inorganic phosphate), releasing glucose-1-phosphate`,`Transglycosylation`,`Adding UDP-glucose`], ans:1, exp:`Glycogen phosphorylase catalyzes: glycogen(n) + Pi → glycogen(n-1) + glucose-1-phosphate. Phosphorolysis (using Pi instead of H2O) is energetically advantageous: the product is already phosphorylated, retaining the phosphate bond energy for glycolysis.` },
      { q:`The debranching enzyme has two activities:`, ch:[`Phosphorylase + isomerase`,`Transferase (moves 3 residues) + alpha-1,6-glucosidase (releases free glucose at branch point)`,`Kinase + phosphatase`,`Synthase + transferase`], ans:1, exp:`Debranching enzyme: (1) glucan transferase moves 3 of 4 residues from the branch to the main chain (alpha-1,4→alpha-1,4); (2) alpha-1,6-glucosidase cleaves the single residue remaining at the branch point → free glucose.` },
      { q:`Glycogen synthase catalyzes:`, ch:[`Addition of glucose-1-phosphate to glycogen`,`Transfer of glucose from UDP-glucose to the non-reducing end of glycogen, forming an alpha-1,4 bond`,`Branching (creating alpha-1,6 bonds)`,`Phosphorylase-independent glucose release`], ans:1, exp:`Glycogen synthase uses UDP-glucose (active form) as the glucose donor. It adds glucose to the non-reducing end via alpha-1,4 linkage. UDP is released. Branching enzyme (amylo-1,4→1,6-transglucosidase) creates the alpha-1,6 branch points separately.` },
      { q:`Glycogen synthase is regulated by phosphorylation: when phosphorylated, it is:`, ch:[`Active (a-form)`,`More active in the presence of glucose-6-phosphate`,`Inactive (b-form), but can be allosterically activated by glucose-6-phosphate`,`Constitutively active`], ans:2, exp:`Glycogen synthase a (dephosphorylated) = active. Glycogen synthase b (phosphorylated by PKA, GPK) = inactive, but allosterically activated by glucose-6-P. This reciprocal regulation with phosphorylase (phosphorylated = active) ensures synthesis and breakdown aren't simultaneous.` },
      { q:`Glucagon stimulates hepatic glycogenolysis by:`, ch:[`Directly activating glycogen phosphorylase`,`Activating adenylate cyclase → cAMP → PKA → phosphorylation cascade activating glycogen phosphorylase`,`Inhibiting glycogen synthase directly`,`Releasing calcium from the ER`], ans:1, exp:`Glucagon (or epinephrine via beta-receptor) → adenylate cyclase → cAMP → PKA → phosphorylates phosphorylase kinase (active) → phosphorylates glycogen phosphorylase b → active form a. Simultaneously: PKA phosphorylates glycogen synthase → inactivates it.` },
      { q:`Von Gierke disease (GSD type Ia) is caused by:`, ch:[`Glycogen phosphorylase deficiency`,`Glucose-6-phosphatase deficiency — liver and kidney accumulate glycogen; severe fasting hypoglycemia`,`Debranching enzyme deficiency`,`Lysosomal acid maltase deficiency`], ans:1, exp:`Von Gierke (GSD-Ia): glucose-6-phosphatase (G6Pase) deficiency → G6P cannot be converted to free glucose → hypoglycemia despite full glycogen stores. Liver/kidneys massively enlarged. Elevated lactate, triglycerides, uric acid. Treatment: continuous cornstarch feeds.` },
      { q:`Pompe disease (GSD type II) involves:`, ch:[`Deficiency of muscle phosphorylase (myophosphorylase)`,`Deficiency of lysosomal acid alpha-glucosidase (acid maltase) → glycogen accumulates in lysosomes → cardiomyopathy, myopathy`,`Deficiency of liver phosphorylase`,`Deficiency of glycogen synthase`], ans:1, exp:`Pompe disease (GSD-II): acid maltase (lysosomal) deficiency → glycogen accumulates in lysosomes in all tissues, especially heart (massive cardiomegaly) and skeletal muscle. Treatment: enzyme replacement therapy (alglucosidase alfa). Only GSD with lysosomal involvement.` },
      { q:`McArdle disease (GSD type V) is characterized by:`, ch:[`Hepatomegaly and fasting hypoglycemia`,`Muscle phosphorylase (myophosphorylase) deficiency — exercise intolerance, painful cramps, myoglobinuria`,`Cardiac glycogen accumulation`,`Low serum lactate after exercise`], ans:1, exp:`McArdle (GSD-V): myophosphorylase deficiency → muscle cannot break down glycogen → exercise-induced muscle cramps, weakness, myoglobinuria. Forearm ischemic exercise test: no lactate rise. Unlike liver GSD, no hypoglycemia (liver phosphorylase is normal).` },
      { q:`Why can skeletal muscle glycogen not directly maintain blood glucose?`, ch:[`Muscle glycogen is too small a pool`,`Muscle lacks glucose-6-phosphatase, so G6P produced from glycogenolysis cannot be exported as free glucose`,`Muscle phosphorylase is inactive in fasting`,`Muscle glycogen is in a different compartment`], ans:1, exp:`Liver (and kidney) have glucose-6-phosphatase, which dephosphorylates G6P → free glucose → exported to blood. Skeletal muscle lacks G6Pase → G6P must enter glycolysis locally for ATP. This is why liver glycogen (not muscle) is the blood glucose buffer.` },
      { q:`Insulin promotes glycogen synthesis by:`, ch:[`Directly activating glycogen synthase by binding to it`,`Activating protein phosphatase 1 (PP1) → dephosphorylates (activates) glycogen synthase`,`Inhibiting glycogen phosphorylase kinase`,`Increasing GLUT2 expression in muscle`], ans:1, exp:`Insulin activates PP1 (protein phosphatase 1) → dephosphorylates glycogen synthase → active form. Simultaneously, PP1 dephosphorylates glycogen phosphorylase → inactive form. Net: glycogen synthesis on, breakdown off.` },
      { q:`Glycogenin is required for glycogen synthesis because:`, ch:[`It phosphorylates the first glucose unit`,`It self-glycosylates to form the primer that glycogen synthase extends`,`It creates branch points`,`It activates UDP-glucose pyrophosphorylase`], ans:1, exp:`Glycogenin is a self-glycosylating protein that builds the oligosaccharide primer (8-10 glucose residues) on its own tyrosine residue. Glycogen synthase can only elongate existing chains — it cannot initiate de novo. One glycogenin molecule forms the core of each glycogen granule.` },
      { q:`The conversion of glucose-1-phosphate to UDP-glucose is driven forward by:`, ch:[`Reversibility and equilibrium`,`Pyrophosphate hydrolysis (PPi → 2Pi by pyrophosphatase) making it essentially irreversible`,`Rate-limiting for glycogen synthesis`,`Inhibited by insulin`], ans:1, exp:`UTP + G1P → UDP-glucose + PPi. Pyrophosphatase hydrolyzes PPi → 2Pi (highly exergonic), making the overall reaction thermodynamically irreversible. This principle (pyrophosphate hydrolysis driving synthesis) applies in many biosynthetic reactions.` },
      { q:`After eating a carbohydrate-rich meal, what happens to hepatic glycogen metabolism?`, ch:[`Glucagon activates glycogen breakdown for glucose export`,`Insulin activates glycogen synthesis; simultaneous glycogenolysis is suppressed`,`Glycogen synthesis and breakdown run simultaneously`,`AMPK activates PPP instead of glycogen synthesis`], ans:1, exp:`After carbohydrate meal: portal blood glucose and insulin rise → insulin activates PP1 (activates glycogen synthase, inactivates phosphorylase) + glucose allosterically inhibits phosphorylase a. Net: liver stores glucose as glycogen for 4-6 hours.` },
    ]
  },
  {
    id:'bb27', cat:'Bio/Biochem', title:'Steroid vs. Peptide Hormones', diff:'Medium',
    qs:[
      { q:`The fundamental difference in mechanism of action between steroid and peptide hormones is:`, ch:[`Steroid hormones act faster than peptide hormones`,`Steroid hormones are lipid-soluble, cross the plasma membrane, and act on nuclear receptors to regulate gene transcription; peptide hormones are water-soluble, bind cell-surface receptors, and activate intracellular signal cascades`,`Peptide hormones require a second messenger; steroid hormones do not have receptors`,`Both act identically via cAMP`], ans:1, exp:`Steroid hormones (lipophilic): cross membrane → cytoplasmic or nuclear receptor → hormone-receptor complex → binds DNA HREs → transcription changes (hours-days). Peptide hormones (hydrophilic): cannot cross membrane → bind cell surface receptor → second messengers → rapid effects (seconds-minutes).` },
      { q:`All steroid hormones are derived from:`, ch:[`Cholesterol`,`Tyrosine`,`Phenylalanine`,`Arachidonic acid`], ans:0, exp:`All steroid hormones (glucocorticoids, mineralocorticoids, sex hormones, vitamin D, bile acids) are synthesized from cholesterol. The rate-limiting step is transport of cholesterol into mitochondria by StAR protein, where side-chain cleavage occurs.` },
      { q:`Peptide hormones are stored in secretory granules and can be released rapidly by exocytosis. This is advantageous because:`, ch:[`They do not need synthesis on demand`,`Release can occur within seconds of stimulus, without waiting for transcription/translation`,`They can be reused after binding their receptor`,`They are only active when stored`], ans:1, exp:`Presynthesized peptide hormone stores enable rapid secretion (seconds) in response to stimuli. For example, insulin granules are released within 2-5 minutes after a glucose spike. Steroid hormones cannot be stored and require de novo synthesis.` },
      { q:`Glucocorticoids (e.g., cortisol) act via:`, ch:[`Membrane-bound tyrosine kinase receptor`,`Intracellular glucocorticoid receptor (GR) that translocates to the nucleus and binds GREs to regulate gene expression`,`GPCR with cAMP second messenger`,`Membrane ion channel`], ans:1, exp:`Cortisol (lipophilic) crosses the cell membrane → binds cytoplasmic GR (heat shock proteins released) → GR-cortisol complex translocates to nucleus → binds glucocorticoid response elements (GREs) → transactivation or transrepression of target genes.` },
      { q:`Neurosteroids like DHEA are notable because:`, ch:[`They are synthesized in the liver`,`They are synthesized in the brain from cholesterol and can modulate GABA-A receptors and other neurotransmitter systems`,`They are water-soluble`,`They act only via classic nuclear receptors`], ans:1, exp:`Neurosteroids (e.g., DHEA, allopregnanolone, pregnenolone) are synthesized in the brain from cholesterol by glial cells. They modulate GABA-A receptors and other neurotransmitter systems. Allopregnanolone (brexanolone) is FDA-approved for postpartum depression.` },
      { q:`Insulin is an example of a peptide hormone. Its receptor is:`, ch:[`A GPCR`,`A nuclear hormone receptor`,`A receptor tyrosine kinase (RTK) that autophosphorylates on ligand binding`,`A ligand-gated ion channel`], ans:2, exp:`Insulin receptor = heterotetrameric RTK (2alpha + 2beta subunits). Insulin binding → beta-subunit autophosphorylation → IRS (insulin receptor substrates) phosphorylated → PI3K-AKT and Ras-MAPK signaling. Downstream: GLUT4 translocation, glycogen synthesis, protein synthesis.` },
      { q:`Thyroid hormones (T3, T4) are unique among hormones because:`, ch:[`They are peptides that act on membrane receptors`,`They are amino acid derivatives (from tyrosine + iodine) that act as lipophilic hormones on nuclear receptors`,`They are stored as cholesterol esters`,`They activate only GPCR signaling`], ans:1, exp:`Thyroid hormones are iodinated tyrosine derivatives, lipophilic despite their amino acid origin. T3 (active form) crosses the membrane → binds nuclear thyroid hormone receptors (TR-alpha, TR-beta) → regulates metabolic genes. T3 acts like a steroid despite not being a steroid.` },
      { q:`Mineralocorticoids (aldosterone) act on kidney collecting duct to:`, ch:[`Promote Na+ excretion and K+ retention`,`Promote Na+ reabsorption and K+ excretion via transcriptional upregulation of ENaC and Na/K-ATPase`,`Increase water excretion`,`Increase glucose reabsorption`], ans:1, exp:`Aldosterone (from adrenal zona glomerulosa) → mineralocorticoid receptor (MR, nuclear) → increases expression of ENaC and Na/K-ATPase → Na+ reabsorption + K+ excretion. Net: volume expansion, hypertension if overproduced (Conn's syndrome).` },
      { q:`The second messenger for glucagon signaling in the liver is:`, ch:[`IP3 and DAG`,`Ca2+ alone`,`cAMP`,`cGMP`], ans:2, exp:`Glucagon → Gs-coupled GPCR → adenylate cyclase → cAMP → PKA. PKA activates glycogen phosphorylase kinase (glycogenolysis), inhibits glycogen synthase, activates hormone-sensitive lipase (adipose), and activates CREB for gene expression changes.` },
      { q:`Steroid hormones in blood are mostly:`, ch:[`Free (unbound) in plasma`,`Bound to specific transport proteins (e.g., CBG for cortisol, SHBG for sex hormones)`,`Packaged in lipoproteins`,`Covalently attached to albumin`], ans:1, exp:`Steroids are lipophilic and require carrier proteins: CBG (corticosteroid-binding globulin) for cortisol and progesterone; SHBG (sex hormone-binding globulin) for testosterone and estradiol; albumin (nonspecific). Only the free (unbound) fraction is biologically active.` },
      { q:`Anabolic steroids (synthetic androgens) work by:`, ch:[`Mimicking insulin at its receptor`,`Binding androgen receptors (AR) in cells → nuclear translocation → transcription of muscle protein genes`,`Activating GPCR for protein synthesis`,`Inhibiting cortisol receptor`], ans:1, exp:`Synthetic androgens bind AR → AR-ligand complex → nucleus → binds androgen response elements → upregulates genes for muscle protein synthesis (anabolic), erythropoiesis, and secondary male characteristics. Side effects include liver toxicity, cardiac hypertrophy, gonadotropin suppression.` },
      { q:`How are steroid hormones metabolized and excreted?`, ch:[`Directly filtered by the glomerulus`,`Hepatic conjugation (glucuronidation, sulfation) → water-soluble metabolites → renal/biliary excretion`,`Broken down by target cells only`,`Excreted unchanged in bile`], ans:1, exp:`Steroid hormones are lipophilic and not water-soluble enough for direct renal filtration. Liver cytochrome P450s hydroxylate them; then UGTs and sulfotransferases conjugate them → water-soluble glucuronides and sulfates → excreted in urine (major) and bile.` },
      { q:`What is the effect of a hormone binding to its receptor in terms of signal amplification?`, ch:[`No amplification — one hormone molecule activates one effector`,`Large amplification: one receptor activates multiple G proteins → each activates enzymes → cascade effect (millions of molecules affected)`,`Amplification only occurs for steroid hormones`,`Signal is reduced with each step to prevent overactivation`], ans:1, exp:`Signal amplification: 1 hormone → 1 receptor → activates multiple G proteins → each activates adenylate cyclase → each produces many cAMP → each activates PKA → each PKA phosphorylates multiple targets → enormous amplification. 1 glucagon molecule can lead to release of millions of glucose molecules.` },
      { q:`Which hormone uses IP3/DAG as second messengers?`, ch:[`Glucagon`,`Cortisol`,`Vasopressin (V1 receptor) and angiotensin II — Gq-coupled receptors`,`Parathyroid hormone`], ans:2, exp:`Gq-coupled receptors activate phospholipase C (PLC) → cleaves PIP2 → IP3 (releases ER Ca2+) + DAG (activates PKC). Examples: V1 (vasopressin), AT1 (angiotensin II), M1/M3 muscarinic, alpha1-adrenergic. Glucagon uses Gs/cAMP; PTH primarily uses cAMP; cortisol is nuclear.` },
      { q:`Proopiomelanocortin (POMC) illustrates the principle that:`, ch:[`Steroid hormones can be made from peptide precursors`,`A single precursor protein can be differentially cleaved to produce multiple different hormones in different tissues`,`POMC is the only peptide hormone with a precursor`,`Post-translational modification converts POMC to a steroid`], ans:1, exp:`POMC is cleaved differently in different tissues: anterior pituitary: ACTH + beta-LPH; intermediate/hypothalamus: alpha-MSH + beta-endorphin. Tissue-specific proteases determine which POMC-derived hormones are produced. Also illustrates proinsulin → insulin + C-peptide.` },
    ]
  },
  {
    id:'bb28', cat:'Bio/Biochem', title:'DNA Replication', diff:'Medium',
    qs:[
      { q:`DNA replication is described as semi-conservative, meaning:`, ch:[`Both strands are newly synthesized`,`Each daughter DNA molecule contains one original parental strand and one newly synthesized strand`,`Original strands are degraded and two new copies are made`,`Both strands stay together in one daughter cell`], ans:1, exp:`Meselson-Stahl experiment (1958) confirmed semi-conservative replication using density labeling. Each daughter DNA contains one parental (template) strand and one new strand. This ensures high fidelity through template-directed synthesis.` },
      { q:`DNA polymerase can only add nucleotides to the:`, ch:[`5' end of the growing strand`,`3' hydroxyl (3'-OH) end of the growing strand`,`The middle of existing DNA`,`Both 5' and 3' ends`], ans:1, exp:`All DNA polymerases synthesize DNA 5'→3' (adding dNTPs to the 3'-OH). This creates the directionality of replication. Consequence: the lagging strand must be synthesized discontinuously (Okazaki fragments), each initiated with a short RNA primer.` },
      { q:`The function of primase in DNA replication is to:`, ch:[`Unwind the double helix`,`Synthesize short RNA primers to provide a 3'-OH for DNA polymerase to extend`,`Remove RNA primers`,`Ligate Okazaki fragments`], ans:1, exp:`DNA polymerase cannot initiate new strands de novo — it can only extend existing strands. Primase (an RNA polymerase) synthesizes short RNA primers (~8-10 nts) providing the 3'-OH needed for DNA pol III to extend. RNA primers are later removed and replaced with DNA.` },
      { q:`Okazaki fragments are short DNA segments on the lagging strand. They are ligated together by:`, ch:[`DNA polymerase I`,`DNA ligase (forms phosphodiester bonds using NAD+ in bacteria, ATP in eukaryotes)`,`Primase`,`Topoisomerase II`], ans:1, exp:`After DNA pol I removes the RNA primer (5'→3' exonuclease) and fills the gap (polymerase activity), a nick remains between adjacent Okazaki fragments. DNA ligase seals nicks by forming a phosphodiester bond.` },
      { q:`The function of helicase in replication is to:`, ch:[`Synthesize the new strand`,`Unwind the double helix by breaking hydrogen bonds between base pairs, creating the replication fork`,`Remove primers`,`Prevent supercoiling ahead of the fork`], ans:1, exp:`Helicase uses ATP hydrolysis to break H-bonds between base pairs and unwind the dsDNA at the replication fork. DnaB (bacteria), MCM2-7 complex (eukaryotes). Unwinding creates positive supercoils ahead of the fork, relieved by topoisomerases.` },
      { q:`Which topoisomerase is targeted by fluoroquinolone antibiotics?`, ch:[`Eukaryotic topoisomerase I`,`Bacterial topoisomerase II (DNA gyrase)`,`Archaeal reverse gyrase`,`Human topoisomerase IIalpha`], ans:1, exp:`Fluoroquinolones (ciprofloxacin, levofloxacin) target bacterial DNA gyrase (topoisomerase II) and topoisomerase IV, stabilizing the enzyme-DNA cleavage complex → double-strand breaks → bacterial death. These bacterial enzymes differ structurally from human topoisomerases.` },
      { q:`In eukaryotes, how do chromosomes replicate in a timely manner despite being very long?`, ch:[`Faster polymerase enzymes`,`Multiple origins of replication (thousands per chromosome) fire simultaneously`,`Replication only occurs during G2`,`Linear chromosomes have faster fork rates`], ans:1, exp:`E. coli has one origin (oriC); eukaryotic chromosomes have thousands of origins (ARS sequences, ~10 kb spacing). Origins fire in a regulated temporal program. This allows S phase to complete in hours despite chromosome lengths of millions of bp.` },
      { q:`The 3'→5' exonuclease activity of DNA polymerase serves as:`, ch:[`Template reading`,`A proofreading mechanism that removes misincorporated nucleotides immediately`,`Primer removal`,`Strand displacement`], ans:1, exp:`DNA pol III (bacteria) / DNA pol delta/epsilon (eukaryotes) have an intrinsic 3'→5' exonuclease (proofreading). If a wrong nucleotide is incorporated, the polymerase backtracks, excises the mismatch, and reinserts the correct nucleotide. This reduces error rate from ~1 in 10^5 to ~1 in 10^7.` },
      { q:`The telomere problem — shortening of chromosome ends with each replication — is solved by:`, ch:[`Extra DNA is added at origins`,`Telomerase (a reverse transcriptase with an RNA template) extends the 3' overhang, compensating for loss`,`DNA pol can extend the 5' end`,`Histones protect chromosome ends`], ans:1, exp:`Without telomeres, linear chromosomes lose ~50-100 bp/replication (primer removal). Telomerase: RNA-protein complex with its own RNA template (TTAGGG repeats) extends 3' overhang → conventional DNA synthesis fills in the complementary strand. Active in stem cells, germ cells, cancer.` },
      { q:`Which eukaryotic DNA polymerase synthesizes the lagging strand?`, ch:[`DNA pol alpha`,`DNA pol beta`,`DNA pol delta`,`DNA pol gamma`], ans:2, exp:`DNA pol alpha: synthesizes RNA primer + short DNA extension; DNA pol delta: synthesizes lagging strand (PCNA-dependent); DNA pol epsilon: synthesizes leading strand; DNA pol beta: base excision repair; DNA pol gamma: mitochondrial DNA replication.` },
      { q:`Replication fidelity is maintained by three mechanisms in order of impact:`, ch:[`Template selectivity > proofreading > mismatch repair`,`Mismatch repair > proofreading > selectivity`,`Proofreading > mismatch repair > template selectivity`,`Template selectivity alone`], ans:0, exp:`(1) Base selectivity during synthesis (~1 error per 10^5): correct dNTP binding is thermodynamically preferred; (2) Proofreading (3'→5' exonuclease): reduces to ~10^-7; (3) Post-replication mismatch repair (MMR): reduces to ~10^-9. Each layer adds ~100-1000-fold improvement.` },
      { q:`Histone chaperones during DNA replication function to:`, ch:[`Permanently remove nucleosomes`,`Displace nucleosomes ahead of the replication fork and reassemble on both daughter strands using new and old histones`,`Keep nucleosomes on the leading strand only`,`Dissolve nucleosomes in the nucleus during S phase`], ans:1, exp:`The replication fork must displace nucleosomes. FACT and ASF1/CAF-1 (histone chaperones) disassemble H3-H4 tetramers ahead of the fork and deposit them onto daughter strands. Old and new histones are randomly distributed, but epigenetic marks can be propagated.` },
      { q:`Single-strand binding proteins (SSBs) function to:`, ch:[`Initiate primer synthesis`,`Stabilize unwound single-stranded DNA at the replication fork, preventing reannealing and secondary structure formation`,`Load the clamp loader`,`Activate helicase`], ans:1, exp:`SSB/RPA coat the single-stranded template regions at the replication fork (after helicase unwinds), preventing hairpin formation and re-annealing that would stall polymerase. They also recruit other replication factors.` },
      { q:`Which statement about the leading vs. lagging strand is TRUE?`, ch:[`Both are synthesized continuously`,`Leading strand is synthesized continuously 5'→3'; lagging strand is synthesized discontinuously as Okazaki fragments 5'→3'`,`Lagging strand is synthesized 3'→5'`,`Leading strand needs more primers`], ans:1, exp:`Leading strand: synthesized continuously 5'→3' (same direction as fork movement) after one primer. Lagging strand: synthesized discontinuously (away from fork, 5'→3') as short Okazaki fragments (~200 bp in eukaryotes, 1-2 kb in bacteria), each needing its own primer.` },
      { q:`What is the role of PCNA in eukaryotic replication?`, ch:[`It is the replicative helicase`,`It is a sliding clamp (homotrimeric ring) that encircles DNA and tethers DNA pol delta/epsilon, increasing processivity`,`It is the eukaryotic primase`,`It repairs double-strand breaks`], ans:1, exp:`PCNA (proliferating cell nuclear antigen) = ring-shaped homotrimer that slides along DNA, tethering polymerase to the template. This processivity clamp prevents polymerase from falling off. Bacterial equivalent: beta clamp. PCNA is also a hub for repair proteins (loaded by RFC clamp loader).` },
    ]
  },
  {
    id:'bb29', cat:'Bio/Biochem', title:'Transcription & Regulation', diff:'Medium',
    qs:[
      { q:`RNA polymerase II transcribes:`, ch:[`Ribosomal RNA (rRNA)`,`Transfer RNA (tRNA)`,`Messenger RNA (mRNA) — all protein-coding genes`,`Small nuclear RNA only`], ans:2, exp:`Three nuclear RNAPols in eukaryotes: RNAP I → 28S, 18S, 5.8S rRNA (in nucleolus); RNAP II → mRNA, snRNA, miRNA (protein-coding + regulatory); RNAP III → tRNA, 5S rRNA, 7SL RNA. Bacteria have a single RNAP (sigma factor confers promoter specificity).` },
      { q:`The TATA box in eukaryotic promoters:`, ch:[`Is found in all eukaryotic genes`,`Is located ~25-30 bp upstream of the transcription start site and is recognized by TBP (TATA-binding protein), initiating RNAP II assembly`,`Is the transcription start site itself`,`Encodes the first codon of all mRNAs`], ans:1, exp:`TBP (TATA-binding protein, part of TFIID) recognizes the TATA box and bends DNA, nucleating general transcription factor (GTF) assembly → RNAP II pre-initiation complex. Note: ~80% of human promoters are TATA-less. TATA-containing promoters are often highly regulated.` },
      { q:`Transcription in bacteria is initiated when:`, ch:[`The ribosome binds the mRNA`,`Sigma factor binds the core RNAP and directs it to the promoter (−10 and −35 elements)`,`TBP binds the TATA box`,`The promoter is methylated`], ans:1, exp:`Bacterial sigma factors recognize specific promoter sequences: sigma70 recognizes the −10 (TATAAT) and −35 (TTGACA) consensus sequences. After promoter recognition and open complex formation (strand separation), sigma is released and RNAP core enzyme synthesizes RNA.` },
      { q:`mRNA 5' capping (addition of 7-methylguanosine cap) occurs:`, ch:[`After polyadenylation in the cytoplasm`,`Co-transcriptionally, after ~20-30 nucleotides are synthesized, while mRNA is still on RNAP II`,`During translation on the ribosome`,`In the cytoplasm after export`], ans:1, exp:`5' cap added co-transcriptionally: GTPs added in 5'→5' triphosphate linkage (unique, not 3'→5') and methylated on N7 of guanosine. Functions: protection from 5' exonucleases, ribosome recognition (cap-dependent translation), promotes splicing.` },
      { q:`The poly(A) tail on mRNA serves to:`, ch:[`Encode amino acids at the C-terminus`,`Stabilize mRNA (protect from 3' degradation) and facilitate nuclear export and translation efficiency`,`Initiate transcription`,`Signal for mRNA degradation immediately`], ans:1, exp:`After cleavage at the poly(A) signal (AAUAAA), poly(A) polymerase adds ~200 adenosines. Poly(A) tail: (1) protects 3' end from exonucleases; (2) binds PABP → promotes cap-dependent translation; (3) promotes nuclear export.` },
      { q:`In the lac operon of E. coli, cAMP-CAP (catabolite activator protein) functions as:`, ch:[`A repressor — inhibits transcription when glucose is absent`,`A positive activator — when glucose is absent (high cAMP), CAP-cAMP binds upstream of the lac promoter and enhances RNAP binding`,`A sigma factor replacement`,`A repressor that binds the operator`], ans:1, exp:`Catabolite repression: when glucose is absent → adenylate cyclase active → high cAMP → CAP-cAMP complex binds the CAP site upstream → recruits RNAP, enhancing transcription of the lac operon up to 50-fold. Both conditions (no glucose + lactose present) needed for maximal lac expression.` },
      { q:`The lac repressor is relieved when:`, ch:[`Activating transcription directly`,`Allolactose binds the lac repressor → conformational change → repressor releases the operator → RNAP can proceed`,`The operator is methylated`,`Competing with RNAP for the promoter`], ans:1, exp:`The lac repressor (lacI gene product) binds the lac operator with high affinity, blocking RNAP. Allolactose (isomer of lactose formed by beta-galactosidase) is the true inducer: binds repressor → low affinity for operator → derepression. IPTG (non-metabolizable) is used experimentally.` },
      { q:`Enhancers differ from typical promoter elements because:`, ch:[`They must be immediately upstream of the transcription start site`,`They can work over long distances (up to 1 Mb) in either orientation, looping to contact the promoter`,`They are only found in prokaryotes`,`They repress rather than activate transcription`], ans:1, exp:`Enhancers: cis-regulatory elements that bind transcription factors → chromatin looping brings TF-bound enhancer into contact with the promoter → activates transcription. They can be hundreds of kb away, upstream or downstream, in either orientation. Mediator complex bridges enhancer-bound TFs to RNAP II.` },
      { q:`Rho-independent (intrinsic) termination in bacteria involves:`, ch:[`Rho helicase unwinding the RNA-DNA hybrid`,`Formation of a GC-rich hairpin in the RNA followed by a U-rich region — hairpin causes polymerase pausing, poly-U-DNA hybrid is weak → dissociation`,`Sigma factor release`,`RNA cleavage by RNase III`], ans:1, exp:`Intrinsic (rho-independent) termination: transcription of an inverted repeat (GC-rich) → hairpin in nascent RNA → pauses RNAP; followed by poly-U (pairs weakly with poly-dA on template) → RNA-DNA hybrid destabilizes → RNAP, RNA, and DNA dissociate.` },
      { q:`Chromatin remodeling complexes (e.g., SWI/SNF) promote transcription by:`, ch:[`Directly recruiting RNAP to the promoter`,`Repositioning or ejecting nucleosomes using ATP hydrolysis, making promoter DNA accessible to transcription factors`,`Adding methyl groups to histones`,`Compacting chromatin for repression`], ans:1, exp:`SWI/SNF and related complexes are ATP-dependent chromatin remodelers that displace, slide, or eject nucleosomes. Nucleosome-free regions (NFR) are created at active promoters and enhancers. Gene activation often requires histone modifications + nucleosome remodeling → accessible DNA → TF binding.` },
      { q:`The CTD (C-terminal domain) of RNAP II coordinates:`, ch:[`Catalysis of phosphodiester bond formation`,`Recruiting co-factors and processing enzymes — heavily phosphorylated serine residues coordinate transcription stages with RNA processing`,`Binding the TATA box`,`DNA unwinding`], ans:1, exp:`RNAP II CTD has 52 heptapeptide repeats. Phosphorylation patterns: Ser5-P (initiation, capping); Ser2-P (elongation, splicing, polyadenylation). CTD serves as a platform integrating transcription with co-transcriptional RNA processing (capping, splicing, 3'-end formation).` },
      { q:`Alternative splicing allows a single gene to produce multiple protein isoforms. This is relevant to:`, ch:[`Prokaryotic gene regulation`,`Only non-coding RNAs`,`Human protein diversity — ~95% of multi-exon human genes are alternatively spliced, potentially producing >100,000 proteins from ~20,000 genes`,`Post-translational modification only`], ans:2, exp:`Alternative splicing (exon skipping, alternative 5'/3' splice sites, intron retention, mutually exclusive exons) vastly expands the proteome. The human genome has ~20,000 protein-coding genes, but >100,000 distinct protein sequences are estimated. Dysregulation causes disease.` },
      { q:`Transcription factors bind DNA via:`, ch:[`Non-specific ionic interactions only`,`Specific DNA-binding domains (HTH, zinc finger, leucine zipper, bHLH) that recognize major groove sequences`,`The RNA polymerase active site`,`Single-stranded DNA only`], ans:1, exp:`TF DNA-binding domains: Helix-turn-helix (HTH, homeodomain proteins); Zinc finger (Cys2His2; ZIF268); Leucine zipper (bZIP: CREB, C/EBP — require dimerization); Basic helix-loop-helix (bHLH: Myc, Max). Most bind the major groove where base-specific contacts can be made.` },
      { q:`In eukaryotes, which general transcription factor is required for RNAP II transcription and contains TBP?`, ch:[`TFIIA`,`TFIID`,`TFIIH`,`TFIIF`], ans:1, exp:`TFIID: multi-subunit complex containing TBP (recognizes TATA box) and TAFs (TBP-associated factors). TFIID binding is the first step in PIC (pre-initiation complex) assembly. TFIIH has helicase (unwinds DNA at TSS) + kinase (phosphorylates RNAP II CTD Ser5 at initiation).` },
      { q:`Negative supercoiling ahead of a transcription or replication complex is relieved by:`, ch:[`Helicase`,`Ligase`,`Topoisomerase I (relaxes supercoils by cutting one strand and re-ligation) or Topoisomerase II (cuts both strands)`,`PCNA`], ans:2, exp:`As RNAP or replicative helicase unwinds DNA, positive supercoils (overwinding) accumulate ahead of the complex. Topoisomerase I cleaves one strand, allows rotation, re-ligates → relieves supercoiling. Topoisomerase II (including gyrase in bacteria) cleaves both strands, passes a strand through, re-ligates. Camptothecin inhibits eukaryotic topo I (anticancer).` },
    ]
  },
  {
    id:'bb30', cat:'Bio/Biochem', title:'Translation & Ribosomes', diff:'Medium',
    qs:[
      { q:`The ribosome is composed of two subunits. In eukaryotes, the small and large subunits are:`, ch:[`30S and 50S (forming 70S)`,`40S and 60S (forming 80S)`,`40S and 50S (forming 90S)`,`30S and 60S (forming 70S)`], ans:1, exp:`Eukaryotic ribosome: small subunit = 40S (18S rRNA + ~33 proteins); large subunit = 60S (28S, 5.8S, 5S rRNA + ~49 proteins); combined = 80S. Prokaryotic: 30S + 50S = 70S. This difference is the basis for antibiotic selectivity (aminoglycosides, tetracyclines target 30S; erythromycin, chloramphenicol target 50S).` },
      { q:`The start codon for translation in eukaryotes is:`, ch:[`AUG (Met-tRNA_i)`,`GUG (Val) primarily`,`CUG (Leu)`,`AUU (Ile)`], ans:0, exp:`AUG codes for methionine and is the universal start codon. The initiator Met-tRNA_i (in eukaryotes, Met-tRNA; in prokaryotes, fMet-tRNA) recognizes AUG in the P-site. The Kozak sequence (ACC-AUG-G context) enhances start codon recognition in eukaryotes.` },
      { q:`The three ribosome sites for tRNA-mRNA interaction are:`, ch:[`3'-, 5'-, and central site`,`A (aminoacyl), P (peptidyl), and E (exit) sites`,`Initiator, elongator, and terminator sites`,`Sender, receiver, and transmitter sites`], ans:1, exp:`A-site: accommodates aminoacyl-tRNA (incoming amino acid); P-site: holds peptidyl-tRNA (growing chain); E-site: exit site for deacylated tRNA after peptide transfer. Translocation moves the ribosome 3 nucleotides (one codon) in the 5'→3' direction on mRNA.` },
      { q:`Peptide bond formation is catalyzed by:`, ch:[`A ribosomal protein (rProtein)`,`The 23S/28S rRNA (ribozyme activity — peptidyl transferase center, PTC)`,`Release factor`,`Elongation factor EF-2/eEF2`], ans:1, exp:`The ribosome is a ribozyme — the 23S rRNA (bacteria) / 28S rRNA (eukaryotes) at the peptidyl transferase center (PTC) catalyzes peptide bond formation. This is the basis for antibiotic action: chloramphenicol and erythromycin bind the 50S PTC region.` },
      { q:`Eukaryotic initiation of translation requires which cap-binding complex?`, ch:[`eIF1A`,`eIF4F (comprising eIF4E cap-binding protein, eIF4G scaffold, eIF4A helicase)`,`eIF2-GTP-Met-tRNA_i`,`PABP alone`], ans:1, exp:`eIF4F complex: eIF4E recognizes the 5' m7G cap; eIF4G is the scaffold (binds eIF4E, eIF4A, PABP); eIF4A (helicase, with eIF4B) unwinds 5' UTR secondary structures. eIF4F then recruits the 43S pre-initiation complex (40S + eIF2-GTP-Met-tRNA) for scanning.` },
      { q:`Elongation factor EF-Tu (bacteria) / eEF1A (eukaryotes) delivers:`, ch:[`The ribosome to the AUG start codon`,`GTP-bound aminoacyl-tRNA to the A-site of the ribosome`,`The peptide chain from P-site to A-site`,`mRNA to the ribosome`], ans:1, exp:`EF-Tu-GTP delivers the aminoacyl-tRNA to the A-site. After cognate codon-anticodon recognition, GTP is hydrolyzed → EF-Tu-GDP dissociates → aa-tRNA enters A-site fully. EF-Ts regenerates EF-Tu-GTP. Diphtheria toxin ADP-ribosylates eEF2, blocking translocation.` },
      { q:`Stop codons in eukaryotic translation are recognized by:`, ch:[`Specialized tRNAs (suppressor tRNAs only in some cases)`,`Release factors (eRF1 recognizes all three stop codons UAA, UAG, UGA; eRF3 is the GTPase)`,`Ribosomal proteins directly`,`mRNA hairpin structures`], ans:1, exp:`Stop codons (UAA, UAG, UGA) are not decoded by tRNAs (normally). eRF1 (class I release factor) recognizes all three stop codons; eRF3 (class II, GTPase) promotes termination. After peptide release, ABCE1 and other factors recycle the ribosome subunits.` },
      { q:`The wobble position allows one tRNA to recognize multiple codons because:`, ch:[`The first codon position is flexible`,`The third codon position (3' end of codon / 5' end of anticodon) can form non-Watson-Crick base pairs, allowing one anticodon to read multiple synonymous codons`,`tRNAs have multiple anticodons`,`Ribosomes correct mismatches at all positions`], ans:1, exp:`Wobble hypothesis (Crick, 1966): the 3' base of the codon (5' base of the anticodon) can engage in non-standard base pairing. Inosine (modified adenosine) in the anticodon can pair with U, C, or A. This explains why 61 sense codons can be read by ~45 tRNAs.` },
      { q:`Aminoglycoside antibiotics (e.g., streptomycin) cause misreading of the genetic code by:`, ch:[`Blocking the 50S subunit peptidyl transferase center`,`Binding the 30S subunit (16S rRNA) and inducing conformational changes that cause misreading of the A-site codon`,`Blocking mRNA binding to the 30S subunit`,`Inhibiting peptide chain elongation by blocking translocation`], ans:1, exp:`Aminoglycosides (streptomycin, gentamicin) bind the 30S 16S rRNA A-site → conformational change → misreading of codons → incorporation of wrong amino acids → nonfunctional/misfolded proteins → cell death. Streptomycin also inhibits initiation.` },
      { q:`Puromycin is a bacteriostatic antibiotic that acts by:`, ch:[`Blocking peptidyl transferase in bacteria only`,`Mimicking aa-tRNA and entering the A-site → accepted into growing chain → causes premature chain termination (acts in both bacteria and eukaryotes)`,`Blocking EF-Tu binding`,`Inhibiting 30S subunit assembly`], ans:1, exp:`Puromycin (structural analog of aminoacyl-tRNA) is accepted into the A-site → peptide transfer occurs → puromycin-peptide is released (chain termination). It acts in both prokaryotes and eukaryotes, making it useful as a research tool (selection marker in cell culture) but not a clinical antibiotic.` },
      { q:`Which vitamin is required as a cofactor for the enzyme that synthesizes amino-acyl tRNA?`, ch:[`Vitamin B12`,`No cofactor — aminoacyl-tRNA synthetase uses ATP directly`,`Pyridoxal phosphate (B6)`,`Thiamine (B1)`], ans:1, exp:`Aminoacyl-tRNA synthetases (20 different enzymes, one per amino acid) activate amino acids using ATP: AA + ATP → AA-AMP + PPi → AA-tRNA + AMP. No vitamin cofactor. Each synthetase has high specificity for its amino acid and cognate tRNA(s). They represent the molecular basis of the genetic code.` },
      { q:`Polyribosomes (polysomes) form when:`, ch:[`Multiple ribosomes translate a single mRNA molecule simultaneously`,`Multiple mRNAs are translated by one ribosome`,`Two ribosomes fuse during translation`,`The endoplasmic reticulum binds mRNA directly`], ans:0, exp:`Multiple ribosomes can simultaneously translate the same mRNA in a head-to-tail arrangement (polysome), increasing the rate of protein production per mRNA. Free polysomes: cytoplasmic proteins. ER-bound polysomes: secretory and membrane proteins (signal sequence → SRP → ER).` },
      { q:`The signal recognition particle (SRP) functions to:`, ch:[`Initiate translation of all mRNAs`,`Recognize the signal peptide on nascent proteins destined for the ER and pause translation until the ribosome docks at the ER translocon`,`Direct mRNA to the nucleus`,`Cleave the signal peptide directly`], ans:1, exp:`SRP binds the hydrophobic N-terminal signal peptide emerging from the ribosome → pauses translation → SRP-ribosome complex → SRP receptor on ER → ribosome docks at the translocon (Sec61 channel) → translation resumes with cotranslational translocation into the ER lumen. Signal peptide is cleaved by signal peptidase.` },
      { q:`The genetic code is described as degenerate because:`, ch:[`It has more codons than amino acids — most amino acids are encoded by 2-6 synonymous codons`,`It has redundant stop codons only`,`Not all 64 codons encode amino acids`,`Multiple amino acids can share one codon`], ans:0, exp:`The genetic code is degenerate (redundant): 64 codons encode only 20 amino acids + 3 stop codons. Most AAs have 2-6 synonymous codons (often differing in the 3rd position, wobble). Methionine (AUG) and tryptophan (UGG) are the only single-codon amino acids. Degeneracy buffers against silent mutations.` },
      { q:`Cycloheximide inhibits translation in eukaryotes by:`, ch:[`Binding the 30S subunit`,`Inhibiting the 60S subunit peptidyl transferase (A-site of 80S ribosome), blocking translocation`,`Blocking eIF4E`,`Blocking ribosome subunit joining`], ans:1, exp:`Cycloheximide inhibits the eukaryotic 80S ribosome (specifically the 60S subunit peptidyl transferase/translocation step), not the 70S prokaryotic ribosome. This specificity makes it useful as a research tool (inhibits eukaryotic translation) and distinguishes it from chloramphenicol (inhibits 50S in bacteria).` },
    ]
  },
  {
    id:'bb31', cat:'Bio/Biochem', title:'Post-Translational Modifications', diff:'Medium',
    qs:[
      { q:`Post-translational modifications (PTMs) are important because they:`, ch:[`Increase mRNA stability`,`Expand protein function beyond what is encoded in the primary amino acid sequence, enabling regulation, localization, and protein interactions`,`Replace transcription regulation`,`Are irreversible in all cases`], ans:1, exp:`PTMs add chemical groups (phosphate, acetyl, methyl, ubiquitin, glycan, etc.) to specific residues, altering protein activity, stability, localization, and interactions. Most PTMs are reversible (e.g., phosphorylation by kinase/phosphatase), enabling dynamic regulation.` },
      { q:`Phosphorylation of proteins is catalyzed by:`, ch:[`Phosphatases`,`Kinases (using ATP as phosphate donor), and reversed by protein phosphatases`,`GTPases`,`Ligases`], ans:1, exp:`Protein kinases transfer the gamma-phosphate of ATP to serine, threonine, or tyrosine (Ser/Thr kinases vs. Tyr kinases). Protein phosphatases remove the phosphate group. ~2% of the human genome encodes kinases (~518 kinases). Phosphorylation changes charge, shape, and activity of proteins.` },
      { q:`N-linked glycosylation of proteins occurs in the:`, ch:[`Cytoplasm`,`Nucleus`,`Endoplasmic reticulum (ER) co-translationally, on asparagine (Asn-X-Ser/Thr sequons)`,`Plasma membrane`], ans:2, exp:`N-linked glycosylation: dolichol-PP-oligosaccharide (Glc3Man9GlcNAc2) is transferred en bloc to Asn in the ER by oligosaccharyltransferase (OST). Glycans are subsequently processed (trimmed/extended) in the ER and Golgi. Functions: protein folding quality control (calnexin/calreticulin), stability, cell recognition.` },
      { q:`Ubiquitination targets proteins for:`, ch:[`Activation in all cases`,`Proteasomal degradation (poly-ubiquitin chain, K48-linkage) or other fates (K63: DNA repair, signaling; monoubiquitin: endocytosis)`,`Transport to the nucleus`,`Membrane insertion`], ans:1, exp:`Ubiquitin (76 aa) is attached to substrate Lys by a three-enzyme cascade (E1 activating, E2 conjugating, E3 ligating). K48-linked poly-Ub chains → 26S proteasome degradation. K63 chains → DNA repair, NF-kB activation. Monoubiquitination → histone regulation, endocytosis. Deubiquitinases (DUBs) reverse it.` },
      { q:`Sumoylation (SUMO modification) affects proteins by:`, ch:[`Targeting them for proteasomal degradation`,`Altering nuclear localization, transcription factor activity, DNA repair, and protein-protein interactions — often by competing with ubiquitination on the same lysine`,`Activating all signaling kinases`,`Modifying mitochondrial proteins only`], ans:1, exp:`SUMO (small ubiquitin-like modifier, ~100 aa) is attached by a process similar to ubiquitination. Sumoylation often changes protein-protein interactions, nuclear localization, and transcriptional activity. Competition with ubiquitin at the same Lys can protect from degradation. Important in nuclear pore function, DNA damage response.` },
      { q:`Acetylation of histone lysine residues is associated with:`, ch:[`Gene silencing and chromatin compaction`,`Transcriptional activation — acetylation neutralizes the positive charge of Lys, reducing DNA-histone interaction and opening chromatin`,`DNA methylation`,`Protein ubiquitination only`], ans:1, exp:`Histone acetyltransferases (HATs) add acetyl groups to Lys on H3/H4 N-terminal tails → neutralizes positive charge → reduces electrostatic attraction to negatively charged DNA → open chromatin (euchromatin) → gene activation. HDACs (deacetylases) reverse this → chromatin compaction → repression.` },
      { q:`Methylation of histone H3 at lysine 4 (H3K4me3) is associated with:`, ch:[`Heterochromatin and gene silencing`,`Active gene promoters (euchromatin) and transcription initiation`,`DNA repair exclusively`,`Cytoplasmic protein activity`], ans:1, exp:`H3K4me3 is a hallmark of active promoters; H3K36me3 marks gene bodies (active elongation); H3K27me3 (by PRC2) marks repressed genes; H3K9me3 marks constitutive heterochromatin. These histone methylation marks are read by bromodomain/chromodomain proteins and regulate transcription.` },
      { q:`GPI anchors attach proteins to the outer leaflet of the plasma membrane. GPI anchor biosynthesis begins in the:`, ch:[`Cytoplasm`,`Endoplasmic reticulum (ER)`,`Golgi apparatus`,`Mitochondria`], ans:1, exp:`GPI (glycosylphosphatidylinositol) anchors are added in the ER: a GPI transamidase cleaves the GPI signal peptide and attaches the preformed GPI anchor to the C-terminus. GPI-anchored proteins (CD55, CD59, alkaline phosphatase, prion protein PrP) reside in lipid rafts on the outer leaflet.` },
      { q:`Prenylation (farnesylation, geranylgeranylation) is a PTM that:`, ch:[`Adds a sugar to serine residues`,`Attaches isoprenoid groups to C-terminal Cys (CAAX motif) to anchor proteins to the cytoplasmic leaflet of membranes`,`Adds phosphate to tyrosine`,`Glycosylates asparagine in the ER`], ans:1, exp:`Prenylation: farnesyltransferase (15C farnesyl) or geranylgeranyltransferase (20C geranylgeranyl) attaches an isoprenoid to the cysteine of the CAAX motif. Ras oncoproteins require farnesylation for membrane localization and oncogenic signaling. Farnesyltransferase inhibitors were developed as anti-cancer agents.` },
      { q:`Hydroxylation of proline in collagen requires:`, ch:[`Vitamin E`,`Vitamin C (ascorbic acid) as a cofactor for prolyl hydroxylase (also requires Fe2+ and alpha-KG)`,`Zinc`,`PLP (vitamin B6)`], ans:1, exp:`Prolyl hydroxylase (4-prolyl hydroxylase) converts Pro → hydroxyproline (Hyp) in collagen, essential for triple helix stability (Hyp H-bonds with water). Requires: Fe2+ (cofactor), alpha-ketoglutarate (co-substrate, → succinate), O2, and vitamin C (reduces Fe3+ back to Fe2+). Scurvy: vitamin C deficiency → poor collagen → bleeding gums, poor wound healing.` },
      { q:`S-nitrosylation refers to:`, ch:[`Addition of glucose to proteins`,`Covalent modification of cysteine thiols by nitric oxide (NO) → -SNO, regulating protein activity`,`Phosphorylation by NO synthase`,`Methylation by nitrous acid`], ans:1, exp:`S-nitrosylation: NO-derived species (e.g., N2O3) transfer a nitroso group to Cys thiols → S-nitroso-cysteine. This PTM regulates hemoglobin oxygen affinity, caspase activity (can protect from apoptosis), and ion channels. NO signaling works through both sGC/cGMP and direct S-nitrosylation.` },
      { q:`Cleavage of the signal peptide from a newly synthesized secretory protein is an example of:`, ch:[`A reversible PTM`,`Irreversible proteolytic processing (limited proteolysis) that removes the ER-targeting sequence`,`Ubiquitination`,`Sumoylation`], ans:1, exp:`Signal peptidase in the ER lumen irreversibly cleaves the N-terminal hydrophobic signal peptide from proteins entering the secretory pathway. Other examples of irreversible proteolytic processing: zymogen activation (trypsinogen → trypsin), proinsulin → insulin + C-peptide, coagulation factor activation.` },
      { q:`Palmitoylation is a PTM that differs from other lipid modifications in that it is:`, ch:[`Permanent — cannot be reversed`,`Reversible — added and removed by palmitoyl transferases (DHHC enzymes) and acyl-protein thioesterases (APTs)`,`N-terminal modification only`,`Located in the ER lumen`], ans:1, exp:`Palmitoylation: attachment of palmitate (C16 saturated FA) to cysteine via a thioester bond. Unlike prenylation (irreversible) and GPI anchoring (irreversible), palmitoylation is reversible, enabling dynamic membrane association/dissociation. Ras, H-Ras, and many GPCRs are palmitoylated.` },
      { q:`Protein disulfide bonds form:`, ch:[`In the cytoplasm (reducing environment)`,`In the ER lumen (oxidizing environment) and are critical for the stability of secreted/membrane proteins`,`In the nucleus`,`Only in mitochondria`], ans:1, exp:`Disulfide bonds (S-S) form between Cys residues in the ER lumen (oxidizing, maintained by Ero1 and PDI) and are crucial for folding and stability of secretory and membrane proteins (antibodies, hormones like insulin, EGF). The cytoplasm is reducing (high GSH) → disulfide bonds are generally not stable there.` },
      { q:`O-GlcNAcylation (O-GlcNAc modification) is notable because:`, ch:[`It only occurs on secreted proteins`,`It occurs on nuclear and cytoplasmic proteins on Ser/Thr — the same residues as phosphorylation — enabling cross-talk between glucose metabolism and cell signaling`,`It requires the Golgi apparatus`,`It is a permanent modification`], ans:1, exp:`O-GlcNAc (O-linked beta-N-acetylglucosamine): added by OGT (O-GlcNAc transferase) to Ser/Thr of nuclear/cytoplasmic proteins; removed by OGA (O-GlcNAcase). Since it uses UDP-GlcNAc (from the hexosamine pathway, dependent on glucose flux), it links glucose metabolism to signaling. Competes with phosphorylation on same sites.` },
    ]
  },
  {
    id:'bb32', cat:'Bio/Biochem', title:'Membrane Transport', diff:'Medium',
    qs:[
      { q:`Simple diffusion across a cell membrane is driven by:`, ch:[`ATP hydrolysis`,`A concentration gradient (high → low), with no carrier protein needed`,`Ion gradients only`,`Active pumps`], ans:1, exp:`Simple diffusion: movement down the concentration gradient (passive), no protein needed. Rate is proportional to concentration difference, membrane area, and inversely proportional to membrane thickness/molecular size (Fick's law). Gases (O2, CO2), water (some), and small lipophilic molecules (ethanol, steroid hormones) can cross by simple diffusion.` },
      { q:`The Na+/K+-ATPase (sodium-potassium pump) maintains:`, ch:[`High Na+ inside the cell and high K+ outside`,`Low Na+ inside the cell and high K+ inside; high Na+ outside and low K+ outside`,`Equal Na+ and K+ concentrations on both sides`,`High Na+ and high K+ inside`], ans:1, exp:`Na+/K+-ATPase (P-type ATPase) uses 1 ATP to pump 3 Na+ out and 2 K+ in. This maintains: high intracellular K+ (~140 mM) and low intracellular Na+ (~10 mM), and high extracellular Na+ (~145 mM) and low extracellular K+ (~4 mM). The Na+ gradient drives secondary active transport (SGLT, NCE, etc.).` },
      { q:`Facilitated diffusion differs from simple diffusion in that it:`, ch:[`Goes against the concentration gradient`,`Requires a carrier protein (channel or transporter) and moves molecules down their concentration gradient`,`Requires ATP`,`Only moves ions, not molecules`], ans:1, exp:`Facilitated diffusion: uses transmembrane carrier proteins (uniporters like GLUT transporters) or ion channels, but does NOT require energy (still passive, down concentration gradient). It allows hydrophilic molecules (glucose, ions) that cannot cross the lipid bilayer by simple diffusion to enter/exit rapidly.` },
      { q:`Secondary active transport uses the energy of the Na+ gradient to transport other molecules. This is possible because:`, ch:[`Na+ gradient is maintained by facilitated diffusion`,`The Na+/K+-ATPase uses ATP to maintain the Na+ gradient; the energy stored in this gradient is then used by co-transporters (symporters/antiporters) to drive uphill transport of other solutes`,`Secondary transport directly hydrolyzes ATP`,`K+ gradient drives secondary transport`], ans:1, exp:`The Na+ electrochemical gradient (maintained by Na+/K+-ATPase at ATP cost) powers secondary active transport. Symporters (SGLT1/2: Na+/glucose, NKCC2: Na+/K+/2Cl-) and antiporters (NCX: Na+/Ca2+ exchanger, NHE: Na+/H+ exchanger) couple Na+ movement (downhill) to uphill transport of other molecules.` },
      { q:`Aquaporins (AQPs) are:`, ch:[`Active transporters for water`,`Passive water channels that allow rapid, selective water movement down osmotic gradients without moving solutes`,`Ion channels that also transport water`,`Receptors for ADH/vasopressin`], ans:1, exp:`Aquaporins (AQP1-13) form tetrameric channels with an hourglass-shaped pore (NPA motifs) that selectively allows water molecules (single file) but excludes ions and protons (H+ blocked by electrostatic barrier). AQP2 in kidney collecting ducts is regulated by ADH/vasopressin: ADH → cAMP → PKA → AQP2 vesicles fuse with apical membrane → water reabsorption.` },
      { q:`The difference between a uniporter, symporter, and antiporter is:`, ch:[`Rate of transport`,`Number of substrates transported simultaneously and direction: uniporter = 1 molecule down gradient; symporter = 2+ in same direction; antiporter = 2+ in opposite directions`,`Whether they require ATP`,`Membrane location`], ans:1, exp:`Uniporter: 1 substrate, passive (e.g., GLUTs). Symporter: 2+ substrates same direction, typically couples Na+ (or H+) downhill movement to uphill movement of another solute (e.g., SGLT1: Na+ + glucose into cell). Antiporter: 2+ substrates opposite directions (e.g., NCX: 3 Na+ in / 1 Ca2+ out; NHE: Na+ in / H+ out).` },
      { q:`SGLT1 and SGLT2 in the kidney proximal tubule are important for:`, ch:[`Excreting glucose in the urine`,`Reabsorbing filtered glucose from the tubular lumen back into the blood (secondary active transport — Na+ gradient driven)`,`Secreting glucose into the tubule`,`Active potassium reabsorption`], ans:1, exp:`SGLT2 (low affinity, high capacity) reabsorbs ~90% of filtered glucose in the early proximal tubule; SGLT1 handles the rest. SGLT2 inhibitors (gliflozins: empagliflozin, dapagliflozin) block reabsorption → glycosuria → lower blood glucose (plus cardiovascular/renal benefits) in T2DM.` },
      { q:`The plasma membrane is asymmetric with respect to phospholipid distribution. Phosphatidylserine (PS) is normally found:`, ch:[`On the outer (extracellular) leaflet`,`On the inner (cytoplasmic) leaflet, maintained by flippases (ATP-dependent)`,`Equally on both leaflets`,`Only in the ER membrane`], ans:1, exp:`Flippases (P4-ATPases, ATP-dependent) maintain membrane asymmetry by pumping PS and PE to the inner leaflet. During apoptosis, scramblases activate → PS flips to outer leaflet → recognized by macrophage phagocytic receptors (e.g., Tim4) → efferocytosis (apoptotic cell clearance). PS exposure is also a signal for platelet activation in coagulation.` },
      { q:`The mitochondrial electron transport chain (ETC) requires which transport protein to exchange ATP/ADP across the inner mitochondrial membrane?`, ch:[`SGLT`,`ANT (adenine nucleotide translocator / ADP/ATP carrier)`,`GLUT`,`Carnitine transporter`], ans:1, exp:`ANT (adenine nucleotide translocator, SLC25A4) is an antiporter: exports ATP4- from the matrix to the IMS in exchange for ADP3- from the IMS to the matrix. One ATP equivalent is lost per cycle due to charge difference (net 1 negative charge moved out per cycle). ANT is inhibited by atractyloside/carboxyatractyloside and bongkrekic acid.` },
      { q:`Gap junctions allow:`, ch:[`Receptor-mediated transport of macromolecules`,`Direct cytoplasmic communication between adjacent cells via channels permeable to small molecules (<1 kDa) including ions, second messengers, and metabolites`,`Active transport of glucose between cells`,`Only water movement`], ans:1, exp:`Gap junctions: connexin hexamers (connexons) on adjacent cells align to form intercellular channels (~1.5 nm pore diameter). Permeable to: ions (electrical coupling in cardiac/smooth muscle, neurons), cAMP, Ca2+, IP3, glucose, amino acids (<1 kDa). Coordinate cell behavior. Mutations in connexin26 (GJB2) cause hereditary hearing loss.` },
      { q:`The proton-motive force (PMF) across the inner mitochondrial membrane drives ATP synthesis. It consists of:`, ch:[`Only a pH gradient`,`Both an electrical gradient (membrane potential, ~-180 mV, inside negative) and a pH gradient (more acidic outside)`,`Only the membrane potential`,`Sodium gradient and membrane potential`], ans:1, exp:`PMF = membrane potential (delta-psi, ~-180 mV) + pH gradient (delta-pH, ~0.5-1 unit; more acidic IMS vs. matrix). Both components contribute to proton movement through ATP synthase. The delta-psi (~65-70%) contributes more than delta-pH (~30-35%) to total PMF in mitochondria.` },
      { q:`V-type ATPases (in lysosomes, endosomes, Golgi) function to:`, ch:[`Transport nutrients into cells`,`Pump protons (H+) into the lumen using ATP hydrolysis, acidifying these organelles`,`Export protons out of the cytoplasm`,`Synthesize ATP from the proton gradient`], ans:1, exp:`V-type ATPases (vacuolar H+-ATPases) use ATP hydrolysis to pump H+ from the cytoplasm into the lumen of lysosomes (pH ~4.5-5), endosomes, Golgi, and the extracellular space (osteoclasts, renal collecting duct intercalated cells). They maintain organelle acidity for hydrolase function and membrane trafficking.` },
      { q:`The Na+/Ca2+ exchanger (NCX) in cardiac myocytes is important for:`, ch:[`Entry of Na+ for action potentials`,`Extruding Ca2+ (3 Na+ in / 1 Ca2+ out) to maintain low cytoplasmic Ca2+ and relax the heart after contraction`,`Pumping Ca2+ into the SR`,`Generating the pacemaker potential`], ans:1, exp:`After cardiac muscle contraction (Ca2+ released), NCX extrudes Ca2+ from the cytoplasm: 3 Na+ (in) / 1 Ca2+ (out). NCX is driven by the Na+ gradient (maintained by Na+/K+-ATPase). Cardiac glycosides (digoxin) inhibit Na+/K+-ATPase → elevated intracellular Na+ → reduced NCX activity → elevated Ca2+ → positive inotropy.` },
      { q:`Vesicular transport (exocytosis, endocytosis) is used for macromolecules because:`, ch:[`Small molecules cannot use vesicles`,`Proteins, polysaccharides, lipoproteins, and other large molecules cannot cross the lipid bilayer by channels or transporters and require membrane-enclosed vesicles`,`Vesicular transport is faster than channel transport`,`ATP is not required for vesicular transport`], ans:1, exp:`Vesicular transport moves macromolecules across membranes: exocytosis (constitutive: secretion of collagen, albumin; regulated: neurotransmitters, hormones) and endocytosis (receptor-mediated: LDL/transferrin; phagocytosis; macropinocytosis). Clathrin-coated pits/vesicles are key for receptor-mediated endocytosis.` },
      { q:`Which of the following correctly describes the CFTR (cystic fibrosis transmembrane conductance regulator) protein?`, ch:[`A Na+ channel requiring no ATP`,`A phosphorylation-activated, ATP-gated Cl- channel (ABC transporter); loss-of-function mutations cause cystic fibrosis`,`A cotransporter for Na+ and Cl-`,`A passive Cl- channel requiring no regulation`], ans:1, exp:`CFTR is an ABC transporter that functions as a chloride channel: activated by PKA phosphorylation (cAMP-dependent) + ATP binding/hydrolysis at its NBDs (nucleotide-binding domains). CFTR mutations → impaired Cl- secretion → dehydrated, viscous mucus → CF (lung, pancreas, gut). Modulators (ivacaftor, elexacaftor/tezacaftor/ivacaftor) correct CFTR function.` },
    ]
  },
  {
    id:'bb33', cat:'Bio/Biochem', title:'TCA Intermediates & Anaplerosis', diff:'Medium',
    qs:[
      { q:`What is the primary function of the TCA cycle (beyond energy production)?`, ch:[`Synthesizing glucose directly`,`Providing carbon skeletons (intermediates) for biosynthesis of amino acids, nucleotides, heme, and fatty acids`,`Generating ATP via substrate-level phosphorylation only`,`Consuming acetyl-CoA from fatty acids only`], ans:1, exp:`The TCA cycle is amphibolic: both catabolic (oxidizes acetyl-CoA to CO2, generating NADH/FADH2 for ATP) and anabolic (intermediates are drawn off for biosynthesis: OAA → glucose, aspartate; alpha-KG → glutamate; succinyl-CoA → porphyrin/heme). This is why replenishment (anaplerosis) is essential.` },
      { q:`Anaplerosis refers to:`, ch:[`Complete TCA cycle oxidation without withdrawals`,`Reactions that replenish TCA cycle intermediates when they are withdrawn for biosynthesis`,`The first step of TCA (acetyl-CoA + OAA → citrate)`,`The export of citrate for FA synthesis`], ans:1, exp:`Anaplerosis (Greek: "filling up"): reactions that supply TCA cycle intermediates to replace those withdrawn for biosynthesis or gluconeogenesis. Key anaplerotic reactions: pyruvate carboxylase (pyruvate → OAA), glutamate/glutamine → alpha-KG, propionyl-CoA → succinyl-CoA (odd-chain FA, Ile, Val), aspartate → OAA.` },
      { q:`Pyruvate carboxylase is the primary anaplerotic enzyme. What is its allosteric activator?`, ch:[`AMP`,`Acetyl-CoA`,`ADP`,`Citrate`], ans:1, exp:`Pyruvate carboxylase (biotin-dependent) converts pyruvate + CO2 + ATP → OAA (mitochondrial). Activated allosterically by acetyl-CoA: when acetyl-CoA is high (from FA oxidation), it signals the need for more OAA to condense with acetyl-CoA in citrate synthase. This elegant regulation ensures TCA cycle capacity matches fuel supply.` },
      { q:`Alpha-ketoglutarate (alpha-KG) can be used for:`, ch:[`Glucose synthesis directly (in one step)`,`Glutamate synthesis (by GDH or aminotransferases), then glutamine, proline, arginine, and as a substrate donor in epigenetic demethylation reactions`,`Fatty acid synthesis directly`,`ATP synthesis without TCA`], ans:1, exp:`alpha-KG is the carbon skeleton for: glutamate (GDH or transaminase), glutamine (glutamine synthetase), proline, arginine, GABA. Also: TET dioxygenases and histone demethylases use alpha-KG as substrate. Alpha-KG analogs (R-2-hydroxyglutarate in IDH mutants) are oncometabolites that competitively inhibit alpha-KG-dependent dioxygenases.` },
      { q:`Succinyl-CoA is the precursor for:`, ch:[`Cholesterol synthesis`,`Heme (porphyrin) biosynthesis — succinyl-CoA + glycine → delta-aminolevulinate (ALA) is the first step`,`Steroid hormone synthesis`,`Urea cycle (first step)`], ans:1, exp:`Heme biosynthesis: succinyl-CoA + glycine → delta-aminolevulinate (ALA) by ALA synthase (rate-limiting, in mitochondria; requires PLP). ALA is then exported to cytoplasm for further steps. Lead inhibits ALA dehydratase (step 2); porphyrias result from defects in various heme synthesis steps.` },
      { q:`Oxaloacetate (OAA) is central to multiple metabolic pathways. When OAA is diverted to gluconeogenesis during fasting, what happens to the TCA cycle?`, ch:[`TCA cycle accelerates because less OAA is present`,`TCA cycle slows unless replenished (anaplerosis); acetyl-CoA diverted to ketogenesis instead of condensing with scarce OAA`,`Citrate production increases`,`TCA cycle is unaffected`], ans:1, exp:`During fasting: OAA is used for gluconeogenesis (OAA → PEP by PEPCK). This depletes TCA cycle intermediates → acetyl-CoA cannot condense with OAA → acetyl-CoA diverts to ketogenesis (ketone body production). This is why gluconeogenesis and ketogenesis are linked in the fasted liver.` },
      { q:`The citrate shuttle removes citrate from the mitochondria. What is citrate's metabolic fate in the cytoplasm?`, ch:[`Citrate is converted to glucose`,`ATP-citrate lyase cleaves citrate → acetyl-CoA + OAA; acetyl-CoA is used for FA synthesis; OAA recycled back`,`Citrate is excreted in urine`,`Citrate directly activates fatty acid synthase`], ans:2, exp:`Citrate shuttle: mitochondrial citrate → cytoplasm → ATP-citrate lyase (ACL) cleaves citrate → acetyl-CoA + OAA. Cytoplasmic acetyl-CoA → FA synthesis (via ACC and FAS). OAA → malate (malate dehydrogenase) → pyruvate (malic enzyme, generating NADPH) → back to mitochondria as pyruvate.` },
      { q:`Isocitrate dehydrogenase (IDH) mutations are found in many cancers. Mutant IDH produces:`, ch:[`More alpha-KG than normal`,`R-2-hydroxyglutarate (2-HG), an oncometabolite that inhibits alpha-KG-dependent dioxygenases, causing epigenetic dysregulation`,`Less citrate`,`More succinate`], ans:1, exp:`IDH1/2 mutations (common in glioma, AML, cholangiocarcinoma) cause neomorphic activity: mutant IDH converts alpha-KG → R-2-hydroxyglutarate (2-HG). 2-HG competitively inhibits TET methylcytosine dioxygenases and histone demethylases (alpha-KG dependent) → hypermethylation phenotype (CpG island methylator phenotype, CIMP) → gene silencing.` },
      { q:`Succinate dehydrogenase (SDH/Complex II) links the TCA cycle to the ETC by:`, ch:[`Converting succinate to malate and generating FADH2 that directly donates electrons to CoQ`,`Converting succinate to fumarate while reducing FAD → FADH2, feeding electrons into the ETC via ubiquinone (CoQ)`,`Pumping protons across the inner mitochondrial membrane`,`Converting fumarate to malate`], ans:1, exp:`SDH (succinate dehydrogenase = Complex II): succinate → fumarate + FADH2. FADH2 donates electrons to ubiquinone (CoQ) → CoQH2 → Complex III. Complex II does NOT pump protons (no proton translocation) — it only transfers electrons. SDH subunit mutations → hereditary paragangliomas/pheochromocytomas (via succinate accumulation mimicking 2-HG).` },
      { q:`Propionyl-CoA enters the TCA cycle as succinyl-CoA. This is important for the catabolism of:`, ch:[`Even-chain fatty acids and glucose`,`Odd-chain fatty acids (last 3C), isoleucine, valine, threonine, and methionine`,`Ketone bodies`,`Glycerol from triglycerides`], ans:1, exp:`Propionyl-CoA (3C) arises from: odd-chain FA oxidation (terminal 3C), catabolism of Ile, Val, Thr, Met, and cholesterol side chains. Conversion: propionyl-CoA → methylmalonyl-CoA (carboxylase, biotin) → succinyl-CoA (mutase, B12). Succinyl-CoA enters TCA cycle. Methylmalonic acidemia: B12 deficiency or mutase defect.` },
      { q:`NADH produced by the TCA cycle cannot cross the inner mitochondrial membrane. How is cytoplasmic NADH oxidized during aerobic conditions?`, ch:[`By transferring electrons directly to Complex I in the inner membrane`,`Via malate-aspartate shuttle (liver, heart) or glycerol-3-phosphate shuttle (muscle, brain), transferring reducing equivalents to the ETC`,`By converting NADH to NADPH directly`,`Via the pentose phosphate pathway`], ans:1, exp:`Malate-aspartate shuttle (liver, heart): OAA + NADH → malate (cytoplasm) → crosses membrane → malate + NAD+ → OAA + NADH (matrix, near Complex I). Net: cytoplasmic NADH = ~2.5 ATP. Glycerol-3-phosphate shuttle (muscle, brain): glycerol-3-P + FAD → DHAP + FADH2 (at Complex II level). Net: ~1.5 ATP per cytoplasmic NADH.` },
      { q:`The TCA cycle intermediate fumarate is the byproduct of which urea cycle reaction?`, ch:[`Arginase reaction`,`Argininosuccinate lyase reaction (argininosuccinate → arginine + fumarate)`,`OTC reaction`,`CPS-I reaction`], ans:1, exp:`Argininosuccinate lyase: argininosuccinate → arginine + fumarate. The fumarate enters the TCA cycle (cytoplasmic fumarase → malate → malate dehydrogenase → OAA), linking the urea cycle to the TCA cycle. This is why the urea cycle and TCA cycle are said to be metabolically interconnected.` },
      { q:`Citrate synthase is allosterically inhibited by:`, ch:[`High AMP`,`High concentrations of its product (citrate) and by NADH and succinyl-CoA — signals that the TCA cycle is running fast`,`Low OAA`,`ADP`], ans:1, exp:`Citrate synthase (OAA + acetyl-CoA → citrate): inhibited by its product citrate (product inhibition) and by NADH and succinyl-CoA (abundance of downstream TCA products signals the cycle is well-supplied). This prevents overproduction of TCA intermediates. Activated by ADP/AMP (energy deficit signals).` },
      { q:`Glutamine is an important anaplerotic substrate for cancer cells. How does glutamine enter the TCA cycle?`, ch:[`Directly as a TCA substrate`,`Glutamine → glutamate (glutaminase) → alpha-KG (GDH or transaminase) → enters TCA at alpha-KG`,`Glutamine → OAA directly`,`Glutamine → acetyl-CoA`], ans:1, exp:`Glutaminolysis: glutamine → glutamate (glutaminase) → alpha-KG (glutamate dehydrogenase or transaminase with OAA → aspartate). Alpha-KG → succinyl-CoA → fumarate → malate → OAA → replenishes TCA cycle. Many cancer cells depend heavily on glutamine for anabolism (nucleotides, lipids) even under normoxia.` },
      { q:`What is the net carbon balance of one complete TCA cycle turn?`, ch:[`4 carbons are consumed`,`No net carbon consumption — the two carbons entering as acetyl-CoA are released as two CO2 during that turn`,`2 carbons net are stored as OAA`,`The 4-carbon OAA is converted to glucose`], ans:1, exp:`Per TCA cycle turn: 2 carbons enter as acetyl-CoA (from pyruvate or FA); 2 CO2 are released (isocitrate dehydrogenase and alpha-ketoglutarate dehydrogenase steps). OAA is regenerated at the end. Net carbon balance: 0 (2 in, 2 out). OAA is not consumed — it is the catalytic carrier.` },
    ]
  },
  {
    id:'bb34', cat:'Bio/Biochem', title:'Coagulation Cascade', diff:'Medium',
    qs:[
      { q:`The coagulation cascade has two main pathways that converge at:`, ch:[`Factor XII activation`,`Factor X activation (common pathway)`,`Thrombin activation`,`Fibrinogen conversion`], ans:1, exp:`The extrinsic pathway (TF + VIIa) and intrinsic pathway (XIIa → XIa → IXa + VIIIa) both converge at Factor X activation. Activated Factor X (Xa) combines with Va (prothrombinase complex) to convert prothrombin (Factor II) to thrombin (IIa). Thrombin then converts fibrinogen to fibrin.` },
      { q:`Vitamin K is essential for coagulation because:`, ch:[`It is a cofactor for thrombin`,`It is required for gamma-carboxylation of glutamate residues on Factors II, VII, IX, X (and Proteins C, S) — enabling their binding to phospholipid membranes via Ca2+`,`It activates platelets`,`It stimulates fibrinogen synthesis`], ans:1, exp:`Vitamin K (reduced form) is a cofactor for gamma-glutamyl carboxylase, which adds carboxyl groups to Glu residues on vitamin K-dependent factors (II, VII, IX, X, Protein C, Protein S, Protein Z). These Gla residues bind Ca2+ → phospholipid membrane binding → assembly of coagulation complexes. Warfarin inhibits vitamin K epoxide reductase (VKOR), depleting active vitamin K.` },
      { q:`Warfarin (a vitamin K antagonist) affects which clotting factors?`, ch:[`Factors I, V, VIII, and XIII`,`Factors II, VII, IX, and X (vitamin K-dependent) plus Proteins C and S`,`Only Factor Xa`,`Factors XII and XI (intrinsic pathway)`], ans:1, exp:`Warfarin inhibits VKOR (vitamin K epoxide reductase), blocking recycling of vitamin K epoxide → reduced vitamin K. Without active vitamin K, factors II, VII, IX, X, and Proteins C, S are synthesized but not gamma-carboxylated (non-functional). Factor VII has the shortest half-life (~6h), so PT/INR rises first with warfarin.` },
      { q:`Thrombin's role in coagulation includes:`, ch:[`Activating only fibrinogen`,`Converting fibrinogen → fibrin (clot formation), activating Factors V, VIII, XI, XIII, and activating platelets and Protein C (anticoagulant)`,`Initiating the extrinsic pathway`,`Activating only the intrinsic pathway`], ans:1, exp:`Thrombin (Factor IIa) is the central coagulation protease: cleaves fibrinogen → fibrin + fibrinopeptides; activates Factor XIII (cross-links fibrin for stability); activates cofactors V and VIII (amplification); activates platelets via PAR-1; activates Protein C (anticoagulant — when bound to thrombomodulin on endothelium).` },
      { q:`The extrinsic pathway is initiated by:`, ch:[`Factor XII binding to exposed collagen`,`Tissue factor (TF/CD142) binding to Factor VIIa after vascular injury, exposing subendothelial TF to blood`,`Platelet activation by ADP`,`Contact activation of Factor XI`], ans:1, exp:`Tissue factor (TF, thromboplastin) is expressed by subendothelial fibroblasts. Upon vascular injury, blood contacts TF → TF binds circulating Factor VIIa → TF-VIIa complex activates Factor X (and Factor IX). The extrinsic pathway is physiologically dominant in initiating hemostasis.` },
      { q:`Heparin's anticoagulant mechanism involves:`, ch:[`Inhibiting thrombin directly`,`Binding antithrombin III (ATIII) and dramatically enhancing its inhibitory activity against thrombin and Factor Xa`,`Blocking vitamin K`,`Activating Protein C`], ans:1, exp:`Heparin (and LMWH) bind antithrombin III → conformational change → massive (~1000x) increase in ATIII's inhibitory activity against thrombin and Xa. UFH inhibits both thrombin and Xa (requires long chains to bridge both); LMWH primarily inhibits Xa. Protamine sulfate reverses heparin by binding it.` },
      { q:`Protein C is an important anticoagulant. It is activated by:`, ch:[`Factor Xa`,`Thrombin bound to thrombomodulin on endothelial cells; activated Protein C (APC) degrades cofactors Va and VIIIa`,`Factor V Leiden mutation`,`ATIII`], ans:1, exp:`When thrombin binds thrombomodulin (on intact endothelium), thrombin's coagulant activity is suppressed and it activates Protein C. APC + Protein S cofactor cleave and inactivate Factors Va and VIIIa → limits coagulation to the injury site. Factor V Leiden (R506Q mutation) is resistant to APC cleavage → hypercoagulable state.` },
      { q:`Von Willebrand factor (vWF) is important for:`, ch:[`Activating the intrinsic pathway`,`Platelet adhesion to exposed subendothelial collagen (via GpIb) and carrying Factor VIII in plasma (protecting it from degradation)`,`Fibrin cross-linking`,`Heparin binding`], ans:1, exp:`vWF (synthesized by endothelium and megakaryocytes) binds exposed collagen at injury sites, then binds platelet GpIb receptor → platelet adhesion and activation. vWF also carries FVIII in plasma, protecting from proteolysis. vWF deficiency (von Willebrand disease) → bleeding; ADAMTS13 deficiency (cleaves large vWF multimers) → TTP.` },
      { q:`The PT (prothrombin time) tests:`, ch:[`Intrinsic pathway only (factors XII, XI, IX, VIII)`,`Extrinsic and common pathways (factors VII, X, V, II, fibrinogen) — prolonged by warfarin, vitamin K deficiency, liver disease`,`Platelet function`,`Factor XIII activity`], ans:1, exp:`PT: patient plasma + tissue factor (thromboplastin) + Ca2+ → time to clot. Tests extrinsic (VII) and common (X, V, II, I) pathways. INR (international normalized ratio) standardizes PT. Prolonged by: warfarin, vitamin K deficiency, liver disease (decreased factor synthesis), DIC (consumption). Normal PT: 11-13 seconds.` },
      { q:`The aPTT (activated partial thromboplastin time) tests:`, ch:[`Extrinsic pathway only`,`Intrinsic and common pathways (factors XII, XI, IX, VIII, X, V, II, fibrinogen) — prolonged by heparin and hemophilia A/B`,`Platelet count`,`Fibrin cross-linking`], ans:1, exp:`aPTT: patient plasma + partial thromboplastin (phospholipid) + contact activator + Ca2+ → time to clot. Tests intrinsic (XII, XI, IX, VIII) and common (X, V, II, I) pathways. Prolonged by: heparin (monitored by aPTT), hemophilia A (FVIII deficiency) and B (FIX deficiency), lupus anticoagulant (paradoxically → thrombosis in vivo).` },
      { q:`Fibrinolysis is the process of clot dissolution, mediated by:`, ch:[`Thrombin and Factor XIII`,`Plasmin (generated from plasminogen by tPA or uPA), which cleaves fibrin into fibrin degradation products (FDPs) including D-dimer`,`Protein C only`,`Alpha-2-antiplasmin only`], ans:1, exp:`Fibrinolysis: tissue plasminogen activator (tPA) or uPA activate plasminogen → plasmin → cleaves fibrin → FDPs (including D-dimer). D-dimer elevation indicates active fibrinolysis (clot breakdown). tPA (alteplase) is used therapeutically for acute MI, PE, and ischemic stroke. Alpha-2-antiplasmin and PAI-1 inhibit plasmin and tPA.` },
      { q:`DIC (disseminated intravascular coagulation) is characterized by:`, ch:[`Localized clot formation only`,`Simultaneous widespread clot formation AND hemorrhage due to consumption of clotting factors and platelets`,`Only factor XII activation`,`Normal platelet count with elevated PT only`], ans:1, exp:`DIC: triggers (sepsis, obstetric emergencies, malignancy, burns) → systemic activation of coagulation → widespread microvascular thrombosis (ischemic organ damage) → consumption of platelets, fibrinogen, and clotting factors → coagulopathy and bleeding. Labs: elevated PT/aPTT, elevated D-dimer, low fibrinogen, low platelets (consumptive thrombocytopenia).` },
      { q:`Hemophilia A and B are caused by deficiencies of:`, ch:[`Factor VII and Factor IX respectively`,`Factor VIII (hemophilia A) and Factor IX (hemophilia B) — both X-linked recessive`,`Protein C and Protein S`,`vWF and Factor XI`], ans:1, exp:`Hemophilia A: FVIII deficiency (intrinsic pathway). Hemophilia B (Christmas disease): FIX deficiency. Both are X-linked recessive — affects males mainly. Clinically: prolonged aPTT, normal PT, hemarthroses (bleeding into joints), deep muscle bleeds. Treatment: recombinant FVIII or FIX replacement; emicizumab (bispecific antibody) for hemophilia A.` },
      { q:`Aspirin reduces platelet aggregation by:`, ch:[`Blocking ADP receptors`,`Irreversibly acetylating and inhibiting COX-1 in platelets, preventing thromboxane A2 (TXA2) synthesis for the platelet lifespan (~10 days)`,`Blocking GPIIb/IIIa receptor`,`Inhibiting von Willebrand factor`], ans:1, exp:`Aspirin irreversibly acetylates COX-1 (and COX-2) Ser530 → blocks thromboxane A2 (TXA2) production in platelets (TXA2 promotes platelet aggregation and vasoconstriction). Since platelets lack nuclei, they cannot synthesize new COX → effect lasts platelet lifetime (~10 days). Aspirin also blocks prostacyclin (PGI2) in endothelium, but EC regenerate COX quickly.` },
      { q:`Factor XIII (fibrin-stabilizing factor) is activated by thrombin and cross-links fibrin by:`, ch:[`Adding phosphate groups`,`Creating covalent isopeptide bonds between Gln and Lys residues of adjacent fibrin molecules, forming a stable fibrin mesh`,`Adding carbohydrate chains`,`Activating plasmin`], ans:1, exp:`Factor XIIIa (transglutaminase, activated by thrombin + Ca2+) catalyzes isopeptide bond formation between Lys and Gln on adjacent fibrin strands → covalent crosslinks → stable, insoluble fibrin clot that resists fibrinolysis. FXIII deficiency → delayed bleeding (clot forms initially but dissolves easily), poor wound healing.` },
    ]
  },
  {
    id:'bb35', cat:'Bio/Biochem', title:'Hemoglobin & Oxygen Binding', diff:'Medium',
    qs:[
      { q:`Normal adult hemoglobin (HbA) has the subunit composition:`, ch:[`Two alpha and two beta chains (alpha2-beta2)`,`Four identical alpha chains`,`Two alpha and two gamma chains (alpha2-gamma2) — fetal form`,`One alpha and one beta chain (ab dimer)`], ans:0, exp:`HbA: alpha2-beta2 (two alpha and two beta globin chains). HbF (fetal): alpha2-gamma2 (two alpha, two gamma — higher O2 affinity, allows O2 transfer from maternal to fetal blood). HbA2 (minor adult): alpha2-delta2 (~2.5%). Each subunit has a heme group (iron-porphyrin) that binds one O2.` },
      { q:`The sigmoidal oxygen-hemoglobin dissociation curve reflects:`, ch:[`Simple first-order binding`,`Cooperative binding — O2 binding to one subunit increases the affinity of remaining subunits for O2 (positive cooperativity due to T→R state transition)`,`Non-saturable binding`,`Independent binding of 4 O2 molecules`], ans:1, exp:`Hemoglobin exhibits cooperative O2 binding (Hill coefficient ~2.8, max 4). T-state (taut, deoxy): low O2 affinity; R-state (relaxed, oxy): high affinity. O2 binding to one subunit → conformational change → other subunits more likely to bind O2. This cooperative behavior gives the sigmoidal curve and efficient O2 delivery.` },
      { q:`The Bohr effect describes how:`, ch:[`Increased pH increases O2 affinity of Hb`,`Increased CO2 and decreased pH (acidosis) decrease O2 affinity of hemoglobin, promoting O2 release in metabolically active tissues`,`Temperature decreases the P50`,`Carbon monoxide shifts the curve right`], ans:1, exp:`Bohr effect: in metabolically active tissues (high CO2, low pH), Hb releases O2 more readily (curve shifts right, P50 increases). Mechanistically: H+ from carbonic acid (CO2 + H2O → H2CO3 → H+ + HCO3-) binds Hb and stabilizes the T-state. Conversely, in the lungs (low CO2, high pH) → R-state → O2 loading.` },
      { q:`2,3-Bisphosphoglycerate (2,3-BPG) decreases hemoglobin's O2 affinity by:`, ch:[`Binding to the heme iron and displacing O2`,`Binding preferentially to deoxy-Hb (T-state) in the central cavity between beta chains, stabilizing the T-state and promoting O2 release`,`Oxidizing iron from Fe2+ to Fe3+`,`Blocking the Bohr effect`], ans:1, exp:`2,3-BPG (high in RBCs, a product of the Rapoport-Luebering shunt from glycolysis) fits into the positively charged central cavity of deoxy-Hb (T-state) between the two beta chains. It stabilizes T-state → shifts O2 dissociation curve right → decreased O2 affinity → facilitates O2 unloading in tissues. Fetal Hb (HbF) has lower affinity for 2,3-BPG → higher O2 affinity.` },
      { q:`Carbon monoxide (CO) binds hemoglobin with ~240x higher affinity than O2. This causes:`, ch:[`Right shift of the O2 dissociation curve`,`Carboxyhemoglobin (HbCO) formation + left shift of remaining Hb O2 curve → severe tissue hypoxia despite normal PaO2`,`Methemoglobin formation`,`Decreased heme synthesis`], ans:1, exp:`CO binds Hb tightly → HbCO cannot carry O2. Additionally, CO induces the remaining oxy-Hb to shift LEFT (increased O2 affinity) → O2 not released in tissues. CO poisoning: cherry-red skin, headache, seizures, coma. Treatment: 100% O2 (displaces CO), hyperbaric O2 in severe cases.` },
      { q:`Methemoglobin (metHb) contains iron in the Fe3+ state. This is clinically significant because:`, ch:[`Fe3+ binds O2 more avidly`,`Fe3+ cannot bind O2 — methemoglobin cannot carry oxygen, causing functional anemia (cyanosis)`,`Fe3+ causes HbF to dominate`,`Fe3+ activates the Bohr effect`], ans:1, exp:`Methemoglobin (Fe3+) cannot bind O2. It is normally reduced back to Fe2+ by methemoglobin reductase (NADH-cytochrome b5 reductase). Causes: dapsone, nitrites, benzocaine, primaquine. Presents as cyanosis unresponsive to O2, chocolate-brown blood. Treatment: methylene blue (reduces metHb via NADPH-metHb reductase), ascorbic acid.` },
      { q:`Sickle cell disease (HbS) results from a glutamate→valine substitution at beta-6. HbS causes disease by:`, ch:[`Increased O2 affinity`,`Deoxy-HbS polymerizes into rigid fibers → sickle-shaped RBCs → hemolysis + vaso-occlusion → ischemia`,`Increased 2,3-BPG binding`,`Impaired heme synthesis`], ans:1, exp:`HbS (Glu6Val in beta chain): valine is hydrophobic → exposes a sticky patch on deoxy-HbS → polymerization into fibers → rigid, sickle-shaped RBCs → vascular occlusion, hemolysis, pain crises, organ damage. Hydroxyurea increases HbF → dilutes HbS → fewer crises. HbS heterozygotes have sickle cell trait (malaria protection).` },
      { q:`Beta-thalassemia major results in severe anemia because:`, ch:[`Beta chains are structurally abnormal and cannot fold`,`Beta chains are absent or severely reduced → excess alpha chains precipitate in RBC precursors → ineffective erythropoiesis and hemolysis`,`HbF cannot replace HbA`,`Iron is not absorbed normally`], ans:1, exp:`Beta-thalassemia major (beta-zero or severe beta-plus mutations): markedly reduced/absent beta chain production → excess alpha chains → precipitate as intracellular inclusions → RBC precursor destruction (ineffective erythropoiesis) + peripheral hemolysis. Severe anemia (Hb <7 g/dL), hepatosplenomegaly, secondary hemochromatosis from transfusions.` },
      { q:`The Hill coefficient (n) for hemoglobin is ~2.8 (maximum 4). A Hill coefficient > 1 indicates:`, ch:[`Non-cooperative binding (like myoglobin, n=1)`,`Positive cooperativity — the binding of successive O2 molecules increases the affinity for the next`,`Negative cooperativity`,`Simple bimolecular binding kinetics`], ans:1, exp:`Hill plot: log[Y/(1-Y)] vs log[pO2]; slope = n (Hill coefficient). n=1: non-cooperative (myoglobin, single heme); n>1: positive cooperativity; n<1: negative cooperativity. Hb's n~2.8 (not 4 because cooperativity is not perfect). Higher Hill coefficient → steeper sigmoidal curve → better discrimination between loading (lung) and unloading (tissue) PO2.` },
      { q:`The Haldane effect describes:`, ch:[`How CO2 affects O2 binding`,`How oxygenation of hemoglobin reduces its affinity for CO2 and protons — promoting CO2 release in the lungs`,`How temperature affects O2 affinity`,`How 2,3-BPG affects CO2 transport`], ans:1, exp:`Haldane effect (complement to Bohr effect): deoxy-Hb has higher affinity for CO2 and H+ than oxy-Hb. In lungs: O2 binding → Hb releases CO2 and H+ → CO2 is exhaled. In tissues: O2 release → Hb becomes deoxy-Hb → picks up more CO2 and H+. Both Bohr and Haldane effects enhance O2 delivery and CO2 removal.` },
      { q:`Most CO2 is transported in blood as:`, ch:[`Dissolved CO2 in plasma (~5%)`,`HbCO2 (carbamate, ~25%)`,`HCO3- (bicarbonate, ~70%) — formed from CO2 + H2O via carbonic anhydrase in RBCs`,`CO3 2- (carbonate)`], ans:2, exp:`CO2 transport: ~70% as HCO3- (CO2 + H2O → H2CO3 → H+ + HCO3-, catalyzed by carbonic anhydrase in RBCs; HCO3- exits via Cl-/HCO3- exchanger "chloride shift"); ~25% as carbamate (CO2 + Hb-NH2 → Hb-NHCOO-); ~5% dissolved. Carbonic anhydrase inhibitors (acetazolamide) affect this pathway and treat altitude sickness.` },
      { q:`Hemoglobin Chesapeake (a high-affinity Hb variant) would cause:`, ch:[`Anemia and right-shifted O2 curve`,`Polycythemia (compensatory erythrocytosis) and left-shifted O2 curve with impaired O2 delivery to tissues`,`Normal blood counts but sickle-like crises`,`Increased 2,3-BPG production`], ans:1, exp:`High-affinity Hb variants (e.g., HbChesapeake, HbKempsey) have mutations that stabilize the R-state → very tight O2 binding → poor release at tissues → tissue hypoxia → EPO release → compensatory polycythemia. O2 dissociation curve is left-shifted (low P50). Contrast with low-affinity Hb variants (right-shifted, mild anemia, better O2 delivery).` },
      { q:`Enzyme deficiency of RBCs that causes hemolytic anemia via impaired antioxidant defense:`, ch:[`Pyruvate kinase deficiency (hemolytic, but mechanism is ATP deficiency)`,`G6PD deficiency specifically causes oxidative hemolysis triggered by infections or oxidative drugs`,`Spectrin deficiency causes spherocytosis`,`PKLR deficiency causes methemoglobin`], ans:1, exp:`G6PD deficiency → decreased NADPH → decreased GSH → RBC oxidative damage → hemolysis (triggered by oxidants). Pyruvate kinase deficiency → decreased ATP → RBC death (non-oxidative mechanism). Hereditary spherocytosis: spectrin/ankyrin mutations → fragile spherical RBCs → mechanical hemolysis in the spleen. Different mechanisms, all cause hemolytic anemia.` },
      { q:`In the lungs (high pO2, low pCO2, high pH), hemoglobin:`, ch:[`Releases O2 and picks up CO2`,`Loads O2 (shifts to R-state) and releases CO2 and H+ (Bohr/Haldane effects promote CO2 exhalation)`,`Releases all CO2 first, then loads O2`,`Maintains its deoxy T-state`], ans:1, exp:`In the lungs: high pO2 → O2 loading → R-state → Haldane effect: O2-Hb has less affinity for CO2 and H+ → CO2 released from carbamate and H+ released from Hb buffer → carbonic anhydrase: HCO3- + H+ → CO2 + H2O → CO2 exhaled. Bohr effect (high pH, low CO2) also promotes O2 loading. Coordinated gas exchange.` },
    ]
  },
  {
    id:'bb36', cat:'Bio/Biochem', title:'Carbohydrate Digestion & Absorption', diff:'Medium',
    qs:[
      { q:`Starch digestion begins in the:`, ch:[`Stomach by gastric acid`,`Mouth by salivary amylase (alpha-amylase)`,`Duodenum by lipase`,`Ileum by intestinal disaccharidases`], ans:1, exp:`Salivary alpha-amylase (ptyalin) begins starch digestion in the mouth, hydrolyzing alpha-1,4 glycosidic bonds → dextrins, maltose, maltotriose. It is inactivated by stomach acid (pH <4). Pancreatic amylase (in duodenum) continues digestion. Disaccharidases (small intestinal brush border) complete monosaccharide liberation.` },
      { q:`The brush border enzyme sucrase-isomaltase cleaves:`, ch:[`Lactose → glucose + galactose`,`Sucrose → glucose + fructose, and alpha-1,6 branch points (isomaltase activity) → glucose`,`Maltose → two glucose units`,`Trehalose → two glucose units`], ans:1, exp:`Sucrase-isomaltase (a single bifunctional enzyme anchored to the brush border): sucrase domain cleaves sucrose (alpha-1,2-fructoside linkage) → glucose + fructose; isomaltase (alpha-dextrinase) domain cleaves alpha-1,6 branch points from isomaltose and alpha-limit dextrins → glucose.` },
      { q:`Lactose intolerance results from:`, ch:[`Sucrase deficiency`,`Insufficient lactase (beta-galactosidase) activity → undigested lactose passes to colon → bacterial fermentation → osmotic diarrhea, gas, bloating`,`Glucose-galactose malabsorption (different condition)`,`Galactosemia`], ans:1, exp:`Primary lactase deficiency (most common): lactase levels decline after weaning in most of the world's adult population. Undigested lactose → colon → fermented by bacteria (H2, CO2, short-chain FA) → osmotic diarrhea and gas. Secondary lactase deficiency: intestinal injury (rotavirus, celiac disease).` },
      { q:`Glucose and galactose are absorbed from the intestinal lumen into enterocytes via:`, ch:[`GLUT5 (passive)`,`SGLT1 (Na+/glucose cotransporter) — secondary active transport driven by the Na+ gradient`,`Simple diffusion`,`GLUT2 on the apical surface`], ans:1, exp:`SGLT1 (SLC5A1) on the apical brush border: cotransports 2 Na+ + 1 glucose (or galactose) into enterocytes. Na+ moves down its gradient (maintained by basolateral Na+/K+-ATPase). Glucose exits at the basolateral surface via GLUT2 (passive, into portal blood). GLUT5 transports fructose across the apical membrane.` },
      { q:`Fructose absorption in enterocytes uses:`, ch:[`SGLT1`,`GLUT2 on the apical surface`,`GLUT5 (facilitated diffusion, not Na+-dependent)`,`Active transport via Na+/fructose cotransporter`], ans:2, exp:`Fructose is absorbed by GLUT5 (SLC2A5, facilitated diffusion, apical surface) and exits basolaterally via GLUT2. GLUT5 is low-affinity, high-capacity; high fructose intake (HFCS) can exceed capacity → osmotic diarrhea. Fructose reaches the liver via portal blood → bypasses PFK-1 regulation → rapid hepatic lipogenesis.` },
      { q:`Congenital sucrase-isomaltase deficiency (CSID) causes:`, ch:[`Lactose intolerance only`,`Osmotic diarrhea, bloating, and abdominal pain after sucrose ingestion, beginning when sucrose is introduced in the diet`,`Galactosemia`,`Fructose malabsorption`], ans:1, exp:`CSID: autosomal recessive deficiency of sucrase-isomaltase → sucrose not digested → osmotic diarrhea with sucrose ingestion. Often diagnosed when fruit or baby food is introduced (~4-6 months of age). Fermentable sugars reach colon → fermentation → gas, diarrhea. Treatment: sacrosidase (enzyme replacement) + sucrose restriction.` },
      { q:`Glucose-galactose malabsorption (GGM) is caused by:`, ch:[`GLUT2 mutation`,`SGLT1 (SLC5A1) loss-of-function mutations — both glucose and galactose cannot be absorbed → severe osmotic diarrhea in neonates`,`Fructokinase deficiency`,`Glucose-6-phosphatase deficiency`], ans:1, exp:`GGM: rare autosomal recessive defect in SGLT1 → glucose and galactose absorption severely impaired → profuse osmotic diarrhea beginning in the neonatal period. Treatment: eliminate glucose and galactose from diet (use fructose-based formula). GLUT5 for fructose absorption is normal.` },
      { q:`Pancreatic amylase is secreted by acinar cells into the duodenum. It requires:`, ch:[`An acidic pH (like pepsin)`,`A neutral-to-slightly-alkaline pH (pH ~7) and Cl- ions for optimal activity`,`Bile salts for activation`,`Ca2+ from bile`], ans:1, exp:`Pancreatic amylase: secreted in active form (unlike pancreatic proteases which are zymogens). Requires neutral-to-slightly-alkaline pH (maintained by pancreatic HCO3- secretion into duodenum). It hydrolyzes alpha-1,4 glycosidic bonds in starch → maltose, maltotriose, alpha-limit dextrins (cannot cleave at branch points).` },
      { q:`Dietary fiber (e.g., cellulose) cannot be digested by humans because:`, ch:[`Humans lack stomach acid strong enough`,`Humans lack beta-galactosidase`,`Humans lack cellulase — cellulose has beta-1,4 glycosidic bonds; human amylases only cleave alpha-1,4 bonds`,`Cellulose is too large to enter the gut`], ans:2, exp:`Cellulose: glucose polymer with beta-1,4 linkages (vs. starch with alpha-1,4). Humans lack cellulase (beta-1,4-glucosidase). Undigested fiber reaches the colon → fermented by gut bacteria → short-chain fatty acids (SCFA: butyrate, propionate, acetate) that nourish colonocytes.` },
      { q:`The hormone cholecystokinin (CCK) is released from:`, ch:[`Stomach G cells`,`Duodenal and jejunal I cells in response to fat and protein in the lumen`,`Pancreatic islet cells`,`Liver hepatocytes`], ans:1, exp:`CCK: released by duodenal/jejunal I cells in response to fat and partially digested protein → stimulates gallbladder contraction (bile release) + pancreatic enzyme secretion (amylase, lipase, proteases). CCK also slows gastric emptying and increases satiety. CCK-A receptor (periphery) mediates these effects.` },
      { q:`After absorption, glucose is first delivered to:`, ch:[`Systemic circulation directly`,`The liver via the portal vein — liver is first to receive absorbed glucose`,`The brain`,`Skeletal muscle`], ans:1, exp:`Portal circulation: all absorbed monosaccharides (glucose, galactose, fructose) travel from small intestinal enterocytes → mesenteric veins → portal vein → liver. The liver extracts ~50-75% of glucose (as glycogen or glycolysis) before it reaches systemic circulation. This is why liver disease impairs glucose homeostasis.` },
      { q:`Galactose (from lactose digestion) is metabolized primarily in the:`, ch:[`Kidney`,`Liver, where it is converted to glucose-1-phosphate via the Leloir pathway (galactokinase, GALT, phosphoglucomutase)`,`Muscle`,`Adipose tissue`], ans:1, exp:`Leloir pathway (liver): galactose + ATP → galactose-1-phosphate (galactokinase) → glucose-1-phosphate + UDP-galactose (GALT, galactose-1-phosphate uridylyltransferase) → phosphoglucomutase → glucose-6-phosphate → glycolysis or glycogen. Classic galactosemia: GALT deficiency → galactose-1-P accumulates → liver damage, cataracts, intellectual disability.` },
      { q:`Trehalose is a disaccharide found in fungi and insects. It is cleaved by:`, ch:[`Salivary amylase`,`Brush border trehalase → two glucose molecules`,`Pancreatic lipase`,`Lactase`], ans:1, exp:`Trehalase (brush border enzyme): cleaves trehalose (alpha-1,1-glucoside bond) → 2 glucose. Trehalase deficiency (rare) causes diarrhea after mushroom ingestion (mushrooms contain trehalose). Trehalose is used commercially as a food stabilizer and is being studied for autophagy induction in neurodegenerative diseases.` },
      { q:`Amylase sensitivity to osmolality and starch structure means that:`, ch:[`All starch is equally digestible`,`Raw (crystalline) starch is digested more slowly than cooked (gelatinized) starch — cooking disrupts starch granule structure, increasing accessibility to amylase`,`Cold starch has higher glycemic index than warm starch`,`Amylase cannot cleave branched starch`], ans:1, exp:`Raw starch: tightly packed crystalline granules → limited amylase access → slower digestion → lower glycemic index. Cooked starch: gelatinization (H2O entry, swelling, disruption of hydrogen bonds) → highly accessible amorphous chains → rapid amylase digestion → high glycemic index. Resistant starch (retrograded starch, after cooling) resists digestion → lower GI.` },
    ]
  },
  {
    id:'bb37', cat:'Bio/Biochem', title:'Protein Digestion & Absorption', diff:'Medium',
    qs:[
      { q:`Protein digestion begins in the:`, ch:[`Mouth by salivary proteases`,`Stomach by pepsin (activated from pepsinogen by HCl)`,`Duodenum only`,`Small intestinal brush border`], ans:1, exp:`Pepsinogen is secreted by gastric chief cells and activated by HCl (pH <2) to pepsin. Pepsin (endopeptidase, cleaves Phe/Tyr bonds) begins protein digestion in the stomach. The low pH also denatures proteins, improving digestion efficiency. Pepsin is inactivated in the duodenum (pH rises due to HCO3-).` },
      { q:`Pancreatic proteases are secreted as zymogens. The first to be activated in the duodenum is:`, ch:[`Chymotrypsinogen`,`Trypsinogen — activated by enteropeptidase (enterokinase) on the duodenal brush border → trypsin → activates all other zymogens`,`Proelastase`,`Procarboxypeptidase`], ans:1, exp:`Enteropeptidase (enterokinase) on the duodenal brush border cleaves trypsinogen → trypsin. Trypsin then autocatalytically activates more trypsinogen and activates all other pancreatic zymogens: chymotrypsinogen → chymotrypsin; proelastase → elastase; procarboxypeptidase A/B → carboxypeptidase A/B.` },
      { q:`Trypsin, chymotrypsin, and elastase are all:`, ch:[`Exopeptidases cleaving from the C-terminus`,`Serine endopeptidases — they cleave peptide bonds in the interior of polypeptides at specific residues (Trypsin: Arg/Lys; Chymotrypsin: Phe/Tyr/Trp; Elastase: small uncharged)`,`Metalloproteinases`,`Aspartyl proteases like pepsin`], ans:1, exp:`All three are serine proteases (serine in active site, catalytic triad Ser-His-Asp). Specificity: Trypsin → cleaves after positively charged residues (Lys, Arg); Chymotrypsin → aromatic/large hydrophobic (Phe, Tyr, Trp); Elastase → small, uncharged (Ala, Gly, Val). These are endopeptidases (cleave interior bonds). Carboxypeptidase A/B are exopeptidases.` },
      { q:`Carboxypeptidases A and B (pancreatic exopeptidases) cleave:`, ch:[`From the N-terminus of peptides`,`From the C-terminus: A cleaves neutral/aromatic residues; B cleaves positively charged (Arg, Lys)`,`Only from proline-rich regions`,`Internal peptide bonds only`], ans:1, exp:`Carboxypeptidases are exopeptidases: they remove amino acids one at a time from the C-terminus. Carboxypeptidase A: Zn2+-metalloprotease, cleaves neutral/aromatic C-terminal residues. Carboxypeptidase B: cleaves Arg or Lys from C-terminus. Together with endopeptidases (trypsin, chymotrypsin, elastase), they reduce polypeptides to small peptides and free AAs.` },
      { q:`Brush border peptidases (aminopeptidases, dipeptidyl aminopeptidase) on intestinal enterocytes:`, ch:[`Degrade all proteins completely before absorption`,`Further hydrolyze small peptides (2-6 residues) to free amino acids and di/tripeptides at the luminal surface`,`Only act on specific peptide sequences`,`Are identical to pancreatic proteases`], ans:1, exp:`Brush border peptidases (aminopeptidases, carboxypeptidases, dipeptidyl peptidase IV, endopeptidases) on enterocyte microvilli complete digestion of small peptides to free AAs and di/tripeptides. Cytoplasmic peptidases inside enterocytes further hydrolyze absorbed di/tripeptides.` },
      { q:`Free amino acids and di/tripeptides are absorbed into enterocytes via:`, ch:[`Simple diffusion`,`Sodium-amino acid cotransporters (for free AAs) and PepT1 (H+-dependent di/tripeptide transporter)`,`GLUT1`,`Only endocytosis`], ans:1, exp:`Free amino acids: absorbed by Na+-coupled amino acid transporters (various families: neutral AAs via System B0AT1 = SLC6A19; cationic via CAT-1/2; anionic via XCT). Di/tripeptides: absorbed by PepT1 (SLC15A1), driven by H+ gradient. Di/tripeptides are then hydrolyzed to free AAs by cytoplasmic peptidases inside enterocytes.` },
      { q:`Hartnup disease is caused by:`, ch:[`Tryptophan dietary deficiency`,`Loss-of-function mutation in SLC6A19 (B0AT1) — a neutral amino acid transporter in the intestine and kidney → tryptophan malabsorption`,`Phenylketonuria`,`Leucine malabsorption`], ans:1, exp:`Hartnup disease: autosomal recessive defect in SLC6A19 (B0AT1) → impaired intestinal and renal tubular absorption of neutral AAs (especially tryptophan). Tryptophan → NAD+ (nicotinamide); deficiency → pellagra-like symptoms (photosensitive rash, ataxia, mental changes). Treat with high-protein diet or niacin supplementation.` },
      { q:`Cystinuria is caused by:`, ch:[`Cystine deficiency`,`Mutations in SLC3A1 or SLC7A9 — impaired renal tubular and intestinal reabsorption of cystine, ornithine, arginine, lysine (COAL); cystine is poorly soluble → kidney stones`,`GALT deficiency`,`Tryptophan transport defect`], ans:1, exp:`Cystinuria: mutations in SLC3A1 (rBAT) or SLC7A9 (b0,+AT) → impaired reabsorption of cystine (and dibasic AAs: ornithine, arginine, lysine) in kidney (and intestine). Cystine accumulates in urine → forms hexagonal crystals and kidney stones at physiologic pH (poorly soluble, pKa ~8). Treatment: hydration, alkalinize urine, D-penicillamine/tiopronin to solubilize cystine.` },
      { q:`Protein quality is assessed by biological value (BV) and PDCAAS. These measures assess:`, ch:[`Protein quantity only`,`Essential amino acid content and digestibility — high BV proteins (e.g., egg, milk) contain all essential AAs in appropriate proportions`,`Fat content of protein sources`,`Processing method`], ans:1, exp:`Biological value = (N retained / N absorbed) x 100. High BV: eggs (~100%), milk (~91%), meat. Complete proteins: contain all 9 essential AAs (His, Ile, Leu, Lys, Met, Phe, Thr, Trp, Val). PDCAAS (protein digestibility-corrected amino acid score) is the current standard, accounting for digestibility. Lysine is the most common limiting AA in plant proteins.` },
      { q:`Aminopeptidase N (CD13) on the intestinal brush border:`, ch:[`Cleaves from the C-terminus`,`Cleaves from the N-terminus, removing one AA at a time from the N-terminal end of peptides`,`Cleaves only Pro-Xaa bonds`,`Is a serine protease like trypsin`], ans:1, exp:`Aminopeptidase N (APN, CD13) is a Zn2+-metallopeptidase on the brush border that sequentially removes single amino acids from the N-terminus of di-, tri-, and oligopeptides. Dipeptidyl peptidase IV (DPP-IV) cleaves Xaa-Pro dipeptides from the N-terminus; this is relevant as DPP-IV on enterocytes degrades GLP-1 (sitagliptin/DPP-4 inhibitors → increased GLP-1 → lower blood glucose in T2DM).` },
      { q:`Pancreatic insufficiency (e.g., from chronic pancreatitis, cystic fibrosis) leads to:`, ch:[`Improved protein digestion because stomach pepsin compensates completely`,`Protein maldigestion (steatorrhea and creatorhea) due to lack of pancreatic enzymes; supplementation with pancreatic enzyme replacement therapy (PERT) is needed`,`Increased intestinal protease activity`,`Nutrient absorption is unaffected because brush border peptidases compensate`], ans:1, exp:`Pancreatic insufficiency → inadequate trypsin, chymotrypsin, elastase, amylase, lipase → maldigestion → steatorrhea (fat malabsorption) and creatorhea (undigested protein in stool). Secondary malabsorption of fat-soluble vitamins. Stomach and brush border enzymes cannot fully compensate. PERT (e.g., Creon) with meals is the treatment.` },
      { q:`Why does hydrochloric acid (HCl) in the stomach facilitate protein digestion even before pepsin acts?`, ch:[`HCl directly cleaves peptide bonds`,`HCl denatures protein tertiary structure (unfolding) and activates pepsinogen → pepsin, increasing peptide bond accessibility for proteases`,`HCl increases the pH for optimal pepsin activity`,`HCl kills bacteria but has no direct effect on protein`], ans:1, exp:`Gastric acid (HCl, pH 1.5-3.5): (1) denatures proteins by disrupting H-bonds and disulfide bonds → unfolds proteins → more peptide bonds exposed for protease access; (2) converts pepsinogen to active pepsin (pepsin requires acidic pH for optimal activity); (3) kills ingested microorganisms (innate defense).` },
      { q:`Intrinsic factor (IF), produced by gastric parietal cells, is required for:`, ch:[`Pepsin activation`,`Vitamin B12 (cobalamin) absorption in the terminal ileum via IF-B12 complex binding to cubilin receptor`,`Pancreatic enzyme activation`,`Bile salt emulsification`], ans:1, exp:`Intrinsic factor (IF): glycoprotein secreted by parietal cells. In the terminal ileum, IF-B12 complex binds the cubilin-amnionless receptor (CUBAM) → endocytosis → B12 released and enters blood bound to transcobalamin II. IF deficiency (pernicious anemia — autoimmune gastritis, anti-IF antibodies) → B12 malabsorption → megaloblastic anemia, subacute combined degeneration.` },
      { q:`R-proteins (haptocorrins, salivary binding proteins) bind B12 in the stomach because:`, ch:[`They are the primary carriers of B12 in blood`,`They protect dietary B12 from acid degradation before IF is available; R-proteins are later degraded by pancreatic proteases in the duodenum → B12 transferred to IF`,`They directly facilitate B12 absorption in the ileum`,`They increase IF production`], ans:1, exp:`R-proteins (haptocorrins) in saliva bind B12 first (high affinity at low pH). In the duodenum, pancreatic proteases degrade R-proteins → B12 released → binds intrinsic factor (IF). IF protects B12 until the terminal ileum receptor. B12 deficiency from pancreatic insufficiency: pancreatic proteases not available to release B12 from R-proteins.` },
    ]
  },
  {
    id:'bb38', cat:'Bio/Biochem', title:'Lipid Digestion & Absorption', diff:'Medium',
    qs:[
      { q:`Dietary triglyceride (TG) digestion begins in the:`, ch:[`Mouth by lingual lipase (minor)`,`Stomach by gastric lipase (minor), then major digestion in the duodenum by pancreatic lipase`,`Duodenum only — all TG digestion occurs there`,`Ileum after bile salt emulsification`], ans:1, exp:`Some TG digestion begins in the stomach by gastric lipase (acid-stable, cleaves sn-3 position). The major digestion occurs in the duodenum: pancreatic lipase (with colipase) cleaves TG at sn-1 and sn-3 positions → 2-monoacylglycerol (2-MAG) + 2 free fatty acids. Bile salts emulsify fat droplets to increase surface area.` },
      { q:`Bile salts function in fat digestion by:`, ch:[`Directly cleaving ester bonds in triglycerides`,`Emulsifying large fat droplets into smaller micelles, increasing the surface area for pancreatic lipase action`,`Activating pancreatic lipase`,`Solubilizing water-soluble vitamins`], ans:1, exp:`Bile salts (amphipathic: hydrophilic and hydrophobic faces) reduce surface tension of fat droplets → emulsification into smaller globules → more surface area for lipase. Products of lipase (FFA, 2-MAG) + phospholipids + bile salts → mixed micelles → transport to the absorptive enterocyte brush border for uptake.` },
      { q:`Pancreatic lipase requires which co-factor for optimal activity in the presence of bile salts?`, ch:[`Cholesterol`,`Colipase — a small protein that anchors lipase to the lipid droplet surface, displacing inhibitory bile salts`,`Phospholipase A2`,`Enteropeptidase`], ans:1, exp:`Colipase (secreted as procolipase, activated by trypsin): binds to both lipase and the lipid droplet surface at the water-lipid interface. Bile salts displace lipase from the interface; colipase counteracts this by anchoring lipase. Without colipase, high bile salt concentrations inhibit lipase. Orlistat inhibits lipase directly.` },
      { q:`How are long-chain fatty acids (LCFA) absorbed into enterocytes?`, ch:[`Via SGLT1 sodium cotransport`,`From mixed micelles via passive diffusion across the apical membrane and/or via FATP4/CD36 protein-mediated uptake`,`Via peptide transporters`,`Via active transport similar to amino acids`], ans:1, exp:`LCFAs (>12C) from mixed micelles are absorbed across the apical membrane by: (1) passive diffusion (some) and (2) protein-facilitated transport (FATP4, CD36). Once inside enterocytes, they bind fatty acid binding proteins (FABPs) and are re-esterified to TG in the ER → packaged into chylomicrons.` },
      { q:`Medium-chain fatty acids (MCFA, C6-C12) are handled differently from LCFA because they:`, ch:[`Require bile salts for absorption`,`Are absorbed directly into the portal circulation (do not require chylomicron packaging) and travel directly to the liver`,`Are incorporated into chylomicrons like LCFA`,`Cannot be absorbed by enterocytes`], ans:1, exp:`MCFA (6-12 carbons): more water-soluble than LCFA → absorbed directly into the portal circulation (bypassing chylomicron assembly) → travel directly to the liver via the portal vein. MCT oil is used clinically in fat malabsorption conditions (pancreatic insufficiency, chylothorax) because MCFAs bypass the lymphatic route.` },
      { q:`Chylomicrons are assembled in enterocytes for the transport of:`, ch:[`Glucose to the portal circulation`,`Absorbed dietary lipids (TG, cholesterol esters, fat-soluble vitamins) via the lymphatic system (thoracic duct) to systemic circulation`,`Free fatty acids directly`,`Only cholesterol from bile`], ans:1, exp:`Chylomicrons: large lipoprotein particles (90% TG) assembled in enterocytes (smooth ER → Golgi → secretory vesicles). Secreted into lacteals (lymphatic vessels in intestinal villi) → thoracic duct → enters systemic circulation at the subclavian vein. This bypasses the liver initially. Chylomicrons are cleared by lipoprotein lipase in peripheral tissues.` },
      { q:`Fat-soluble vitamins (A, D, E, K) are absorbed similarly to:`, ch:[`Water-soluble vitamins via carrier proteins`,`Dietary lipids — they require bile salts for micelle formation and are packaged into chylomicrons for lymphatic transport`,`Glucose via SGLT1`,`Mineral ions via ion pumps`], ans:1, exp:`Fat-soluble vitamins require dietary fat, bile salts, and normal fat absorption for absorption. They are incorporated into mixed micelles → absorbed into enterocytes → packaged into chylomicrons → lymphatic transport. Fat malabsorption (pancreatic insufficiency, celiac disease, biliary obstruction) causes fat-soluble vitamin deficiencies.` },
      { q:`Phospholipase A2 (from pancreas) cleaves:`, ch:[`The ester bonds of cholesterol esters`,`The sn-2 fatty acid from phospholipids → lysophospholipid + fatty acid`,`The glycerol backbone of triglycerides`,`The phosphate headgroup from phospholipids`], ans:1, exp:`Pancreatic PLA2 (secretory PLA2): cleaves the sn-2 ester bond of phospholipids → lysophospholipid + fatty acid. Activated in the duodenum by trypsin and bile salts. Products (lysophospholipids) are also absorbed in micelles. Venom PLA2 (same mechanism) causes cell membrane destruction.` },
      { q:`Orlistat (weight loss drug) reduces fat absorption by:`, ch:[`Blocking bile salt synthesis`,`Irreversibly inhibiting pancreatic and gastric lipases → undigested TG passes to colon → steatorrhea`,`Blocking chylomicron assembly`,`Inhibiting FATP4 transporters`], ans:1, exp:`Orlistat covalently inactivates lipases (mimics TG as a substrate, forms covalent bond with active site Ser). Without lipases, dietary TG is not hydrolyzed → cannot form micelles → not absorbed → excreted in stool (steatorrhea is a common side effect). Reduces fat absorption by ~30%. Decreases fat-soluble vitamin absorption as well.` },
      { q:`Lipoprotein lipase (LPL) in peripheral tissues cleaves:`, ch:[`Cholesterol esters in HDL`,`TG in chylomicrons and VLDL → free fatty acids + glycerol, which are taken up by tissues (muscle for energy, adipose for storage)`,`Phospholipids in chylomicron shells`,`LDL cholesterol`], ans:1, exp:`LPL (on endothelial surfaces, especially adipose and muscle) is activated by ApoC-II (on chylomicrons and VLDL). It cleaves TG → FFA + glycerol. Tissues take up FFA: muscle → oxidation (energy); adipose → re-esterification (storage). Insulin upregulates adipose LPL; exercise upregulates muscle LPL. LPL deficiency → hypertriglyceridemia, pancreatitis.` },
      { q:`During absorption, cholesterol esters from the diet are hydrolyzed by:`, ch:[`Pancreatic lipase`,`Cholesterol esterase (pancreatic non-specific esterase) → free cholesterol + fatty acid; free cholesterol is then absorbed into enterocytes and re-esterified by ACAT`,`Bile salt lipase`,`Gastric lipase`], ans:2, exp:`Dietary cholesterol: mostly as cholesterol esters → hydrolyzed by pancreatic cholesterol esterase (carboxyl ester lipase, CEL) → free cholesterol → absorbed into enterocytes via NPC1L1 → re-esterified by ACAT (acyl-CoA:cholesterol acyltransferase) → packaged into chylomicrons. Ezetimibe blocks NPC1L1.` },
      { q:`Steatorrhea (fatty stools) is a sign of fat malabsorption. Which condition does NOT typically cause steatorrhea?`, ch:[`Pancreatic exocrine insufficiency`,`Bile duct obstruction`,`Celiac disease (gluten-sensitive enteropathy)`,`Lactase deficiency`], ans:3, exp:`Lactase deficiency causes lactose malabsorption (osmotic diarrhea, gas) but does NOT cause steatorrhea (fat malabsorption). Steatorrhea results from: (1) lipase deficiency (pancreatic insufficiency); (2) bile salt deficiency (bile duct obstruction, primary biliary cholangitis); (3) small intestinal mucosal disease (celiac disease, Crohn's disease, tropical sprue).` },
      { q:`The lymphatic route for fat absorption (vs. portal route for sugars/AAs) is clinically important because:`, ch:[`It is faster than portal absorption`,`It means dietary fat does not immediately pass through the liver — VLDL production and hepatic fat metabolism are not immediately affected by a meal`,`It allows fat-soluble vitamins to be stored in the liver immediately`,`It is irrelevant clinically`], ans:1, exp:`Chylomicrons enter systemic circulation via the thoracic duct (bypassing portal/hepatic first-pass). Chylomicron remnants are taken up by the liver later (by LDL receptor-related protein, LRP). Portal route: glucose, galactose, fructose, amino acids, water-soluble vitamins, minerals → immediately processed by liver.` },
      { q:`ApoB-48 is the structural apolipoprotein of chylomicrons. It is produced by:`, ch:[`Hepatocytes`, `Enterocytes — it is a truncated form of ApoB-100 produced by apoB mRNA editing (cytidine deaminase creates a stop codon at codon 2153)`,`Adipocytes`,`Endothelial cells`], ans:1, exp:`ApoB-48: produced by enterocytes via ApoB mRNA editing (APOBEC1 converts C → U at codon 2153 → stop codon → 48% of full ApoB-100 protein). ApoB-100: produced by hepatocytes for VLDL/LDL. ApoB-48 (on chylomicrons) is not recognized by LDL receptors; chylomicron remnants are taken up by LRP (LDL receptor-related protein) via ApoE.` },
    ]
  },
  {
    id:'bb39', cat:'Bio/Biochem', title:'Renal Physiology & Biochemistry', diff:'Medium',
    qs:[
      { q:`The functional unit of the kidney is the:`, ch:[`Glomerulus`,`Nephron (comprising glomerulus, proximal tubule, loop of Henle, distal tubule, and collecting duct)`,`Renal corpuscle only`,`Collecting duct`], ans:1, exp:`The nephron (~1 million per kidney) performs filtration, reabsorption, and secretion. Components: Bowman's capsule + glomerular capillaries (filtration); proximal convoluted tubule (bulk reabsorption); loop of Henle (concentration); distal convoluted tubule (fine tuning); collecting duct (ADH-regulated water reabsorption).` },
      { q:`GFR (glomerular filtration rate) is estimated clinically by:`, ch:[`Plasma glucose concentration`,`Serum creatinine-based equations (CKD-EPI, MDRD) or creatinine clearance, because creatinine is freely filtered and minimally secreted`,`Blood urea nitrogen (BUN) alone`,`Urine protein/creatinine ratio`], ans:1, exp:`Creatinine: produced at constant rate from muscle creatine phosphate degradation → freely filtered, minimally secreted → reliable GFR marker. CKD-EPI equation uses serum creatinine, age, sex, and race to estimate GFR. Cystatin C is an alternative marker, less affected by muscle mass. GFR declines with age and CKD progression.` },
      { q:`The proximal convoluted tubule (PCT) reabsorbs approximately:`, ch:[`~25% of filtered Na+ and water`,`~65-70% of filtered Na+, Cl-, water, K+, glucose, amino acids, HCO3-, and phosphate (with most glucose and amino acids near-completely reabsorbed)`,`~100% of filtered proteins`,`Only water (no solutes)`], ans:1, exp:`PCT: major reabsorption site. ~65-70% of filtered Na+ (via Na+/H+ exchanger NHE3, Na+-glucose cotransporter SGLT2, Na+-amino acid cotransporters), water (follows osmotically via AQP1), glucose (SGLT2: ~90%, SGLT1: ~10%), amino acids (100%), HCO3- (~80%), phosphate (~70-80%), urea (~50%), K+ (~65%). Na+/K+-ATPase on basolateral side drives everything.` },
      { q:`The loop of Henle creates the medullary concentration gradient by:`, ch:[`Active water reabsorption in the descending limb`,`The countercurrent multiplier system: the descending limb is permeable to water (not solute), the ascending limb pumps NaCl (impermeable to water) → creates high interstitial osmolality in the medulla`,`Urea recycling in the thin ascending limb`,`ADH action on the loop`], ans:1, exp:`Countercurrent multiplier: descending thin limb: permeable to water, not solute → water exits, tubular fluid concentrates; ascending limb (thin + thick): impermeable to water, NKCC2 pumps NaCl out → dilutes tubular fluid but concentrates interstitium. Urea recycling (collecting duct → inner medullary interstitium) also contributes to the gradient.` },
      { q:`Aldosterone's primary site of action is:`, ch:[`Proximal tubule`,`Loop of Henle`,`Principal cells of the distal tubule and collecting duct — increases ENaC and Na+/K+-ATPase expression → Na+ reabsorption, K+ secretion`,`Glomerulus`], ans:2, exp:`Aldosterone (mineralocorticoid) → binds intracellular MR (mineralocorticoid receptor) in principal cells → transcription of ENaC (epithelial Na+ channels), ROMK (K+ secretion channels), and Na+/K+-ATPase → Na+ reabsorption with K+ excretion and H+ excretion. Net: blood volume expansion, K+ loss. Excess → Conn's syndrome (hypertension, hypokalemia).` },
      { q:`ADH (vasopressin) increases water reabsorption by:`, ch:[`Opening Na+ channels in the DCT`,`Binding V2 receptors on collecting duct principal cells → cAMP → PKA → AQP2 vesicle fusion with apical membrane → water permeability increases`,`Inhibiting aldosterone release`,`Constricting the efferent arteriole`], ans:1, exp:`ADH (from posterior pituitary) → V2 receptor (Gs-coupled, Gsα → adenylate cyclase → cAMP → PKA) → phosphorylation of AQP2 → insertion into the apical membrane → water enters cells → exits basolaterally via AQP3/4 → water reabsorption. ADH deficiency → diabetes insipidus (massive dilute urine).` },
      { q:`The kidney produces erythropoietin (EPO) in response to:`, ch:[`High blood glucose`,`Renal tissue hypoxia (detected by HIF-1alpha) → EPO → stimulates RBC production in bone marrow`,`High aldosterone`,`Elevated serum creatinine`], ans:1, exp:`Peritubular fibroblasts (and hepatocytes to a lesser extent) produce EPO. Hypoxia stabilizes HIF-1alpha (normally degraded by PHD/VHL pathway under normoxia) → HIF-1alpha binds HRE on EPO gene → EPO transcription. EPO → bone marrow → erythroid progenitor proliferation/differentiation → increased RBC production. CKD → EPO deficiency → normocytic normochromic anemia.` },
      { q:`Ammonia production in the kidney is important for:`, ch:[`Excreting excess ketone bodies`,`Buffering urinary acids — kidneys produce NH3 from glutamine (glutaminase) → NH3 + H+ → NH4+ (ammonium), excreted in urine, regenerating HCO3- for blood`,`Activating renin`,`Producing urea for excretion`], ans:1, exp:`Renal glutaminase converts glutamine → glutamate + NH3; glutamate dehydrogenase → alpha-KG + NH3. NH3 diffuses into tubule lumen → NH3 + H+ → NH4+; NH4+ is excreted in urine (trapped by protonation in acidic tubular fluid). Each NH4+ excreted regenerates one HCO3- → bicarbonate back to blood (crucial for metabolic acidosis compensation).` },
      { q:`Renin is released from juxtaglomerular cells in response to:`, ch:[`High blood pressure`,`Low renal perfusion pressure, sympathetic activation (beta-1 adrenergic), and low Na+ delivery to the macula densa`,`High aldosterone`,`High plasma K+`], ans:1, exp:`Renin (serine protease) release triggers: (1) reduced stretch on afferent arteriole (baroreceptor mechanism, low BP); (2) sympathetic stimulation (beta-1 receptors on JG cells → cAMP); (3) low Na+/Cl- delivery to macula densa (NaCl sensor in thick ascending limb). Renin → angiotensinogen → Ang I → ACE → Ang II → aldosterone, vasoconstriction.` },
      { q:`Glucose reabsorption in the kidney is normally complete (Tm=~375 mg/min) because:`, ch:[`Glucose is converted to glycogen before filtration`,`SGLT2 in the PCT has sufficient transport capacity to reabsorb all filtered glucose at normal plasma glucose levels`,`Glucose is too large to be filtered at the glomerulus`,`Glucose is actively secreted into the urine`], ans:1, exp:`Threshold for glucosuria: plasma glucose ~180 mg/dL (renal threshold) — when filtered load exceeds SGLT2+SGLT1 Tm (~375 mg/min) → glycosuria. In diabetes, plasma glucose >180 mg/dL → filtered load exceeds Tm → glucose in urine. SGLT2 inhibitors intentionally lower the Tm for glucose → therapeutic glucosuria in T2DM.` },
      { q:`Potassium is secreted in the collecting duct by:`, ch:[`Intercalated cells only`,`Principal cells via ROMK (renal outer medullary K+ channels) and BK channels in the apical membrane, driven by the negative luminal potential from ENaC-mediated Na+ reabsorption`,`Active pumping against concentration gradient without Na+`,`Active secretion coupled to Cl- reabsorption`], ans:1, exp:`K+ secretion in principal cells: Na+ enters via ENaC → creates lumen-negative potential → K+ exits via ROMK/BK (apical) → secreted into urine. Aldosterone increases both ENaC (more Na+ reabsorption, more negative lumen potential) and ROMK → more K+ secretion. RAAS activation or ENaC-activating mutations (Liddle syndrome) → hypokalemia.` },
      { q:`The anion gap is used to classify metabolic acidosis. It is calculated as:`, ch:[`Na+ - (K+ + Cl-)`,`Na+ - (Cl- + HCO3-)`, `Na+ + K+ - (Cl- + HCO3-)`,`HCO3- - Cl-`], ans:1, exp:`Anion gap (AG) = Na+ - (Cl- + HCO3-). Normal AG: ~8-12 mEq/L (unmeasured anions like albumin, phosphate, sulfate). Elevated AG acidosis (MUDPILES: Methanol, Uremia, DKA, Propylene glycol, INH/Iron, Lactic acidosis, Ethylene glycol, Salicylates). Normal AG acidosis: HCO3- loss (diarrhea, RTA) with compensatory Cl- retention (hyperchloremic acidosis).` },
      { q:`Vitamin D activation requires the kidney because:`, ch:[`The kidney synthesizes cholesterol, the precursor of vitamin D`,`The kidney performs the final hydroxylation: 25-hydroxyvitamin D3 → 1,25-dihydroxyvitamin D3 (calcitriol) by 1-alpha-hydroxylase in proximal tubular cells`,`The kidney activates vitamin D receptor`,`Kidney is needed for parathyroid hormone synthesis`], ans:1, exp:`Vitamin D activation: skin (UV → vitamin D3) → liver 25-hydroxylase → 25(OH)D3 → kidney 1alpha-hydroxylase (CYP27B1, activated by PTH and hypocalcemia) → 1,25(OH)2D3 (calcitriol, active form) → intestinal Ca2+ absorption, renal Ca2+ reabsorption. CKD impairs 1alpha-hydroxylase → low calcitriol → secondary hyperparathyroidism, renal osteodystrophy.` },
      { q:`Para-aminohippuric acid (PAH) is used to estimate:`, ch:[`GFR`,`Renal plasma flow (RPF) — PAH is freely filtered AND actively secreted; at low concentrations, it is nearly completely extracted in one pass → clearance approximates RPF`,`Tubular Tm for glucose`,`Aldosterone sensitivity`], ans:1, exp:`PAH clearance estimates effective renal plasma flow (ERPF) because PAH is: (1) freely filtered at the glomerulus; (2) actively secreted by proximal tubule OAT (organic anion transporter) transporters; (3) not reabsorbed. At low plasma concentrations, ~90% extracted per pass → clearance ~RPF. RPF/RBF ratio = 1 - hematocrit (plasma fraction).` },
    ]
  },
  // ── Hard ────────────────────────────────────────────────────────────────────
  {
    id:'bb40', cat:'Bio/Biochem', title:'Allosteric & Covalent Enzyme Regulation', diff:'Hard',
    qs:[
      { q:`Allosteric regulation differs from competitive inhibition in that allosteric effectors:`, ch:[`Bind the active site directly`,`Bind a site distinct from the active site and cause conformational changes that alter enzyme activity`,`Only inhibit enzymes, never activate`,`Require covalent bond formation`], ans:1, exp:`Allosteric effectors bind the allosteric (regulatory) site (distinct from the active site) → conformational change → alters substrate affinity (Km) or Vmax. Can be activators (shift T→R state) or inhibitors (stabilize T-state). Allosteric enzymes often show sigmoidal kinetics (cooperativity).` },
      { q:`PFK-1 is the key regulatory step of glycolysis. It is inhibited by:`, ch:[`AMP and ADP`,`ATP (high energy charge) and citrate, and activated by AMP, ADP, and fructose-2,6-bisphosphate`,`NADH only`,`Glucose-6-phosphate`], ans:1, exp:`PFK-1: inhibited by ATP (allosteric site) and citrate (signals TCA cycle sufficiency). Activated by AMP, ADP (energy deficit), and fructose-2,6-bisphosphate (F2,6BP — the most potent activator, synthesized by PFK-2 under insulin signaling). This keeps glycolysis coordinated with energy status.` },
      { q:`The concerted (MWC) model of allostery proposes that:`, ch:[`Each subunit can switch states independently`,`All subunits exist in either all-T (taut) or all-R (relaxed) states simultaneously — the protein acts as a unit`,`Ligand binding causes sequential conformational changes`,`Allosteric sites are identical to active sites`], ans:1, exp:`MWC (Monod-Wyman-Changeux) model: oligomeric enzyme exists in all-T or all-R state (concerted transition). Activators bind preferentially to R-state → shift equilibrium toward R; inhibitors prefer T-state. The sequential (KNF) model allows hybrid states.` },
      { q:`Pyruvate kinase (PK) in the liver is inhibited during fasting by:`, ch:[`Allosteric inhibition by AMP`,`Phosphorylation by PKA (downstream of glucagon/cAMP) → inactive; ensures PEP goes to gluconeogenesis`,`Inhibition by fructose-1,6-bisphosphate`,`Activation by alanine`], ans:1, exp:`Liver PK allosteric: activated by F1,6BP (feedforward); inhibited by alanine and ATP. Covalent regulation by glucagon: cAMP → PKA → phosphorylates PK → inactive. This prevents futile cycling during gluconeogenesis (PEP must be directed toward glucose synthesis, not back to pyruvate).` },
      { q:`The bifunctional enzyme PFK-2/FBPase-2 under fasting conditions (glucagon):`, ch:[`PFK-2 domain is active → high F2,6BP → activates PFK-1`,`PKA phosphorylates the enzyme → FBPase-2 domain active → F2,6BP is degraded → PFK-1 less active → glycolysis slows`,`PFK-2 is allosterically activated by citrate`,`The enzyme is degraded by proteolysis`], ans:1, exp:`Glucagon → PKA → phosphorylates PFK-2/FBPase-2 → FBPase-2 domain active (F2,6BP → F6P) + PFK-2 domain inactive → [F2,6BP] falls → PFK-1 less activated → glycolysis decreases. Insulin reverses this via protein phosphatase 2A (PP2A).` },
      { q:`Aspartate transcarbamoylase (ATCase) is feedback-inhibited by:`, ch:[`ATP (end product of purine synthesis)`,`CTP (end product of pyrimidine synthesis), and activated by ATP (signals need for more pyrimidines)`,`Both ATP and CTP equally`,`Aspartate itself`], ans:1, exp:`ATCase (first committed step of pyrimidine synthesis): feedback-inhibited by CTP (end product); activated by ATP (signals purine availability, coordinate pyrimidine synthesis). A classic example of feedback inhibition and heterotropic allosteric regulation.` },
      { q:`Covalent modification by phosphorylation differs from allosteric regulation in that:`, ch:[`It is faster than allosteric regulation`,`It requires an enzyme (kinase/phosphatase) to add/remove the modification; creates signal amplification cascades and can have longer-lasting effects`,`It only occurs on Tyr residues`,`It cannot be reversed`], ans:1, exp:`Covalent modification: requires kinase (add phosphate, uses ATP) or phosphatase (remove phosphate). Creates signal cascades with amplification. Phosphorylation adds negative charge and steric bulk, altering active site geometry or protein interactions. Many drugs target kinases (e.g., imatinib targets BCR-ABL).` },
      { q:`Acetyl-CoA carboxylase (ACC) is allosterically activated by:`, ch:[`AMP`,`Citrate — promotes polymerization from inactive dimers to active filaments (fed state signal)`,`Palmitoyl-CoA`,`AMPK`], ans:1, exp:`ACC allosteric regulation: citrate (signals excess acetyl-CoA/energy) activates ACC by promoting polymerization of inactive dimers → active filaments. Palmitoyl-CoA (product) inhibits. Covalent: AMPK phosphorylates ACC → inactive; insulin/PP2A dephosphorylates → active.` },
      { q:`Phosphorylase a (active form) differs from phosphorylase b in that:`, ch:[`Phosphorylase a is dephosphorylated`,`Phosphorylase a is phosphorylated at Ser14 by phosphorylase kinase; phosphorylase b is dephosphorylated and activated only by AMP`,`Phosphorylase b is the constitutively active form`,`Phosphorylase a requires AMP for activity`], ans:1, exp:`Phosphorylase b (dephosphorylated): inactive, but allosterically activated by AMP (energy deficiency) and inhibited by ATP/G6P. Phosphorylase a (phosphorylated by phosphorylase kinase): constitutively active; in the liver it is allosterically inhibited by glucose (when glucose is high → no need to break down glycogen).` },
      { q:`Calmodulin is a Ca2+-binding protein that activates:`, ch:[`PKA`,`Phosphorylase kinase (contains calmodulin as delta subunit), CaM kinase II, and other Ca2+-dependent processes`,`Only protein phosphatase 2B (calcineurin)`,`Only smooth muscle myosin light-chain kinase (MLCK)`], ans:1, exp:`Ca2+-calmodulin complex activates: phosphorylase kinase (delta subunit = calmodulin → glycogenolysis); CaM-KII (multiple targets); MLCK (smooth muscle contraction); calcineurin (phosphatase, activates NFAT, target of cyclosporine). Ca2+ thus links neural/hormonal signals to enzyme activity.` },
      { q:`Feedback inhibition refers specifically to:`, ch:[`Product inhibiting only the last step`,`The end product of a pathway inhibiting an early committed step, preventing wasteful intermediate accumulation`,`Product inhibition anywhere in a pathway`,`Inhibition requiring covalent modification`], ans:1, exp:`Feedback inhibition: end product inhibits a committed step early in the pathway (e.g., CTP inhibits ATCase; IMP → GMP → feedback to ADSS step; excess FA → palmitoyl-CoA inhibits ACC). Prevents overaccumulation of intermediates and conserves raw materials.` },
      { q:`Glutamate dehydrogenase (GDH) is inhibited by GTP. GTP inhibition signals:`, ch:[`Energy deficit requiring amino acid catabolism`,`Energy sufficiency — TCA cycle is running well (producing GTP) → reduce amino acid catabolism`,`GTP is a substrate for GDH`,`Promotes deamination`], ans:1, exp:`GDH (mitochondrial, reversible): activated by ADP/GDP (energy deficit → break down amino acids) and leucine. Inhibited by GTP (energy surfeit — TCA cycle producing GTP → no need for more amino acid catabolism), NADH, and ATP. Fine-tunes amino acid degradation to energy status.` },
      { q:`Isocitrate dehydrogenase (TCA cycle) is allosterically regulated by:`, ch:[`Citrate`,`ADP/AMP (activators, energy deficit) and NADH/ATP (inhibitors, energy sufficiency)`,`Succinyl-CoA`,`OAA`], ans:1, exp:`IDH3 (mitochondrial, NAD-dependent): activated by ADP and AMP (low energy charge); inhibited by NADH and ATP (high energy charge). This ensures TCA cycle flux matches energy needs. IDH1 (cytoplasmic, NADP-dependent) is mutated in cancers, producing the oncometabolite 2-HG.` },
      { q:`Glucokinase (hexokinase IV) in the liver differs from hexokinase I–III in that:`, ch:[`Glucokinase has a lower Km for glucose`,`Glucokinase is not product-inhibited by G6P and has a high Km (~10 mM), making it a glucose sensor that continues working at high portal glucose concentrations`,`Glucokinase is expressed in all tissues`,`Glucokinase has identical kinetics to hexokinase I`], ans:1, exp:`Glucokinase (liver/pancreatic beta cells, low affinity Km ~10 mM, no G6P inhibition, sigmoidal kinetics): acts as a glucose sensor — responds to post-meal portal glucose surges. Hexokinase I-III (ubiquitous, high affinity Km ~0.1 mM): product-inhibited by G6P — protects cell from excess glycolysis.` },
    ]
  },
  {
    id:'bb41', cat:'Bio/Biochem', title:'Fed vs. Fasted Metabolism Integration', diff:'Hard',
    qs:[
      { q:`In the well-fed state (2 hours after a carbohydrate-rich meal), the primary metabolic fuel for most tissues is:`, ch:[`Fatty acids`,`Glucose`,`Ketone bodies`,`Amino acids`], ans:1, exp:`Fed state: high portal glucose → pancreatic beta cells secrete insulin → GLUT4 upregulation in muscle/adipose → glucose uptake → glycolysis, glycogen synthesis, lipogenesis. Insulin suppresses glucagon → no gluconeogenesis, no ketogenesis. Brain and muscle use glucose primarily.` },
      { q:`During prolonged fasting, the liver primarily:`, ch:[`Stores glucose as glycogen`,`Produces glucose (gluconeogenesis), synthesizes ketone bodies, and maintains blood glucose for the brain`,`Produces insulin`,`Oxidizes glucose for ATP`], ans:1, exp:`Fasted liver: glycogen depleted after 12-24h → gluconeogenesis (from alanine, glutamine, glycerol, lactate) sustains blood glucose. Beta-oxidation of FFA generates acetyl-CoA → ketogenesis (OAA diverted to gluconeogenesis). Ketone bodies (acetoacetate, beta-hydroxybutyrate) exported for brain/muscle fuel.` },
      { q:`During the early fasting state (2-8 hours), blood glucose is maintained primarily by:`, ch:[`Hepatic gluconeogenesis from scratch`,`Hepatic glycogenolysis`,`Renal gluconeogenesis`,`Muscle glycogenolysis`], ans:1, exp:`Early fasting: glucagon rises → activates hepatic glycogenolysis (phosphorylase a) → glucose release. Liver glycogen (limited ~100g, lasts ~12-24h) is the first-line glucose source. Gluconeogenesis increases progressively. Muscle glycogen cannot contribute (no G6Pase).` },
      { q:`Transition from glycolysis to gluconeogenesis in the liver is coordinated by:`, ch:[`Allosteric activation of all the same enzymes`,`Reciprocal regulation: glucagon/cAMP/PKA activates gluconeogenesis-specific enzymes and inactivates glycolytic enzymes simultaneously`,`Increased glucose uptake by the liver`,`Transcription of new enzymes within minutes`], ans:1, exp:`Glucagon → PKA → (1) inactivates PFK-2 (lowers F2,6BP → PFK-1 less active → glycolysis down); (2) inactivates pyruvate kinase → PEP diverted to gluconeogenesis; (3) activates PEPCK/G6Pase via CREB. Insulin does the opposite through PP2A and Akt.` },
      { q:`During prolonged fasting (>48 hours), the brain adapts by using:`, ch:[`Only glucose`,`Ketone bodies (acetoacetate and beta-hydroxybutyrate) for up to 75% of fuel needs, reducing glucose demand`,`Fatty acids directly`,`Amino acids directly`], ans:1, exp:`Brain normally requires glucose (cannot use FFA — can't cross BBB). During prolonged starvation, brain adapts to ketone bodies via MCT1 at the BBB. This reduces glucose demand from ~120 to ~40 g/day → reduces gluconeogenesis → spares muscle protein. Critical survival adaptation.` },
      { q:`GIP and GLP-1 are incretin hormones. Their role in the fed state is:`, ch:[`Inhibiting insulin secretion`,`Potentiating glucose-stimulated insulin secretion from pancreatic beta cells (the incretin effect)`,`Stimulating glucagon release`,`Activating hepatic glycogenolysis`], ans:1, exp:`Incretins (GIP from K cells, GLP-1 from L cells) are released in response to fat and carbohydrate → amplify glucose-stimulated insulin secretion ~2-3 fold. GLP-1 also slows gastric emptying. DPP-4 inhibitors and GLP-1 receptor agonists (semaglutide) exploit this pathway for T2DM treatment.` },
      { q:`The Cori cycle functions to:`, ch:[`Provide lactate as a direct muscle fuel`,`Transfer reducing equivalents from muscle to liver`,`Convert muscle-derived lactate to glucose in the liver (gluconeogenesis), returning glucose to muscle — at an ATP cost borne by the liver`,`Produce ketone bodies from lactate`], ans:2, exp:`Cori cycle: anaerobic muscle → lactate → blood → liver → pyruvate → gluconeogenesis → glucose → blood → muscle. Net: muscle uses 2 ATP/glucose (anaerobic); liver uses 6 ATP to regenerate glucose. The liver subsidizes anaerobic muscle work. Critical during sprinting.` },
      { q:`Hormone-sensitive lipase (HSL) in adipose tissue is activated during fasting by:`, ch:[`Insulin`,`Glucagon/epinephrine → cAMP → PKA → phosphorylates HSL + activates perilipin → TG hydrolysis → FFA + glycerol`,`Malonyl-CoA`,`Insulin receptor tyrosine kinase`], ans:1, exp:`HSL (adipocyte): glucagon + epinephrine → beta-adrenergic receptor → Gs → cAMP → PKA → phosphorylates HSL (+ activates perilipin) → HSL accesses TG → hydrolysis. FFA → albumin-bound in plasma → liver and muscle. Insulin activates phosphodiesterase (lowers cAMP) and protein phosphatase → inactivates HSL.` },
      { q:`AMPK is activated by which metabolic conditions?`, ch:[`High energy charge (high ATP/AMP ratio)`,`Low energy charge (low ATP, high AMP) — exercise, fasting, metformin → phosphorylates ACC (inhibits FA synthesis), activates FA oxidation, inhibits mTOR`,`High insulin levels`,`Fed state with glucose abundance`], ans:1, exp:`AMPK: activated when AMP/ATP ratio rises (ATP depletion during exercise, hypoxia, fasting). AMP binds gamma subunit → LKB1 phosphorylation → AMPK active → phosphorylates: ACC (inactivates → less malonyl-CoA → more FA oxidation), TSC2 (inhibits mTOR → less anabolism), HMGCR (less cholesterol synthesis). Metformin activates AMPK via complex I inhibition.` },
      { q:`mTORC1 integrates:`, ch:[`Only exercise signals`,`Nutrient availability (amino acids, glucose), growth factors (insulin/IGF-1), and energy status to coordinate protein synthesis, autophagy, and cell growth`,`Only stress signals`,`Only oxygen availability`], ans:1, exp:`mTORC1: activated by amino acids (sensed by Rag GTPases), insulin/IGF-1 (PI3K-AKT-TSC pathway), and high energy (AMPK opposes). Active mTORC1 → phosphorylates S6K1 and 4E-BP1 → promotes protein synthesis and ribosome biogenesis. Inhibits autophagy. Rapamycin inhibits mTORC1.` },
      { q:`Gluconeogenesis is regulated at which unique steps (not shared with glycolysis)?`, ch:[`All 10 steps of glycolysis (they simply run in reverse)`,`PC (pyruvate→OAA), PEPCK (OAA→PEP), FBPase-1 (F1,6BP→F6P), G6Pase (G6P→glucose)`,`Only at the glucose-6-phosphatase step`,`Only at the pyruvate carboxylase step`], ans:1, exp:`Gluconeogenesis bypasses the three irreversible glycolytic steps with four unique enzymes: (1) PC (pyruvate→OAA, biotin, mitochondria); (2) PEPCK (OAA→PEP); (3) FBPase-1 (inhibited by AMP, F2,6BP); (4) G6Pase (liver/kidney only). Regulation at these steps controls gluconeogenesis flux.` },
      { q:`Insulin suppresses hepatic glucose production by:`, ch:[`Directly inhibiting G6Pase catalytic activity`,`Akt phosphorylates and excludes FOXO1 from the nucleus → reduced PEPCK and G6Pase transcription; also increases F2,6BP → inhibits FBPase-1`,`Stimulating glucagon secretion`,`Increasing liver uptake of glucagon`], ans:1, exp:`Insulin → IR → PI3K → PIP3 → PDK1 → Akt → FOXO1 phosphorylation → nuclear exclusion → reduced PEPCK/G6Pase gene expression. Akt also suppresses gluconeogenesis at multiple levels. Multiple mechanisms converge to suppress hepatic glucose output.` },
      { q:`During the absorptive (fed) state, which metabolic processes are active in the liver?`, ch:[`Glycogenolysis and gluconeogenesis only`,`Glycogen synthesis, lipogenesis, VLDL assembly and secretion, and glycolysis`,`Beta-oxidation and ketogenesis`,`Urea cycle is off in the fed state`], ans:1, exp:`Fed liver: high portal glucose/insulin → glycolysis → pyruvate → acetyl-CoA → FA synthesis → TG → VLDL secretion; glycogen synthesis; cholesterol synthesis. Gluconeogenesis, beta-oxidation, and ketogenesis are all suppressed by high insulin/low glucagon.` },
      { q:`Why does alcohol (ethanol) metabolism in the liver cause hypoglycemia?`, ch:[`Ethanol activates glycogen phosphorylase`,`Ethanol metabolism → excess NADH → inhibits gluconeogenesis (NADH shifts OAA → malate, pyruvate → lactate) and promotes fat accumulation`,`Ethanol inhibits insulin secretion`,`Ethanol activates GLUT2 in beta cells`], ans:1, exp:`Alcohol → alcohol dehydrogenase + ALDH → excess NADH: (1) NADH/NAD+ high → OAA reduced to malate; lactate accumulates → OAA and pyruvate depleted → gluconeogenesis blocked → hypoglycemia (especially on empty stomach); (2) excess acetyl-CoA + NADH → fat synthesis → alcoholic fatty liver (steatosis).` },
    ]
  },
  {
    id:'bb42', cat:'Bio/Biochem', title:'GPCR, RTK & JAK-STAT Signaling', diff:'Hard',
    qs:[
      { q:`G protein-coupled receptors (GPCRs) activate G proteins when:`, ch:[`Intracellular kinase domain is phosphorylated`,`Ligand binding → receptor conformation change → GDP→GTP exchange on the Gα subunit`,`The receptor translocates to the nucleus`,`Ligand binding opens an ion channel`], ans:1, exp:`GPCRs (7-transmembrane receptors): ligand binds → receptor conformation changes → acts as GEF on Gα → GDP replaced by GTP → Gα-GTP and Gβγ dimer dissociate and activate effectors. Gα intrinsic GTPase terminates signaling. Gα-GDP reassociates with Gβγ.` },
      { q:`Gs-coupled receptors activate:`, ch:[`Phospholipase C → IP3/DAG`,`Adenylate cyclase → cAMP → PKA`,`Rho GTPase`,`Ion channels directly`], ans:1, exp:`Gαs activates adenylate cyclase → cAMP → PKA → phosphorylates many substrates (glycogen phosphorylase kinase, HSL, CREB, etc.). Examples of Gs-coupled receptors: beta-adrenergic (catecholamines), glucagon, PTH, TSH, histamine H2, vasopressin V2. Cholera toxin ADP-ribosylates Gαs → constitutively active.` },
      { q:`Gq-coupled receptors activate:`, ch:[`Adenylate cyclase`,`Phospholipase C-beta → PIP2 hydrolysis → IP3 (ER Ca2+ release) + DAG (activates PKC)`,`Phosphodiesterase (reducing cAMP)`,`Potassium channels (hyperpolarization)`], ans:1, exp:`Gαq activates PLC-beta → PIP2 → IP3 + DAG. IP3 → IP3 receptor on ER → Ca2+ release. DAG + Ca2+ → PKC activation. Examples: alpha1-adrenergic, M1/M3 muscarinic, H1 histamine, AT1 (angiotensin II), V1 (vasopressin), thrombin (PAR1), endothelin.` },
      { q:`Receptor tyrosine kinases (RTKs) are activated by:`, ch:[`Ligand-induced dimerization → transautophosphorylation of intracellular kinase domains → phosphotyrosine residues recruit SH2-domain-containing adaptor proteins`,`Ligand binding → direct activation of adenylate cyclase`,`Ligand binding → nuclear translocation`,`Ligand binding → opening an ion channel`], ans:0, exp:`RTK activation: ligand (EGF, insulin, PDGF, VEGF) → receptor dimerization → transautophosphorylation of cytoplasmic kinase domains → pTyr docking sites → recruit SH2-domain adaptors (GRB2, SHC, PI3K p85) → activate downstream cascades: Ras-MAPK (growth), PI3K-Akt (survival/metabolism).` },
      { q:`The Ras-MAPK pathway leads to:`, ch:[`Rapid glycogen breakdown`,`Gene transcription changes promoting cell growth and proliferation (via ELK1, c-Fos, c-Jun → AP-1)`,`Insulin-stimulated glucose uptake`,`Apoptosis under all conditions`], ans:1, exp:`Ras-MAPK: RTK → GRB2-SOS (GEF) → Ras-GTP → Raf → MEK → ERK1/2 → nucleus → phosphorylates TFs (ELK1 → c-Fos, c-Jun → AP-1 → proliferation genes). Oncogenic RAS mutations (constitutively active) are in ~30% of human cancers (KRAS in colorectal, pancreatic, lung).` },
      { q:`PI3K-Akt-mTOR pathway activated by insulin/IGF-1 promotes:`, ch:[`Apoptosis`,`Cell survival, growth, and metabolism: Akt phosphorylates BAD (pro-survival), FOXO1 (suppresses gluconeogenesis), TSC2 (activates mTOR → protein synthesis), GSK3 (inhibits → glycogen synthesis)`,`Inhibits glucose uptake`,`Blocks protein synthesis by inhibiting mTOR`], ans:1, exp:`PI3K-Akt: RTK → PI3K → PIP3 → PDK1+TORC2 → Akt (Ser/Thr kinase) → phosphorylates BAD (apoptosis suppressed); FOXO1 (nuclear exclusion); GSK3 (inhibited → glycogen synthase active); mTOR activator (TSC2 inactivated → Rheb active → mTORC1). PTEN opposes PI3K (PIP3→PIP2 phosphatase).` },
      { q:`The JAK-STAT pathway is used by:`, ch:[`GPCRs for rapid responses`,`Cytokine receptors (lacking intrinsic kinase activity) — JAKs constitutively associated with receptor → activated by dimerization → phosphorylate receptor and STAT proteins → STAT dimers enter nucleus`,`RTKs directly`,`Steroid hormone receptors`], ans:1, exp:`JAK-STAT: cytokine receptor dimerization → JAK1/2/3/TYK2 transphosphorylate each other and receptor → STAT proteins dock via SH2 domain → JAK phosphorylates STAT → STAT dimers → nucleus → target gene transcription. Used by: IFN-alpha/beta/gamma, IL-2/4/6/7/12, EPO, growth hormone, prolactin. Ruxolitinib inhibits JAK2.` },
      { q:`cAMP is degraded by:`, ch:[`Adenylate cyclase (reverse reaction)`,`Cyclic nucleotide phosphodiesterases (PDEs) → 5'-AMP; inhibited by caffeine/theophylline`,`Protein kinase A`,`GPCR kinases (GRKs)`], ans:1, exp:`PDEs hydrolyze cAMP → 5'-AMP and cGMP → 5'-GMP. Methylxanthines (caffeine, theophylline) inhibit PDEs → elevated cAMP/cGMP → bronchodilation, cardiac stimulation. PDE5 inhibitors (sildenafil, tadalafil) elevate cGMP in smooth muscle → vasodilation.` },
      { q:`GPCR desensitization occurs by:`, ch:[`Permanent dissociation of the G protein`,`GRK phosphorylation of agonist-occupied receptor → beta-arrestin binding → receptor uncoupled from G protein → internalized`,`Degradation of all G proteins`,`Upregulation of phosphodiesterase only`], ans:1, exp:`Homologous desensitization: GRK2/3 phosphorylate agonist-occupied GPCR → beta-arrestin binds → blocks G protein coupling + clathrin-mediated endocytosis. Receptor recycled (resensitization) or degraded. Heterologous desensitization: PKA/PKC phosphorylate receptors regardless of occupancy.` },
      { q:`The second messenger cGMP is produced by:`, ch:[`Adenylate cyclase`,`Guanylate cyclase — activated by ANP (receptor GC) or NO (soluble GC) → cGMP → PKG activation`,`Phospholipase C`,`Cyclic nucleotide PDEs`], ans:1, exp:`cGMP production: receptor guanylate cyclase (ANP → NPR-A → cGMP → PKG → vasodilation, natriuresis); soluble guanylate cyclase (NO → sGC → cGMP → PKG → smooth muscle relaxation → vasodilation, penile erection). Sildenafil (PDE5 inhibitor) increases cGMP in smooth muscle.` },
      { q:`EGFR mutations in lung cancer are clinically important because:`, ch:[`They prevent EGFR dimerization`,`Activating EGFR mutations cause constitutively active RTK → permanent Ras-MAPK + PI3K-Akt → uncontrolled proliferation; EGFR inhibitors (erlotinib, osimertinib) are targeted therapies`,`They cause GPCR overexpression`,`They prevent cytokine signaling`], ans:1, exp:`Activating EGFR mutations in NSCLC (~15-20% Western, ~50% East Asian) → constitutively active tyrosine kinase → continuous growth signaling. EGFR TKIs (erlotinib, gefitinib, osimertinib) are first-line therapy in EGFR-mutant NSCLC. T790M resistance mutation is addressed by 3rd-generation osimertinib.` },
      { q:`Cross-talk between GPCR and RTK signaling occurs because:`, ch:[`Both pathways always have identical outcomes`,`Both pathways converge on shared downstream effectors (Ras, ERK, PI3K, PKC) allowing integration of multiple extracellular signals`,`There is no cross-talk between these pathways`,`GPCRs activate RTK directly`], ans:1, exp:`Signaling cross-talk: beta-arrestin (GPCR desensitization) also activates ERK (alternative signaling). Gbg can activate PI3K. PKC (from Gq) can modulate RTK activity. Ras is activated by some GPCRs. Shared effectors integrate diverse inputs into coherent cellular responses.` },
      { q:`STAT3 is constitutively activated in many cancers because:`, ch:[`Cytokine receptors are absent in cancer`,`Gain-of-function JAK2 mutations or autocrine cytokine loops keep STAT3 phosphorylated → continuous transcription of BCL-2, c-Myc, VEGF`,`STAT3 is normally activated by steroids`,`STAT3 promotes apoptosis`], ans:1, exp:`Constitutively active STAT3 (in multiple myeloma, glioblastoma, breast cancer): promotes transcription of BCL-xL, MCL-1 (anti-apoptotic), c-Myc, cyclin D1 (proliferation), VEGF (angiogenesis). JAK2 V617F mutation activates STAT3/5 in myeloproliferative neoplasms. Ruxolitinib (JAK1/2 inhibitor) approved for myelofibrosis.` },
      { q:`Heterotrimeric G proteins return to the inactive state when:`, ch:[`The ligand remains bound to the receptor`,`Gα's intrinsic GTPase activity hydrolyzes GTP → GDP; Gα-GDP reassociates with Gβγ → inactive heterotrimer; accelerated by RGS proteins`,`Beta-arrestin degrades G proteins`,`The receptor is internalized`], ans:1, exp:`G protein inactivation: Gα intrinsic GTPase (slow) → GTP → GDP; Gα-GDP + Gβγ → inactive heterotrimer. RGS proteins (GAPs) accelerate Gα GTP hydrolysis → faster signal termination. Pertussis toxin ADP-ribosylates Gαi → prevents activation → whooping cough mechanism.` },
    ]
  },
  {
    id:'bb43', cat:'Bio/Biochem', title:'Eukaryotic Gene Regulation', diff:'Hard',
    qs:[
      { q:`Transcription factors activate gene expression by:`, ch:[`Directly methylating DNA`,`Binding enhancer/promoter sequences and recruiting coactivators (Mediator, HATs, chromatin remodelers) enabling RNAP II to initiate transcription`,`Synthesizing mRNA directly`,`Inhibiting DNA methylation only`], ans:1, exp:`Activating TFs bind specific DNA sequences (via DBDs) and recruit coactivators: Mediator (bridges TF to RNAP II), HATs (acetylate histones → open chromatin), chromatin remodelers (displace nucleosomes). These create a permissive chromatin environment and stabilize the RNAP II pre-initiation complex.` },
      { q:`CpG islands in promoters are:`, ch:[`Regions methylated in all active genes`,`GC-rich regions (CG dinucleotides) in promoters; unmethylated = active, methylated = silenced`,`Sites of TATA box sequences only`,`Regions exclusive to enhancers`], ans:1, exp:`CpG islands (regions of high CG dinucleotide frequency): normally unmethylated (active genes); methylation by DNMTs → recruitment of MBD proteins → HDAC recruitment → chromatin compaction → transcriptional silencing. Aberrant CpG island hypermethylation silences tumor suppressors in cancer (p16, MLH1, BRCA1).` },
      { q:`PRC2 silences genes by:`, ch:[`Acetylating H3K27`,`Trimethylating H3K27 (H3K27me3) → recruitment of PRC1 → chromatin compaction → repression of developmental genes`,`Methylating DNA directly`,`Degrading TF mRNAs`], ans:1, exp:`PRC2 (EZH2 catalytic subunit): catalyzes H3K27me3 → PRC1 reads H3K27me3 → ubiquitinates H2AK119 → chromatin compaction → transcriptional repression. Polycomb targets: Hox genes, developmental regulators. EZH2 is overexpressed/mutated in many cancers; tazemetostat (EZH2 inhibitor) is approved for follicular lymphoma.` },
      { q:`Super-enhancers are:`, ch:[`Large clusters of multiple enhancer elements with extremely high TF occupancy that drive high-level expression of key cell identity genes`,`Identical to typical enhancers but twice the size`,`Found only in cancer cells`,`Promoter-proximal sequences only`], ans:0, exp:`Super-enhancers: large (~10-50 kb) clusters of enhancers with very high levels of Mediator, BRD4 (H3K27ac reader), H3K27ac. They control master TFs of cell identity (e.g., MYC). Cancer cells often acquire new super-enhancers near oncogenes. BET bromodomain inhibitors (JQ1) disrupt super-enhancer activity.` },
      { q:`Cohesin and CTCF are important for:`, ch:[`Histone modification directly`,`Organizing the genome into topologically associating domains (TADs) and facilitating chromatin looping between enhancers and promoters`,`Recruiting RNA polymerase to promoters`,`DNA methylation in CpG islands`], ans:1, exp:`CTCF binds CCCTC sequences, organizes chromatin loops and boundaries between TADs (topologically associating domains). Cohesin physically holds chromatin loops together. TAD boundaries constrain enhancer-promoter interactions, preventing inappropriate cross-domain regulatory crosstalk.` },
      { q:`RNAP II pausing is released by:`, ch:[`TFIID binding`,`P-TEFb (CDK9/cyclin T1) phosphorylating RNAP II CTD Ser2, DSIF, and NELF → releasing paused RNAP into productive elongation`,`TFIIH at initiation`,`Nucleosome eviction alone`], ans:1, exp:`After promoter escape, RNAP II often pauses 30-60 bp downstream (NELF + DSIF promote pausing). Release requires P-TEFb (CDK9/cyclin T1): CDK9 phosphorylates CTD Ser2 (elongation mark), DSIF (converts to elongation-compatible), and NELF (releases). BRD4 displaces P-TEFb from the 7SK snRNP complex for activation.` },
      { q:`Nuclear receptor corepressors (NCoR, SMRT) maintain genes in a silenced state by:`, ch:[`Recruiting HATs to promoters`,`Binding unliganded nuclear receptors and recruiting HDACs → histone deacetylation → chromatin compaction → transcriptional repression`,`Methylating DNA`,`Competing with activating TFs`], ans:1, exp:`Unliganded nuclear receptors (TR, RAR, RXR, Rev-erb) recruit NCoR/SMRT corepressor complexes → HDAC3 → H3/H4 deacetylation → chromatin compaction → repression. Ligand binding (T3, retinoic acid) → corepressor dismissed, coactivator recruited (SRC-1, CBP/p300 with HAT activity) → derepression and activation.` },
      { q:`In the absence of Wnt signaling, beta-catenin is:`, ch:[`Active in the nucleus`,`Phosphorylated by the APC/Axin/GSK3/CK1 destruction complex → ubiquitinated by beta-TrCP → proteasomally degraded`,`Constitutively nuclear`,`Bound to Frizzled receptor`], ans:1, exp:`Without Wnt: APC-Axin-GSK3beta-CK1 complex phosphorylates beta-catenin → beta-TrCP ubiquitin ligase → proteasomal degradation → TCF/LEF binds Groucho (repressor). With Wnt: LRP5/6 + Frizzled → Dishevelled → inactivates destruction complex → beta-catenin accumulates → nucleus → activates Myc, cyclin D1.` },
      { q:`p53 is described as the "guardian of the genome" because:`, ch:[`It repairs DNA directly`,`It is activated by DNA damage and other stresses → acts as a TF to induce cell cycle arrest (p21), apoptosis (BAX, PUMA), or senescence → prevents propagation of damaged DNA`,`It is constitutively active in normal cells`,`It only functions in hematopoietic cells`], ans:1, exp:`p53 (TP53): activated by DNA damage (ATM/ATR → CHK1/2 → MDM2 phosphorylation → p53 stabilized). As TF, p53 activates: p21 (CDK inhibitor → G1 arrest); GADD45 (G2/M arrest); BAX, PUMA, NOXA (apoptosis); TIGAR (antioxidant). MDM2 (E3 ubiquitin ligase) normally degrades p53; MDM2 overexpression in sarcomas inactivates p53.` },
      { q:`lncRNAs such as XIST and HOTAIR regulate gene expression by:`, ch:[`Acting as templates for protein translation`,`Serving as scaffolds for chromatin-modifying complexes (XIST coats Xi → X-inactivation; HOTAIR scaffolds PRC2 + LSD1 to specific loci)`,`Acting as microRNA precursors only`,`Binding mRNA in the cytoplasm only`], ans:1, exp:`lncRNAs (>200 nt, not translated): XIST coats the inactive X chromosome → recruits PRC2 (H3K27me3) → X-inactivation (dosage compensation). HOTAIR: scaffold for PRC2 + LSD1 → HoxD silencing; overexpressed in many cancers → invasion/metastasis.` },
      { q:`Nucleosome positioning affects gene expression because:`, ch:[`Nucleosomes increase gene expression by stabilizing the promoter`,`Nucleosomes occlude TF binding sites; eviction or repositioning at promoters (creating NFRs) is required for TF binding and transcription initiation`,`Nucleosomes only regulate histone H1`,`Nucleosomes have no effect on gene regulation`], ans:1, exp:`Nucleosome-free regions (NFRs) at active promoters and enhancers are required for TF and RNAP II access. ATAC-seq and DNase I-seq map accessible chromatin (NFRs). Chromatin remodelers (SWI/SNF, ISWI, CHD) reposition nucleosomes to control access.` },
      { q:`The Mediator complex functions as:`, ch:[`A DNA repair complex`,`A large ~30-subunit complex that bridges sequence-specific TFs bound at enhancers to the RNAP II pre-initiation complex at the promoter`,`A histone methyltransferase`,`The RNAP II holoenzyme core`], ans:1, exp:`Mediator: ~1.2 MDa complex of ~30 subunits. Tail module interacts with TFs; head module interacts with RNAP II; CDK8 kinase module regulates. Mediator is required for transcriptional activation by most TFs. The CDK8 kinase module is a proto-oncogene (amplified in colorectal cancer).` },
      { q:`Epigenetic inheritance through cell division involves:`, ch:[`DNA mutations being passed to daughter cells`,`Propagation of chromatin states; DNMT1 (maintenance methyltransferase) remethylates hemimethylated CpGs post-replication`,`All histone modifications being reset after mitosis`,`Gene expression patterns cannot be inherited`], ans:1, exp:`Epigenetic inheritance: DNMT1 (with UHRF1) recognizes hemimethylated CpG after DNA replication → methylates the newly synthesized strand → faithful propagation. Histone marks (H3K9me3, H3K27me3) are propagated by positive feedback (HP1 recruits SUV39H to neighboring nucleosomes; PRC self-renewal at PRE sites).` },
    ]
  },
  {
    id:'bb44', cat:'Bio/Biochem', title:'mRNA Processing & Splicing', diff:'Hard',
    qs:[
      { q:`The branch point sequence in pre-mRNA splicing contains an adenosine that:`, ch:[`Binds the exonic splicing enhancer`,`Attacks the 5' splice site in the first transesterification reaction (via 2'-OH), forming a lariat intermediate`,`Marks the polypyrimidine tract`,`Starts the GU dinucleotide`], ans:1, exp:`Splicing mechanism: Step 1: Branch point 2'-OH of adenosine (within intron) attacks the 5' splice site → 2'-5' phosphodiester bond → lariat + free 5' exon 3'-OH. Step 2: 3'-OH of free 5' exon attacks the 3' splice site → exon ligation + lariat release. The branch point is always an A residue.` },
      { q:`The five snRNPs of the major spliceosome are:`, ch:[`U1, U2, U3, U4, U5`,`U1, U2, U4, U5, U6`,`U1, U2, U4, U6, U7`,`U1, U3, U4, U5, U6`], ans:1, exp:`Five snRNPs of the major (U2-type) spliceosome: U1 (recognizes 5' splice site GU); U2 (recognizes branch point A); U4/U6 (di-snRNP, U6 is the catalytic RNA); U5 (bridges exons). U4 is unwound from U6 during spliceosome activation → U6 forms the catalytic core.` },
      { q:`SR proteins bind exonic splicing enhancers (ESEs) and:`, ch:[`Block splicing`,`Recruit U1 snRNP (5' splice site) and U2AF (3' splice site) → promote exon inclusion`,`Determine intron length`,`Methylate pre-mRNA`], ans:1, exp:`SR proteins (serine/arginine-rich, e.g., SRSF1-12) bind ESEs → recruit U1 snRNP and U2AF → promote exon inclusion. HnRNP proteins bind ESSs/ISSs → sterically block splice site recognition → exon skipping. Tissue-specific splicing factors (NOVA, RBFOX, nSR100) control neural alternative splicing.` },
      { q:`Nonsense-mediated decay (NMD) is a surveillance mechanism that:`, ch:[`Degrades all mRNAs without a poly(A) tail`,`Recognizes and degrades mRNAs with premature termination codons (PTCs, >50-55 nt upstream of an exon-junction complex)`,`Edits adenosine to inosine in mRNA`,`Prevents translation of incorrectly spliced mRNAs in the nucleus`], ans:1, exp:`NMD: if a ribosome encounters a stop codon >50-55 nt upstream of an exon-junction complex (EJC, deposited at exon-exon junctions after splicing), the mRNA is degraded. Key proteins: UPF1 + UPF2 + UPF3 (at EJC). NMD degrades ~10-33% of normal mRNAs (regulatory role), not just aberrant ones.` },
      { q:`Which of the following is NOT a function of the 5' m7G cap?`, ch:[`Protection from 5' exonucleases`,`Ribosome recognition (cap-dependent translation via eIF4E)`,`Promotion of splicing`,`Adding the poly(A) tail to the 3' end`], ans:3, exp:`5' cap functions: (1) protects from 5' exonucleases; (2) recognized by eIF4E → cap-dependent translation; (3) promotes pre-mRNA splicing (stimulates U1 snRNP via CBC). The poly(A) tail is added at the 3' end by poly(A) polymerase after cleavage at the poly(A) signal — unrelated to 5' capping.` },
      { q:`RNA editing in mammals includes:`, ch:[`Changing G to A in all mRNAs`,`A-to-I editing (ADAR enzymes) and C-to-U editing (APOBEC enzymes) that change codons and alter function`,`Adding methyl groups to adenosine (m6A) only`,`Removing introns post-translationally`], ans:1, exp:`A-to-I editing: ADAR1/2 convert adenosine → inosine (read as G). Important examples: GluR-B (Q→R editing, prevents Ca2+ entry); ALU elements. C-to-U: APOBEC1 edits ApoB mRNA codon 2153 → stop codon → ApoB-48 in intestine. m6A (by METTL3) is a major modification affecting mRNA stability and translation.` },
      { q:`U1 snRNA recognizes the 5' splice site by:`, ch:[`Protein-protein interactions only`,`Base-pairing between the 5' end of U1 snRNA and the 5' splice site consensus sequence (GU at the intron start)`,`Binding the polypyrimidine tract`,`Forming the branch point`], ans:1, exp:`U1 snRNP: the 5' end of U1 snRNA base-pairs with the 5' splice site (GU|AAGU... where | is the exon-intron boundary). This base-pairing is the initial recognition event in spliceosome assembly (E complex). The consensus 5' splice site is exon/GURAGU (R=purine).` },
      { q:`Polyadenylation signal (AAUAAA) mutations cause:`, ch:[`Defective 5' capping`,`Defective 3' cleavage and polyadenylation → read-through transcription, unstable mRNA → reduced gene expression`,`Defective splicing`,`Defective nuclear export only`], ans:1, exp:`Poly(A) signal (AAUAAA): recognized by CPSF. CPSF + CstF (at downstream GU/U-rich element) recruit CPSF73 (endonuclease) → pre-mRNA cleavage → poly(A) polymerase adds ~200 A residues. AAUAAA mutations → no polyadenylation → unstable mRNA. Clinically: thalassemia mutations in HBB poly(A) signal.` },
      { q:`Circular RNAs (circRNAs) are produced by:`, ch:[`Alternative polyadenylation`,`Back-splicing — a downstream 5' splice donor is joined to an upstream 3' splice acceptor, producing a covalently closed circular RNA that resists exonucleases`,`CRISPR editing of mRNAs`,`Reverse transcription of mRNAs`], ans:1, exp:`CircRNA biogenesis: back-splicing (head-to-tail splicing) involves a downstream 5' splice site joining an upstream 3' splice site. The resulting circRNA lacks free 3'-OH → resists exonucleases (more stable than linear mRNA). CircRNAs can sponge miRNAs (CDR1as sponges miR-7), interact with proteins, and serve as translation templates.` },
      { q:`Phosphorylated SR proteins are:`, ch:[`Inactive for splicing`,`Active in splicing — phosphorylation by SRPK1/2 and CLK/STY kinases allows nuclear localization and spliceosome assembly`,`Localized to the cytoplasm permanently`,`Bind hnRNPs and block splicing`], ans:1, exp:`SR protein activity cycle: SRPK1/2 (in cytoplasm) phosphorylate SR proteins → nuclear import; nuclear CLK1/CLK2 further phosphorylate → active for splicing. During catalysis, PP1 dephosphorylates SR proteins. Kinase/phosphatase balance governs splicing decisions.` },
      { q:`The nucleolus is the site of:`, ch:[`mRNA splicing`,`rRNA transcription (by RNAP I), pre-rRNA processing, and ribosome subunit assembly`,`snRNA synthesis`,`tRNA maturation only`], ans:1, exp:`Nucleolus = site of rRNA synthesis and ribosome biogenesis. RNAP I transcribes 47S pre-rRNA → processed to 28S, 18S, 5.8S rRNA (by snoRNAs and nucleases). Ribosomal proteins (made in cytoplasm) are imported → assembled with rRNA → pre-ribosomal subunits exported to cytoplasm. Stress disrupts nucleolus → p53 stabilization (ARF-MDM2 pathway).` },
      { q:`MicroRNAs (miRNAs) regulate gene expression by:`, ch:[`Editing mRNA sequence`,`Binding the 3' UTR of target mRNAs via seed sequence complementarity (nts 2-8) → RISC complex (AGO2) → translation repression and/or mRNA deadenylation/decay`,`Recruiting RNAP II to promoters`,`Blocking splicing at 5' splice sites`], ans:1, exp:`miRNA biogenesis: RNAP II → pri-miRNA → DROSHA (nucleus) → pre-miRNA → Exportin-5 → cytoplasm → DICER → ~22 nt miRNA duplex → one strand loaded into RISC (AGO1-4). miRNA seed sequence (nts 2-8) base-pairs with target 3' UTR → translation inhibition + mRNA deadenylation/decay. >60% of human genes have miRNA target sites.` },
      { q:`A mutation at the 5' splice site GU→AU would cause:`, ch:[`Altered polyadenylation`,`Exon skipping or intron retention — the mutant splice site is not recognized by U1 snRNP → alternative splicing, often producing non-functional protein`,`Loss of the cap structure`,`Branch point alteration`], ans:1, exp:`5' splice site GU is required for U1 snRNP base-pairing. GU→AU mutation → U1 snRNP cannot bind → that splice site is not used → consequences: cryptic splice site usage, exon skipping, or intron retention → out-of-frame or truncated protein. Clinically: many splicing mutations in beta-thalassemia affect the beta-globin 5' splice site.` },
    ]
  },
  {
    id:'bb45', cat:'Bio/Biochem', title:'Epigenetics', diff:'Hard',
    qs:[
      { q:`Epigenetics refers to:`, ch:[`Mutations in the DNA sequence`,`Heritable changes in gene expression that do not involve changes to the DNA sequence itself`,`Only histone modifications`,`Post-translational protein modifications`], ans:1, exp:`Epigenetics: changes in gene expression that are heritable through cell division but do not alter the DNA sequence. Mechanisms: DNA methylation, histone modifications (acetylation, methylation, phosphorylation, ubiquitination), chromatin remodeling, non-coding RNA regulation. These create cell-type-specific gene expression patterns.` },
      { q:`DNA methylation at CpG dinucleotides is carried out by:`, ch:[`HATs (histone acetyltransferases)`,`DNMT1 (maintenance), DNMT3A and DNMT3B (de novo) using S-adenosylmethionine (SAM) as the methyl donor`,`TET dioxygenases`,`Histone methyltransferases`], ans:1, exp:`DNMTs (DNA methyltransferases): DNMT3A/3B establish de novo methylation during development; DNMT1 (with UHRF1) maintains methylation after replication (recognizes hemimethylated CpG). SAM provides the methyl group (generating S-adenosylhomocysteine). Folate and B12 deficiency deplete SAM, impairing methylation.` },
      { q:`TET dioxygenases are responsible for:`, ch:[`Adding methyl groups to cytosine`,`Oxidizing 5-methylcytosine (5mC) → 5-hydroxymethylcytosine (5hmC) → further oxidized forms → DNA demethylation`,`Histone acetylation`,`DNMT activation`], ans:1, exp:`TET1/2/3 (alpha-KG and Fe2+-dependent dioxygenases) convert 5mC → 5hmC → 5-formylcytosine → 5-carboxylcytosine. TDG (thymidine DNA glycosylase) removes the oxidized cytosines → BER pathway → unmodified cytosine = active DNA demethylation. IDH1/2 mutations produce 2-HG that inhibits TETs → hypermethylation.` },
      { q:`H3K9me3 is associated with:`, ch:[`Active gene transcription`,`Constitutive heterochromatin (pericentromeric regions), recognized by HP1 (heterochromatin protein 1) → gene silencing`,`Active enhancers`,`Promoters of housekeeping genes`], ans:1, exp:`H3K9me3 (by SUV39H1/H2): hallmark of constitutive heterochromatin (pericentromeric and telomeric regions). HP1 binds H3K9me3 via its chromodomain → recruits more SUV39H (spreading) → stable gene silencing. Also important for genome integrity (silences transposable elements). H3K9me2 marks facultative heterochromatin.` },
      { q:`H3K4me3 vs H3K27me3 bivalent chromatin domains are found in:`, ch:[`Terminally differentiated cells only`,`Embryonic stem cells — bivalent promoters carry both active (H3K4me3) and repressive (H3K27me3) marks, keeping developmental genes poised but not expressed`,`All adult somatic cells`,`Cancer cells only`], ans:1, exp:`Bivalent chromatin: H3K4me3 (active mark, by MLL/SET1) + H3K27me3 (repressive mark, by PRC2) at the same promoter = "poised" state. These are developmental genes that can be rapidly activated or stably repressed upon differentiation. During differentiation, one mark is lost, resolving the bivalent state.` },
      { q:`Genomic imprinting is an epigenetic phenomenon where:`, ch:[`Both alleles of a gene are equally expressed`,`Only one allele is expressed depending on parental origin — methylation patterns are established in the germline and maintained throughout development`,`Random X-inactivation occurs in males`,`All imprinted genes are on the X chromosome`], ans:1, exp:`Genomic imprinting: parent-of-origin-specific gene expression. Differentially methylated regions (DMRs) are established in gametes by DNMT3A/3B/DNMT3L. Examples: IGF2 (paternal expression); H19 (maternal expression); SNRPN (paternal expression — imprinted region on chr15 involved in Prader-Willi/Angelman syndromes). Loss of imprinting (LOI) is found in Wilms tumor, Beckwith-Wiedemann syndrome.` },
      { q:`The bromodomain is a protein module that:`, ch:[`Methylates lysine residues`,`Reads acetylated lysine residues (binds Kac) — recruits chromatin-modifying complexes to acetylated histones at active genes`,`Demethylates DNA`,`Binds methylated cytosine`], ans:1, exp:`Bromodomains (in BRD2, BRD4, CBP/p300, TAF1, etc.) bind acetylated lysine residues on histone tails. BRD4 reads H3K27ac and H4K16ac at enhancers/promoters → recruits P-TEFb → RNA pol II elongation. BET inhibitors (JQ1, OTX015) competitively inhibit bromodomains → disrupt super-enhancer activity → suppress MYC expression in cancers.` },
      { q:`X-inactivation in female mammals is controlled by:`, ch:[`Histone H1 binding to the active X`,`XIST lncRNA (transcribed from the inactive X) coating the Xi → PRC2 recruitment → H3K27me3 → chromatin compaction, plus DNA methylation → stable silencing`,`All X-linked genes being equally expressed in males and females`,`Testosterone-dependent silencing`], ans:1, exp:`X-inactivation (Lyon hypothesis): random in each cell of female embryo (~blastocyst stage); maintained clonally. XIST (X-inactive specific transcript): transcribed from Xi → spreads along Xi → recruits PRC2 → H3K27me3; also recruits DNMTs → CpG methylation. Barr body = cytologically visible condensed Xi. ~15-25% of X-linked genes escape inactivation.` },
      { q:`SIRT1 (sirtuin 1) is a histone deacetylase that is unusual because:`, ch:[`It uses NADH as a cofactor`,`It requires NAD+ as a cofactor (not just a cosubstrate) — links metabolic state (NAD+/NADH ratio) to chromatin regulation`,`It is constitutively active`,`It only modifies non-histone proteins`], ans:1, exp:`SIRT1 (class III HDAC): NAD+-dependent deacetylase (reaction: substrate-Kac + NAD+ → deacetylated substrate + nicotinamide + O-acetyl-ADP-ribose). NAD+ is consumed → SIRT1 activity reflects metabolic state (fasting: high NAD+ → SIRT1 active → deacetylates PGC-1alpha, FOXO1 → metabolic adaptation). Resveratrol was proposed as SIRT1 activator.` },
      { q:`DNMT inhibitors (azacitidine, decitabine) used in cancer therapy work by:`, ch:[`Inhibiting histone deacetylases`,`Incorporating into DNA as cytosine analogs → covalently trapping DNMT1 → passive demethylation → reactivation of silenced tumor suppressor genes`,`Blocking DNA replication completely`,`Inhibiting TET dioxygenases`], ans:1, exp:`5-azacytidine (azacitidine) and 5-aza-2'-deoxycytidine (decitabine): nucleoside analogs incorporated into DNA during replication. When DNMT1 attempts to methylate the analog → covalent bond (DNMT1 trapped) → DNMT1 degradation → passive loss of methylation with each cell division → reactivation of silenced genes (e.g., p15/CDKN2B in MDS). FDA-approved for MDS, AML.` },
      { q:`Which histone modification is associated with DNA double-strand break response?`, ch:[`H3K4me3`,`gamma-H2AX (H2AX phosphorylated on Ser139)`,`H3K27me3`,`H4K16ac`], ans:1, exp:`gamma-H2AX: ATM/ATR kinases phosphorylate the H2AX histone variant on Ser139 → recruits DNA repair proteins (MDC1, NBS1, BRCA1, 53BP1) → forms repair foci visible by microscopy. gamma-H2AX foci are a sensitive marker for DSBs (used in comet assay, radiation biology). Number of foci correlates with DSB burden.` },
      { q:`The concept of "histone code" suggests that:`, ch:[`Only one histone modification matters at a time`,`Specific combinations of histone modifications create distinct binding platforms for regulatory proteins, encoding complex gene expression information beyond a simple on/off switch`,`Histone modifications are read only in the context of DNA sequence`,`All modifications are equivalent in their effects`], ans:1, exp:`Histone code hypothesis (Strahl & Allis 2000): single or combinatorial histone modifications (the "code") are read by effector proteins to specify downstream functions. Active promoter: H3K4me3 + H3K27ac + H4K16ac. Active enhancer: H3K4me1 + H3K27ac. Repressed: H3K27me3 or H3K9me3. Combinations create a regulatory language beyond binary on/off.` },
      { q:`Transgenerational epigenetic inheritance in mammals refers to:`, ch:[`Genetic inheritance through mutations`,`Epigenetic marks surviving reprogramming in the germline and being transmitted to offspring (largely restricted but documented in some cases)`,`DNA methylation patterns being erased completely in each generation`,`Only applicable to plants`], ans:1, exp:`Mammals undergo two waves of epigenetic reprogramming: (1) post-fertilization → global demethylation; (2) in primordial germ cells → demethylation + remethylation. However, some loci (imprinted genes, some retrotransposons) escape reprogramming → potentially transmitted epigenetic information. Evidence in humans: famine studies (Dutch Hunger Winter) suggesting metabolic epigenetic effects transmitted across generations.` },
    ]
  },
  {
    id:'bb46', cat:'Bio/Biochem', title:'DNA Damage & Repair', diff:'Hard',
    qs:[
      { q:`The most lethal DNA lesion is a:`, ch:[`Thymine dimer`,`Double-strand break (DSB) — both strands severed, threatening chromosome integrity and requiring specialized repair (HR or NHEJ)`,`Single-strand nick`,`Deamination of cytosine`], ans:1, exp:`DSBs are the most dangerous DNA lesions: both strands severed → chromosome fragmentation if unrepaired. DSBs are caused by: ionizing radiation, replication fork collapse, endonucleases (including CRISPR). Repair by: NHEJ (fast, error-prone, dominant in G1) or HR (accurate, uses sister chromatid, dominant in S/G2).` },
      { q:`Nucleotide excision repair (NER) is responsible for removing:`, ch:[`Mismatched bases from replication errors`,`Bulky, helix-distorting lesions (UV-induced pyrimidine dimers, chemical adducts) — recognizes distorted helix structure`,`Oxidized bases (e.g., 8-oxoguanine)`,`Deaminated cytosines`], ans:1, exp:`NER: recognizes helix-distorting lesions (CPD and 6-4 photoproducts from UV, chemical adducts from carcinogens). Two sub-pathways: GG-NER (genome-wide, XPC/HR23B) and TC-NER (transcription-coupled, stalled RNAP II recruits CSA/CSB). XPA/RPA/XPB/XPD unwind → XPG and XPF-ERCC1 cut → excise ~25-30 nt patch. Xeroderma pigmentosum: defects in XP proteins.` },
      { q:`Mismatch repair (MMR) corrects:`, ch:[`Bulky adducts`,`Replication errors — mispaired bases and small insertion/deletion loops (IDLs) from replication slippage`,`DSBs`,`UV photoproducts`], ans:1, exp:`MMR: recognizes mismatch or small IDL formed during replication. Key proteins: MSH2-MSH6 (MutSalpha, recognizes mismatches) or MSH2-MSH3 (MutSbeta, recognizes IDLs) → MLH1-PMS2 (MutLalpha) → strand discrimination (via PCNA/RFCleft nick) → exonuclease 1 excises → re-synthesis. Lynch syndrome: MMR gene mutations (MLH1, MSH2, MSH6, PMS2) → microsatellite instability (MSI) → colorectal/endometrial cancer.` },
      { q:`Base excision repair (BER) repairs:`, ch:[`Bulky adducts`,`Small non-helix-distorting base lesions (oxidized bases, alkylated bases, deaminated bases) via DNA glycosylase recognition`,`Mismatched bases from replication errors`,`DSBs`], ans:1, exp:`BER: (1) DNA glycosylase recognizes specific altered base → removes it → AP site (abasic site); (2) APE1 (AP endonuclease) → nick 5' to AP site; (3) Pol beta (short-patch BER) or Pol delta/epsilon (long-patch) fill gap; (4) ligase. Important substrates: 8-oxoguanine (OGG1), uracil (UNG), 3-methyladenine (MPG). PARP1 is critical for BER (activated by single-strand breaks).` },
      { q:`Homologous recombination (HR) uses the sister chromatid as a template for accurate DSB repair. HR requires:`, ch:[`The cell to be in G1 phase`,`S/G2 phase (sister chromatid available); key proteins: BRCA1, BRCA2 (loads RAD51), RAD51 (strand invasion), RPA, BRCA1/PALB2/BRCA2 complex`,`Only NHEJ proteins`,`No homologous template`], ans:1, exp:`HR: DSB resection by MRN complex + CtIP → ssDNA → RPA binding → BRCA2 (with PALB2/BRCA1) loads RAD51 → RAD51-ssDNA filament invades sister chromatid → D-loop → DNA synthesis using sister as template → accurate repair. HR is restricted to S/G2 (CDK-dependent CtIP activation). BRCA1/BRCA2 mutations → HR deficiency → PARP inhibitor sensitivity (synthetic lethality).` },
      { q:`Non-homologous end joining (NHEJ) is:`, ch:[`Accurate repair using a template`,`Error-prone, fast repair of DSBs without a template: Ku70/Ku80 bind broken ends → DNA-PKcs → ARTEMIS → ligase IV/XRCC4 → join ends (often with small deletions)`,`Active only in S/G2 phase`,`Dependent on BRCA2`], ans:1, exp:`NHEJ: Ku70/Ku80 heterodimer binds broken ends → recruits DNA-PKcs (phosphorylates H2AX, XRCC4) → ARTEMIS exonuclease trims ends → Pol mu/lambda fill gaps → XLF/XRCC4/ligase IV join. Often introduces small deletions/insertions (indels). Dominant in G1. Immunoglobulin V(D)J recombination uses NHEJ. NHEJ deficiency → radiosensitivity, immunodeficiency (e.g., LIG4 syndrome).` },
      { q:`PARP inhibitors (olaparib, rucaparib) are effective against BRCA1/2-mutant tumors due to:`, ch:[`Directly inhibiting BRCA1/2`,`Synthetic lethality: PARP inhibition traps PARP1 on single-strand breaks → SSBs persist → become DSBs during replication → in HR-deficient cells (BRCA1/2 mutant), DSBs cannot be repaired → cell death`,`Inhibiting DNA replication`,`Activating p53`], ans:1, exp:`Synthetic lethality: normal cells lose PARP1 → use BER backup. BRCA1/2-mutant cells have deficient HR; when PARP is also inhibited → accumulated DSBs cannot be repaired by HR → tumor cells die. Normal cells survive (functional HR). PARP inhibitors (olaparib, rucaparib, niraparib) approved for BRCA1/2-mutant ovarian, breast, prostate, and pancreatic cancers.` },
      { q:`Fanconi anemia (FA) is caused by defects in:`, ch:[`NER pathway proteins`,`The FA pathway (20+ FANC proteins) that repairs interstrand crosslinks (ICLs) — lesions that covalently link both DNA strands, blocking replication`,`BER proteins`,`Mismatch repair proteins`], ans:1, exp:`FA: defects in FA pathway (FANCA, FANCB, FANCC, FANCD2, etc.) → failure to repair interstrand crosslinks (ICLs from chemotherapeutic agents — cisplatin, mitomycin C, endogenous aldehydes). FA cells are hypersensitive to these agents. FA core complex → FANCI-FANCD2 monoubiquitination → recruitment of NER/HR proteins → ICL unhooking + repair. FA: congenital aplastic anemia, cancer predisposition.` },
      { q:`ATM kinase is activated by:`, ch:[`Single-strand DNA breaks`,`DSBs — ATM is recruited by the MRN complex (MRE11-RAD50-NBS1) to DSB sites → autophosphorylation → activation → phosphorylates H2AX, CHK2, p53, BRCA1`,`UV light directly`,`Mismatch repair intermediates`], ans:1, exp:`ATM (ataxia-telangiectasia mutated): activated by DSBs via MRN complex. Key ATM substrates: H2AX (Ser139 → gamma-H2AX, repair focus formation); CHK2 (Thr68 → active → phosphorylates CDC25A → G1 arrest); p53 (Ser15 → stabilization → cell cycle arrest/apoptosis); BRCA1 (activates HR). Ataxia-telangiectasia: AT kinase mutations → cerebellar ataxia, telangiectasias, radiation hypersensitivity, lymphoma.` },
      { q:`Translesion synthesis (TLS) polymerases are used to:`, ch:[`Repair damaged bases`,`Bypass unrepaired DNA lesions (bypass polymerization) — low-fidelity, error-prone polymerases (pol eta, pol iota, pol kappa, Rev1) allow replication to proceed past lesions`,`Provide high-fidelity backup for pol delta`,`Repair DSBs`], ans:1, exp:`TLS polymerases (Y-family: pol eta, pol iota, pol kappa; B-family: pol zeta/Rev3): lack proofreading exonuclease → low fidelity. Activated when replication stalls at lesions → PCNA monoubiquitination → recruits TLS pols. Pol eta: correctly inserts AA opposite T-T dimers (xeroderma pigmentosum variant = pol eta deficiency → skin cancer). TLS is mutagenic but prevents lethal replication fork collapse.` },
      { q:`O6-methylguanine DNA methyltransferase (MGMT) repairs:`, ch:[`UV photoproducts`,`Alkylation of guanine at O6 position (by temozolomide, CCNU) by direct reversal — MGMT protein accepts the alkyl group onto its active-site Cys and is inactivated`,`Oxidative damage`,`Deamination of cytosine`], ans:1, exp:`MGMT (direct reversal repair): removes alkyl groups from O6-methylguanine. MGMT accepts the methyl/alkyl group onto Cys145 (suicide enzyme — one repair per molecule). O6-methylguanine mispairs with thymine → G→A transversions. MGMT promoter methylation (silencing) sensitizes tumors to alkylating agents (temozolomide in glioblastoma). MGMT status guides chemotherapy decisions in GBM.` },
      { q:`The p53-dependent G1 checkpoint prevents cell cycle progression when:`, ch:[`Replication is complete`,`DNA damage (DSBs, bulky lesions) → ATM/ATR → CHK1/2 → p53 phosphorylation/stabilization → p21 (CIP1) induction → CDK2-cyclin E inhibition → G1 arrest`,`Only in S phase`,`No checkpoint exists in G1`], ans:1, exp:`DNA damage → ATM (DSBs) or ATR (ssDNA/stalled forks) → CHK1 (S/G2 checkpoint) and CHK2 (G1 checkpoint) → CHK2 phosphorylates p53 (Ser20) → MDM2 cannot bind → p53 stabilized → p21 transcription → p21 inhibits CDK2/CDK4-cyclin complexes → G1/S arrest. Also: CHK1/2 → CDC25A phosphorylation/degradation → CDK2 not activated.` },
      { q:`Xeroderma pigmentosum (XP) results from:`, ch:[`Mismatch repair defects`,`Defects in NER pathway genes (XPA, XPB/ERCC3, XPC, XPD/ERCC2, XPE, XPF/ERCC4, XPG) → inability to repair UV photoproducts → extreme photosensitivity and skin cancer`,`Base excision repair defects`,`Telomere shortening`], ans:1, exp:`XP: autosomal recessive defects in 7 complementation groups (XP-A through XP-G) of NER proteins. XP cells: ~1000x increase in UV-induced mutation rate. Patients: extreme sun sensitivity, >10,000-fold increased risk of skin cancer (basal cell, squamous cell, melanoma). XP variant = pol eta deficiency (can't bypass T-T dimers).` },
    ]
  },
  {
    id:'bb47', cat:'Bio/Biochem', title:'Oncogenes & Cell Cycle', diff:'Hard',
    qs:[
      { q:`The cell cycle is divided into four phases. CDK4/6-cyclin D primarily drives:`, ch:[`S phase entry`,`G1 progression and G1/S checkpoint — phosphorylates RB → E2F release → S phase entry genes`,`G2/M transition`,`M phase spindle assembly`], ans:1, exp:`CDK4/6-cyclin D (mid-G1): phosphorylates RB (retinoblastoma protein) → releases E2F transcription factors → activates S phase genes (cyclin E, DNA polymerases). CDK2-cyclin E (late G1) hyperphosphorylates RB → complete derepression. CDK4/6 inhibitors (palbociclib, ribociclib, abemaciclib) approved for HR+/HER2- breast cancer.` },
      { q:`Oncogenes arise from proto-oncogenes by:`, ch:[`Loss-of-function mutations or deletions`,`Gain-of-function mutations, amplification, chromosomal translocation, or proviral insertion → constitutive or overactivated signaling`,`Epigenetic silencing`,`Haploinsufficiency`], ans:1, exp:`Proto-oncogenes → oncogenes by: (1) point mutation (KRAS G12D → constitutively active RAS-GTP); (2) gene amplification (HER2 in breast cancer, MYC amplification); (3) chromosomal translocation (BCR-ABL in CML, MYC-IgH in Burkitt lymphoma); (4) promoter mutation or insertion → overexpression. Gain-of-function → dominant (only one allele needs mutation).` },
      { q:`RAS GTPases are mutated in many cancers. The most common oncogenic mutation is:`, ch:[`Q61K`,`G12D or G12V — impairs intrinsic GTPase activity → constitutively GTP-bound → continuous Raf-MEK-ERK and PI3K-Akt signaling`,`T35S`,`A146T only`], ans:1, exp:`KRAS, NRAS, HRAS mutations at codon 12 (Gly→Asp, Val, Cys, Ser, Arg, or Ala) or codon 61 (Gln→Leu, His, Arg) impair GTPase activity → Ras stays in GTP-bound active state → continuous Raf-MEK-ERK and PI3K-Akt → uncontrolled proliferation, survival, metabolism. KRAS G12C: now targetable by sotorasib, adagrasib (covalent inhibitors).` },
      { q:`Tumor suppressor genes follow the Knudson "two-hit" hypothesis, meaning:`, ch:[`One mutation is sufficient to cause cancer`,`Both alleles must be inactivated (loss of function); first hit may be inherited or somatic, second hit (LOH) inactivates remaining allele`,`Tumor suppressors are dominant oncogenes`,`Haploinsufficiency always causes cancer`], ans:1, exp:`Knudson two-hit hypothesis (from retinoblastoma): RB1 tumor suppressor requires loss of both alleles. Familial retinoblastoma: inherited germline RB1 mutation (first hit) + somatic second hit → bilateral, early onset. Sporadic: two somatic hits → unilateral, later onset. Applies to most tumor suppressors (TP53, APC, BRCA1/2, VHL, PTEN).` },
      { q:`CDK inhibitors (INK4 family and CIP/KIP family) differ in that:`, ch:[`Both families inhibit all CDKs equally`,`INK4 proteins (p16, p15, p18, p19) specifically inhibit CDK4/6 (block cyclin D binding); CIP/KIP proteins (p21, p27, p57) inhibit CDK2, CDK4, CDK6 broadly`,`CIP/KIP proteins only inhibit CDK1`,`INK4 proteins inhibit CDK2`], ans:1, exp:`INK4 family: p16/CDKN2A, p15/CDKN2B, p18, p19 — bind CDK4/6 and prevent cyclin D binding → RB hypophosphorylation → G1 arrest. CIP/KIP family: p21/CDKN1A (induced by p53), p27/CDKN1B, p57/CDKN1C — inhibit CDK2-cyclin E/A and CDK4/6-cyclin D (weak) → G1/S arrest. p16 is commonly deleted in many cancers (CDK4/6 inhibitors compensate for p16 loss).` },
      { q:`The spindle assembly checkpoint (SAC) ensures accurate chromosome segregation by:`, ch:[`Stopping replication if any base is mispaired`,`Delaying anaphase onset until all kinetochores are attached to spindle microtubules — via Mad2, BubR1, and Bub3 sequestering APC/C-Cdc20 (MCC complex)`,`Checking DNA repair at G2`,`Activating CDK4/6`], ans:1, exp:`SAC: unattached or tensionless kinetochores generate a wait anaphase signal. Mad1 recruits Mad2 → conformational change → Mad2 sequesters Cdc20 → MCC (Mad2-MCC) inhibits APC/C-Cdc20 (which would degrade securin/cyclin B) → no sister chromatid separation until all kinetochores attached. Once attached → tension → SAC silenced → APC/C active → securin degraded → separase → cohesin cleavage → anaphase.` },
      { q:`Cyclin E overexpression (a common cancer alteration) promotes:`, ch:[`G2 arrest`,`Premature or deregulated S phase entry → CDK2 overactivation → replication stress, DNA re-replication, and genomic instability`,`M phase progression`,`Cell senescence`], ans:1, exp:`Cyclin E (CCNE1) overexpression (amplification in ovarian cancer, high-grade serous): premature CDK2 activation → S phase entry before cells are ready → origin overfiring, re-replication, replication-transcription conflicts → replication stress → DSBs → chromosomal instability (CIN). Cyclin E-CDK2 also inactivates p27, preventing G1 arrest.` },
      { q:`APC/C (anaphase-promoting complex/cyclosome) is an E3 ubiquitin ligase that targets:`, ch:[`CDK2 and CDK4 only`,`Cyclin B and securin (for anaphase); multiple substrates through mitotic exit via CDC20 (in SAC-off state) and CDH1 (in G1)`,`p53 for degradation`,`RAS for degradation`], ans:1, exp:`APC/C-Cdc20 (activated when SAC is satisfied): degrades securin (→ separase active → cohesin cleavage → chromosome separation) and cyclin B (→ CDK1 inactivation → mitotic exit). APC/C-CDH1 (G1): degrades cyclin A, cyclin B, Geminin, Aurora kinases. APC/C is inactivated by Emi1 (early mitosis), re-activated by CDC20 at metaphase-anaphase transition.` },
      { q:`MYC is a transcription factor/proto-oncogene. When overexpressed in cancer, MYC:`, ch:[`Acts as a tumor suppressor`,`Drives transcription of genes for ribosome biogenesis, cell cycle entry, metabolism (Warburg effect), and suppresses differentiation → promotes aggressive cancer phenotypes`,`Inhibits CDK2 directly`,`Acts via a nuclear receptor mechanism`], ans:1, exp:`MYC (c-MYC, N-MYC, L-MYC): bHLH-LZ TF that forms heterodimers with MAX → binds E-boxes (CACGTG) → activates ~15% of all genes (especially those for ribosome biogenesis, protein synthesis, glycolysis, cell cycle). MYC amplification/translocation (Burkitt lymphoma: MYC-IgH) → massive transcriptional reprogramming → uncontrolled proliferation. MYC also promotes genomic instability.` },
      { q:`The restriction point (R point) in G1 is the point after which:`, ch:[`All cells halt to check DNA`,`Cells are committed to cell cycle progression and no longer require growth factor stimulation`,`Cells enter senescence`,`CDK1 is first activated`], ans:1, exp:`The R point (late G1, ~3-4h before S phase): if growth factor signals are removed before R point → cells exit to G0; after R point → cells proceed to S phase regardless of growth factors. Mechanistically: R point = full RB hyperphosphorylation (E2F liberation). Cancer cells bypass R point by deleting RB, overexpressing cyclin D, mutating CDK4, or deleting p16.` },
      { q:`HER2 (ERBB2) overexpression in breast cancer:`, ch:[`Activates the Notch pathway only`,`Amplified HER2 → constitutive RTK signaling (Ras-MAPK + PI3K-Akt) → proliferation, survival, invasion; trastuzumab (Herceptin) targets HER2 extracellular domain`,`Causes constitutive JAK-STAT signaling only`,`Has no clinical significance`], ans:1, exp:`HER2/ERBB2: EGF receptor family member. Amplified in ~15-20% of breast cancers → overexpressed HER2 → constitutive homo- and heterodimerization → continuous Ras-MAPK + PI3K-Akt → aggressive phenotype, poor prognosis. Trastuzumab (anti-HER2 antibody) + pertuzumab + lapatinib (TKI) dramatically improved outcomes in HER2+ breast cancer.` },
      { q:`CDKN2A locus encodes two tumor suppressors through alternative reading frames:`, ch:[`p16 and p21 (separate genes)`,`p16/INK4A (inhibits CDK4/6 → RB pathway) and p14/ARF (inhibits MDM2 → stabilizes p53) — both read from overlapping ORFs in different frames`,`p27 and p57`,`Cyclin D1 and CDK4`], ans:1, exp:`CDKN2A (chromosome 9p21): encodes p16/INK4A (exons 1alpha, 2, 3 → CDK4/6 inhibitor) and p14/ARF (exons 1beta, 2, 3 in different ORF → MDM2 inhibitor → p53 stabilization). Both are tumor suppressors. CDKN2A deletion inactivates both RB and p53 pathways simultaneously → potent tumor suppressor. Among the most commonly deleted loci in human cancer.` },
    ]
  },
  {
    id:'bb48', cat:'Bio/Biochem', title:'Apoptosis', diff:'Hard',
    qs:[
      { q:`The two main pathways of apoptosis are:`, ch:[`Necrosis and pyroptosis`,`The intrinsic (mitochondrial) pathway and the extrinsic (death receptor) pathway`,`Autophagy and necroptosis`,`The caspase-8 and caspase-9 pathways only`], ans:1, exp:`Intrinsic pathway: intracellular stress (DNA damage, oxidative stress, ER stress) → BCL-2 family proteins regulate → cytochrome c release from mitochondria → apoptosome → caspase-9 → caspase-3 (executioner). Extrinsic pathway: FasL, TRAIL, TNF binds death receptors → DISC complex → caspase-8 → caspase-3 (or BID cleavage → mitochondria, "type II cells").` },
      { q:`Bcl-2 family proteins regulate the intrinsic apoptosis pathway. Anti-apoptotic members include:`, ch:[`BAX, BAK, BOK`,`BCL-2, BCL-XL, MCL-1, BCL-W — prevent cytochrome c release by inhibiting BAX/BAK pore formation`,`BIM, PUMA, NOXA`,`Caspase-9 and caspase-3`], ans:1, exp:`Anti-apoptotic BCL-2 family (all have 4 BH domains): BCL-2, BCL-XL, MCL-1, BCL-W, A1. They inhibit BAX/BAK by direct binding. Pro-apoptotic effectors: BAX, BAK (pore-formers, oligomerize in outer mitochondrial membrane → MOMP → cytochrome c release). BH3-only proteins (BIM, PUMA, NOXA, BID): sensitizers/activators that release BAX/BAK from anti-apoptotic BCL-2 members.` },
      { q:`Cytochrome c release from mitochondria is significant in apoptosis because:`, ch:[`It produces ATP for the dying cell`,`Cytochrome c + Apaf-1 + ATP → apoptosome → recruits and activates procaspase-9 → active caspase-9 → cleaves procaspase-3 → active caspase-3 → cell death`,`It activates the extrinsic pathway`,`Cytochrome c directly cleaves nuclear DNA`], ans:1, exp:`MOMP (mitochondrial outer membrane permeabilization): BAX/BAK oligomers form pores → cytochrome c released + SMAC/DIABLO (inhibits IAPs). Cytochrome c binds Apaf-1 (Apoptotic Protease Activating Factor 1) → conformational change → heptameric wheel structure (apoptosome) with 7 Apaf-1 + 7 cyt c → recruits 7 procaspase-9 → dimerization → activation → cleaves caspase-3/7 → execution phase.` },
      { q:`Caspase-3 is an "executioner" caspase. What are its substrates?`, ch:[`Only BCL-2 family members`,`PARP-1 (DNA repair inhibited), lamins (nuclear envelope dismantled), ICAD (releases CAD nuclease → DNA fragmentation), cytoskeletal proteins → classic apoptotic morphology`,`Only cytochrome c`,`Only death receptor complexes`], ans:1, exp:`Executioner caspases-3/7 cleave: PARP1 (Asp214 → p89/p24 fragments; cleavage marker of apoptosis); nuclear lamins A/B/C → blebbing; ICAD → releases CAD (caspase-activated DNase) → internucleosomal DNA ladder; gelsolin, CAD, PAK2. These create the morphological features of apoptosis: nuclear condensation, DNA fragmentation, membrane blebbing, apoptotic bodies.` },
      { q:`IAPs (Inhibitor of Apoptosis Proteins) such as XIAP prevent apoptosis by:`, ch:[`Promoting caspase synthesis`,`Directly binding and inhibiting caspases-3, -7, and -9 via BIR domains`,`Preventing cytochrome c release`,`Activating the extrinsic pathway`], ans:1, exp:`XIAP (X-linked IAP): most potent IAP; BIR2 domain inhibits caspase-3/7; BIR3 domain inhibits caspase-9. Smac/DIABLO released from mitochondria during apoptosis binds XIAP → relieves IAP inhibition → apoptosis proceeds. Smac mimetics (BV6, LCL161) are being developed as cancer therapeutics to override IAP-mediated apoptosis resistance.` },
      { q:`The extrinsic pathway of apoptosis is initiated by:`, ch:[`DNA damage in the nucleus`,`Death receptor ligation (Fas/FasL, TRAIL-R/TRAIL, TNFR1/TNF) → DISC (death-inducing signaling complex) formation → caspase-8 activation → caspase-3`,`BCL-2 overexpression`,`Cytochrome c binding Apaf-1`], ans:1, exp:`Extrinsic pathway: FasL (FasR → DISC: FADD + caspase-8) → caspase-8 dimerization → active → cleaves and activates caspase-3 (type I cells, enough active caspase-8) or cleaves BID → tBID → mitochondria → BAX/BAK → MOMP (type II cells, amplifies through intrinsic pathway). Viral caspase-8 inhibitors (FLIP) block extrinsic apoptosis.` },
      { q:`BCL-2 t(14;18) translocation in follicular lymphoma causes:`, ch:[`Loss of BCL-2 expression`,`BCL-2 placed under the IgH heavy chain promoter → BCL-2 overexpression → B cells are immortalized because they cannot undergo apoptosis`,`Activation of BAX`,`Constitutive caspase-9 activity`], ans:1, exp:`t(14;18)(q32;q21): IGH promoter → BCL-2 overexpression → B cells are rescued from apoptosis → accumulate = follicular lymphoma (indolent B-cell lymphoma). BCL-2 inhibitor venetoclax (ABT-199) directly binds and inhibits BCL-2 → restores apoptosis → approved for CLL, AML. Demonstrates BCL-2 as therapeutic target.` },
      { q:`Anoikis is a form of apoptosis that occurs when:`, ch:[`Cells are deprived of nutrients`,`Anchorage-dependent cells detach from the extracellular matrix → loss of integrin signaling → anoikis (apoptosis from loss of attachment)`,`Cells are infected by viruses`,`DNA is damaged by radiation`], ans:1, exp:`Anoikis (Greek: "homelessness"): apoptosis induced by detachment from ECM in anchorage-dependent cells. Integrins engage ECM → FAK-Src signaling → PI3K-Akt → survival. Detachment → integrin signal loss → pro-apoptotic signals. Cancer cells resist anoikis (through overexpression of BCL-2, activated PI3K, fibronectin autocrine loops) → survive in circulation → metastasis.` },
      { q:`P53-induced apoptosis involves transcription of:`, ch:[`BCL-2 and BCL-XL`,`PUMA, NOXA, and BAX (BH3-only and effector pro-apoptotic BCL-2 family members)`,`CDK4 and cyclin D1`,`IAPs`], ans:1, exp:`p53 transcriptional targets for apoptosis: PUMA (p53 upregulated modulator of apoptosis) — most potent BH3-only sensitizer, neutralizes all anti-apoptotic BCL-2 members; NOXA — selectively inhibits MCL-1 and A1; BAX — pro-apoptotic effector; APAF-1; DR5 (TRAIL receptor). p53 can also directly interact with mitochondria to promote MOMP in a transcription-independent manner.` },
      { q:`Necroptosis differs from apoptosis in that:`, ch:[`Necroptosis requires caspase activation`,`Necroptosis is programmed necrosis triggered by RIPK1/RIPK3/MLKL — does NOT require caspases; causes membrane disruption and pro-inflammatory DAMP release`,`Necroptosis requires BCL-2`,`Necroptosis produces apoptotic bodies`], ans:1, exp:`Necroptosis: death receptor or viral dsRNA → RIPK1 → RIPK3 → phosphorylation and oligomerization of MLKL (mixed lineage kinase domain-like protein) → plasma membrane permeabilization → cell death with DAMP release (ATP, HMGB1, IL-1alpha) → inflammation. Unlike apoptosis: immunogenic, no caspase requirement, no apoptotic bodies. RIPK1 inhibitors (necrostatins) block necroptosis.` },
      { q:`Caspase-8 can be inhibited by FLIP (FLICE-inhibitory protein), which:`, ch:[`Activates caspase-8`,`Structurally resembles caspase-8 but lacks catalytic activity → competes for DISC incorporation → dominant-negative inhibition of caspase-8`,`Promotes cytochrome c release`,`Is identical to caspase-9`], ans:1, exp:`c-FLIP (CASP8 and FADD-like apoptosis regulator): truncated caspase-8 homolog lacking active-site Cys → competes for caspase-8 incorporation into DISC → blocks extrinsic pathway initiation. Viruses encode viral FLIP homologs (vFLIP, e.g., KSHV MC159) to prevent apoptosis in infected cells. c-FLIP is overexpressed in many cancers → resistance to TRAIL-induced apoptosis.` },
      { q:`Ceramide acts as a second messenger in apoptosis by:`, ch:[`Inhibiting BAX directly`,`Being generated by sphingomyelinase in response to death stimuli → activates downstream apoptotic signals (via PP2A, CATHEPSIN D) and promotes BAK oligomerization`,`Activating BCL-2`,`Inhibiting caspase-9`], ans:1, exp:`Ceramide: sphingolipid generated by sphingomyelinase (cleaves sphingomyelin) or ceramide synthase in response to Fas ligation, TNF, radiation. Ceramide activates protein phosphatase 2A (PP2A), cathepsin D, and directly promotes BAK/BAX oligomerization at the outer mitochondrial membrane. Ceramide-induced apoptosis is exploited by some chemotherapeutic drugs.` },
      { q:`The "BH3 mimetic" venetoclax works by:`, ch:[`Inducing BAX expression`,`Mimicking BH3-only proteins — directly binds BCL-2 in the BH3-binding groove → displaces and releases BAX/BAK → MOMP → apoptosis in BCL-2-dependent cancer cells`,`Inhibiting caspase-9 directly`,`Inhibiting MDM2`], ans:1, exp:`Venetoclax (ABT-199): BH3 mimetic with high selectivity for BCL-2. Binds BCL-2's hydrophobic BH3-binding groove → displaces sequestered BAX/BAK → BAK/BAX oligomerize → MOMP → cyt c → apoptosis. Approved for CLL, AML. Selectivity for BCL-2 over BCL-XL reduces thrombocytopenia (platelet survival depends on BCL-XL, not BCL-2).` },
    ]
  },
  {
    id:'bb49', cat:'Bio/Biochem', title:'B-Cell Activation & Immunoglobulins', diff:'Hard',
    qs:[
      { q:`B cells develop in the bone marrow and undergo:`, ch:[`Positive selection only in bone marrow`,`V(D)J recombination to generate diverse BCR (IgM) — positive selection (functional BCR) and negative selection (deletion of strongly self-reactive clones)`,`Class switching in bone marrow`,`Somatic hypermutation in bone marrow`], ans:1, exp:`B cell development: pro-B → pre-B → immature B (expresses IgM on surface = BCR). V(D)J recombination (heavy chain: V-D-J; light chain: V-J) generates diverse BCR repertoire. Immature B cells with strongly self-reactive BCR undergo central tolerance: deletion (clonal deletion) or receptor editing. Mature naive B cells exit to periphery expressing IgM + IgD.` },
      { q:`V(D)J recombination is mediated by:`, ch:[`Transposons`,`RAG1 and RAG2 (recombination-activating genes) — recognize RSS (recombination signal sequences) flanking V, D, J segments → double-strand breaks → NHEJ-mediated joining`,`Homologous recombination proteins`,`RNA polymerase III`], ans:1, exp:`RAG1/2 recognize RSS (12/23-spacer rule) flanking V, D, J gene segments → synaptic complex → hairpin DSBs → NHEJ rejoins coding ends. N-nucleotides (by TdT, terminal deoxynucleotidyl transferase) are added at junctions → generates enormous CDR3 diversity. V(D)J recombination is restricted to pro-B, pre-B, and developing T cells.` },
      { q:`Class switch recombination (CSR) changes the antibody isotype (IgM→IgG, IgA, IgE) by:`, ch:[`V(D)J recombination`,`Deleting the DNA between switch regions (S regions), removing intervening constant region genes — mediated by AID (activation-induced cytidine deaminase) and NHEJ`,`Adding new V regions`,`Silent mutation in CH genes`], ans:1, exp:`CSR: AID (AICDA) deaminates C→U in S regions → U removed by UNG → abasic site → nick/DSB → NHEJ joins the variable exon to a new CH gene (e.g., IgM Smu to IgG Sgamma) → new isotype produced. AID is activated by CD40L (from T helper cells) and cytokines (IL-4 → IgE, TGF-beta → IgA). AID deficiency → Hyper-IgM syndrome (no CSR, no SHM).` },
      { q:`Somatic hypermutation (SHM) in the germinal center:`, ch:[`Creates new V regions`,`Introduces point mutations in the variable regions of BCR genes (V segments) via AID → selection for higher affinity clones (affinity maturation)`,`Changes antibody class`,`Generates new CDR3 diversity`], ans:1, exp:`SHM: AID deaminates C→U in BCR V genes → error-prone repair → point mutations accumulate (~10^-3/bp/generation, ~10^6 higher than normal). Germinal center B cells with higher affinity BCR (for antigen displayed on FDC) receive survival signals; lower affinity cells die. This affinity maturation produces high-affinity antibodies after repeated antigen exposure.` },
      { q:`The structure of an IgG antibody includes:`, ch:[`4 identical heavy chains`,`2 identical heavy chains + 2 identical light chains (kappa or lambda) joined by disulfide bonds; 2 Fab (antigen-binding) arms + 1 Fc (effector function) region`,`6 chains with 3 antigen-binding sites`,`Only kappa light chains`], ans:1, exp:`IgG: heterotetramer (H2L2). Each heavy chain: VH + CH1 + hinge + CH2 + CH3. Each light chain: VL + CL. Variable regions (VH + VL) form the Fab antigen-binding site (CDR1, CDR2, CDR3 loops). Fc region (CH2+CH3): binds Fc receptors on effector cells and C1q (complement). Hinge region: flexibility + disulfide bonds between H chains.` },
      { q:`IgE-mediated allergy involves:`, ch:[`NK cell activation`,`IgE bound to mast cells and basophils via FcεRI; antigen crosslinks IgE → mast cell degranulation → histamine, prostaglandins, leukotrienes → allergic symptoms`,`Complement MAC pore formation`,`CTL killing`], ans:1, exp:`Type I hypersensitivity: sensitization → IL-4/IL-13 (Th2 cytokines) → class switching to IgE → IgE binds FcεRI on mast cells/basophils. Re-exposure to antigen → crosslinks IgE → mast cell activation → degranulation (histamine) + lipid mediators (PGD2, LTC4) + late-phase cytokines (IL-4, IL-5, IL-13) → bronchoconstriction, urticaria, anaphylaxis. Omalizumab (anti-IgE antibody) treats severe allergic asthma.` },
      { q:`The complement activation by the classical pathway requires:`, ch:[`Mannose-binding lectin`,`C1q binding to Fc regions of IgG or IgM (in antigen-antibody complexes) → C1r/C1s activation → C4b/C2a (C3 convertase) → C3b → opsonization, C5a → inflammation, C5b-9 (MAC) → lysis`,`Alternative pathway activation`,`TLR signaling`], ans:1, exp:`Classical pathway: Ag-Ab complex → C1q (recognizes Fc of IgG1/3 or IgM) → C1r/C1s activation → C4 + C2 → C4b2a (classical C3 convertase) → C3b → opsonization (phagocytosis via CR1). C3bBb (alternative C3 convertase, spontaneous) amplifies. C5a: anaphylatoxin, neutrophil chemotaxis. C5b-9 (MAC): pores in gram-negative bacteria membranes.` },
      { q:`The BCR (B cell receptor) complex includes:`, ch:[`Only the membrane immunoglobulin`,`Membrane IgM (or IgD) + Igalpha/Igbeta (CD79a/CD79b) heterodimer — Igalpha/Igbeta contain ITAMs (immunoreceptor tyrosine-based activation motifs) that transduce the signal`,`T cell receptor subunits`,`CD3 chains`], ans:1, exp:`BCR complex: membrane Ig (recognition) + Igalpha/Igbeta (CD79a/CD79b) signaling heterodimer. ITAM (Tyr-X-X-Leu-X6-7-Tyr-X-X-Leu) in Igalpha/beta: upon BCR crosslinking → Lyn phosphorylates ITAMs → Syk recruited → PLCgamma2 → IP3/DAG → Ca2+/PKC → NFAT, AP-1 activation + PI3K → Akt + Ras → proliferation. Analogous to CD3/zeta in TCR complex.` },
      { q:`Antibody-dependent cell-mediated cytotoxicity (ADCC) involves:`, ch:[`Complement activation`,`NK cells expressing FcgammaRIIIa (CD16) recognizing IgG-opsonized target cells → NK cell activation → cytotoxic granule release → target cell death`,`T cell-mediated killing`,`Mast cell degranulation`], ans:1, exp:`ADCC: IgG antibodies bind tumor or infected cell antigens → Fc region accessible → NK cells (FcgammaRIIIa/CD16) recognize Fc → NK activation → perforin/granzyme B release → target cell apoptosis. ADCC is a key mechanism of trastuzumab (anti-HER2) and rituximab (anti-CD20) anti-tumor activity. Obinutuzumab engineered for enhanced ADCC vs rituximab.` },
      { q:`Secondary antibody response characteristics include:`, ch:[`More IgM, lower titer, slower`,`Faster (days not weeks), higher titer, predominantly IgG (or IgA/IgE), higher affinity — due to memory B cells from the primary response`,`No somatic hypermutation`,`No affinity maturation`], ans:1, exp:`Primary response: 7-14 days, peaks at ~3 weeks, mostly IgM, lower affinity. Secondary response (re-exposure or booster vaccine): 1-3 days, much higher titer, predominantly IgG (or IgA), higher affinity (due to prior SHM and affinity maturation in germinal centers). Memory B cells are long-lived and rapidly become plasma cells upon re-exposure.` },
      { q:`The Fc region of IgG mediates:`, ch:[`Antigen binding`,`Effector functions: binding Fcgamma receptors (ADCC, phagocytosis), activating classical complement (C1q binding), neonatal transport (FcRn), and determining serum half-life (FcRn recycling)`,`CDR3 diversity`,`Light chain variable region function`], ans:1, exp:`IgG Fc (CH2+CH3): (1) FcgammaRI/II/III on macrophages/NK cells → phagocytosis/ADCC; (2) C1q binding (IgG1/3) → classical complement; (3) FcRn (neonatal Fc receptor): at pH 7.4 (blood) low affinity, at pH 6 (endosome) high affinity → IgG rescued from degradation → extends t1/2 (~21 days for IgG vs ~1 day for IgM); (4) FcRn: maternal IgG → placental transfer (protection of neonate).` },
      { q:`Hyper-IgM syndrome type 1 is caused by:`, ch:[`RAG1 mutations`,`CD40L (CD40 ligand, CD154) mutations on T cells → B cells cannot receive CD40 signaling → no CSR → no IgG/IgA/IgE, only IgM produced; also impaired AID expression`,`AID mutations directly`,`IgM heavy chain mutations`], ans:1, exp:`Hyper-IgM syndrome type 1 (X-linked): CD40L (TNFSF5) mutations on activated CD4+ T cells → cannot engage CD40 on B cells → no CD40 signaling → no class switch recombination or somatic hypermutation → only IgM and IgD produced; IgG, IgA, IgE absent. Also affects macrophage activation (CD40-CD40L → IVIG recommended). Susceptible to Pneumocystis jirovecii, Cryptosporidium.` },
    ]
  },
  {
    id:'bb50', cat:'Bio/Biochem', title:'T-Cell Activation & MHC', diff:'Hard',
    qs:[
      { q:`T cells recognize antigen only when presented by:`, ch:[`Free antigen in solution`,`MHC molecules on antigen-presenting cells — peptide-MHC complex (pMHC) is recognized by the TCR`,`Antibodies on B cells`,`Complement fragments on pathogen surface`], ans:1, exp:`T cells are MHC-restricted: TCR recognizes peptide fragments only when bound to MHC class I (CD8+ T cells) or MHC class II (CD4+ T cells). This requirement for MHC presentation (not free antigen) is MHC restriction. APCs (dendritic cells, macrophages, B cells) express both MHC I and II; most nucleated cells express MHC I only.` },
      { q:`MHC class I presents:`, ch:[`Exogenous antigens from endocytic pathway`,`Endogenous peptides (from cytoplasmic/nuclear proteins) — processed by proteasome → TAP transporter → ER → MHC class I assembly → cell surface → CD8+ T cell recognition`,`Lipid antigens only`,`Only viral glycoproteins`], ans:1, exp:`MHC class I (HLA-A, -B, -C): expressed on all nucleated cells. Peptides (8-10 aa): generated by the ubiquitin-proteasome system → TAP1/TAP2 (transporter associated with antigen presentation) pumps into ER → loaded onto MHC I (with tapasin, calreticulin, ERp57 — loading complex) → beta-2-microglobulin associates → stable pMHC-I → Golgi → cell surface.` },
      { q:`MHC class II presents:`, ch:[`Endogenous cytoplasmic antigens`,`Exogenous antigens (from endocytic pathway) — peptides from lysosomal degradation of extracellular proteins replace CLIP (class II-associated invariant chain peptide) in MIIC, facilitated by HLA-DM → CD4+ T cell recognition`,`Only self-peptides`,`Lipid antigens via CD1 molecules`], ans:1, exp:`MHC class II (HLA-DR, -DP, -DQ): on APCs (DC, macrophages, B cells). Alpha/beta chain heterodimer. Invariant chain (li/CD74) fills peptide-binding groove during transport → lysosome (MIIC) → li cleaved → CLIP remains → HLA-DM (chaperone) removes CLIP → exogenous peptides (13-25 aa) from lysosomal degradation → stable pMHC-II → cell surface → CD4+ T cell.` },
      { q:`The TCR complex consists of:`, ch:[`TCR alpha/beta chains only`,`TCR alpha/beta (or gamma/delta) heterodimer + CD3 complex (CD3gamma, CD3delta, CD3epsilon, CD3zeta) for signal transduction — TCR recognizes pMHC, CD3 transduces the signal via ITAMs`,`TCR gamma/delta + CD19`,`TCR alpha/beta + BCR`], ans:1, exp:`TCR: TCR alpha/beta (recognition of pMHC) + CD3gamma, CD3delta, CD3epsilon, and zeta homodimer (signal transduction). Zeta chain: 3 ITAMs each (6 ITAM Tyr total) → phosphorylated by Lck (associated with CD4/CD8) → ZAP-70 recruited → LAT, SLP-76 → PLCgamma1 → IP3/DAG → Ca2+/NFAT + PKC/AP-1 + RAS/ERK.` },
      { q:`T cell activation requires two signals. Signal 2 (co-stimulation) is:`, ch:[`TCR binding to pMHC (Signal 1)`,`CD28 on T cells binding B7-1/B7-2 (CD80/CD86) on APCs — without this signal, T cells become anergic (unresponsive) rather than activated`,`Cytokine binding to the T cell`,`MHC binding to CD8`], ans:1, exp:`Two-signal model: Signal 1 (TCR-pMHC) alone → anergy or deletion. Signal 2 (CD28-B7) → activates PI3K → Akt, activates AP-1 → IL-2 production → autocrine/paracrine growth. Signal 3: cytokines (IL-12 → Th1; IL-4 → Th2; TGF-beta + IL-6 → Th17; TGF-beta → Treg). CTLA-4 (inducible, competes with CD28 for B7 with higher affinity) → immune checkpoint → downregulates T cell activation.` },
      { q:`CD4+ T helper cell subsets are defined by:`, ch:[`Expression of CD8 instead of CD4`,`Cytokine environment during activation that induces master TF expression: Th1 (IL-12 → T-bet → IFN-gamma); Th2 (IL-4 → GATA3 → IL-4/5/13); Th17 (TGF-beta + IL-6/IL-21 → RORgt → IL-17/22); Treg (TGF-beta → Foxp3 → IL-10, TGF-beta)`,`Only by CD4 and CD8 co-receptor levels`,`Only by BCR isotype`], ans:1, exp:`Th1 (IFN-gamma): activates macrophages → intracellular pathogen killing; DTH responses. Th2 (IL-4, IL-5, IL-13): B cell help, IgE → allergy, eosinophil activation (helminths). Th17 (IL-17, IL-22): mucosal defense, neutrophil recruitment → extracellular bacteria/fungi. Treg (Foxp3): immune suppression, self-tolerance. Cytokine environment from innate immune cells biases naive CD4+ T cells to each subset.` },
      { q:`Central tolerance in the thymus involves:`, ch:[`Positive selection in the medulla`,`Positive selection (cortex, by cortical epithelial cells, MHC restriction) and negative selection (medulla, by medullary epithelial cells expressing AIRE → delete strongly self-reactive T cells)`,`Only deletion of T cells`,`Only TCR editing`], ans:1, exp:`Thymic selection: (1) Positive selection (cortex): DP T cells (CD4+CD8+) that can bind self-MHC (with weak/moderate affinity) survive; non-binding die. CD4 vs CD8 lineage commitment. (2) Negative selection (medulla): T cells with strong self-reactivity are deleted (clonal deletion) or converted to Tregs. AIRE (autoimmune regulator) drives ectopic expression of peripheral tissue antigens in mTECs → delete T cells reactive to those antigens.` },
      { q:`Peripheral tolerance mechanisms include:`, ch:[`Only thymic deletion`,`Clonal anergy (no co-stimulation), suppression by Tregs, clonal deletion by AICD (activation-induced cell death, Fas-FasL), and immune privilege`,`Only Fas-FasL deletion`,`Receptor editing`], ans:1, exp:`Peripheral tolerance: (1) Clonal anergy: TCR signal without CD28 → T cell becomes unresponsive (CTLA-4 and PD-1 promote anergy); (2) Treg suppression (IL-10, TGF-beta, CTLA-4); (3) AICD: repeated stimulation → Fas (CD95) upregulation → FasL-Fas → caspase-8 → apoptosis of chronically activated T cells; (4) Immune privilege sites (eye, brain, testis): low MHC, high FasL, TGF-beta.` },
      { q:`Checkpoint inhibitors (anti-PD-1, anti-CTLA-4) are immunotherapy drugs that:`, ch:[`Activate regulatory T cells`,`Block inhibitory immune checkpoints → relieve T cell exhaustion/suppression → enable anti-tumor T cell activity`,`Replace BCG vaccination`,`Activate B cells`], ans:1, exp:`CTLA-4 and PD-1/PD-L1 are immune checkpoints that normally prevent autoimmunity by dampening T cell responses. Anti-CTLA-4 (ipilimumab): blocks CTLA-4-B7 interaction → more T cell activation. Anti-PD-1 (nivolumab, pembrolizumab): blocks PD-1 → prevents PD-L1/PD-L2 (on tumor cells/APCs) from exhausting T cells. Approved for melanoma, NSCLC, many other cancers. Immune-related adverse events (irAEs) = autoimmunity.` },
      { q:`Alloreactivity (rejection of transplanted organs) is caused by:`, ch:[`Mismatch in blood group antigens`,`T cell recognition of non-self MHC molecules (allogeneic MHC) — the TCR can directly bind intact allogeneic pMHC (direct pathway) or donor peptides presented by self-MHC (indirect pathway)`,`Antibody-mediated rejection only`,`Complement activation only`], ans:1, exp:`Allorecognition: Direct pathway: recipient T cells recognize donor MHC directly (high frequency because many T cells cross-react with allo-MHC). Indirect pathway: donor MHC peptides presented by recipient APCs on self-MHC. Both activate CD4+ and CD8+ T cells → graft rejection. Immunosuppressants (tacrolimus, cyclosporine): block calcineurin → prevent NFAT → IL-2 suppression → T cell unresponsiveness.` },
      { q:`CD8+ cytotoxic T lymphocytes (CTLs) kill target cells by:`, ch:[`Secreting antibodies`,`Perforin-granzyme pathway (perforin pores → granzyme B enters → caspase activation) and Fas-FasL pathway (CTL FasL binds target Fas → extrinsic apoptosis)`,`Complement activation`,`ADCC`], ans:1, exp:`CTL killing: (1) Perforin/granzyme pathway: cytotoxic granules (perforin, granzyme A/B, granulysin) released into immunological synapse → perforin creates pores in target cell membrane → granzyme B enters → cleaves caspase-3 (and BID) → apoptosis. (2) Fas-FasL: CTL upregulates FasL (CD95L) → binds Fas (CD95) on target → DISC → caspase-8 → apoptosis.` },
      { q:`The immunological synapse formed between T cell and APC is important because:`, ch:[`It prevents T cell from activating`,`It concentrates TCR-pMHC complexes and co-stimulatory molecules (CD28-B7) in the central supramolecular activation cluster (cSMAC) → amplifies and sustains signaling; directional secretion of cytokines/granules`,`It prevents APC from presenting antigen`,`It only occurs in the lymph node`], ans:1, exp:`Immunological synapse: T cell-APC junction with central supramolecular activation cluster (cSMAC: TCR-CD3 + PKCtheta + CD28) surrounded by peripheral SMAC (pSMAC: LFA-1-ICAM-1 adhesion ring). This polarized junction: concentrates signaling (amplifies weak TCR signals), directs cytokine/granule secretion toward target cell, sustains T cell activation. Lytic synapse in CTL is similar but more focused.` },
    ]
  },
  {
    id:'bb51', cat:'Bio/Biochem', title:'Complement System', diff:'Hard',
    qs:[
      { q:`The complement system has three activation pathways. The alternative pathway is activated by:`, ch:[`Antibody-antigen complexes`,`Spontaneous hydrolysis of C3 (tick-over) → C3b deposits on surfaces → if not inactivated by host regulators → amplification loop`,`Mannose-binding lectin (MBL) on pathogen surfaces`,`All viruses specifically`], ans:1, exp:`Alternative pathway: C3 spontaneously hydrolyzes to C3(H2O) → binds Factor B → Factor D cleaves B → C3(H2O)Bb (fluid-phase C3 convertase) → deposits C3b on surfaces. On pathogens (lacking regulators like DAF, CD46): Factor B binds C3b → Factor D cleaves → C3bBb (amplification C3 convertase) → further C3b deposition. Host cells are protected by surface regulators (Factor H, DAF, MCP) and CD59.` },
      { q:`The membrane attack complex (MAC, C5b-9) kills gram-negative bacteria by:`, ch:[`Opsonizing bacteria for phagocytosis`,`Forming transmembrane pores in bacterial outer membranes → osmotic lysis`,`Activating mast cells`,`Promoting adaptive immune responses`], ans:1, exp:`MAC assembly: C5b + C6 + C7 + C8 → inserts into lipid bilayer → 18 C9 molecules polymerize → transmembrane pore → osmotic lysis. Effective against gram-negative bacteria (double membrane; MAC penetrates outer membrane + some cytoplasmic membrane). Gram-positive bacteria: thick peptidoglycan blocks MAC access. Complement deficiencies of C5-C9 → recurrent Neisseria infections.` },
      { q:`C3a and C5a are called "anaphylatoxins" because they:`, ch:[`Activate the adaptive immune response`,`Trigger mast cell and basophil degranulation, increase vascular permeability, and act as chemoattractants (C5a > C3a) for neutrophils → acute inflammation`,`Form the membrane attack complex`,`Opsonize bacteria`], ans:1, exp:`C3a (from C3) and C5a (from C5): small fragments cleaved during complement activation. Both bind receptors (C3aR, C5aR1/C5aR2) on mast cells/basophils → degranulation (histamine, prostaglandins) → increased vascular permeability. C5a: potent neutrophil chemoattractant and activator → respiratory burst, opsonin receptor upregulation. Excess C5a → systemic inflammatory response syndrome (SIRS), ARDS.` },
      { q:`Factor I is a complement regulator that:`, ch:[`Activates C3`,`Cleaves C3b and C4b (inactivating them) in the presence of cofactors (Factor H, C4BP, MCP, CR1) → prevents amplification`,`Activates the lectin pathway`,`Degrades C5a`], ans:1, exp:`Factor I (serine protease): cleaves C3b → iC3b → C3d (inactivation) and C4b → C4d. Requires a cofactor: Factor H (fluid phase and cell-surface), C4b-binding protein (C4BP) for C4b, MCP (membrane cofactor protein, CD46) and CR1 (CD35) on cells. Factor I deficiency → uncontrolled C3 consumption → C3 depletion → recurrent bacterial infections.` },
      { q:`CD59 (protectin) is a complement regulator that:`, ch:[`Degrades C3b`,`Blocks the final polymerization of C9, preventing MAC formation on host cells`,`Inactivates C5a`,`Activates Factor I`], ans:1, exp:`CD59 (GPI-anchored): binds C5b-8 complex → prevents C9 polymerization → no MAC pore on host cells. Paroxysmal nocturnal hemoglobinuria (PNH): somatic PIGA mutation in hematopoietic stem cells → no GPI anchor synthesis → no CD59 (or DAF/CD55) on RBCs/platelets → complement-mediated hemolysis + thrombosis. Eculizumab (anti-C5) prevents C5 cleavage → no C5a or MAC.` },
      { q:`C3b bound to pathogens acts as an opsonin by:`, ch:[`Activating NK cells directly`,`Binding CR1 (CD35) on phagocytes (neutrophils, macrophages) → enhancing phagocytosis; iC3b binds CR3 (Mac-1, CD11b/CD18) on phagocytes`,`Activating T cells`,`Initiating apoptosis in pathogens`], ans:1, exp:`C3b (and iC3b) deposited on pathogens are recognized by complement receptors: CR1 (C3b/C4b) → phagocytosis signal (requires Fc receptor co-engagement or cytokines for full activation); CR3 (Mac-1, CD11b/CD18, integrin) binds iC3b → phagocytosis; CR4 (CD11c/CD18) similar. Together with IgG Fc opsonization → synergistic phagocytosis enhancement.` },
      { q:`The lectin pathway is activated by:`, ch:[`Antibody-antigen complexes`,`Mannose-binding lectin (MBL) and ficolins binding carbohydrate patterns (e.g., terminal mannose, N-acetylglucosamine) on pathogen surfaces → MASPs (MBL-associated serine proteases) → C4/C2 activation`,`Alternative pathway amplification`,`IgE-FcεRI crosslinking`], ans:1, exp:`Lectin pathway: MBL (like C1q structurally) or ficolins recognize pathogen surface carbohydrates → MASP1/MASP2 (structurally like C1r/C1s) → cleave C4 and C2 → C4b2a (same as classical C3 convertase). Bypasses antibody requirement → important in early infection before adaptive immunity. MBL deficiency → recurrent infections in infants.` },
      { q:`Hereditary angioedema (HAE) is caused by:`, ch:[`C3 deficiency`,`C1 inhibitor (C1-INH, SERPING1) deficiency → uncontrolled C1r/C1s + kallikrein activation → excess bradykinin + complement fragments → episodic edema`,`C5 deficiency`,`Factor H deficiency`], ans:1, exp:`HAE (autosomal dominant): C1-INH deficiency → C1r/C1s overactivation → excess C4a/C2b + unregulated contact activation → bradykinin (major mediator) → kinin B2 receptor → vascular permeability → non-pitting edema (larynx is life-threatening). Treatment: plasma C1-INH replacement, icatibant (bradykinin B2 antagonist), berotralstat/lanadelumab (plasma kallikrein inhibitors).` },
      { q:`Paroxysmal nocturnal hemoglobinuria (PNH) illustrates the importance of:`, ch:[`Complement activation in adaptive immunity`,`Complement regulators on self-cells — PIGA mutation → no GPI-anchored proteins (CD59, DAF) → uncontrolled MAC formation on RBCs → intravascular hemolysis`,`C3a as an anti-inflammatory molecule`,`DAF activating complement`], ans:1, exp:`PNH: somatic PIGA mutation in HSC → deficient GPI anchor biosynthesis → no CD59 (blocks MAC) or DAF/CD55 (degrades C3/C5 convertases) on affected blood cells → complement-mediated hemolysis + thrombosis + cytopenias. Eculizumab (anti-C5 antibody) blocks C5 cleavage → prevents MAC formation → treats PNH hemolysis. Ravulizumab: long-acting anti-C5.` },
      { q:`The properdin (Factor P) in the alternative pathway:`, ch:[`Inhibits C3 convertase`,`Stabilizes C3bBb (alternative C3 convertase), prolonging its half-life and amplifying the alternative pathway`,`Cleaves C5`,`Activates Factor I`], ans:1, exp:`Properdin (Factor P): the only known complement activation positive regulator. Binds C3bBb convertase → extends its half-life from ~90 seconds to ~18 minutes → amplification loop. Properdin also can directly bind pathogen surfaces and recruit C3b → initiate alternative pathway (pattern recognition role). Properdin deficiency → susceptibility to Neisseria meningitidis.` },
      { q:`Systemic lupus erythematosus (SLE) is associated with:`, ch:[`Complement overactivation with no autoantibodies`,`Deficiencies in early complement components (C1q, C2, C4) → impaired immune complex clearance → autoantibodies (anti-dsDNA, anti-Sm) → immune complex deposition → tissue damage`,`C5 overactivation only`,`CD59 overexpression`], ans:1, exp:`SLE pathogenesis: defective clearance of apoptotic debris (C1q normally opsonizes apoptotic cells → phagocytosis; C1q deficiency → debris accumulates → autoantigen exposure → anti-dsDNA, anti-Sm antibodies) → immune complex formation → deposits in kidney, skin, joints → complement activation → inflammation. C4A null allele (C4A*Q0) increases SLE risk. C1q deficiency is actually the strongest complement-associated SLE risk factor.` },
      { q:`Complement activation products that bridge innate and adaptive immunity include:`, ch:[`C3a only`,`C3d (from C3b degradation): binds CR2 (CD21) on B cells → lowers threshold for B cell activation; C4b-bound antigens targeted to follicular dendritic cells for germinal center reactions`,`MAC only`,`Properdin`], ans:1, exp:`C3d acts as a natural adjuvant: C3b degradation product C3d covalently bound to antigen → binds CR2 (CD21) on B cells (CR2-CD19-CD81 co-receptor complex) → co-stimulates BCR signaling → lowers threshold for B cell activation by ~100-fold. C4b-coated immune complexes captured by CR1 on follicular DCs → antigen presentation in germinal centers. Complement thus bridges innate opsonization with adaptive B cell responses.` },
    ]
  },
  {
    id:'bb52', cat:'Bio/Biochem', title:'Eicosanoids & Lipid Mediators', diff:'Hard',
    qs:[
      { q:`Eicosanoids are derived from:`, ch:[`Linoleic acid (omega-6) only`,`20-carbon polyunsaturated fatty acids, primarily arachidonic acid (AA, 20:4, omega-6) and EPA (20:5, omega-3)`,`Saturated fatty acids`,`Cholesterol directly`], ans:1, exp:`Eicosanoids: lipid mediators derived from C20 PUFAs. Primary precursor: arachidonic acid (AA, 20:4 omega-6) from membrane phospholipids (PLA2 liberation). EPA (20:5 omega-3, from fish oil) competes with AA and produces less potent eicosanoids (e.g., 3-series thromboxanes instead of 2-series). Eicosanoids act locally as autocrine/paracrine mediators (very short half-life).` },
      { q:`Cyclooxygenase (COX) enzymes catalyze the first step in prostaglandin/thromboxane synthesis. COX has:`, ch:[`Only cyclooxygenase activity`,`Both cyclooxygenase activity (AA + 2O2 → PGG2) and peroxidase activity (PGG2 → PGH2) — aspirin irreversibly acetylates the COX active site Ser530`,`Only peroxidase activity`,`Lipoxygenase activity`], ans:1, exp:`COX1/COX2 bifunctional enzyme: cyclooxygenase domain (adds 2 O2 to AA → PGG2, a bicyclic endoperoxide) + peroxidase domain (PGG2 → PGH2, stable endoperoxide). PGH2 is the common precursor for PGE2, PGI2 (prostacyclin), TXA2, and PGF2alpha. Aspirin: irreversible acetylation of Ser530 of COX → blocks AA access to active site.` },
      { q:`Thromboxane A2 (TXA2) is produced by platelets and causes:`, ch:[`Vasodilation and platelet aggregation inhibition`,`Vasoconstriction and platelet aggregation promotion — opposing effects to prostacyclin (PGI2) from vascular endothelium`,`Bronchoconstriction only`,`Fever induction`], ans:1, exp:`TXA2 (from COX-1 in platelets, TXA synthase → TX receptor): platelet aggregation (Gs-coupled → Gq → Ca2+), vasoconstriction. Short half-life (~30s) → TXB2 (inactive). PGI2 (prostacyclin, from COX in endothelium, prostacyclin synthase → IP receptor): vasodilation (Gs → cAMP → PKA → inhibits platelet aggregation). TXA2/PGI2 balance regulates hemostasis. Aspirin low-dose: preferentially inhibits platelet COX-1 (irreversible, no new synthesis) → less TXA2 → anti-platelet effect.` },
      { q:`PGE2 (prostaglandin E2) contributes to fever by:`, ch:[`Directly resetting the hypothalamic temperature`,`Stimulating hypothalamic EP3/EP1 receptors → activating adenylate cyclase (cAMP) or PLC → elevation of the temperature set-point → fever`,`Directly activating COX in the hypothalamus`,`Inhibiting IL-1 beta and IL-6`], ans:1, exp:`Fever mechanism: infection → macrophages release IL-1beta, IL-6, TNF-alpha → enter blood → COX-2 induction in brain endothelium → PGE2 synthesis → PGE2 crosses to hypothalamic preoptic area → EP3/EP1/EP4 receptors → increased cAMP → raises temperature set-point → sympathetic activation → heat conservation + shivering → fever. NSAIDs/aspirin block COX → reduce PGE2 → antipyretic.` },
      { q:`Lipoxygenase (LOX) pathway produces:`, ch:[`Prostaglandins and thromboxanes`,`Leukotrienes (LTB4, LTC4, LTD4, LTE4) and lipoxins — critical for allergic inflammation and asthma`,`Prostacyclin`,`Lipoxins only`], ans:1, exp:`5-LOX pathway (in leukocytes): AA + 5-LOX + FLAP → 5-HPETE → LTA4. LTA4: (1) LTA4 hydrolase → LTB4 (potent neutrophil chemoattractant via BLT1 receptor); (2) glutathione S-transferase → LTC4 → LTD4 → LTE4 (cysteinyl leukotrienes, via CysLT1/CysLT2 receptors → bronchoconstriction, mucus secretion, edema). Montelukast (Singulair): CysLT1 antagonist for asthma.` },
      { q:`Lipoxins are "stop signals" for inflammation because they:`, ch:[`Activate neutrophil chemotaxis`,`Promote resolution of inflammation by inhibiting neutrophil infiltration, stimulating macrophage phagocytosis of apoptotic cells (efferocytosis), and promoting tissue repair`,`Activate mast cells`,`Increase leukotriene production`], ans:1, exp:`Lipoxins (LXA4, LXB4, and aspirin-triggered lipoxins/ATL): synthesized by transcellular metabolism (platelet LOX-12 + neutrophil LTA4; endothelial COX-2 + neutrophil 5-LOX). LXA4: binds ALX/FPR2 receptor → inhibits neutrophil migration, promotes macrophage phagocytosis of apoptotic neutrophils (efferocytosis) → resolution. Aspirin triggers production of 15-epi-LXA4 (aspirin-triggered lipoxin), part of aspirin's anti-inflammatory effects.` },
      { q:`The anti-inflammatory mechanism of corticosteroids includes:`, ch:[`Inhibiting COX directly (like NSAIDs)`,`Inducing lipocortin/annexin A1 → inhibits PLA2 → less AA release → less all eicosanoids; also inhibiting COX-2 gene expression, cytokine production, and NF-kB`,`Blocking leukotriene receptors`,`Inhibiting LOX directly`], ans:1, exp:`Corticosteroids (dexamethasone, prednisone) → GR activation → (1) induce annexin A1/lipocortin → inhibits PLA2 → less AA substrate for all eicosanoid pathways; (2) transrepression of NF-kB and AP-1 → less COX-2, iNOS, cytokines; (3) reduce prostaglandin and leukotriene synthesis. Broader than NSAIDs (which only block COX). Side effects: immunosuppression, Cushing's, osteoporosis.` },
      { q:`Zileuton is an anti-asthma drug that targets:`, ch:[`COX-1`,`5-LOX (lipoxygenase) — prevents LTB4 and cysteinyl leukotriene synthesis`,`CysLT1 receptor (same as montelukast)`,`Prostacyclin synthase`], ans:1, exp:`Zileuton: 5-LOX inhibitor → blocks leukotriene synthesis (both LTB4 and cysteinyl leukotrienes) at the enzyme level. Montelukast/zafirlukast: CysLT1 receptor antagonists (block leukotriene effect, not synthesis). Both used in asthma. Zileuton has hepatotoxicity concern. 5-LOX also involved in atherosclerosis and cancer.` },
      { q:`Thromboxane synthesis is primarily in platelets using COX-1. Prostacyclin synthesis is primarily in endothelium using:`, ch:[`COX-1 only`,`Both COX-1 and COX-2 (with prostacyclin synthase/PGIS)`,`COX-3 only`,`LOX only`], ans:1, exp:`Prostacyclin (PGI2): produced by endothelial cells using COX-1 (basal) and COX-2 (inducible) + prostacyclin synthase (PGIS). Unlike platelets (which are anucleate and cannot replace COX after irreversible aspirin inhibition), endothelial cells can synthesize new COX-2 → continue making PGI2 even with aspirin. Selective COX-2 inhibitors (coxibs) reduce PGI2 without affecting TXA2 → cardiovascular risk (↑ TXA2/PGI2 ratio).` },
      { q:`Platelet-activating factor (PAF) is:`, ch:[`A prostaglandin`,`A phospholipid mediator (acetyl-GPC) that activates platelets via PAF receptor → platelet aggregation and bronchoconstriction; also potent inflammatory mediator`,`A thromboxane analog`,`An endocannabinoid`], ans:1, exp:`PAF (1-O-alkyl-2-acetyl-sn-glycero-3-phosphocholine): synthesized by mast cells, neutrophils, platelets, eosinophils. PAF receptor (PAFR, GPCR) → Gq → PLC → Ca2+/PKC → platelet aggregation, bronchoconstriction, vasoconstriction, increased permeability, eosinophil activation. PAF acetylhydrolase (lipoprotein-associated, PAFAH1B2) rapidly inactivates PAF in blood.` },
      { q:`Endocannabinoids (anandamide, 2-AG) are lipid mediators derived from:`, ch:[`Arachidonic acid directly via COX`,`Membrane phospholipids on demand (not stored) — AA-containing lipids → N-arachidonoyl ethanolamine (anandamide) or 2-arachidonoylglycerol (2-AG) → activate CB1/CB2 receptors`,`Eicosapentaenoic acid (EPA)`,`Cholesterol`], ans:1, exp:`Endocannabinoids: released on demand from membrane lipids. Anandamide (AEA): N-arachidonoyl phosphatidylethanolamine → NAPE-PLD → AEA. 2-AG: DAG lipase from 1-2-AA-DAG. Both activate CB1 (brain: retrograde synapse modulation, psychoactivity) and CB2 (immune: immunomodulation). Metabolized by FAAH (anandamide) and MAGL (2-AG). Basis for THC pharmacology and endocannabinoid therapeutic interest (nabilone, rimonabant).` },
      { q:`NSAIDs (non-specific COX inhibitors) have what gastrointestinal side effect?`, ch:[`Constipation`,`Gastric ulceration and bleeding — due to loss of prostaglandin-mediated gastric protection (PGE2 and PGI2 maintain mucosal integrity by stimulating bicarbonate/mucus secretion and reducing acid secretion)`,`Malabsorption of all nutrients`,`Hepatotoxicity`], ans:1, exp:`COX-1 (constitutive): produces prostaglandins that protect gastric mucosa (PGE2 → EP3 receptor → decreases HCl secretion from parietal cells; PGE2/PGI2 → stimulates mucus and bicarbonate secretion). NSAID COX-1 inhibition → less gastroprotective prostaglandins → H. pylori or acid damage → ulcers. Misoprostol (PGE1 analog) or PPIs co-prescribed with NSAIDs. Selective COX-2 inhibitors (coxibs) spare gastric mucosa but increase CV risk.` },
    ]
  },
  {
    id:'bb53', cat:'Bio/Biochem', title:'Ketone Body Metabolism', diff:'Hard',
    qs:[
      { q:`Ketone bodies are synthesized in the:`, ch:[`Adipose tissue`,`Liver mitochondria — from acetyl-CoA generated by beta-oxidation when acetyl-CoA exceeds TCA capacity`,`Muscle`,`Brain`], ans:0, exp:`Ketogenesis occurs exclusively in liver mitochondria. During fasting/starvation: beta-oxidation exceeds TCA capacity (OAA is depleted → gluconeogenesis) → excess acetyl-CoA → ketogenesis. The liver cannot use ketone bodies (lacks succinyl-CoA transferase/thiophorase). Extrahepatic tissues (brain, heart, muscle, kidney) use ketones.` },
      { q:`The rate-limiting enzyme of ketogenesis is:`, ch:[`Acetyl-CoA acetyltransferase (thiolase)`,`HMG-CoA synthase (mitochondrial) — converts acetoacetyl-CoA + acetyl-CoA → HMG-CoA`,`HMG-CoA lyase`,`Beta-hydroxybutyrate dehydrogenase`], ans:1, exp:`Ketogenesis pathway: 2 acetyl-CoA → acetoacetyl-CoA (thiolase) → HMG-CoA (m-HMG-CoA synthase, rate-limiting) → acetoacetate + acetyl-CoA (HMG-CoA lyase). Acetoacetate → beta-hydroxybutyrate (BHBA, by BHBA-dehydrogenase, major form in blood) or → acetone (spontaneous decarboxylation). Note: m-HMG-CoA synthase is distinct from c-HMG-CoA synthase (cholesterol synthesis).` },
      { q:`Beta-hydroxybutyrate (BHB) is the predominant ketone body in blood because:`, ch:[`It is the only ketone body made`,`Under conditions of elevated NADH (from beta-oxidation), acetoacetate is reduced to BHB by BHBA-dehydrogenase; BHB:acetoacetate ratio reflects mitochondrial NADH/NAD+`,`BHB is more stable than acetoacetate`,`It is derived from glucose`], ans:1, exp:`Acetoacetate + NADH + H+ ↔ BHB + NAD+ (BHBA-dehydrogenase). When beta-oxidation is high → high NADH → equilibrium favors BHB. BHB:acetoacetate ratio in blood (~3:1 in DKA) reflects hepatic mitochondrial NADH/NAD+. BHB is not "acidic" in the standard sense (it's the salt form at physiologic pH, but together with acetoacetate depresses blood pH in DKA).` },
      { q:`Extrahepatic tissues use ketone bodies for energy via:`, ch:[`Direct beta-oxidation of BHB`,`BHB → acetoacetate (by BHBA-DH) → succinyl-CoA + acetoacetate → acetoacetyl-CoA (by succinyl-CoA-acetoacetate CoA transferase, SCOT/thiophorase) → 2 acetyl-CoA → TCA cycle`,`BHB → glucose via gluconeogenesis`,`BHB → fatty acids`], ans:1, exp:`Ketolysis: BHB → acetoacetate → acetoacetyl-CoA (SCOT transfers CoA from succinyl-CoA — present in all tissues except liver) → thiolase → 2 acetyl-CoA → TCA cycle. The liver lacks SCOT (succinyl-CoA:acetoacetate CoA-transferase) → cannot oxidize its own ketone bodies (prevents futile cycling). Brain uses ketones efficiently during starvation.` },
      { q:`Diabetic ketoacidosis (DKA) occurs in type 1 diabetes because:`, ch:[`High insulin + glucagon`,`Absolute insulin deficiency → unopposed glucagon → massive lipolysis → beta-oxidation → excessive ketogenesis beyond tissue capacity → metabolic acidosis (anion gap), hyperglycemia, ketonemia`,`Reduced liver ketone production`,`Normal glucose but high ketones only`], ans:1, exp:`DKA: no insulin → glucagon/catecholamines dominant → lipolysis (FFA flood to liver) → beta-oxidation → acetyl-CoA → excessive ketogenesis (acetoacetate + BHB → both are weak acids). Simultaneously: no insulin → hyperglycemia (no GLUT4). Metabolic acidosis: H+ from dissociation of keto acids → compensatory Kussmaul breathing. Labs: elevated anion gap, hyperglycemia, ketonemia, low HCO3-.` },
      { q:`Ketone body production is regulated primarily by:`, ch:[`Intracellular glucose concentration`,`Availability of fatty acids to the liver (determined by hormone-sensitive lipase activity in adipose) and the glucagon/insulin ratio regulating hepatic malonyl-CoA levels`,`Mitochondrial SCOT activity`,`Hepatic NADPH levels`], ans:1, exp:`Ketogenesis regulation: (1) FFA supply: insulin inhibits HSL → low FFA → low ketogenesis; glucagon/fasting → high FFA → high ketogenesis. (2) Malonyl-CoA: insulin → ACC → malonyl-CoA → CPT-I inhibited → less FA enters mitochondria. Fasting: AMPK → ACC inactive → low malonyl-CoA → CPT-I active → FA enters mitochondria → beta-oxidation → ketogenesis. Net: ketogenesis mirrors FFA supply and hepatic fat oxidation.` },
      { q:`Acetone (a ketone body) is clinically notable because:`, ch:[`It is the main energy substrate for the brain`,`It is volatile and exhaled → sweet/fruity breath in DKA; it can be converted to pyruvate/acetate (minor pathway) — largely useless as fuel but important diagnostic marker`,`It is metabolized to glucose`,`It causes lactic acidosis`], ans:1, exp:`Acetone: forms spontaneously from acetoacetate (non-enzymatic decarboxylation). Not significantly metabolized (mainly exhaled or excreted in urine). Clinical: "fruity breath" or "nail polish remover" odor in DKA/starvation ketosis. Acetone can be converted to pyruvate (minor pathway via acetol) but this is quantitatively minor. Urine ketone strips detect acetoacetate (and some acetone), not BHB.` },
      { q:`Medium-chain fatty acyl-CoA dehydrogenase (MCAD) deficiency causes:`, ch:[`Enhanced ketone body production`,`Impaired fatty acid oxidation (C6-C12) → during fasting: hypoketotic hypoglycemia (no energy from FA, no substrate for ketogenesis)`,`Increased glycogen storage`,`Excess TCA cycle intermediates`], ans:1, exp:`MCAD deficiency: inability to oxidize C6-C12 acyl-CoAs → during fasting (when these FAs are needed) → hypoketotic hypoglycemia (low ketones because FA can't enter beta-oxidation, low glucose because no energy from fat) → hypoglycemic encephalopathy. Diagnosis by neonatal screening (acylcarnitine profile: C8 acylcarnitine elevated). Treatment: avoid prolonged fasting.` },
      { q:`The "ketogenic diet" (high fat, very low carbohydrate) produces a physiological state resembling:`, ch:[`Fed state`,`Prolonged fasting — induces ketosis (elevated BHB) → brain uses ketones for ~75% of energy, reducing glucose utilization and potentially seizing threshold`,`Diabetes type 2`,`Liver disease`], ans:1, exp:`Ketogenic diet (KD): ~75-80% fat, 15-20% protein, <5% carbs → insulin low, glucagon-like metabolic state → hepatic ketogenesis. BHB is neuroprotective and anticonvulsant (exact mechanism unclear: HCAR2 receptor, KATP channel, mitochondrial effects). KD is effective for drug-resistant epilepsy, investigated for glioblastoma, Alzheimer's, and metabolic diseases.` },
      { q:`HMG-CoA lyase deficiency causes:`, ch:[`Elevated cholesterol`,`Inability to produce ketone bodies OR to complete leucine degradation → hypoglycemia + metabolic acidosis + NO ketonemia (unlike other causes of metabolic acidosis)`,`Methylmalonyl acidemia`,`Enhanced ketogenesis`], ans:1, exp:`HMG-CoA lyase (mitochondrial): cleaves HMG-CoA → acetoacetate + acetyl-CoA (ketogenesis) AND is required for leucine catabolism (HMG-CoA is an intermediate). Deficiency → (1) no ketogenesis → fasting hypoketotic hypoglycemia; (2) HMG-CoA + leucine metabolite accumulation → organic acidemia. Presentation: neonatal crisis with severe hypoglycemia, metabolic acidosis, and absence of ketonemia.` },
      { q:`The brain transitions from glucose to ketone body utilization during starvation because:`, ch:[`The blood-brain barrier blocks glucose after day 3`,`Ketone transporters (MCT1/2, monocarboxylate transporters) are upregulated in response to elevated blood ketones → brain can efficiently import and oxidize BHB and acetoacetate`,`Insulin is absent in the brain`,`Liver begins producing glucose from ketones`], ans:2, exp:`Brain adaptation: normally exclusive glucose user. During starvation: elevated blood BHB/acetoacetate → upregulates MCT1 expression in brain endothelium and neurons → efficient ketone import. Brain ketone oxidation (SCOT, BHBA-DH present) generates 2 acetyl-CoA per BHB → TCA cycle. By day 3-5 of starvation, ketones supply ~60%; by day 40+, ~70% of brain energy → protein (gluconeogenic precursors) spared.` },
      { q:`Why does DKA but not starvation ketosis lead to severe acidosis?`, ch:[`Starvation produces no acetoacetate`,`In DKA: unregulated, massive ketogenesis (very high insulin/glucagon ratio disturbance) overwhelms buffering capacity; in starvation, ketosis is self-limiting (ketones stimulate insulin release → negative feedback)`,`Starvation has different ketone bodies`,`DKA produces lactic acid, not ketone acids`], ans:1, exp:`Starvation ketosis: ketones rise to ~7-8 mM; ketones stimulate modest insulin release from residual beta cells → negative feedback limits ketogenesis. pH rarely below 7.30. DKA: type 1 diabetes = absolute insulin deficiency → no feedback → unrestrained ketogenesis → ketones 20-30 mM → severe metabolic acidosis (pH <7.3, sometimes <7.1). Glucosuria also causes volume depletion, worsening DKA.` },
    ]
  },
  {
    id:'bb54', cat:'Bio/Biochem', title:'Insulin & Counter-Regulatory Hormones', diff:'Hard',
    qs:[
      { q:`Insulin secretion from pancreatic beta cells is triggered by:`, ch:[`Low blood glucose`,`Glucose uptake via GLUT2 → glucokinase → ATP production → closure of K-ATP channels → membrane depolarization → voltage-gated Ca2+ entry → exocytosis of insulin granules`,`Glucagon stimulation`,`Fatty acid increase alone`], ans:1, exp:`Glucose-stimulated insulin secretion (GSIS): glucose → GLUT2 → glucokinase (glucose sensor, Km ~10 mM) → glycolysis → ATP/ADP ratio rises → K-ATP channel (Kir6.2/SUR1) closes → depolarization → L-type voltage-gated Ca2+ channels open → Ca2+ influx → vesicle fusion → insulin secretion. Sulfonylureas (glipizide, glibenclamide) block K-ATP → force depolarization → enhance insulin secretion.` },
      { q:`The primary anabolic effects of insulin on adipose tissue include:`, ch:[`Stimulating hormone-sensitive lipase (lipolysis)`,`Inhibiting HSL (reducing lipolysis), activating lipoprotein lipase (LPL, for TG uptake from VLDL/chylomicrons), and promoting glucose uptake (GLUT4) → TG synthesis`,`Promoting FFA release`,`Activating hormone-sensitive lipase via cAMP`], ans:1, exp:`Insulin on adipose: (1) inhibits HSL (via PDE activation → lower cAMP; direct dephosphorylation) → less lipolysis; (2) activates LPL on capillary endothelium → TG hydrolysis from chylomicrons/VLDL → FA uptake for re-esterification; (3) GLUT4 translocation → glucose → DHAP → glycerol-3-P for TG backbone; (4) activates acetyl-CoA carboxylase → de novo FA synthesis.` },
      { q:`Glucagon's primary target is:`, ch:[`Skeletal muscle`,`The liver — glucagon has minimal direct effects on muscle and adipose (at physiological concentrations); liver has high glucagon receptor density`,`The brain`,`The kidney`], ans:1, exp:`Glucagon: secreted by pancreatic alpha cells → binds glucagon receptor (Gs-coupled GPCR) on hepatocytes (very high receptor density) → cAMP → PKA → glycogenolysis, gluconeogenesis, ketogenesis. Glucagon also acts on adipose (especially in pharmacological concentrations) to stimulate HSL. Muscle lacks significant glucagon receptors.` },
      { q:`Epinephrine (adrenaline) is released from the adrenal medulla during stress. Its metabolic effects include:`, ch:[`Promoting glycogen synthesis and FA synthesis`,`Activating glycogenolysis (liver and muscle), lipolysis (adipose HSL), and gluconeogenesis → rapid glucose and FA mobilization`,`Stimulating insulin secretion`,`Inhibiting glucagon release`], ans:1, exp:`Epinephrine (beta-2 adrenergic on muscle/liver: glycogenolysis + gluconeogenesis; beta-1 on heart: increased CO; alpha-1 on adipose: lipolysis via HSL activation; beta-2 also inhibits insulin secretion → hyperglycemia). Epinephrine alpha-2 receptor also inhibits insulin secretion. Net: rapid fuel mobilization for fight-or-flight. Epinephrine inhibits insulin secretion from beta cells (alpha-2 receptor → cAMP decrease).` },
      { q:`Cortisol (glucocorticoid) counter-regulatory effects on metabolism include:`, ch:[`Promoting glucose uptake and glycogen synthesis`,`Stimulating gluconeogenesis (PEPCK, G6Pase gene induction), promoting proteolysis in muscle (substrate provision), and inhibiting glucose uptake in peripheral tissues (insulin resistance)`,`Inhibiting gluconeogenesis`,`Promoting lipogenesis`], ans:1, exp:`Cortisol (chronic stress hormone): (1) induces PEPCK, G6Pase → gluconeogenesis; (2) promotes muscle proteolysis → amino acids → gluconeogenesis substrate; (3) promotes lipolysis (visceral fat) → FFA; (4) insulin resistance in peripheral tissues (reduces IRS signaling). Net: hyperglycemia, muscle wasting, visceral obesity. Prolonged: Cushing's syndrome.` },
      { q:`Growth hormone (GH) is counter-regulatory because it:`, ch:[`Promotes glucose uptake in muscle`,`Reduces glucose uptake in peripheral tissues (GH-induced insulin resistance), promotes lipolysis, and increases IGF-1 (which promotes anabolism in muscle/bone)`,`Suppresses gluconeogenesis`,`Stimulates insulin secretion chronically`], ans:1, exp:`GH: anti-insulin effects — reduces insulin-stimulated glucose uptake and glycogen synthesis (insulin resistance); promotes lipolysis (FFA → liver → gluconeogenesis). IGF-1 (produced by liver in response to GH): promotes anabolic growth. Acromegaly (GH excess) → diabetes. Dawn phenomenon in T1DM: GH surge before awakening → insulin resistance → fasting hyperglycemia.` },
      { q:`The incretin effect is observed when:`, ch:[`Glucose is given intravenously`,`Oral glucose causes more insulin secretion than the same amount of IV glucose — due to GIP and GLP-1 from intestinal cells`,`Fasting increases insulin`,`Glucagon is given with glucose`], ans:1, exp:`Incretin effect: oral glucose → intestinal GIP (K cells) and GLP-1 (L cells) → amplify glucose-stimulated insulin secretion (GSIS) ~2-3 fold. IV glucose bypasses intestinal signal. GLP-1 also suppresses glucagon, slows gastric emptying, increases satiety. Incretin effect is reduced in T2DM. DPP-4 inhibitors and GLP-1 receptor agonists exploit this.` },
      { q:`Hypoglycemia (low blood glucose) triggers a counter-regulatory response that includes:`, ch:[`Increased insulin secretion`,`Glucagon secretion (first line), followed by epinephrine, then cortisol and GH (if hypoglycemia is prolonged or severe)`,`Increased GLP-1 release`,`Decreased gluconeogenesis`], ans:1, exp:`Counter-regulatory response to hypoglycemia (glucose <70 mg/dL): (1) glucagon → hepatic glycogenolysis + gluconeogenesis; (2) epinephrine (sympathoadrenal response, triggers hypoglycemic symptoms: tachycardia, tremor, sweating) → glycogenolysis + lipolysis; (3) cortisol + GH (>2-4h of hypoglycemia) → sustained gluconeogenesis. In T1DM: impaired glucagon response + hypoglycemia unawareness (no epinephrine response) → severe hypoglycemia risk.` },
      { q:`Somatostatin is released from pancreatic delta cells and:`, ch:[`Stimulates both insulin and glucagon`,`Inhibits both insulin (from beta cells) and glucagon (from alpha cells) secretion — acts as a paracrine brake on islet hormone secretion; also inhibits GH from pituitary`,`Stimulates glucagon only`,`Stimulates GLP-1 only`], ans:1, exp:`Somatostatin (SRIF): released from pancreatic delta cells (responding to high glucose, FFA, amino acids) → paracrine inhibition of beta cells (insulin) and alpha cells (glucagon). Acts as a brake to prevent excessive hormone secretion. Also released from hypothalamus (GH inhibition) and intestinal D cells (inhibits GI secretions). Octreotide (SST analog) used for acromegaly, carcinoid tumors, variceal bleeding.` },
      { q:`In the fasted state, the regulation of hepatic metabolism shifts so that:`, ch:[`Glycolysis and FA synthesis are maximally active`,`Gluconeogenesis, beta-oxidation, and ketogenesis are simultaneously activated; glycolysis and FA synthesis are suppressed`,`Insulin is the dominant regulatory hormone`,`AMPK is inactive`], ans:1, exp:`Fasted hepatic state: glucagon → cAMP → PKA → activates phosphorylase (glycogenolysis), inactivates PFK-2 (low F2,6BP → PFK-1 less active → glycolysis down) and PK, activates PEPCK/G6Pase (gluconeogenesis). Low insulin → AMPK active → ACC inhibited (low malonyl-CoA → CPT-I active → FA enters mitochondria → beta-oxidation). Excess acetyl-CoA + depleted OAA → ketogenesis.` },
      { q:`Type 2 diabetes pathophysiology involves:`, ch:[`Autoimmune destruction of beta cells`,`Insulin resistance in peripheral tissues (muscle, adipose, liver) + progressive beta cell dysfunction → relative insulin deficiency → hyperglycemia`,`Absolute insulin deficiency from day one`,`Glucagon deficiency`], ans:1, exp:`T2DM: initially, insulin resistance (excess nutrients → lipotoxicity, glucotoxicity, inflammation → impaired IRS-1/PI3K signaling) → compensatory hyperinsulinemia by beta cells. Over years: beta cell exhaustion (glucolipotoxicity, amyloid deposition of IAPP) → insufficient insulin → fasting and postprandial hyperglycemia. Glucagon is paradoxically elevated (alpha cell dysfunction) → adds to hyperglycemia.` },
      { q:`Metformin, the most common T2DM drug, primarily acts by:`, ch:[`Stimulating insulin secretion from beta cells`,`Inhibiting hepatic gluconeogenesis (via complex I inhibition → AMPK activation → phosphorylates CREB-CBP complex and decreases PEPCK/G6Pase expression) and increasing insulin sensitivity`,`Blocking K-ATP channels in beta cells`,`Activating GLP-1 receptor`], ans:1, exp:`Metformin: (1) inhibits mitochondrial complex I → elevated AMP/ATP ratio → AMPK activation → phosphorylates CBP at the CREB-CBP complex → reduced gluconeogenic gene expression (PEPCK, G6Pase); (2) activates AMPK → mTOR inhibition → reduced protein synthesis; (3) reduces hepatic fat accumulation. Does NOT cause hypoglycemia (no direct beta cell effect). Lactic acidosis risk in renal failure (impaired excretion).` },
    ]
  },
  {
    id:'bb55', cat:'Bio/Biochem', title:'Thyroid Hormone Synthesis', diff:'Hard',
    qs:[
      { q:`Thyroid hormone synthesis requires iodide uptake into follicular cells via:`, ch:[`GLUT transporters`,`NIS (sodium-iodide symporter) — secondary active transport (2 Na+ in / 1 I- in), driven by the Na+ gradient maintained by basolateral Na+/K+-ATPase`,`Ion channels`,`Pendrin on the apical membrane`], ans:1, exp:`NIS (SLC5A5): basolateral transporter in thyroid follicular cells. Secondary active transport: 2 Na+ (down gradient) + 1 I- (up gradient) → into cell. NIS is upregulated by TSH and iodine deficiency. Radioactive iodine (I-131) is taken up via NIS → destroys thyroid tissue (treatment for hyperthyroidism, thyroid cancer). Perchlorate (ClO4-) competitively inhibits NIS.` },
      { q:`Within the thyroid follicle lumen, iodide is oxidized and incorporated into thyroglobulin by:`, ch:[`NIS`,`Thyroid peroxidase (TPO) — on the apical membrane; oxidizes I- → I+ (using H2O2 from DUOX2) → organification of thyroglobulin Tyr residues → MIT and DIT formation → coupling to T3/T4`,`Deiodinase`,`Pendrin`], ans:1, exp:`TPO (thyroid peroxidase): (1) Oxidation: I- + H2O2 → reactive iodine species (I+ or I); (2) Organification: reactive iodine + thyroglobulin (Tg) Tyr residues → monoiodotyrosine (MIT) + diiodotyrosine (DIT); (3) Coupling: DIT+DIT → T4; MIT+DIT → T3 (within Tg). Propylthiouracil (PTU) and methimazole inhibit TPO → used for hyperthyroidism. PTU also inhibits peripheral T4→T3 conversion.` },
      { q:`T4 (thyroxine) is considered a prohormone because:`, ch:[`T4 is the active form that binds TRs`,`T4 must be converted to T3 by peripheral deiodinases — T3 is 3-5x more potent and binds TR with higher affinity`,`T4 is stored in lysosomes`,`T4 is inactive in all tissues`], ans:1, exp:`T4 (tetraiodothyronine, 2 iodines on each ring): produced in greater quantities (~80%) but lower potency. Peripheral deiodinases convert T4 → T3 (active, 5'-deiodination, type I and II DIO) or rT3 (reverse T3, inactive, type III DIO). Selenoproteins (type I/II DIO require selenium). Sick euthyroid syndrome: illness → downregulates type I DIO → elevated rT3, low T3.` },
      { q:`TSH (thyroid-stimulating hormone) from the anterior pituitary stimulates:`, ch:[`Thyroid hormone production by inhibition`,`NIS expression, TPO activity, thyroglobulin synthesis, and release of stored T4/T3 (via TSH receptor → Gs → cAMP → PKA → all steps of TH synthesis)`,`Only T4 release, not synthesis`,`Direct T3 binding in the thyroid`], ans:1, exp:`TSH receptor (TSHR): Gs-coupled GPCR on follicular cell membrane. TSH → cAMP → PKA → upregulates NIS transcription, thyroglobulin synthesis, TPO activity, DUOX2 (H2O2 generation), endocytosis of Tg from follicular lumen → lysosomal T3/T4 liberation → secretion. TSH receptor activating mutations → hyperthyroidism (toxic multinodular goiter). Graves' disease: TSI antibodies activate TSHR.` },
      { q:`Wolff-Chaikoff effect refers to:`, ch:[`Iodide stimulating TH synthesis`,`High iodide transiently inhibiting TH synthesis — excess iodide blocks organification; normally, the thyroid "escapes" after days (adaptation) by downregulating NIS`,`PTU inhibiting deiodinase`,`Hashimoto's thyroiditis pathology`], ans:1, exp:`Wolff-Chaikoff effect: pharmacological doses of iodide → acute inhibition of organification → transient hypothyroid state (used clinically: Lugol's iodine solution before thyroid surgery to reduce vascularity and hormone release; also used in thyroid storm). Normal thyroid escapes in ~2 weeks (NIS downregulation). Amiodarone (40% iodine by weight) can cause Wolff-Chaikoff-mediated hypothyroidism.` },
      { q:`T3 acts on target cells by:`, ch:[`Binding a cell-surface GPCR`,`Entering cells (passive) → binding intranuclear TRalpha or TRbeta → TR-RXR heterodimer binds TRE (thyroid response elements) → gene regulation (activates metabolic genes, suppresses TSH)`,`Activating adenylate cyclase`,`Binding to specific transport proteins in the nucleus`], ans:1, exp:`T3 (lipophilic): passive membrane crossing (some MCT8 transporter mediated) → binds TR (alpha/beta) in nucleus → TR-RXR heterodimer binds TRE → activation (with coactivators) or repression (with unliganded TR + corepressors). T3 activates: Na+/K+-ATPase, beta-adrenergic receptors, mitochondrial biogenesis (PGC-1alpha), glucose absorption, protein synthesis, GH secretion. T3 suppresses TSH and TRH (negative feedback).` },
      { q:`Hypothyroidism commonly presents with:`, ch:[`Weight loss, heat intolerance, palpitations`,`Fatigue, weight gain, cold intolerance, constipation, dry skin, bradycardia, elevated TSH (primary hypothyroidism) due to loss of T3/T4 negative feedback`,`Exophthalmos and goiter`,`Low TSH and high T4`], ans:1, exp:`Hypothyroidism (primary): TSH elevated (TRH/TSH not suppressed), low T4/T3. Common cause: Hashimoto's thyroiditis (autoimmune: anti-TPO, anti-Tg antibodies → lymphocytic thyroiditis → destruction). Clinical: fatigue, weight gain, cold intolerance, bradycardia, constipation, dry skin, macroglossia, delayed DTRs, myxedema, dyslipidemia. Treatment: levothyroxine (synthetic T4).` },
      { q:`Pendred syndrome (deafness + goiter) is caused by:`, ch:[`TPO mutations`,`Pendrin (SLC26A4) mutations — apical transporter that exports iodide into the follicular lumen; without pendrin, iodide cannot reach Tg → impaired TH synthesis → goiter; pendrin also in cochlea → sensorineural deafness`,`NIS mutations`,`TRalpha mutations`], ans:1, exp:`Pendrin: apical anion exchanger (I-/Cl-) in follicular cells → exports I- into follicular lumen for TPO-mediated organification. Also expressed in inner ear (endolymph regulation). SLC26A4 mutations → impaired iodide transport into lumen → reduced TH synthesis → TSH-driven goiter; + cochlear dysfunction → congenital deafness. Autosomal recessive, accounts for ~10% of hereditary deafness.` },
      { q:`Graves' disease is characterized by:`, ch:[`Anti-TPO antibodies causing hypothyroidism`,`TSI (thyroid-stimulating immunoglobulins) that are TSH receptor agonist antibodies → continuous TSHR activation → hyperthyroidism + goiter + exophthalmos`,`Anti-Tg antibodies causing thyroid destruction`,`TSH receptor loss-of-function`], ans:1, exp:`Graves' disease: autoimmune hyperthyroidism. TSI (IgG antibodies against TSHR extracellular domain) activate TSHR without regulation → continuous cAMP → unregulated TH synthesis + thyroid gland hyperplasia (goiter). TSI can cross placenta → neonatal hyperthyroidism. Exophthalmos (proptosis): orbital fibroblasts also have TSHR → TSI activates → glycosaminoglycan deposition + inflammation. Treatment: methimazole, PTU, radioiodine, thyroidectomy.` },
      { q:`Iodide deficiency leads to:`, ch:[`Hyperthyroidism`,`Goiter — TSH rises (no TH negative feedback) → thyroid gland hyperplasia; in severe deficiency: hypothyroidism; in fetus/neonate: cretinism (intellectual disability, growth retardation)`,`Decreased TSH production`,`Exophthalmos`], ans:1, exp:`Iodine deficiency (most common preventable intellectual disability worldwide): insufficient iodide → reduced TH synthesis → no negative feedback → elevated TSH → thyroid hyperplasia → goiter. If severe: hypothyroidism. In pregnancy: fetal hypothyroidism → cretinism (profound intellectual disability, growth failure, deafness, myxedema). Prevention: iodized salt. Iodine deficiency affects 30% of world population in deficient areas.` },
      { q:`The hypothalamic-pituitary-thyroid (HPT) axis works by:`, ch:[`Positive feedback — high T3/T4 increases TSH`,`Negative feedback — T3 inhibits TRH (from hypothalamus) and TSH (from anterior pituitary) production; when T3/T4 are low, TRH and TSH rise to stimulate thyroid`,`TSH directly controls hypothalamic TRH`,`Cortisol provides the primary feedback`], ans:1, exp:`HPT axis: hypothalamus → TRH → anterior pituitary → TSH → thyroid → T4/T3 → negative feedback at both hypothalamic (TRH) and pituitary (TSH subunit gene, TRH receptor) levels. T3 is the primary inhibitory signal (pituitary expresses high type 2 DIO → local T4→T3 conversion). Primary hypothyroidism: low T3/T4 → high TRH → high TSH (diagnostic). Secondary: pituitary disease → low TSH. Tertiary: hypothalamic disease → low TRH.` },
      { q:`Methimazole inhibits thyroid hormone synthesis by:`, ch:[`Blocking NIS`,`Inhibiting TPO (thyroid peroxidase) — prevents organification and coupling reactions, reducing TH synthesis; faster onset than PTU but crosses placenta more`,`Blocking T4→T3 conversion`,`Inhibiting TSH receptor`], ans:2, exp:`Methimazole (MMI): (1) inhibits TPO → blocks organification of iodide (and coupling) → no T3/T4 synthesis. Does NOT affect stored TH → clinical effect delayed 4-8 weeks (until stored T4 depleted). Preferred over PTU (except in pregnancy 1st trimester and thyroid storm). PTU: also inhibits TPO + inhibits peripheral type I DIO (T4→T3 conversion). Methimazole crosses placenta → can cause fetal hypothyroidism; used in 2nd/3rd trimester.` },
    ]
  },
  {
    id:'bb56', cat:'Bio/Biochem', title:'Steroid Hormone Synthesis', diff:'Hard',
    qs:[
      { q:`The rate-limiting step of steroid hormone synthesis is:`, ch:[`HMG-CoA reductase`,`Transport of cholesterol into the inner mitochondrial membrane by StAR (steroidogenic acute regulatory protein)`,`CYP11A1 (cholesterol side-chain cleavage enzyme)`,`3beta-HSD`], ans:1, exp:`StAR (steroidogenic acute regulatory protein): rapidly synthesized (minutes) in response to ACTH (adrenal), LH/FSH (gonads) → mitochondrial outer to inner membrane cholesterol transfer → rate-limiting step for steroidogenesis. CYP11A1 (P450scc, inner mitochondrial membrane): cholesterol → pregnenolone (first enzymatic step). StAR mutations → congenital lipoid adrenal hyperplasia.` },
      { q:`All steroid hormone synthesis begins in the mitochondria with conversion of cholesterol to:`, ch:[`Cortisol`,`Pregnenolone — by CYP11A1 (P450scc, cholesterol side-chain cleavage), using NADPH and 3 O2`,`Testosterone`,`Aldosterone`], ans:1, exp:`CYP11A1 (P450scc): cholesterol (C27) → pregnenolone (C21). Requires 3 O2 and 3 NADPH. Removes 6-carbon side chain from cholesterol. Pregnenolone is the common precursor for all steroid hormones. CYP11A1 is a mitochondrial cytochrome P450, dependent on adrenodoxin (iron-sulfur protein) and adrenodoxin reductase for electron transfer from NADPH.` },
      { q:`The zona glomerulosa of the adrenal cortex produces:`, ch:[`Cortisol and androgens`,`Aldosterone — via the unique expression of CYP11B2 (aldosterone synthase), which performs the final oxidations in the zona glomerulosa only`,`Cortisol only`,`DHEA and androstenedione`], ans:1, exp:`Adrenal cortex zones (from outside in): zona glomerulosa (outer): aldosterone (CYP11B2 = aldosterone synthase, does: 11-beta-hydroxylation + 18-hydroxylation + 18-oxidation). Zona fasciculata (middle): cortisol (CYP11B1 = 11-beta-hydroxylase). Zona reticularis (inner): androgens (DHEA, androstenedione). Different CYP11B isozymes explain zone-specific outputs.` },
      { q:`21-Hydroxylase (CYP21A2) deficiency is the most common congenital adrenal hyperplasia (CAH). It causes:`, ch:[`Excess mineralocorticoids and glucocorticoids`,`Excess androgens (17-hydroxyprogesterone cannot proceed to cortisol → diverts to androgens) + cortisol deficiency (→ ACTH rise → further androgen excess) ± salt wasting (if aldosterone also deficient)`,`Only estrogen excess`,`Only aldosterone deficiency`], ans:1, exp:`CYP21A2 deficiency: 17-OH-progesterone cannot be converted to 11-deoxycortisol → 17-OH-progesterone diverts to DHEA/androstenedione → testosterone → virilization (females: ambiguous genitalia; males: precocious puberty). ACTH rises (no cortisol feedback) → further androgen production. Classic salt-wasting form: aldosterone deficiency → hyponatremia, hyperkalemia, shock. 17-OH-progesterone is the diagnostic marker (elevated).` },
      { q:`Aromatase (CYP19A1) converts:`, ch:[`Progesterone to estradiol`,`Androgens (testosterone, androstenedione) to estrogens (estradiol, estrone) — key in ovary, adipose, breast tissue, and brain`,`Cholesterol to pregnenolone`,`Cortisol to cortisone`], ans:1, exp:`Aromatase (CYP19A1): microsomal enzyme in granulosa cells (ovary, primary site), adipose, breast, brain, placenta. Converts testosterone → estradiol and androstenedione → estrone. Requires O2 and NADPH. FSH stimulates aromatase in granulosa cells. Aromatase inhibitors (anastrozole, letrozole, exemestane) block estrogen synthesis in postmenopausal breast cancer (peripheral conversion in adipose is the main source after menopause).` },
      { q:`Cortisol is released from zona fasciculata in response to ACTH. Cortisol synthesis requires:`, ch:[`Only CYP11A1`,`CYP11A1 (cholesterol → pregnenolone) → 3beta-HSD → 17alpha-hydroxylase (CYP17A1) → CYP21A2 → CYP11B1 (11-deoxycortisol → cortisol)`,`Only CYP11B1`,`CYP17A1 only`], ans:1, exp:`Cortisol synthesis pathway (zona fasciculata): Cholesterol → pregnenolone (CYP11A1, mitochondrial) → 17OH-pregnenolone (CYP17A1, ER) → 17OH-progesterone (3beta-HSD) → 11-deoxycortisol (CYP21A2, ER) → cortisol (CYP11B1, mitochondria). Each CYP enzyme is a cytochrome P450 requiring NADPH and O2. CYP11B1 is exclusive to zona fasciculata; CYP11B2 is exclusive to zona glomerulosa.` },
      { q:`5alpha-Reductase converts testosterone to:`, ch:[`Estradiol`,`Dihydrotestosterone (DHT) — more potent androgen (binds AR with higher affinity), primarily active in prostate, skin, and external genitalia`,`Androstenedione`,`DHEA`], ans:1, exp:`5alpha-Reductase (5AR, types 1 and 2): reduces the A/B ring double bond (at C4-C5) of testosterone → DHT (5alpha-dihydrotestosterone). DHT binds AR ~5x more tightly than T → more potent in prostate and skin. 5AR type 2 deficiency: pseudohermaphroditism (46,XY with female external genitalia at birth, virilize at puberty). 5AR inhibitors (finasteride, dutasteride) used for BPH and male-pattern alopecia.` },
      { q:`ACTH (adrenocorticotropic hormone) stimulates the adrenal cortex by:`, ch:[`Activating a nuclear receptor`,`Binding MC2R (melanocortin-2-receptor, Gs-coupled) → cAMP → PKA → (1) rapid: StAR transcription (minutes), cholesterol delivery to mitochondria; (2) slower: transcription of CYP11A1 and other steroidogenic enzymes`,`Activating only CYP11B1 directly`,`Binding aldosterone synthase`], ans:1, exp:`ACTH → MC2R (adrenal-specific Gs-GPCR) → cAMP → PKA → (1) rapid acute effect (minutes): StAR phosphorylation + transcription → cholesterol transport → pregnenolone synthesis; (2) chronic trophic effect (hours-days): transcription of CYP11A1, CYP11B1, 3beta-HSD, CYP21A2 → increased steroidogenic capacity + adrenal hypertrophy. ACTH also stimulates adrenal androgen production (DHEA, DHEA-S).` },
      { q:`The enzyme 11beta-HSD type 1 (HSD11B1) is important in:`, ch:[`Converting testosterone to DHT`,`Converting cortisone (inactive) to cortisol (active) in peripheral tissues (especially liver, adipose, brain) — amplifying local glucocorticoid action`,`Converting progesterone to aldosterone`,`Inactivating cortisol in the kidney`], ans:1, exp:`11beta-HSD1 (reductase activity in vivo): converts cortisone → cortisol in liver, adipose, muscle, brain (amplifies glucocorticoid action). In obesity, adipose 11beta-HSD1 is upregulated → excess local cortisol → visceral fat accumulation, insulin resistance. 11beta-HSD2 (dehydrogenase): inactivates cortisol → cortisone in the kidney (mineralocorticoid protection: prevents cortisol activating MR). Carbenoxolone, licorice inhibit 11beta-HSD2 → cortisol activates MR → apparent mineralocorticoid excess.` },
      { q:`Cholesterol for steroid synthesis in the adrenal comes from:`, ch:[`Only de novo synthesis`,`Multiple sources: circulating LDL (via LDL receptor → receptor-mediated endocytosis → lysosomal CEH → free cholesterol), de novo synthesis (HMGCR), HDL (via SR-BI), and intracellular lipid droplet stores`,`Only dietary cholesterol`,`Only HDL`], ans:1, exp:`Adrenal cholesterol sources: (1) LDL receptor pathway (major, especially under basal conditions); (2) scavenger receptor SR-BI (HDL → selective CE uptake, major in rodents); (3) de novo synthesis (minor, but ACTH stimulates HMG-CoA reductase expression); (4) intracellular lipid droplets (stored CE). ACTH stimulation → rapid StAR-mediated mobilization + LDL uptake upregulation. Adrenals have the highest cholesterol content per gram of any organ.` },
      { q:`Congenital lipoid adrenal hyperplasia (CLAH) is caused by:`, ch:[`CYP21A2 deficiency`,`StAR mutations → cholesterol cannot enter inner mitochondrial membrane → no steroidogenesis → no cortisol, aldosterone, or sex hormones; cholesterol accumulates in adrenal → lipoid hyperplasia`,`CYP11A1 mutations`,`3beta-HSD deficiency`], ans:1, exp:`CLAH: most severe form of CAH. StAR mutations → no cholesterol delivery to inner mitochondrial membrane → CYP11A1 cannot function → no pregnenolone → no steroid hormones. Consequence: no cortisol (adrenal crisis), no aldosterone (salt wasting), no sex steroids (all 46,XY patients appear female). Cholesterol accumulates in adrenal → massive lipoid hyperplasia → secondary damage to all steroidogenic cells.` },
      { q:`Pseudohypoaldosteronism type 1 (PHA1) is caused by:`, ch:[`Aldosterone synthase deficiency`,`Loss-of-function mutations in MR (mineralocorticoid receptor) or ENaC subunits → resistance to aldosterone signaling → salt wasting, hyponatremia, hyperkalemia despite elevated aldosterone`,`Excess aldosterone production`,`CYP21A2 deficiency`], ans:3, exp:`PHA1: (1) autosomal dominant (MR mutations) or (2) autosomal recessive (ENaC subunit mutations, more severe). Both cause aldosterone resistance: salt wasting (hyponatremia), hyperkalemia, elevated aldosterone and renin. Treatment: high salt intake, potassium binders. Important to distinguish from primary hypoaldosteronism (low aldosterone) and CAH (different enzyme deficiencies).` },
    ]
  },
  {
    id:'bb57', cat:'Bio/Biochem', title:'Muscle Physiology & Biochemistry', diff:'Hard',
    qs:[
      { q:`The sliding filament theory of muscle contraction states that:`, ch:[`Sarcomere length decreases because myosin filaments shorten`,`Thin (actin) and thick (myosin) filaments slide past each other without changing length — cross-bridge cycling shortens the sarcomere`,`Sarcomere length increases during contraction`,`Only actin moves during contraction`], ans:1, exp:`Sliding filament theory (Huxley & Hanson, 1954): sarcomere shortening occurs because myosin heads (cross-bridges) attach to actin, pull actin toward the M-line, detach, and reattach. The I-band (actin only) and H-zone (myosin only) narrow; the A-band (myosin length) stays constant. ATP is required for cross-bridge cycling, especially for detachment (rigor without ATP, e.g., rigor mortis).` },
      { q:`The power stroke in muscle contraction is driven by:`, ch:[`ATP binding to myosin`,`ADP and Pi release from the myosin head → conformational change (lever arm movement) → actin filament pulled toward M-line`,`Ca2+ binding to troponin C`,`Tropomyosin movement`], ans:1, exp:`Cross-bridge cycle: (1) Rigor state: myosin-actin, no nucleotide. (2) ATP binds myosin → detaches from actin. (3) ATP hydrolysis (ATPase in myosin head) → myosin-ADP-Pi (energized, cocked position). (4) Myosin binds actin. (5) Pi release → POWER STROKE (ADP release → lever arm motion → force generation). (6) ADP release → return to rigor state. Net: 1 ATP consumed per cross-bridge cycle.` },
      { q:`Troponin and tropomyosin regulate skeletal muscle contraction by:`, ch:[`Directly generating force`,`Tropomyosin blocks myosin-binding sites on actin at rest; Ca2+ binds TnC → conformational change in TnI → tropomyosin moves → exposes binding sites → cross-bridge cycling begins`,`Providing structural support only`,`Regulating ATP hydrolysis directly`], ans:1, exp:`Regulatory protein complex: TnT (binds tropomyosin), TnI (inhibitory, blocks actin-myosin interaction at rest), TnC (Ca2+-binding, 4 EF-hand sites). Ca2+ binds TnC → TnI detaches from actin → tropomyosin shifts ~7 Å → myosin-binding sites on actin exposed → cross-bridge cycling. Clinical: troponin I and troponin T are cardiac-specific isoforms → elevated in myocardial infarction (diagnostic markers).` },
      { q:`Excitation-contraction coupling in skeletal muscle involves:`, ch:[`Hormone binding to a GPCR on the muscle cell`,`Action potential → T-tubule → voltage-sensing DHPR (L-type Ca2+ channel) → mechanically activates RyR1 (ryanodine receptor 1) on SR → Ca2+ flood from SR → binds TnC → contraction`,`Ca2+ entering from the extracellular space primarily`,`cAMP directly opening SR Ca2+ channels`], ans:1, exp:`Skeletal muscle EC coupling: AP → T-tubule (invaginates to SR) → DHPR (dihydropyridine receptor, voltage sensor) → conformational change → physically activates RyR1 (in SR junctional membrane) → Ca2+ release from SR without extracellular Ca2+ entry (unlike cardiac muscle where Ca2+-induced Ca2+ release via CICR is key). Ca2+ released → binds TnC → cross-bridge cycling.` },
      { q:`Smooth muscle contraction is regulated by a different mechanism than skeletal muscle. Smooth muscle uses:`, ch:[`Troponin and tropomyosin`,`Calmodulin-MLCK: Ca2+-CaM activates MLCK (myosin light-chain kinase) → phosphorylates myosin regulatory light chain → allows cross-bridge cycling; MLCP (phosphatase) relaxes muscle`,`Ryanodine receptor only`,`Direct Ca2+ binding to myosin`], ans:1, exp:`Smooth muscle regulation: no troponin. Ca2+-calmodulin → activates MLCK → phosphorylates MLC20 (myosin regulatory light chain) → allows myosin-actin cross-bridge cycling. MLCP (myosin light-chain phosphatase, PP1M, includes MYPT1 subunit) dephosphorylates MLC → relaxation. RhoA-ROCK (calcium sensitization): phosphorylates and inactivates MYPT1 → more phospho-MLC even without increased Ca2+ → sustained contraction.` },
      { q:`Fast-twitch (type IIa, IIx) vs. slow-twitch (type I) muscle fibers differ in:`, ch:[`Fiber size only`,`Myosin ATPase isoform (fast: MHC IIa/IIx, rapid ATP hydrolysis, quick fatigue; slow: MHC I/beta, slow ATPase, fatigue-resistant), mitochondrial content, and fuel usage`,`Only location in the body`,`Only response to neural stimulation`], ans:1, exp:`Type I (slow oxidative): red, many mitochondria, high myoglobin, oxidative metabolism, fatigue-resistant; marathon running. Type IIa (fast oxidative-glycolytic): intermediate. Type IIx/IIb (fast glycolytic): white, few mitochondria, glycolytic, generates high force but fatigues rapidly; sprinting. Motor neuron determines fiber type (cross-innervation experiments can switch types).` },
      { q:`Creatine phosphate (phosphocreatine) is important in muscle because:`, ch:[`It is stored glycogen equivalent`,`It immediately regenerates ATP via creatine kinase (PCr + ADP → Cr + ATP) during maximal exercise — acts as a phosphate buffer for the first ~10 seconds`,`It drives the tricarboxylic acid cycle`,`It stores oxygen like myoglobin`], ans:1, exp:`Phosphocreatine (PCr): high-energy phosphate compound in muscle (~4-5x resting ATP). Creatine kinase (CK): PCr + ADP → ATP + Cr (very fast, forward reaction during intense exercise; reverse in recovery). Provides ATP for ~6-10 seconds of maximal exertion. CK isoforms: MM (muscle), MB (cardiac), BB (brain). Elevated CK-MM: muscle damage; CK-MB: myocardial injury.` },
      { q:`Duchenne muscular dystrophy (DMD) is caused by:`, ch:[`Myosin heavy chain mutation`,`Dystrophin (DMD gene, X-linked) loss-of-function — dystrophin links intracellular F-actin cytoskeleton to extracellular matrix via DGC (dystrophin-glycoprotein complex) → mechanical stability; absence → membrane fragility → Ca2+ influx → necrosis`,`Troponin mutation`,`Myophosphorylase deficiency`], ans:1, exp:`DMD: X-linked recessive, frameshift/deletion mutations in DMD gene → absence of dystrophin → repeated contraction-induced membrane tears → Ca2+ entry → muscle fiber necrosis + incomplete regeneration → progressive muscle wasting. Onset ~3-5y, wheelchair-bound ~10-12y, cardiomyopathy. Exon-skipping therapies (eteplirsen) restore partial dystrophin. Becker MD: in-frame mutations → truncated but partly functional dystrophin → milder.` },
      { q:`SERCA (sarco/endoplasmic reticulum Ca2+-ATPase) in muscle:`, ch:[`Releases Ca2+ from the SR`,`Re-sequesters Ca2+ back into the SR using ATP hydrolysis after contraction, allowing muscle to relax`,`Activates myosin`,`Is the same as the Na+/K+-ATPase`], ans:1, exp:`SERCA (P-type ATPase): pumps 2 Ca2+ into SR per ATP hydrolyzed, against 10,000-fold concentration gradient (SR [Ca2+] ~1 mM, cytoplasm resting ~100 nM). Phospholamban (PLB) inhibits SERCA2a in cardiac SR at rest; PKA phosphorylates PLB → releases inhibition → faster Ca2+ re-uptake → faster relaxation (lusitropic effect of beta-agonists/adrenergic stimulation in heart).` },
      { q:`Malignant hyperthermia (MH) is caused by:`, ch:[`Hyperactivation of MLCK`,`Mutations in RyR1 (or DHPR) → uncontrolled Ca2+ release from SR in response to volatile anesthetics (halothane) or succinylcholine → sustained muscle contraction + thermogenesis → life-threatening hyperthermia + rhabdomyolysis`,`Myoglobin accumulation`,`Troponin mutations`], ans:1, exp:`MH: autosomal dominant mutations in RYR1 (most common) or CACNA1S (DHPR). Trigger: volatile anesthetics (halothane, sevoflurane) ± depolarizing NMB (succinylcholine) → prolonged RyR1 opening → massive SR Ca2+ leak → sustained cross-bridge cycling → heat, CO2, rigidity, rhabdomyolysis, hyperkalemia, acidosis. Treatment: dantrolene (RyR1 blocker → reduces SR Ca2+ release).` },
      { q:`The sarcoplasmic reticulum in skeletal muscle is specialized to:`, ch:[`Synthesize glycogen`,`Store and rapidly release large amounts of Ca2+ (via RyR1) during excitation — SR is a specialized ER with very high Ca2+ binding capacity (calsequestrin)`,`Generate ATP via oxidative phosphorylation`,`House the myosin thick filaments`], ans:1, exp:`SR: highly specialized ER in muscle → stores ~90% of muscle Ca2+ (~1 mM in SR lumen, bound to calsequestrin). Junctional SR (terminal cisternae): directly opposed to T-tubule DHPR → RyR1 release. SERCA pumps Ca2+ back. SR Ca2+ overload: DAD (delayed afterdepolarizations) in cardiac muscle → arrhythmia. Calsequestrin (CASQ2) mutations → catecholaminergic polymorphic VT (CPVT).` },
    ]
  },
  {
    id:'bb58', cat:'Bio/Biochem', title:'Nerve Physiology & Neurotransmission', diff:'Hard',
    qs:[
      { q:`The resting membrane potential (~-70 mV in neurons) is maintained primarily by:`, ch:[`Na+/K+-ATPase directly generating the potential`,`K+ leak channels (more permeable to K+ at rest) + Na+/K+-ATPase (electrogenic, 3 Na+ out / 2 K+ in, creating small negative contribution)`,`Cl- channels only`,`Ca2+ pumps primarily`], ans:1, exp:`Resting potential: primarily due to K+ equilibrium potential (Ek ~ -90 mV) because the membrane is mostly K+-permeable at rest (Kir channels). Na+/K+-ATPase: (1) maintains ion gradients (high Ki, low Nai) and (2) is slightly electrogenic (net 1 positive charge out per cycle → -5 to -10 mV contribution). Goldman equation considers permeabilities of K+, Na+, Cl-.` },
      { q:`The action potential depolarization phase is caused by:`, ch:[`K+ efflux`,`Rapid opening of voltage-gated Na+ channels (Nav) → massive Na+ influx → membrane depolarizes toward +40 mV (Na+ equilibrium potential ~+60 mV)`,`Cl- influx`,`Ca2+ influx in all neurons`], ans:1, exp:`AP phases: threshold depolarization (-70 → -55 mV) → voltage-gated Nav opens (m gates open) → Na+ influx → depolarization (+40 mV, overshoots 0). Repolarization: Nav h-gate closes (inactivation) + voltage-gated K+ channels (Kv) open (delayed) → K+ efflux → repolarization. Hyperpolarization (afterhyperpolarization): Kv slow to close → briefly below rest.` },
      { q:`Refractory periods in neurons are explained by:`, ch:[`K+ channels closing rapidly`,`Absolute refractory: Nav h-gate inactivation (cannot reopen regardless of stimulus); relative refractory: Nav h-gate recovering + Kv still open (higher threshold needed)`,`Ca2+ channels inactivation`,`Na+/K+-ATPase overactivity`], ans:1, exp:`Absolute refractory period (ARP): Nav is inactivated (h-gate closed) — cannot respond to any stimulus. Lasts ~1-2 ms. Relative refractory period (RRP): h-gate partially recovered, but Kv still open → membrane more negative than rest → higher threshold needed for AP. ARP limits maximum firing rate and ensures one-way AP propagation.` },
      { q:`Myelination of axons increases conduction velocity by:`, ch:[`Increasing Na+ channel density uniformly`,`Saltatory conduction — myelin insulates internodal regions, restricting current flow to nodes of Ranvier (high Nav density) → AP jumps from node to node → much faster`,`Decreasing internodal distance`,`Increasing the diameter of the axon directly`], ans:1, exp:`Myelin (from Schwann cells in PNS, oligodendrocytes in CNS): high-resistance, low-capacitance wrap that insulates the axon. Current flows fast through cytoplasm and jumps to the next node of Ranvier (saltatory = "jumping" conduction). Unmyelinated C fibers: 0.5-2 m/s. Myelinated A-alpha: 70-120 m/s. Multiple sclerosis: demyelination → slowed/blocked conduction → neurological deficits.` },
      { q:`Synaptic vesicle exocytosis requires:`, ch:[`cAMP second messenger`,`Voltage-gated Ca2+ channel (Cav2.1/2.2 at active zones) opening → Ca2+ influx → SNARE protein complex (synaptobrevin-SNAP-25-syntaxin) + synaptotagmin (Ca2+ sensor) → vesicle fusion`,`Receptor activation before Ca2+ entry`,`IP3-mediated Ca2+ release`], ans:1, exp:`Neurotransmitter release: AP → Cav2.1 (P/Q type, CNS) or Cav2.2 (N type) at active zones → Ca2+ influx → Ca2+ binds synaptotagmin 1 (C2 domains) → synaptotagmin displaces complexin → SNARE complex zippering → vesicle membrane fusion → NT exocytosis (quantal). Botulinum toxin: cleaves SNARE proteins (SNAP-25 or synaptobrevin) → prevents vesicle fusion → flaccid paralysis.` },
      { q:`The principal excitatory neurotransmitter in the CNS is:`, ch:[`GABA`,`Glutamate — acts on AMPA, NMDA, and kainate receptors; released by >80% of CNS synapses`,`Dopamine`,`Glycine`], ans:1, exp:`Glutamate: major excitatory NT. AMPA receptors (ionotropic, Na+/K+, rapid depolarization); NMDA receptors (ionotropic, Ca2+/Na+/K+, require both glutamate AND glycine co-agonist AND membrane depolarization to remove Mg2+ block → coincidence detector for LTP); kainate (ionotropic); mGluRs (metabotropic). Glutamate excess → excitotoxicity (stroke, TBI) via NMDA Ca2+ overload.` },
      { q:`GABA (gamma-aminobutyric acid) is the main inhibitory NT in the CNS. GABA-A receptors are:`, ch:[`G-protein coupled receptors`,`Ligand-gated Cl- channels (ionotropic) — GABA opens Cl- channel → Cl- influx (usually hyperpolarizing) → inhibition`,`Metabotropic receptors coupled to K+ channels`,`NMDA-type receptors`], ans:1, exp:`GABA-A: pentameric Cys-loop ligand-gated ion channel. GABA binding → Cl- channel opens → Cl- influx → membrane hyperpolarization → inhibition. Allosteric modulators at distinct sites: benzodiazepines (enhance GABA affinity, don't open channel alone); barbiturates (increase channel open duration); propofol and etomidate (similar); ethanol; neurosteroids (allopregnanolone). GABA-B: Gi/Go-coupled → K+ opens (slow IPSP) / Ca2+ closes.` },
      { q:`Long-term potentiation (LTP) at glutamatergic synapses requires:`, ch:[`GABA-A receptor activation`,`NMDA receptor activation (requiring simultaneous pre- and postsynaptic activity to remove Mg2+ block) → Ca2+ influx → CaMKII activation → AMPA receptor insertion + phosphorylation → strengthened synapse`,`Dopamine D1 receptor activation`,`Decrease in synaptic vesicle recycling`], ans:1, exp:`LTP: (1) weak stimulation → AMPA-mediated EPSPs (NMDA blocked by Mg2+). (2) Strong/repeated stimulation → sufficient depolarization → Mg2+ leaves NMDA → Ca2+ enters. (3) Ca2+ → CaMKII (calmodulin kinase II) → phosphorylates AMPA-GluA1 (increased single-channel conductance) + drives AMPA insertion into synapse → more AMPAs → larger EPSP. (4) CREB phosphorylation → late LTP (new protein synthesis).` },
      { q:`The neuromuscular junction (NMJ) uses which neurotransmitter and receptor?`, ch:[`Norepinephrine and alpha-adrenergic receptor`,`Acetylcholine (ACh) acting on nicotinic ACh receptors (nAChR, ionotropic Na+/K+ channel) at the motor end plate`,`Glutamate and AMPA receptors`,`Dopamine and D2 receptors`], ans:1, exp:`NMJ: motor neuron terminal releases ACh → nAChR (pentameric ligand-gated Na+/K+ channel, subunit composition alpha2-beta-delta-epsilon at adult NMJ) → Na+ influx → end-plate potential (EPP) → AP in muscle → EC coupling. AChE (acetylcholinesterase) rapidly hydrolyzes ACh. Myasthenia gravis: anti-nAChR antibodies. Lambert-Eaton: anti-VGCC antibodies (blocks ACh release). Botulinum toxin: SNARE cleavage → no ACh release.` },
      { q:`Substance P is a neuropeptide involved in:`, ch:[`Motor control`,`Pain transmission — released from primary afferent nociceptive C fibers at the dorsal horn → NK1 receptor → enhanced pain signaling (slow component); also from sensory neurons → neurogenic inflammation (vasodilation, extravasation)`,`Balance and coordination`,`Synaptic inhibition`], ans:1, exp:`Substance P (SP, NK-1 receptor): undecapeptide released by C-fiber nociceptors in dorsal horn → NK1 receptor on projection neurons → amplifies pain. Also released peripherally → neurogenic inflammation. Substance P also important in vomiting (NK1 receptors in dorsal vagal nucleus → anti-emetics: aprepitant, NK1 antagonist, used for chemotherapy-induced nausea). Codergocrine, morphine inhibit SP release.` },
      { q:`Local anesthetics (lidocaine, bupivacaine) block pain by:`, ch:[`Activating GABA-A receptors`,`Blocking voltage-gated Na+ channels (Nav) from the intracellular side in a use-dependent manner → prevents AP initiation and propagation in pain fibers`,`Blocking NMDA receptors`,`Increasing K+ permeability`], ans:1, exp:`Local anesthetics (tertiary amines, pKa ~7.5-8.5): membrane-permeable neutral form diffuses across membrane → protonated form (cationic) blocks open/inactivated Nav from inside → use-dependent block (more firing = more block). Smallest diameter, unmyelinated C fibers (pain) blocked first; large myelinated A-alpha (motor, proprioception) blocked last. Vasoconstrictors (epinephrine) co-administered → reduce clearance → prolong effect.` },
      { q:`The blood-brain barrier (BBB) is formed by:`, ch:[`Astrocyte foot processes alone`,`Brain microvascular endothelial cells with tight junctions (claudin-5, occludin, ZO-1) + pericytes + astrocyte end-feet — highly selective barrier for most molecules`,`Only the myelin sheath`,`Oligodendrocytes`], ans:1, exp:`BBB: brain capillary endothelium with tight junctions (minimal paracellular permeability) + pericytes + astrocyte end-feet (produce barrier-inducing factors). Lipophilic molecules (O2, CO2, steroids, ethanol) freely cross. Glucose (GLUT1), amino acids (LAT1), and specific transporters mediate essential nutrient entry. P-glycoprotein (MDR1) efflux pump removes many drugs (barrier to CNS drug delivery). BBB breakdown in neuroinflammation, stroke, MS.` },
    ]
  },
  {
    id:'bb59', cat:'Bio/Biochem', title:'GI Hormones', diff:'Hard',
    qs:[
      { q:`Gastrin is produced by G cells in the gastric antrum and stimulates:`, ch:[`Pancreatic enzyme secretion`,`Gastric acid secretion (by parietal cells via CCK-B/gastrin receptor → IP3/Ca2+ → H+/K+-ATPase activation), and gastric mucosal growth`,`Bile release from gallbladder`,`Small intestinal motility only`], ans:1, exp:`Gastrin: secreted by antral G cells in response to protein in the stomach, vagal stimulation, gastric distension. Acts on parietal cells via CCK-B (= gastrin) receptors → Gq → IP3 → Ca2+ → PKC + histamine (ECL cells) → H+/K+-ATPase (proton pump) → HCl secretion. Also stimulates ECL cells directly. Gastrin is also a trophic factor for gastric mucosa. Zollinger-Ellison syndrome: gastrinoma → excess gastrin → severe peptic ulcer disease.` },
      { q:`Secretin is released from S cells in the duodenum in response to:`, ch:[`Fat in the duodenum`,`Acid (low pH) in the duodenum → stimulates pancreatic ductal cells to secrete HCO3- and water (buffering the acid)`,`Protein digestion products`,`Glucose absorption`], ans:1, exp:`Secretin: released by S cells (duodenum/jejunum) when luminal pH <4.5. Acts on pancreatic ductal cells (via Gs → cAMP → CFTR → Cl-/HCO3- exchanger → HCO3- secretion) → neutralizes gastric acid in duodenum. Also inhibits gastric acid secretion (feedback). Secretin test: used to diagnose gastrinoma (exaggerated gastrin release in ZE syndrome).` },
      { q:`CCK (cholecystokinin) is released by I cells in response to:`, ch:[`Stomach acid`,`Fat and protein in the duodenum → stimulates gallbladder contraction, pancreatic enzyme secretion, and sphincter of Oddi relaxation`,`Hypoglycemia`,`Alkaline duodenal pH`], ans:1, exp:`CCK: released by I cells (duodenum/proximal jejunum) in response to fat (FFA, monoacylglycerol) and protein (partially digested peptides). CCK-A receptor (peripheral): gallbladder contraction (bile release) + pancreatic acinar cell enzyme secretion (amylase, lipase, proteases) + sphincter of Oddi relaxation → fat digestion. CCK-B receptor (brain): satiety. CCK also slows gastric emptying.` },
      { q:`GLP-1 (glucagon-like peptide-1) is released from:`, ch:[`Pancreatic alpha cells`,`Intestinal L cells (distal ileum, colon) in response to fat and glucose → stimulates insulin secretion, suppresses glucagon, slows gastric emptying, promotes satiety`,`Gastric G cells`,`Duodenal S cells`], ans:1, exp:`GLP-1: proglucagon-derived peptide (same gene as glucagon, different processing). L cells (ileum, colon): released in response to nutrients. Actions: (1) potentiates GSIS (incretin effect, via GLP-1R/Gs → cAMP in beta cells → K-ATP closure → insulin secretion); (2) suppresses glucagon; (3) slows gastric emptying; (4) reduces appetite (CNS GLP-1R). DPP-4 rapidly degrades GLP-1 (t1/2 ~1-2 min). GLP-1 receptor agonists (semaglutide, liraglutide) are major T2DM and obesity drugs.` },
      { q:`Motilin is a GI hormone that:`, ch:[`Stimulates HCl secretion`,`Triggers the migrating motor complex (MMC, interdigestive motility pattern) — the housekeeping contractions that sweep debris from stomach and small intestine between meals`,`Inhibits pancreatic enzyme secretion`,`Promotes gastric relaxation`], ans:1, exp:`Motilin: secreted by M cells and enterochromaffin cells in the upper small intestine during fasting (cyclically, every ~90-100 min) → initiates Phase III of the MMC (high-amplitude propagating contractions that sweep from stomach to ileum). Macrolide antibiotics (erythromycin) are motilin receptor agonists → prokinetic effect → used for gastroparesis. Motilin receptor agonists also used in GI motility disorders.` },
      { q:`Vasoactive intestinal peptide (VIP) is released from enteric neurons and causes:`, ch:[`Vasoconstriction and smooth muscle contraction`,`Smooth muscle relaxation (lower esophageal sphincter, pylorus), increased intestinal secretion, vasodilation, and inhibition of gastric acid — acts as a "non-adrenergic non-cholinergic" (NANC) neurotransmitter`,`Increased gastric acid secretion`,`Gallbladder contraction`], ans:1, exp:`VIP (Gs-coupled VPAC1/VPAC2 receptors → cAMP): secreted by enteric nervous system neurons (IPAN, secretomotor neurons). Actions: intestinal smooth muscle relaxation (including LES → achalasia from VIP neuron loss); stimulates intestinal Cl- and water secretion; pancreatic secretion; vasodilation. VIPoma (Verner-Morrison syndrome, WDHA): excess VIP → watery diarrhea, hypokalemia, achlorhydria.` },
      { q:`Ghrelin is called the "hunger hormone" because it:`, ch:[`Promotes satiety after a meal`,`Is released from gastric oxyntic cells when the stomach is empty → stimulates appetite via the hypothalamic arcuate nucleus (NPY/AgRP neurons) and GH release from the pituitary`,`Stimulates glucagon from the pancreas`,`Inhibits gastric emptying`], ans:1, exp:`Ghrelin: acylated peptide (octanoylation at Ser3 required for activity, by GOAT — ghrelin O-acyltransferase). Released from fundal X/A-like cells during fasting → rises pre-meal. GHSR (growth hormone secretagogue receptor) in hypothalamus: activates NPY/AgRP neurons → increases appetite + decreases energy expenditure. Also stimulates GH release from anterior pituitary. Ghrelin falls after food intake.` },
      { q:`Leptin is produced by adipose tissue and acts in the hypothalamus to:`, ch:[`Increase appetite`,`Signal satiety and energy stores — decreases NPY/AgRP (orexigenic) neurons and activates POMC/CART (anorexigenic) neurons → reduced food intake, increased energy expenditure`,`Stimulate GI motility`,`Promote GI secretion`], ans:1, exp:`Leptin: adipocyte-derived hormone (ob gene product). Acts on LepR (JAK2-STAT3 signaling) in arcuate nucleus: (1) inhibits NPY/AgRP neurons (hunger); (2) activates POMC/CART neurons → alpha-MSH → MC4R → decreased food intake + increased energy expenditure. Leptin-deficient mice (ob/ob): massive obesity, diabetes. Leptin resistance in obesity: high leptin but impaired signaling → insufficient satiety.` },
      { q:`Peptide YY (PYY3-36) is released from L cells after eating. It acts as a:`, ch:[`Hormone that stimulates further eating`,`Satiety signal — acts on Y2 receptors in the hypothalamic arcuate nucleus → inhibits NPY/AgRP neurons → reduces appetite; also slows gastric emptying (ileal brake)`,`Prokinetic hormone`,`Gastric acid stimulant`], ans:1, exp:`PYY (peptide YY, 3-36 form): released from L cells (same as GLP-1) of ileum and colon after meals (proportional to caloric content). Acts on hypothalamic Y2 autoreceptors (inhibit NPY/AgRP neurons presynaptically) → reduces food intake. Also slows gastric emptying and intestinal transit (ileal brake — fat in ileum inhibits gastric emptying). PYY and GLP-1 are both from L cells and synergistically signal satiety.` },
      { q:`Pancreatic polypeptide (PP) is secreted by F cells in the pancreatic islets and:`, ch:[`Stimulates exocrine pancreatic secretion`,`Inhibits exocrine pancreatic secretion and gallbladder contraction; acts as a satiety signal; released in response to protein intake and hypoglycemia`,`Stimulates bile secretion`,`Promotes glucagon release`], ans:1, exp:`PP (pancreatic polypeptide): secreted by F (or PP) cells in pancreatic islets, in response to a protein-rich meal, hypoglycemia, and vagal stimulation. Y4 receptor (hypothalamus, GI). Actions: (1) inhibits pancreatic exocrine secretion; (2) reduces gallbladder motility; (3) contributes to satiety. PP levels are low in obesity and elevated after gastric bypass surgery (contributing to reduced appetite post-bypass).` },
      { q:`The "brain-gut axis" refers to:`, ch:[`The physical connection between the brain and intestine`,`Bidirectional communication between the CNS and enteric nervous system — via vagal (enteric→brain: satiety signals; brain→enteric: regulate motility, secretion) and hormonal pathways`,`Only hormonal signaling from gut to brain`,`Only serotonin from the gut`], ans:1, exp:`Brain-gut axis: vagal afferents (mechanoreceptors, chemoreceptors) → brainstem → limbic → cortex. Vagal efferents (parasympathetic): regulate gastric acid, motility, insulin secretion. ENS (~500 million neurons): often called the "second brain" — can function autonomously but is modulated by vagal and sympathetic inputs. Gut-derived hormones (GLP-1, PYY, CCK) act on vagal afferents AND cross BBB. Serotonin (95% from enterochromaffin cells) activates 5-HT3/4 on vagal afferents → nausea, fullness, motility.` },
      { q:`Histamine from gastric ECL cells stimulates acid secretion by:`, ch:[`Directly pumping protons`,`Binding H2 receptors on parietal cells → Gs → cAMP → PKA → H+/K+-ATPase (proton pump) activation → HCl secretion`,`Activating M3 muscarinic receptors`,`Binding to gastrin receptors`], ans:1, exp:`Parietal cell stimulation pathways (all converge on H+/K+-ATPase activation): (1) Histamine → H2 receptor (Gs → cAMP → PKA); (2) Gastrin/CCK → CCK-B receptor (Gq → Ca2+); (3) Acetylcholine → M3 receptor (Gq → Ca2+). H2 blockers (ranitidine, famotidine) → reduce cAMP → reduce acid. PPIs (omeprazole, esomeprazole) → irreversibly block H+/K+-ATPase → most potent acid suppression.` },
    ]
  },
  { id:`bb60`, cat:`Bio/Biochem`, title:`Oxidative Phosphorylation & ATP Synthase`, diff:`Expert`, qs:[
      { q:`The proton motive force (pmf) across the inner mitochondrial membrane consists of:`, ch:[`Only a pH gradient`,`Only a membrane potential`,`Both a chemical gradient (ΔpH) and an electrical gradient (ΔΨ) — pH is the larger contributor in mitochondria`,`Neither gradient — ATP synthase uses substrate-level phosphorylation`], ans:2, exp:`pmf = ΔΨ + Z·ΔpH (Z ≈ 59 mV/pH unit at 37°C). In mitochondria: ΔΨ ≈ −150–180 mV (inside negative), ΔpH ≈ 0.5–1 unit (matrix alkaline). Total pmf ≈ −200 mV. In chloroplasts: ΔpH dominates. ATP synthase F0 subunit is the proton channel; F1 subunit contains catalytic β-subunits. Uncouplers (DNP, FCCP) dissipate pmf → heat without ATP synthesis. Oligomycin blocks F0 c-ring → halts ATP synthesis and O2 consumption.` },
      { q:`Complex I of the electron transport chain:`, ch:[`Transfers electrons from FADH2 to CoQ`,`Transfers electrons from NADH to CoQ, pumping 4 H+ per pair of electrons`,`Is inhibited by antimycin A`,`Is also called cytochrome bc1 complex`], ans:1, exp:`Complex I (NADH:ubiquinone oxidoreductase): NADH → FMN → 8 iron-sulfur clusters → CoQ. Pumps 4H+ per 2e−. Inhibitors: rotenone (pesticide), amobarbital, MPTP (Parkinson model). Complex II (SDH): FADH2 → CoQ; does NOT pump protons. Complex III (bc1): CoQ → cytochrome c; pumps 4H+ via Q-cycle; inhibited by antimycin A. Complex IV (cytochrome c oxidase): cytochrome c → O2; pumps 2H+ per 2e−; inhibited by cyanide, CO, azide.` },
      { q:`The binding change mechanism of ATP synthase proposes that:`, ch:[`Each β-subunit independently catalyzes ATP synthesis`,`The three β-subunits simultaneously cycle through open (O), loose (L), and tight (T) conformations as the γ-subunit rotates`,`ATP is synthesized by direct chemical phosphorylation without conformational change`,`The c-ring rotation is driven by ATP hydrolysis under normal conditions`], ans:1, exp:`Boyer's binding-change mechanism (Nobel 1997): γ-subunit rotation (driven by proton flux through F0 c-ring) drives sequential conformational changes in three β-subunits: O (open, low affinity) → L (loose, ADP+Pi bind) → T (tight, ATP synthesized spontaneously) → O (ATP released). Energy input is for ATP RELEASE, not synthesis. ≈3 protons per ATP in mitochondria; c-ring has 8 c-subunits in mammals → ~2.7 H+ per ATP overall.` },
      { q:`If Complex IV is inhibited by cyanide, which substrate would accumulate?`, ch:[`NADH only`,`Reduced cytochrome c, CoQH2, NADH, and FADH2 — all upstream carriers remain reduced`,`ATP`,`FAD+`], ans:1, exp:`Cyanide binds Fe3+ in cytochrome a3 of Complex IV → blocks O2 reduction → entire ETC becomes backed up (fully reduced). Cytochrome c cannot donate electrons → CoQH2 accumulates → Complex I and II cannot turn over → NADH, FADH2 accumulate. Net: [NAD+]/[NADH] drops precipitously → TCA and glycolysis slow. Cells switch to anaerobic glycolysis → lactic acidosis. Treatment: hydroxocobalamin (binds CN), nitrites (create methemoglobin as CN sink), thiosulfate (converts CN to thiocyanate).` },
      { q:`The P/O ratio for NADH in mitochondria is approximately:`, ch:[`1.0`,`1.5`,`2.5`,`3.0`], ans:2, exp:`P/O ratio = ATP synthesized per oxygen atom (½ O2) consumed. Modern measurements: NADH → 2.5 ATP (used to be quoted as 3); FADH2 → 1.5 ATP (used to be quoted as 2). Basis: NADH pumps 10 H+ (4+4+2 at complexes I,III,IV); FADH2 bypasses Complex I → pumps 6 H+. Each ATP requires ~3.3 H+. NADH: 10/3.3 ≈ 3 → corrected accounting gives ~2.5. The discrepancy with older values reflects the actual c-ring stoichiometry and proton slip.` },
      { q:`Dinitrophenol (DNP) was historically used as a weight-loss drug. Its mechanism is:`, ch:[`Inhibiting Complex I`,`Blocking ATP synthase`,`Acting as a proton ionophore — carries protons across the inner mitochondrial membrane, dissipating the pmf as heat`,`Activating uncoupling protein 1 (UCP1)`], ans:2, exp:`DNP is a lipophilic weak acid. Protonated form (pKa ≈ 4) crosses IMM into matrix (alkaline) → deprotonates → anion crosses back electrogenically → net: proton shuttled, pmf dissipated, energy released as heat. Result: ETC runs fast (no pmf back-pressure) but no ATP made → cells burn fuel rapidly → weight loss. Fatally toxic (hyperthermia, agranulocytosis). UCP1: endogenous uncoupler in brown adipose tissue; activated by free fatty acids, inhibited by purine nucleotides. Thermogenin.` },
      { q:`Which statement about the Q-cycle (Complex III) is correct?`, ch:[`One proton is pumped per electron`,`CoQH2 is oxidized at the Qi site`,`The Q-cycle effectively doubles the number of protons pumped per pair of electrons — pumping 4H+ despite only 2e− passing to cytochrome c`,`Antimycin A inhibits the Qo site`], ans:2, exp:`Q-cycle: CoQH2 oxidized at Qo (outer) site: 1e− → Rieske Fe-S → cytochrome c1; 1e− → heme bL → heme bH → CoQ at Qi (inner) site (semi-reduced). Second CoQH2 at Qo: same split. Net: 2 CoQH2 → 1 CoQ regenerated at Qi, 2 cytochrome c reduced, 4H+ released to IMS. Antimycin A: blocks Qi site. Stigmatellin/myxothiazol: block Qo. The cycle doubles efficiency of proton pumping relative to simple CoQH2 oxidation.` },
      { q:`ATP/ADP translocase (ANT) in the inner mitochondrial membrane:`, ch:[`Imports ADP and exports ATP in an electroneutral exchange`,`Exports ATP4− from matrix and imports ADP3− from IMS — electrogenic exchange driven by membrane potential (inside negative)`,`Is inhibited by atractyloside by blocking the matrix side`,`Works independently of the proton gradient`], ans:1, exp:`ANT (adenine nucleotide translocator): exchange of ATP4− (out) for ADP3− (in) — net transfer of one negative charge outward. Driven by ΔΨ (inside negative → outward movement of negative charge is energetically favorable). Inhibitors: atractyloside and bongkrekic acid block ANT (atractyloside from matrix side? No — atractyloside blocks the cytoplasmic side; bongkrekic acid traps ANT in matrix-facing conformation). Phosphate transporter: Pi/OH− exchange brings Pi into matrix. Together, ANT + Pi transporter cost ~1 H+ per ATP delivered to cytoplasm.` },
      { q:`In the context of oxidative phosphorylation, which statement about reactive oxygen species (ROS) is most accurate?`, ch:[`ROS are exclusively produced by Complex IV`,`Superoxide (O2•−) is primarily generated at Complex I (site IQ) and Complex III (site IIIQo) when electrons leak to O2`,`Mitochondrial ROS have no signaling function`,`Superoxide dismutase (SOD) converts O2•− directly to H2O`], ans:1, exp:`Electron leak → O2 → O2•− (superoxide). Major sites: Complex I (NADH/NAD+ ratio high; reverse electron transport from succinate → Complex I → NAD+ → leak), Complex III Qo site (semiquinone radical). SOD2 (mitochondrial matrix): O2•− → H2O2. Catalase and GPx: H2O2 → H2O. H2O2 is a redox signaling molecule (NF-κB, HIF-1α). Excess → oxidative stress → lipid peroxidation, protein carbonylation, mtDNA damage. Antioxidants: coenzyme Q, glutathione, vitamin C, E.` },
      { q:`The chemiosmotic hypothesis, proposed by Peter Mitchell, was initially controversial because:`, ch:[`It suggested ATP synthase was not needed for ATP production`,`It proposed that energy coupling occurred through a transmembrane electrochemical proton gradient rather than a covalent "high-energy" phosphorylated intermediate`,`It correctly predicted substrate-level phosphorylation`,`It denied the existence of the electron transport chain`], ans:1, exp:`Before Mitchell (1961), the prevailing hypothesis (chemical coupling hypothesis) proposed an obligate covalent high-energy intermediate (~X–P) that coupled electron transport to phosphorylation — analogous to substrate-level phosphorylation. No such intermediate was ever found. Mitchell proposed that the IMM itself stores energy as an electrochemical gradient. Initially dismissed; confirmed by: (1) pH gradient measurements; (2) pH-jump experiments forcing ATP synthesis; (3) reconstituted liposomes with F0F1. Mitchell received Nobel Prize in Chemistry 1978. Boyer (binding change) and Walker (crystal structure) — Nobel 1997.` },
      { q:`A patient with Leigh syndrome has a mutation in ATP6 (subunit a of F0). The expected biochemical finding is:`, ch:[`Elevated FADH2 and normal ATP`,`Decreased ATP synthesis, elevated NADH, lactic acidosis, and elevated plasma lactate despite normal ETC complexes I–IV`,`Normal ATP due to compensatory substrate-level phosphorylation`,`Decreased NADH but normal lactate`], ans:1, exp:`ATP6 (MT-ATP6): maternally inherited mtDNA gene encoding subunit a (F0). Subunit a + c-ring form the proton channel. Mutation → protons cannot flow through F0 → pmf builds up → ETC slows (back-pressure) → NADH accumulates → TCA stalls → pyruvate → lactate (lactic acidosis). Leigh syndrome: subacute necrotizing encephalomyelopathy. Basal ganglia, brainstem lesions. Mutations in SURF1 (Complex IV assembly), SDHA, NDUFS genes also cause Leigh. Diagnosis: MRI (bilateral symmetric lesions), elevated CSF lactate, mtDNA/nuclear gene sequencing.` },
      { q:`Thermogenesis in brown adipose tissue (BAT) differs from white adipose tissue (WAT) in that BAT:`, ch:[`Lacks mitochondria`,`Expresses UCP1 (thermogenin) which short-circuits the proton gradient to produce heat instead of ATP`,`Uses only substrate-level phosphorylation`,`Has fewer lipid droplets than WAT`], ans:1, exp:`BAT: multilocular lipid droplets, abundant mitochondria with high UCP1 expression. UCP1 (uncoupling protein 1 = thermogenin): allows proton re-entry into matrix bypassing ATP synthase → pmf energy → heat. Activated by long-chain free fatty acids (released by sympathetic stimulation → β3-AR → cAMP → PKA → HSL → TG hydrolysis); inhibited by purine nucleotides (GDP). Newborns: large BAT deposits (around kidneys, interscapular) — critical for non-shivering thermogenesis. Adults: perirenal, supraclavicular (detectable by 18F-FDG PET in cold conditions).` },
      { q:`In the malate-aspartate shuttle, the net effect is:`, ch:[`NADH produced in the cytoplasm is converted to FADH2 in the mitochondria`,`Cytoplasmic NADH equivalents are transferred into the mitochondrial matrix as NADH, yielding ~2.5 ATP per NADH`,`No proton gradient is involved`,`Only used in muscle, not liver`], ans:1, exp:`Malate-aspartate shuttle (liver, heart, kidney): (1) cytoplasmic oxaloacetate + NADH → malate + NAD+ (MDH1); (2) malate enters matrix via malate-αKG carrier; (3) malate + NAD+ → oxaloacetate + NADH (MDH2, matrix — yields mitochondrial NADH → ~2.5 ATP); (4) OAA → aspartate (GOT2, matrix); (5) aspartate exits via aspartate-glutamate carrier (electrogenic, consumes ΔΨ); (6) aspartate → OAA in cytoplasm (GOT1). Net: 1 cytoplasmic NADH → 1 mitochondrial NADH → ~2.5 ATP. Glycerol-3-phosphate shuttle (muscle, brain): cytoplasmic NADH → mitochondrial FADH2 → ~1.5 ATP only.` },
      { q:`Cyanide-resistant respiration in plants is mediated by:`, ch:[`A separate cytochrome c pool`,`Alternative oxidase (AOX) — accepts electrons from CoQH2 and reduces O2 to H2O without pumping protons`,`A modified Complex IV with lower affinity for cyanide`,`Reverse operation of ATP synthase`], ans:1, exp:`AOX: plant/fungal/protist inner mitochondrial membrane enzyme. Branches from CoQ pool, bypasses Complexes III and IV. Insensitive to cyanide, CO, azide. Reduces O2 → H2O (no proton pumping). Allows electron flow when CoQ is over-reduced (e.g., rapid NADH production) — prevents ROS but generates no extra ATP. In Arum lily: AOX drives rapid respiration → heat → volatilize amines to attract pollinators (thermogenesis). Inhibited by salicylhydroxamic acid (SHAM). In mammals: no AOX — accounts for why cyanide poisoning is so lethal.` },
      { q:`Which inhibitor combination would completely block mitochondrial ATP synthesis?`, ch:[`Rotenone + antimycin A`,`Oligomycin alone (F0 inhibitor)`,`Oligomycin + atractyloside (ANT inhibitor) — blocks both ATP synthase and adenine nucleotide exchange`,`FCCP (uncoupler) + oligomycin`], ans:2, exp:`Oligomycin blocks F0 c-ring proton channel → ATP synthase inactive → pmf builds → ETC slows (back-pressure). But matrix ATP remains; ANT can still export existing ATP. Atractyloside + oligomycin: ATP synthase OFF + no ADP/ATP exchange → complete block of mitochondrial ATP delivery. Rotenone + antimycin A: block ETC → no pmf → no ATP synthesis, but this works via upstream inhibition. FCCP + oligomycin: FCCP dissipates pmf (no ATP made) + oligomycin blocks ATP synthase even if pmf were present — complete block. Clinical: oligomycin used as research tool; atractyloside from Atractylis gummifera (toxic plant) causes fatal hepatotoxicity.` },
    ]
  },
  { id:`bb61`, cat:`Bio/Biochem`, title:`Nucleotide De Novo & Salvage Synthesis`, diff:`Expert`, qs:[
      { q:`In purine de novo synthesis, the first committed step is:`, ch:[`Conversion of ribose-5-phosphate to PRPP`,`Synthesis of phosphoribosylamine from PRPP + glutamine (catalyzed by PRPP amidotransferase)`,`Ring closure to form IMP`,`Conversion of IMP to AMP`], ans:1, exp:`PRPP (phosphoribosylpyrophosphate) synthesis from R5P + ATP is not committed — PRPP is used in both purine and pyrimidine synthesis and histidine/tryptophan metabolism. The committed step: PRPP + glutamine → phosphoribosylamine + PPi + glutamate, catalyzed by glutamine phosphoribosylpyrophosphate amidotransferase (PPAT). Regulated by AMP, GMP, IMP (feedback inhibition) and PRPP (activation). The purine ring is built directly on ribose-5-phosphate in 10 steps → IMP. Contributes: N1 from aspartate, C2/C8 from formyl-THF, N3/N9 from glutamine, C4/C5/N7 from glycine, C6 from CO2.` },
      { q:`The atoms of the purine ring derive from multiple sources. Which atoms are contributed by glycine?`, ch:[`N1, C2`,`N9, C4, C5 — the entire imidazole portion of the ring is derived from glycine`,`C6, N1`,`C2 only (from formyl-THF)`], ans:1, exp:`Purine ring atom origins (memorization aid — ACGFG: Aspartate, CO2, Glycine, Formyl-THF, Glutamine): N1 = aspartate; C2 = formyl-THF; N3 = glutamine; C4, C5, N7 = glycine (intact 3-carbon unit); C6 = CO2; N9 = glutamine; C8 = formyl-THF. Glycine contributes C4+C5+N7. Two formyl-THF = C2 + C8. Two glutamine = N3 + N9 (amide nitrogens). One aspartate = N1 (skeleton lost as fumarate). One CO2 = C6.` },
      { q:`De novo pyrimidine synthesis differs from purine synthesis in that:`, ch:[`Pyrimidine uses PRPP later — the ring is built first and then attached to ribose-5-phosphate`,`Pyrimidines are built on the ribose scaffold from the start, just like purines`,`PRPP is not required for pyrimidine synthesis`,`UMP is the first product of purine, not pyrimidine synthesis`], ans:0, exp:`Key distinction: Purines are built atom-by-atom on ribose (PRPP scaffold from step 1). Pyrimidines: ring built first (carbamoyl phosphate + aspartate → dihydroorotate → orotate), THEN orotate attached to PRPP → OMP → UMP (decarboxylation). This matters pharmacologically: 5-fluorouracil inhibits thymidylate synthase (dUMP → dTMP). Leflunomide inhibits dihydroorotate dehydrogenase (DHODH, step 4 of de novo pyrimidine). CAD trifunctional protein (carbamoyl phosphate synthetase II + aspartate transcarbamylase + dihydroorotase) catalyzes first three cytoplasmic steps.` },
      { q:`Which enzyme is deficient in Lesch-Nyhan syndrome?`, ch:[`Adenosine deaminase (ADA)`,`Hypoxanthine-guanine phosphoribosyltransferase (HGPRT)`,`Xanthine oxidase`,`Purine nucleoside phosphorylase (PNP)`], ans:1, exp:`Lesch-Nyhan: X-linked recessive. HGPRT deficiency → hypoxanthine and guanine cannot be salvaged → PRPP accumulates (no longer consumed by salvage) → de novo purine synthesis increased → uric acid overproduction. Features: hyperuricemia, gout, nephrolithiasis, self-mutilation (lip/finger biting), choreoathetosis, intellectual disability. Treatment: allopurinol (XO inhibitor — reduces uric acid) but does NOT reverse neurological symptoms. ADA deficiency → SCID (T and B cell). PNP deficiency → T-cell immunodeficiency. Adenosine deaminase catalyzes adenosine → inosine.` },
      { q:`In the regulation of purine synthesis, the branch point enzyme that controls AMP vs GMP production from IMP is:`, ch:[`Adenylosuccinate synthetase and IMP dehydrogenase, regulated by cross-feedback (GTP drives AMP synthesis; ATP drives GMP synthesis)`,`PRPP amidotransferase alone`,`Xanthine oxidase`,`Ribonucleotide reductase`], ans:0, exp:`IMP branch: adenylosuccinate synthetase → AMP (uses GTP as energy source); IMP dehydrogenase → xanthosine monophosphate → GMP synthetase → GMP (uses ATP as energy source). Cross-regulation: GTP drives AMP synthesis; ATP drives GMP synthesis → if one purine is abundant, it drives production of the other, maintaining balance. Overall regulation: AMP + GMP inhibit PRPP amidotransferase (committed step). Ribonucleotide reductase: converts NDPs → dNDPs (committed step for deoxyribonucleotide synthesis).` },
      { q:`5-Fluorouracil (5-FU) exerts its main cytotoxic effect by:`, ch:[`Blocking dihydrofolate reductase`,`Inhibiting thymidylate synthase — 5-FdUMP forms a covalent complex with TS and methylenetetrahydrofolate, blocking dTMP synthesis`,`Intercalating into DNA`,`Inhibiting ribonucleotide reductase`], ans:1, exp:`5-FU → 5-FdUMP (active metabolite). 5-FdUMP + methylene-THF + thymidylate synthase (TS) → covalent ternary complex (suicide inhibitor). TS normally: dUMP + methylene-THF → dTMP + DHF. Without dTMP: no thymine nucleotides → "thymineless death" — replication stalls. Also: 5-FUTP incorporated into RNA → disrupts RNA processing. Leucovorin (folinic acid, 5-formyl-THF) potentiates 5-FU by increasing methylene-THF pool. Methotrexate inhibits DHFR → blocks THF regeneration → also limits dTMP synthesis (different step). Capecitabine: oral 5-FU prodrug.` },
      { q:`Adenosine deaminase (ADA) deficiency causes severe combined immunodeficiency (SCID) because:`, ch:[`Adenosine accumulates and is toxic to all cells equally`,`Deoxyadenosine accumulates → dATP pools rise in lymphocytes (which lack 5′-nucleotidase) → inhibits ribonucleotide reductase → blocks DNA synthesis → lymphocyte apoptosis`,`IgM cannot be isotype-switched`,`CD4+ cells cannot bind MHC II`], ans:1, exp:`ADA catalyzes adenosine → inosine (and deoxyadenosine → deoxyinosine). ADA deficiency: deoxyadenosine accumulates → dATP builds in lymphocytes (lack of 5′-nucleotidase to degrade). dATP: allosterically inhibits ribonucleotide reductase → can't make other dNTPs → DNA synthesis blocked → apoptosis. Lymphocytes are most sensitive (lack of 5′-nucleotidase activity). Result: SCID (~15% of SCID cases), absent B and T cells. Treatment: PEG-ADA (enzyme replacement), gene therapy (first successful gene therapy target), bone marrow transplant.` },
      { q:`Allopurinol treats gout by inhibiting xanthine oxidase. An expected side effect in patients taking azathioprine is:`, ch:[`Increased conversion of azathioprine to 6-mercaptopurine`,`Dangerous accumulation of 6-mercaptopurine/thiopurine — because XO normally catabolizes 6-MP; allopurinol blocks this → toxic 6-MP levels`,`Decreased efficacy of allopurinol itself`,`Hyperkalemia`], ans:1, exp:`Azathioprine → 6-mercaptopurine (6-MP) → active thiopurine metabolites (6-TGN via TPMT) or inactivation by XO (6-MP → 6-thiouric acid) or TPMT (6-MP → 6-MMP). Allopurinol inhibits XO → 6-MP catabolism blocked → 6-TGN accumulates → severe myelosuppression (leukopenia, thrombocytopenia). Clinical management: if allopurinol is required in a patient on azathioprine, reduce azathioprine dose by ~75% and monitor CBC. TPMT genotyping also affects dosing. Similar issue with 6-MP itself.` },
      { q:`The rate-limiting step of pyrimidine synthesis that is under allosteric regulation is:`, ch:[`Dihydroorotate dehydrogenase`,`Orotate phosphoribosyltransferase`,`CPS-II in the CAD trifunctional complex — activated by PRPP and ATP; inhibited by UMP/UDP (pyrimidine end-product feedback)`,`Thymidylate synthase`], ans:2, exp:`CPS-II (carbamoyl phosphate synthetase II) — cytoplasmic, part of CAD (CPS-II + ATCase + DHOase). Uses glutamine as nitrogen donor. Regulated: activated by PRPP, ATP; inhibited by UMP/UDP (feedback). Compare with CPS-I (mitochondrial, urea cycle): uses NH3, activated by N-acetylglutamate, no feedback inhibition by pyrimidines. Orotic aciduria (UMP synthase deficiency): orotate in urine, megaloblastic anemia, responds to uridine supplementation. Leflunomide/teriflunomide: inhibit DHODH (step 4) → used in RA, MS.` },
      { q:`Ribonucleotide reductase (RNR) is a key regulatory enzyme for deoxyribonucleotide synthesis. Which statement is correct?`, ch:[`RNR is activated by dATP at the overall activity site`,`RNR converts ribonucleoside diphosphates (NDPs) to deoxyribonucleoside diphosphates (dNDPs) using thioredoxin as reductant; dATP allosterically inhibits overall activity; specificity site determines which substrate is reduced`,`RNR is found only in the nucleus`,`Hydroxyurea activates RNR`], ans:1, exp:`RNR: R1 (regulatory) + R2 (catalytic, contains tyrosyl radical) subunits. Overall activity site on R1: ATP → activates; dATP → inhibits (signals sufficient dATP, all dNTP synthesis OFF). Specificity sites: determine which NDP is reduced (dATP → reduces CDP, UDP; dTTP → reduces GDP; dGTP → reduces ADP). Thioredoxin provides electrons (oxidized → reduced by thioredoxin reductase using NADPH). Hydroxyurea: quenches tyrosyl radical on R2 → inhibits RNR → used in sickle cell disease (↑HbF), CML, head/neck cancer. Gemcitabine: also inhibits RNR.` },
      { q:`In pyrimidine catabolism, uracil is degraded to:`, ch:[`Uric acid`,`Hypoxanthine and xanthine`,`β-alanine + CO2 + NH3 (water-soluble products, excreted by kidney)`,`Orotic acid`], ans:2, exp:`Pyrimidine catabolism (reductive pathway, occurs in liver): cytosine → uracil (cytosine deaminase); uracil + NADPH → dihydrouracil; dihydrouracil → N-carbamyl-β-alanine → β-alanine + CO2 + NH3. β-alanine: incorporated into CoA (pantothenate pathway) or excreted. Thymine → dihydrothymine → N-carbamyl-β-aminoisobutyrate → β-aminoisobutyrate + CO2 + NH3 (β-AIB elevated in leukemia, radiotherapy). Contrast: purines → uric acid (sparingly soluble). β-alanine: only β-amino acid in humans; component of carnosine (β-alanyl-histidine) in muscle.` },
      { q:`PRPP (phosphoribosyl pyrophosphate) is a substrate for which of the following?`, ch:[`Purine de novo synthesis only`,`Both purine and pyrimidine de novo synthesis AND salvage pathways AND histidine/tryptophan biosynthesis in bacteria`,`Pyrimidine de novo synthesis only`,`Glycolysis`], ans:1, exp:`PRPP (5-phosphoribosyl-1-pyrophosphate): synthesized from ribose-5-phosphate + ATP by PRPP synthetase. Used in: (1) purine de novo synthesis (step 1); (2) pyrimidine synthesis (orotate + PRPP → OMP by OPRT); (3) purine salvage (HGPRT, APRT); (4) NAD+, NADP+, FAD synthesis (from nicotinic acid, tryptophan); (5) histidine biosynthesis (bacteria/plants). PRPP synthetase: activated by Pi, inhibited by ADP, GDP. Superactive PRPP synthetase mutations → gout (overproduction of purines).` },
      { q:`In the deoxyribonucleotide synthesis pathway, where does dTMP come from?`, ch:[`dUDP reduced by ribonucleotide reductase → dUTP → dUMP → dTMP`,`dUMP + methylene-THF → dTMP (thymidylate synthase); dUMP derives from dUTP via dUTPase or from dCDP via deaminase pathways`,`dTTP directly from dietary sources`,`Adenosine converted to thymidine by a phosphorylase`], ans:1, exp:`dTMP synthesis: two main routes for dUMP: (1) dUTP → dUMP (dUTPase — important to prevent dUTP incorporation into DNA); (2) dCMP → dUMP (dCMP deaminase). Then: dUMP + 5,10-methylene-THF → dTMP + DHF (thymidylate synthase, TS). DHF → THF (DHFR; inhibited by methotrexate, trimethoprim). dTMP → dTDP → dTTP. dUTPase deficiency: dUTP incorporates into DNA → uracil-containing DNA → attempted repair → DNA strand breaks. This is why folate/B12 deficiency impairs DNA synthesis (insufficient methylene-THF for TS).` },
      { q:`Orotic aciduria (hereditary) is characterized by excretion of orotic acid in urine without hyperammonemia. The likely enzyme deficiency is:`, ch:[`CPS-I (mitochondrial)`,`UMP synthase (bifunctional enzyme containing OPRT and ODCase) — orotic acid cannot be converted to OMP or UMP → accumulates and is excreted`,`Dihydroorotase`,`DHODH`], ans:1, exp:`UMP synthase: bifunctional enzyme with orotate phosphoribosyltransferase (OPRT) + orotidine 5′-monophosphate decarboxylase (ODCase) activities. Deficiency → orotic acid accumulates → orotic aciduria, megaloblastic anemia (cannot make UMP → no pyrimidines for DNA/RNA synthesis), failure to thrive. Key: NO hyperammonemia (CPS-I and OTC deficiencies cause hyperammonemia with orotic aciduria — because OTC deficiency → carbamoyl phosphate overflows into cytoplasm → excessive pyrimidine synthesis → orotic acid). Treatment: uridine supplementation (bypasses the block → provides UMP, also feeds back to inhibit CPS-II → reduces orotic acid).` },
      { q:`The antiviral drugs acyclovir and ganciclovir exert their effects by:`, ch:[`Inhibiting viral RNA polymerase`,`Being phosphorylated by viral thymidine kinase (TK) → triphosphate form inhibits viral DNA polymerase and acts as a chain terminator`,`Blocking viral proteases`,`Inhibiting reverse transcriptase`], ans:1, exp:`Acyclovir (HSV, VZV): acyclovir (guanosine analog, lacks 3′-OH) → monophosphate by viral TK (HSV TK has much broader substrate specificity than human TK — selectivity mechanism); further phosphorylated by cellular kinases → acyclovir-TP. Acyclovir-TP: (1) competitive inhibitor of viral DNA polymerase (vs. dGTP); (2) incorporated into DNA → chain termination (no 3′-OH for extension); (3) viral polymerase is irreversibly bound to the chain-terminated primer (suicide inhibition). Selectivity: human TK phosphorylates acyclovir ~200× less efficiently. Ganciclovir: broader spectrum (CMV); more toxic (myelosuppression) because cellular TK phosphorylates it more readily.` },
    ]
  },
  { id:`bb62`, cat:`Bio/Biochem`, title:`Recombinant DNA & CRISPR`, diff:`Expert`, qs:[
      { q:`Which enzyme is used to generate complementary DNA (cDNA) from mRNA?`, ch:[`DNA polymerase I`,`Reverse transcriptase (RNA-dependent DNA polymerase) — requires a primer (oligo-dT or random hexamers) and synthesizes a DNA strand complementary to the RNA template`,`RNA polymerase`,`Restriction endonuclease`], ans:1, exp:`Reverse transcriptase (RT): retroviral enzyme (HIV RT = pol gene product). Steps: (1) RT synthesizes DNA strand from mRNA template (RNA-DNA hybrid); (2) RNase H activity degrades RNA strand; (3) DNA polymerase activity synthesizes second DNA strand → dsDNA (cDNA). In the lab: oligo-dT primer (binds poly-A tail) or random hexamers + RT → first-strand cDNA; then PCR or DNA polymerase I for second strand. cDNA libraries lack introns (mRNA is mature, processed). RT inhibitors: AZT, tenofovir (NRTIs); efavirenz (NNRTI).` },
      { q:`Type II restriction endonucleases are most useful in molecular biology because:`, ch:[`They require ATP to cut DNA`,`They cut at specific palindromic sequences near the recognition site, generating predictable fragments (often with 3′ or 5′ overhangs) used for cloning`,`They methylate DNA rather than cut it`,`They cut RNA`], ans:1, exp:`Type II RE: recognize 4–8 bp palindromic sequences, cut at or near the recognition site without requiring ATP (only Mg2+). Produce: blunt ends (SmaI: CCC↓GGG) or 5′-overhang/3′-overhang (sticky ends). EcoRI: 5′-G↓AATTC-3′; produces 4-nt 5′ overhangs (AATT). Sticky ends: allow ligation with compatible fragments. Type I RE: cut far from recognition site, require ATP + SAM. Type III RE: intermediate. Restriction-modification system: bacteria methylate own DNA (dam: GATC; dcm: CCWGG) to protect from own restriction enzymes.` },
      { q:`In CRISPR-Cas9 gene editing, the PAM (protospacer adjacent motif) sequence:`, ch:[`Is part of the guide RNA and is required for target binding`,`Is a short DNA sequence (NGG for SpCas9) immediately downstream of the target site in genomic DNA — required for Cas9 recognition and cleavage`,`Is cut by Cas9`,`Is found in the crRNA`], ans:1, exp:`PAM for SpCas9 (Streptococcus pyogenes): 5′-NGG-3′ on the non-template strand, immediately 3′ of the 20-nt protospacer. Cas9 PAM-interacting (PI) domain reads PAM → licenses DNA unwinding → RNA-DNA hybrid (R-loop) forms → RuvC domain cuts non-template strand; HNH domain cuts template strand → blunt-end DSB (3 bp upstream of PAM). gRNA (= crRNA + tracrRNA fusion = sgRNA) provides 20-nt specificity. Off-target: mismatches tolerated especially at 5′ end of spacer (distal from PAM); seed region (PAM-proximal 10–12 nt) is critical. Cas12a: TTTV PAM, 5′ of target; generates staggered cuts.` },
      { q:`The double-strand break (DSB) created by Cas9 can be repaired by two main pathways. Which is used for precise gene correction?`, ch:[`Non-homologous end joining (NHEJ) — error-free ligation`,`Homology-directed repair (HDR) using a provided donor template — allows precise sequence insertion or correction, but requires cell division (S/G2 phase)`,`Base excision repair`,`Mismatch repair`], ans:1, exp:`DSB repair: (1) NHEJ: rapid, dominant in G1; error-prone → insertions/deletions (indels) → frameshift → gene knockout. Useful for loss-of-function. (2) HDR: requires homologous template (sister chromatid or exogenous donor); highly precise; predominant in S/G2 phase; less efficient (~1–10% in most cell types). Strategies to improve HDR: provide single-stranded oligodeoxynucleotide (ssODN) as donor; use Cas9 variants that nick (nickase, D10A or H840A) to reduce NHEJ; inhibit NHEJ proteins (Ku70/80, DNA-PKcs). Base editors (CBE, ABE): convert C→T or A→G without DSB — higher precision for single-nucleotide changes.` },
      { q:`Southern blotting detects:`, ch:[`RNA transcripts`,`Protein by antibody binding`,`Specific DNA sequences — genomic DNA is digested with restriction enzymes, separated by gel electrophoresis, transferred to membrane, and probed with a labeled complementary DNA/RNA`,`Protein-protein interactions`], ans:2, exp:`Blotting memory aid — DNA: Southern (named for Edwin Southern); RNA: Northern; Protein: Western; Protein-protein: Far-Western. Southern blot: restriction digest → agarose gel electrophoresis → denaturing (NaOH) → transfer to nylon/nitrocellulose → UV cross-link → hybridization with labeled probe → wash → detection. Used for: RFLP analysis, gene copy number, germline mutations. Modern replacement: PCR + sequencing; array CGH; NGS. Northern blot: detects mRNA size and abundance. Western: SDS-PAGE + antibody. ELISA: also protein detection but not a blot.` },
      { q:`PCR (polymerase chain reaction) requires all of the following EXCEPT:`, ch:[`Two oligonucleotide primers flanking the target`,`A thermostable DNA polymerase (e.g., Taq polymerase)`,`Deoxynucleoside triphosphates (dNTPs)`,`RNA template (mRNA is required for standard PCR)`], ans:3, exp:`Standard PCR template: double-stranded or single-stranded DNA. mRNA is NOT a template for standard PCR — it requires RT-PCR (reverse transcription first). PCR cycle: (1) denaturation (94–98°C); (2) primer annealing (50–65°C; Tm-specific); (3) extension (72°C for Taq). Taq polymerase lacks 3′→5′ proofreading (exonuclease) — error rate ~1 in 10^5. High-fidelity polymerases (Pfu, Q5): have 3′→5′ proofreading. Quantitative PCR (qPCR): uses fluorescent dyes (SYBR Green) or TaqMan probes to measure amplification in real time. Applications: diagnosis, forensics, cloning, mutagenesis.` },
      { q:`In the context of gene expression vectors, a promoter sequence is required because:`, ch:[`It encodes the protein of interest`,`It is recognized by RNA polymerase (directly or via transcription factors) to initiate transcription of the downstream gene of interest`,`It provides the polyadenylation signal`,`It encodes the selectable marker`], ans:1, exp:`Expression vector components: (1) Origin of replication (ori) — for propagation in bacteria; (2) Selectable marker (antibiotic resistance) — ensures only transformed bacteria survive; (3) Multiple cloning site (MCS) — restriction sites for insert; (4) Promoter — drives transcription of insert; (5) Terminator/poly-A signal — ensures proper mRNA 3′ end. Bacterial promoters: T7, lac, tac, araBAD. Eukaryotic: CMV (strong, constitutive), EF1α, PGK; or inducible (TRE/Tet-On, cumate). Kozak sequence: around start codon in eukaryotic mRNA — affects translational efficiency.` },
      { q:`Gel electrophoresis of DNA separates fragments based on:`, ch:[`Molecular weight alone`,`DNA sequence composition`,`Size (number of base pairs) — smaller fragments migrate faster through the porous agarose matrix in an electric field`,`Charge — since charge varies by fragment`], ans:2, exp:`DNA is uniformly negatively charged (phosphate backbone) — charge/mass ratio is approximately constant for all DNA fragments. Therefore, migration rate in agarose gel is determined entirely by size (and shape for circular vs. linear). Smaller fragments: migrate faster (less resistance through agarose pores). DNA ladder (size markers) provides reference. Agarose concentration: low % (0.7%) → resolves large fragments (>5 kb); high % (3%) → separates small fragments (50–500 bp). Ethidium bromide (intercalates) or SYBR Safe for visualization under UV. Polyacrylamide gel electrophoresis (PAGE): higher resolution for small DNA (sequencing, EMSA).` },
      { q:`Which of the following is a key safety concern with AAV (adeno-associated virus) gene therapy vectors?`, ch:[`AAV integrates randomly into the genome at high frequency, causing insertional mutagenesis`,`Wild-type AAV preferentially integrates at the AAVS1 safe harbor on chromosome 19, but recombinant AAV (rAAV) is largely episomal with low integration rate — risk is low compared to retroviral vectors`,`AAV is highly immunogenic and always triggers fatal immune responses`,`AAV can replicate autonomously without a helper virus`], ans:1, exp:`rAAV: 4.7 kb ssDNA parvovirus capsid. Recombinant (no rep gene): episomal persistence in non-dividing cells (liver, muscle, CNS) — months to years; low integration rate (~0.1% of wild-type AAV's AAVS1 preference). Helper-dependent: needs adenovirus or HSV co-infection for replication. Advantages: low immunogenicity, broad tropism (serotypes: AAV1-13 differ in capsid → tissue tropism). Limitations: 4.7 kb packaging limit, pre-existing neutralizing antibodies in many patients, difficult repeat dosing (neutralizing Ab). Approved therapies: voretigene neparvovec (RPE65 mutation → LCA), onasemnogene abeparvovec (SMA).` },
      { q:`CRISPR base editors (cytosine base editors, CBE) convert C·G to T·A by:`, ch:[`Cutting both strands and replacing the C with T via HDR`,`Deaminating the target cytosine within the ssDNA R-loop using a fused cytidine deaminase (e.g., APOBEC1) → C becomes U → U:G mismatch → DNA replication → T:A product; a UGI fusion blocks uracil-DNA glycosylase to prevent U removal`,`Using a guide RNA that contains T instead of C`,`Activating endogenous mismatch repair to change C to T`], ans:1, exp:`Base editors bypass DSB: dCas9 (catalytically inactive) or nickase Cas9 (nCas9, D10A) fused to cytidine deaminase (rAPOBEC1 for BE3) and UGI (uracil-DNA glycosylase inhibitor). Process: (1) sgRNA directs Cas9 to target; (2) R-loop formation exposes ssDNA (protospacer, positions 4–8 from PAM = editing window); (3) deaminase converts C → U; (4) UGI blocks BER; (5) nicking of non-edited strand triggers replication → T:A. ABEs (adenine base editors): TadA-evolved adenine deaminase converts A → I (inosine, read as G) → A:T to G:C. No DSB, no donor template needed; efficient for point mutations.` },
      { q:`Yeast two-hybrid system detects:`, ch:[`Protein-DNA interactions`,`Protein-protein interactions — one protein is fused to a DNA-binding domain, the other to a transcriptional activation domain; interaction brings domains together → activates reporter gene`,`mRNA-protein interactions`,`Chromosomal rearrangements`], ans:1, exp:`Yeast two-hybrid (Y2H; Fields & Song 1989): Bait protein X fused to GAL4 DNA-binding domain (DBD). Prey protein Y fused to GAL4 activation domain (AD). If X interacts with Y → reconstituted GAL4 → reporter gene (HIS3, ADE2, lacZ, GFP) transcription → cell survival or color. False positives: autoactivating baits, sticky proteins. False negatives: require nuclear localization, misfolding. Split-ubiquitin: for membrane protein interactions. Mammalian two-hybrid: for interactions that need mammalian PTMs. BiFC (bimolecular fluorescence complementation): split GFP detects interactions in live cells.` },
      { q:`The technique of ChIP-seq (chromatin immunoprecipitation followed by sequencing) is used to:`, ch:[`Sequence the entire human genome`,`Map genome-wide binding sites of a specific protein (transcription factor, histone modification) — chromatin is cross-linked, sheared, immunoprecipitated with a specific antibody, cross-links reversed, and resulting DNA is sequenced`,`Detect RNA splicing variants`,`Identify all protein-protein interactions in a cell`], ans:1, exp:`ChIP-seq workflow: (1) Cross-link protein-DNA with formaldehyde; (2) Lyse cells, shear chromatin (sonication → 200–500 bp fragments); (3) Immunoprecipitate with antibody specific to protein of interest; (4) Reverse cross-links, purify DNA; (5) Library prep → next-gen sequencing; (6) Bioinformatics: map reads to genome, call peaks (MACS2 etc.). Applications: TF binding sites (e.g., CTCF, p53), histone modifications (H3K4me3 = active promoters; H3K27me3 = polycomb repression; H3K27ac = active enhancers), RNA Pol II occupancy. ATAC-seq: accessible chromatin. Hi-C: 3D genome organization.` },
      { q:`Prime editing (Anzalone et al., 2019) offers an advantage over standard CRISPR because:`, ch:[`It is much faster than Cas9`,`It can install all 12 possible base substitutions, small insertions, and deletions without DSB or exogenous donor template using a reverse transcriptase fused to nickase Cas9 and a pegRNA`,`It uses two guide RNAs for better specificity`,`It only works in E. coli`], ans:1, exp:`Prime editing components: (1) nCas9 (H840A nickase) fused to reverse transcriptase (M-MLV RT); (2) pegRNA (prime editing guide RNA) = standard spacer + scaffold + 3′ RT template (encodes desired edit) + 3′ primer binding site (PBS). Process: pegRNA guides nCas9 to target → nicks non-template strand → 3′ flap primed by PBS → RT extends using RT template → edited 3′ flap replaces original → second nick initiates repair → edit installed. Can make all 12 substitutions + small indels + insertions up to ~44 nt. No DSB, no donor template. Lower efficiency than base editors for base substitutions; higher versatility. PE3 strategy (second sgRNA nicks opposite strand) improves efficiency.` },
      { q:`DNA libraries (genomic vs. cDNA) differ in that:`, ch:[`cDNA libraries contain introns while genomic libraries do not`,`Genomic libraries represent all DNA sequences (including introns, regulatory regions, and non-coding DNA) at approximately equal representation; cDNA libraries represent only expressed sequences (exons, no introns) and reflect the transcriptome of a specific cell type/condition`,`Both are made from mRNA`,`Genomic libraries are smaller than cDNA libraries`], ans:1, exp:`Genomic library: all genomic DNA fragmented (partial restriction digest or mechanical shearing) and cloned → represents every sequence. Limitation: very large (human genome = 3×10^9 bp); introns present; regulatory sequences included. cDNA library: from mRNA → cDNA (RT) → clone → represents only expressed genes; no introns; cell-type and condition specific. Applications: cDNA → protein expression (no splicing needed in bacteria); genomic → study regulatory elements, introns. Next-gen sequencing has largely replaced physical library screening: RNA-seq (transcriptome, replaces cDNA library); WGS (replaces genomic library).` },
      { q:`Off-target editing by CRISPR-Cas9 can be reduced by which strategy?`, ch:[`Using longer guide RNAs (>25 nt)`,`Using high-fidelity Cas9 variants (e.g., eSpCas9, HiFi Cas9), paired nickases, or truncated guide RNAs (17–18 nt) — all reduce tolerance for mismatches at off-target sites`,`Increasing Cas9 concentration`,`Using a PAM sequence that is less common (e.g., NAG instead of NGG)`], ans:1, exp:`Off-target reduction strategies: (1) High-fidelity Cas9: eSpCas9 (charge-neutralizing mutations: K848A/K1003A/R1060A), HiFi Cas9 (R691A) — reduce non-specific DNA contacts; (2) Truncated gRNA (17–18 nt): more sensitive to mismatches; (3) Paired nickases (D10A + offset gRNAs ~20 nt apart): each nick alone → SSB (repaired accurately); both nicks together → functional DSB at target; off-target single nicks repaired accurately; (4) Anti-CRISPR proteins; (5) Controlled delivery (RNP vs. plasmid — shorter exposure = fewer off-target events); (6) Computational design (Cas-OFFinder, CRISPOR) to select gRNAs with minimal off-target sites.` },
    ]
  },
  { id:`bb63`, cat:`Bio/Biochem`, title:`Viral Replication Cycles`, diff:`Expert`, qs:[
      { q:`The lytic cycle of a bacteriophage culminates in:`, ch:[`Integration into the host chromosome`,`Host cell lysis — viral genes are expressed, new phage particles are assembled, and the cell is lysed to release progeny`,`Latency with minimal gene expression`,`Budding without cell death`], ans:1, exp:`Lytic cycle: phage injects DNA → early gene expression (enzymes for DNA replication, host defense evasion) → DNA replication → late gene expression (structural proteins, lysis genes) → assembly → lysis (holin punches holes in inner membrane; lysin/endolysin degrades peptidoglycan; spanin disrupts outer membrane in gram-negative hosts). Lysogenic cycle (lambda phage): integrase (Int) → phage DNA integrates at attB site → prophage; repressor (CI) silences lytic genes; excisionase (Xis) + Int excise upon SOS response. Lambda CI repressor: occupies OR1/OR2/OR3 to maintain lysogeny; cleaved by RecA (SOS) → lytic cycle.` },
      { q:`HIV (an enveloped RNA retrovirus) requires which unique enzymatic activities not present in host cells?`, ch:[`DNA-dependent DNA polymerase`,`Reverse transcriptase, integrase, and protease — all encoded by the pol gene and absent in or distinct enough from host enzymes to be therapeutic targets`,`RNA-dependent RNA polymerase`,`Topoisomerase II`], ans:1, exp:`HIV pol gene encodes: (1) Reverse transcriptase (RNA→DNA, RNase H) — makes dsDNA from ssRNA genome; (2) Integrase (IN) — inserts viral dsDNA into host chromatin; (3) Protease (PR) — cleaves Gag-Pol polyprotein into functional proteins. Drug targets: NRTIs (AZT, tenofovir) block RT; NNRTIs (efavirenz) block RT allosterically; integrase inhibitors (raltegravir, dolutegravir); protease inhibitors (ritonavir, lopinavir). HIV also encodes structural proteins (Gag: MA, CA, NC, p6; Env: gp120/gp41) and regulatory (Tat, Rev) and accessory proteins (Vif, Vpr, Vpu, Nef).` },
      { q:`Influenza A virus undergoes antigenic shift, which results from:`, ch:[`Point mutations in hemagglutinin accumulating over time`,`Reassortment of segmented genome segments between two different influenza strains co-infecting the same cell — can create novel HA/NA combinations with pandemic potential`,`Integration into the host genome`,`Recombination in a non-segmented RNA genome`], ans:1, exp:`Antigenic shift (major): influenza A has 8 segmented ssRNA (−) genome segments. If two strains infect the same cell (e.g., avian H5N1 + human H3N2 in pig "mixing vessel") → segments reassort → novel strain with new HA and/or NA subtypes. Result: population lacks pre-existing immunity → pandemic potential (1918: H1N1; 1957: H2N2; 1968: H3N2). Antigenic drift (minor): error-prone RNA polymerase → point mutations → gradual HA/NA change → seasonal epidemics, requires annual vaccine reformulation. 18 HA subtypes (H1–H18), 11 NA subtypes. HA: receptor binding (sialic acid); NA: neuraminidase (release from cell → inhibited by oseltamivir).` },
      { q:`The process of viral budding in enveloped viruses such as HIV involves:`, ch:[`Random diffusion through the plasma membrane`,`Recruitment of ESCRT (endosomal sorting complexes required for transport) machinery by the viral Gag p6 domain to pinch off viral particles at the plasma membrane`,`Lysis of the host cell`,`Use of clathrin-coated vesicles`], ans:1, exp:`HIV budding: Gag polyprotein (MA-CA-NC-p6) drives particle assembly at plasma membrane. MA (myristylated): targets Gag to membrane. CA: capsid formation. NC: binds RNA genome (Ψ packaging signal). p6: contains PTAP and LYPX(n)L late domain motifs → recruits TSG101 (ESCRT-I) and ALIX (ESCRT-associated) → ESCRT machinery drives membrane scission. Protease: cleaves Gag during/after budding → mature, infectious core. Vpu: degrades CD4 in ER, antagonizes BST-2/tetherin (host restriction factor that tethers budding virions). Nef: downregulates CD4, MHC-I. ESCRT also used by EBOV, RSV, CMV.` },
      { q:`Positive-sense (+)ssRNA viruses (e.g., poliovirus, SARS-CoV-2) can directly serve as mRNA after cell entry because:`, ch:[`Their RNA is already methylated at the 5′ end like host mRNA`,`(+)ssRNA has the same polarity as mRNA → can be directly translated by host ribosomes upon entry; also serves as template for RNA-dependent RNA polymerase (RdRp) to make (−) strand intermediate → new (+) genomes`,`They carry ribosomes from the previous host`,`They undergo reverse transcription first`], ans:1, exp:`(+)ssRNA virus classification: genome = mRNA sense. After cell entry, genome is directly translated by host ribosomes → produces polyprotein including RdRp. RdRp makes (−)ssRNA complement → template for multiple (+) strands (exponential amplification). Coronaviruses (SARS-CoV-2): largest RNA genome (29.9 kb); 5′ cap-1 (2′-O-methyltransferase, nsp14 methyltransferase, nsp10/nsp16), 3′ poly-A. ORF1a/1b: polyprotein → 16 nsps (nsp12=RdRp; nsp3=PLpro; nsp5=3CLpro/Mpro — target of nirmatrelvir/paxlovid). Subgenomic mRNAs encode structural proteins. (−)ssRNA: must bring RdRp within virion (cannot be translated directly).` },
      { q:`Interferons (IFNs) are part of the innate antiviral response. Type I IFN (IFN-α/β) induces an antiviral state by:`, ch:[`Directly killing virus-infected cells`,`Signaling via IFNAR → JAK1/TYK2 → STAT1/STAT2 heterodimer + IRF9 (ISGF3) → ISRE element → induction of ISGs (antiviral effectors including OAS, PKR, Mx proteins, IFIT family)`,`Producing antibodies`,`Activating cytotoxic T lymphocytes directly`], ans:1, exp:`IFN signaling (Jak-STAT): IFNAR1/2 → JAK1 (IFNAR2) + TYK2 (IFNAR1) → phosphorylate STAT1/STAT2 → heterodimer + IRF9 = ISGF3 complex → ISRE (IFN-stimulated response element) → ISG transcription. Key ISGs: PKR (dsRNA → eIF2α phosphorylation → global translation shutdown); OAS/RNase L (dsRNA → 2′-5′ oligoadenylate → RNase L activation → mRNA degradation); Mx (GTPase → blocks viral RNA synthesis); IFIT proteins (cap-1 RNA discrimination); viperin. Viruses evade IFN: influenza NS1 (sequesters dsRNA); HSV ICP0 (degrades STING); HIV Vif (degrades APOBEC3G).` },
      { q:`The mechanism by which SARS-CoV-2 enters cells involves:`, ch:[`Using neuraminidase to cleave sialic acid on ACE2`,`Spike (S) protein binding to ACE2 → S2 subunit is cleaved by TMPRSS2 (or cathepsin L in endosomes) → fusion peptide inserts into host membrane → six-helix bundle formation → membrane fusion`,`Injecting RNA through a syringe-like apparatus`,`Receptor-mediated endocytosis via the transferrin receptor`], ans:1, exp:`SARS-CoV-2 entry: S protein = S1 + S2 (cleaved by furin during biosynthesis at PRRA site — unique to SARS-CoV-2 vs. SARS-CoV-1). S1 RBD binds ACE2 (Kd ~15 nM). TMPRSS2 cleaves S2′ site at cell surface → immediate fusion (primary route). Alternatively, endocytosis → cathepsin L cleavage in endosome. S2 fusion peptide inserts → heptad repeats HR1+HR2 form 6-HB → membranes merge. Camostat (TMPRSS2 inhibitor) → blocks cell surface fusion. S mutations (Delta: L452R, T478K; Omicron: extensive RBD mutations) alter ACE2 affinity and Ab neutralization.` },
      { q:`Which statement about herpesvirus latency is most accurate?`, ch:[`Herpesviruses destroy all infected neurons during primary infection`,`HSV-1 establishes latency in sensory neurons (trigeminal ganglia) — viral DNA persists as circular episome, only LATs (latency-associated transcripts) are expressed, and reactivation by stress/UV/immunosuppression leads to lytic cycle and recurrence`,`Varicella-zoster virus cannot reactivate after primary infection`,`EBV latency never involves nuclear antigen (EBNA) expression`], ans:1, exp:`HSV-1 latency: retrograde transport along sensory axons → trigeminal (or sacral for HSV-2) ganglia → circularization of viral DNA → heterochromatinization of lytic genes (H3K9me3, H3K27me3) → only LATs (non-coding RNA, anti-sense to ICP0 region) expressed → neuronal survival. Reactivation: anterograde transport → epithelial cells → lytic cycle → cold sores. EBV latency programs: Latency 0 (no proteins, resting B cells); Latency I (EBNA1 only, Burkitt lymphoma); Latency II (EBNA1 + LMP1/2, NPC, Hodgkin); Latency III (all EBNAs + LMPs, immunoblastic lymphoma in immunocompromised). VZV reactivation: shingles (dermatome-restricted).` },
      { q:`Hemagglutinin (HA) of influenza virus is a target for neutralizing antibodies. The HA stalk domain is preferred for universal vaccine design because:`, ch:[`The stalk is more immunogenic than the head`,`The stalk domain is highly conserved across influenza subtypes and strains (unlike the hypervariable head domain that bears receptor-binding site — hence prone to antigenic drift); broadly neutralizing stalk Abs block membrane fusion`,`The stalk domain encodes neuraminidase activity`,`Stalk-targeting Abs block receptor binding`], ans:1, exp:`HA structure: trimeric glycoprotein. HA1 (head): receptor-binding site (sialic acid binding) — hypervariable, immunodominant, site of antigenic drift. HA2 (stalk): fusion peptide region — membrane fusion mechanism, more conserved. Head Abs: potently neutralizing but strain-specific. Stalk Abs: broadly cross-reactive (across subtypes H1, H3, H5 within Group 1 or Group 2); neutralize by blocking conformational change needed for fusion (Class I mechanism); also ADCC. Universal flu vaccine strategies: headless HA, chimeric HA (present stalk on exotic HA heads not present in human population → focus immunity to stalk). FluBlok: recombinant HA (no eggs).` },
      { q:`RNA-dependent RNA polymerase (RdRp) inhibitor remdesivir works by:`, ch:[`Blocking neuraminidase`,`Being incorporated as a adenosine analogue by viral RdRp → acts as a delayed chain terminator (3–4 nt after incorporation, before the active site, stalling the polymerase)`,`Preventing viral entry`,`Inhibiting viral protease`], ans:1, exp:`Remdesivir (GS-5734): adenosine monophosphate prodrug → activated to remdesivir-TP intracellularly. RdRp (e.g., SARS-CoV-2 nsp12) incorporates remdesivir-TP opposite U → continues 3–4 more nucleotides → encounters the incorporated analogue → stalls (delayed chain termination; 3′ exonuclease of SARS-CoV-2 may excise it but with lower efficiency). FDA authorized for COVID-19. Also active in vitro against Ebola, MERS, RSV. Favipiravir (T-705): purine analogue, broad-spectrum RdRp inhibitor → used in influenza, COVID. Molnupiravir: cytidine analogue → incorporated → mutagenesis → lethal error catastrophe.` },
      { q:`Which mechanism allows some viruses to evade MHC class I antigen presentation?`, ch:[`Expressing CD8 on their surface`,`Downregulating TAP (transporter associated with antigen processing) or MHC-I itself — e.g., HSV ICP47 blocks TAP; HCMV US2/US11 redirect MHC-I to ERAD; Kaposi sarcoma herpesvirus K3/K5 ubiquitinate MHC-I for endosomal degradation`,`Producing soluble CD8 that binds peptides`,`Upregulating NK cell activating ligands`], ans:1, exp:`MHC-I pathway: proteasome → peptides → TAP1/TAP2 → ER → loaded on MHC-I/β2m/tapasin → Golgi → surface → CD8+ T cell recognition. Viral evasion: HSV ICP47 blocks TAP (peptide import into ER); HCMV US2 redirects MHC-I to cytoplasm → ERAD; HCMV US11 similar; HCMV US3 retains MHC-I in ER; EBV BNLF2a blocks TAP. NK cell counter: some HCMV proteins (UL18) mimic MHC-I → inhibit NK cells (missing-self). KSHV K3/K5 (MIR1/2): E3 ubiquitin ligases → MHC-I polyubiquitination → lysosomal degradation.` },
      { q:`The error rate of HIV reverse transcriptase (~1 error per 10^4–10^5 nucleotides) contributes to:`, ch:[`Rapid, predictable mutation patterns that make therapy easy`,`Quasi-species diversity — each replication cycle generates many variants; this diversity underlies rapid evolution of drug resistance, immune escape, and tropism changes`,`Low HIV replication rate`,`Efficient proofreading`], ans:1, exp:`HIV RT lacks 3′→5′ proofreading exonuclease (unlike cellular DNA polymerases). Error rate: ~3×10^-5 per base per cycle. HIV replication: ~10^10 virions/day × 9,749 nt genome → ~10^6 potential mutations/day. Within-host viral population = quasi-species (swarm of related variants). Consequences: (1) Drug resistance mutations preexist before therapy; (2) Single-drug therapy → rapid selection of resistant mutants; (3) Combination antiretroviral therapy (cART) uses 3+ drugs → requires simultaneous resistance to all → probability ≈ product of individual frequencies → clinically undetectable. APOBEC3G: host cytidine deaminase → C→U in (−)DNA strand → G→A hypermutation in progeny; Vif counteracts by targeting APOBEC3G for proteasomal degradation.` },
      { q:`The cGAS-STING pathway detects:`, ch:[`Single-stranded RNA`,`Cytoplasmic double-stranded DNA (from viral infection, mtDNA release, micronuclei) — cGAS synthesizes cGAMP → binds and activates STING (ER membrane protein) → TBK1 → IRF3 phosphorylation → type I IFN production`,`Only bacterial LPS`,`mRNA in the cytoplasm`], ans:1, exp:`cGAS (cyclic GMP-AMP synthase): DNA sensor, activated by cytoplasmic dsDNA (≥10 bp, sequence-independent). Catalyzes GTP + ATP → 2′3′-cGAMP (cyclic dinucleotide). 2′3′-cGAMP: high-affinity ligand for STING (stimulator of interferon genes = TMEM173, ER/Golgi membrane). STING → TBK1 → IRF3 homodimer → IFN-β transcription; also NF-κB → inflammatory cytokines. Viral DNAs activate cGAS-STING: HSV, HCMV, HIV (reverse transcription intermediates). Cancer relevance: cGAS-STING in tumor cells promotes antitumor immunity; tumors often silence STING. STING agonists (DMXAA, diABZI) as immunotherapy. Evasion: HCMV pUL83 inhibits cGAS; Kaposi LANA degrades cGAS; Vaccinia C16 binds and inhibits cGAS.` },
      { q:`Receptor tropism of viruses is determined by:`, ch:[`The host cell's ability to produce viral DNA`,`The affinity of viral surface proteins for specific host cell receptor molecules — which cells express the receptor determines the virus' target tissue and host range`,`Random selection of host cells`,`Only the size of the virus`], ans:1, exp:`Viral tropism: depends on receptor-ligand interaction between viral attachment protein and specific host receptor. Examples: HIV gp120 → CD4 + CCR5/CXCR4 (T cells, macrophages); SARS-CoV-2 S → ACE2 + TMPRSS2 (pneumocytes, enterocytes); EBV gp350 → CD21 (CR2, B cells); Rabies G-protein → nAChR, NCAM, p75NTR (neurons); RSV F/G → heparan sulfate + nucleolin (airway epithelium); Adenovirus fiber knob → CAR (coxsackievirus-adenovirus receptor). Beyond receptor: post-entry determinants (nuclear pore entry, protease availability, innate immune evasion, transcription factor availability) also shape tropism. Tissue-specific proteases (TMPRSS2, furin) enable cleavage-dependent entry.` },
    ]
  },
  { id:`bb64`, cat:`Bio/Biochem`, title:`Protein Misfolding & Prions`, diff:`Expert`, qs:[
      { q:`The central dogma of prion biology proposes that:`, ch:[`Prions are viruses with conventional nucleic acid`,`The infectious agent is a misfolded protein (PrPSc) that templates the conversion of the normal cellular prion protein (PrPC) into the misfolded conformation — propagating without nucleic acid`,`Prions replicate by binary fission`,`PrPC is pathogenic and PrPSc is protective`], ans:1, exp:`Prion hypothesis (Prusiner, Nobel 1997): PrPC (α-helix-rich, GPI-anchored, normal) → PrPSc (β-sheet-rich, insoluble, protease-resistant). PrPSc acts as a template: contacts PrPC → induces conformational change → PrPSc; autocatalytic propagation. Strains: different PrPSc conformations can propagate stably → explain multiple disease phenotypes from one protein. Diseases: CJD (sporadic, familial, iatrogenic, variant), kuru (cannibalism), GSS, FFI (familial, D178N+M129 haplotype), scrapie (sheep), BSE (mad cow disease), CWD (chronic wasting, deer). Pathology: spongiform vacuolation, astrogliosis, neuron loss.` },
      { q:`PrPC and PrPSc are encoded by the same gene (PRNP) and have identical primary structure, yet differ in:`, ch:[`Amino acid sequence`,`Post-translational modifications (glycosylation pattern)`,`Secondary and tertiary structure — PrPC is 42% α-helix, 3% β-sheet; PrPSc is 30% α-helix, 43% β-sheet — and physical properties (solubility, proteinase K resistance)`,`Signal peptide presence`], ans:2, exp:`PrPC: monomeric, GPI-anchored (after signal peptide cleavage), two N-glycosylation sites, Cu2+-binding octapeptide repeats, largely unstructured N-terminus + C-terminal domain (α-helices H1/H2/H3 + two short β-strands). Function: uncertain — copper homeostasis, neuroprotection, signaling. PrPSc: same primary structure, reorganized to β-rich conformation → forms oligomers and amyloid fibrils → insoluble in non-denaturing detergents → resistant to PK (proteinase K cleaves N-terminus of PrPSc → 27–30 kDa core = PrP 27-30). This is the basis for PK-resistant Western blot used in prion diagnosis.` },
      { q:`Familial fatal insomnia (FFI) involves a mutation at codon 178 (D178N) of PRNP. The disease phenotype (FFI vs. CJD) depends on:`, ch:[`The presence of two copies of the mutation`,`The amino acid at the polymorphic codon 129 (methionine vs. valine) on the mutant allele — D178N + M129 → FFI; D178N + V129 → familial CJD`,`The gender of the patient`,`The presence of PrP antibodies`], ans:1, exp:`PRNP codon 129: common polymorphism (M or V). Homozygosity (MM or VV) is a risk factor for sporadic CJD and greater susceptibility to prion diseases generally. For D178N mutation: the allele's codon 129 determines phenotype: M/D178N → FFI (fatal insomnia, thalamic neurodegeneration, autonomic failure); V/D178N → familial CJD (dementia predominant). Other pathogenic PRNP mutations: E200K (most common familial CJD worldwide), P102L (GSS), Y145stop (amyloid angiopathy). All variant CJD (vCJD) patients so far have been MM at codon 129.` },
      { q:`The cellular quality control mechanism that degrades misfolded proteins in the ER is:`, ch:[`Autophagy`,`ER-associated degradation (ERAD) — misfolded proteins are retrotranslocated to the cytoplasm via the Hrd1/SEL1L channel and degraded by the 26S proteasome`,`Lysosomal proteolysis only`,`Caspase-mediated cleavage`], ans:1, exp:`ERAD: BiP (HSP70) and calnexin/calreticulin recognize misfolded glycoproteins (via exposed hydrophobic patches or incompletely trimmed N-glycans). Persistent misfolding → ERAD substrate. Retrotranslocation channel: Hrd1 (E3 ubiquitin ligase)/SEL1L complex. Protein is ubiquitinated in the ER lumen/membrane → p97/VCP AAA-ATPase pulls it into cytoplasm → 26S proteasome. UPR (unfolded protein response): if ERAD overwhelmed → IRE1α (XBP1s), PERK (eIF2α-P), ATF6 → expand ER folding capacity, upregulate ERAD, induce apoptosis (CHOP). Diseases: cystic fibrosis (ΔF508 CFTR → ERAD despite partial function).` },
      { q:`Alzheimer disease is associated with the accumulation of which misfolded proteins?`, ch:[`α-synuclein and TDP-43`,`Amyloid-β (Aβ) plaques (extracellular) and hyperphosphorylated tau neurofibrillary tangles (intracellular)`,`Huntingtin polyQ aggregates`,`Prion protein (PrPSc)`], ans:1, exp:`Alzheimer: amyloid cascade hypothesis. APP (amyloid precursor protein) cleaved by β-secretase (BACE1) then γ-secretase (presenilin 1/2) → Aβ40/Aβ42. Aβ42 more aggregation-prone → amyloid fibrils → plaques. Tau: microtubule-associated protein; hyperphosphorylation (GSK3β, CDK5) → dissociates from microtubules → aggregates into PHFs (paired helical filaments) → NFTs. Other proteinopathies: Parkinson: α-synuclein (Lewy bodies); ALS/FTD: TDP-43 or FUS; Huntington: polyQ huntingtin; Parkinson/DLB: both Aβ + α-synuclein. Tau spreads cell-to-cell via prion-like mechanism.` },
      { q:`Chaperone-mediated autophagy (CMA) selectively degrades cytoplasmic proteins bearing a KFERQ-like motif by:`, ch:[`Ubiquitinating substrates for proteasomal degradation`,`HSC70 recognizes KFERQ motif → substrate-HSC70 complex binds LAMP-2A receptor on lysosomal membrane → substrate is unfolded and translocated directly into the lysosome for degradation`,`Engulfing cytoplasm in autophagosomes`,`Using the Hrd1 channel`], ans:1, exp:`CMA (Dice et al.): substrate proteins containing pentapeptide KFERQ-like motif (biochemically: K, R, H + Q + F, I, L, V in specific arrangement). HSC70 (heat shock cognate 70) + co-chaperones (HSP40, HSP90, HIP, HOP) recognizes motif. Complex docks on LAMP-2A (lysosome-associated membrane protein 2A) — rate-limiting receptor. Substrate unfolded → translocated into lysosomal lumen → degraded by cathepsins. Activated during: prolonged starvation, oxidative stress. Declines with age → contributes to accumulation of damaged proteins. Parkinson: α-synuclein with A53T/A30P mutations blocks CMA (not KFERQ-dependent degradation but clogs LAMP-2A channel).` },
      { q:`Which of the following correctly describes the heat shock response?`, ch:[`HSPs are constitutively expressed at maximal levels regardless of stress`,`Misfolded proteins titrate HSP70 away from HSF1 (heat shock factor 1), freeing HSF1 to trimerize, translocate to nucleus, and bind HSEs (heat shock elements) → upregulate HSP70, HSP90, HSP27, etc.`,`The heat shock response is triggered by oxidized nucleotides`,`HSF1 is activated by direct heat sensing without HSP involvement`], ans:1, exp:`Heat shock response: normally, HSF1 monomers are kept inactive by binding to HSP70/HSP90 (chaperone competition model). Stress → protein unfolding → titration of HSP70/90 onto unfolded proteins → HSF1 released → trimerization → hyperphosphorylation → nuclear translocation → HSE (nGAAn repeats) binding → transcription of HSPs. HSPs functions: HSP70 (DnaK ortholog): prevents aggregation, assists folding, ERAD substrate recognition. HSP90: client proteins include HER2, steroid receptors, kinases (Src, Raf, CDK4). HSP27: small HSP, actin stabilization, anti-apoptotic. HSP60 (GroEL ortholog): mitochondrial folding. HSP90 inhibitors (geldanamycin, 17-AAG): anti-cancer.` },
      { q:`SOD1 (superoxide dismutase 1) mutations cause familial ALS by which proposed mechanism?`, ch:[`Loss of SOD1 enzymatic activity alone is sufficient to cause motor neuron death`,`Gain of toxic function — mutant SOD1 misfolds, forms aggregates, and sequesters chaperones/mitochondria/proteasomes; functional SOD1 activity may even be partially retained in mutants`,`Overproduction of superoxide from normal SOD1`,`SOD1 mutations cause lysosomal storage disease`], ans:1, exp:`Familial ALS (~10% of ALS): SOD1 mutations (A4V most common in North America; >200 mutations known). Evidence for toxic gain-of-function: (1) Transgenic mice with human mutant SOD1 develop motor neuron disease even in presence of wild-type SOD1; (2) Reduced/null SOD1 mice do NOT develop ALS. Proposed mechanisms: mutant SOD1 forms misfolded aggregates → impair mitochondria (oxidative phosphorylation), ER function (ER stress), axonal transport, proteasome. Also: wild-type SOD1 may misfold under oxidative stress. Antisense oligonucleotide (tofersen/Qalsody): reduces mutant SOD1 expression → first approved SOD1-ALS treatment.` },
      { q:`The proteasome degrades ubiquitinated proteins. The minimal modification required for 26S proteasomal targeting is:`, ch:[`Monoubiquitination`,`A polyubiquitin chain linked via K48 (at least 4 ubiquitins) — K48-linked chains are the canonical proteasomal signal; monoubiquitin or K63-linked chains serve other functions`,`Phosphorylation`,`SUMO modification`], ans:1, exp:`Ubiquitin (76 aa): attached via E1 (activating) → E2 (conjugating) → E3 (ligase, provides substrate specificity) cascade. Chain linkages: K48-polyUb (≥4) → 26S proteasome degradation (ERAD, cell cycle, tumor suppressors); K63-polyUb → DNA damage response, NF-κB signaling, endolysosomal sorting; K11 → cell cycle (APC/C substrates); M1 (linear) → NF-κB. Monoubiquitin → endocytosis of membrane receptors, histone regulation, DNA repair. 26S proteasome: 20S barrel (protease core: β1=caspase-like; β2=trypsin-like; β5=chymotrypsin-like) + 2×19S regulatory caps (ATPases unfold substrate; deubiquitinases remove chains; gate opens). Proteasome inhibitors: bortezomib, carfilzomib (multiple myeloma).` },
      { q:`Huntington disease involves a polyglutamine (polyQ) expansion in huntingtin (HTT). The pathogenesis is thought to involve:`, ch:[`Loss of normal huntingtin function only`,`Toxic gain-of-function of misfolded polyQ-HTT — the expanded polyQ forms β-amyloid-like aggregates that sequester transcription factors (SP1, CBP), impair proteasomal and mitochondrial function, and cause striatal neurodegeneration`,`A trinucleotide repeat in the 3′ UTR only`,`Reduced HTT mRNA levels`], ans:1, exp:`HD: CAG repeat expansion in exon 1 of HTT gene (>40 repeats = pathogenic; 36–39 = reduced penetrance; <36 = normal). polyQ > ~37: conformation change → aggregation → NIIs (nuclear inclusions). Toxic effects: sequestration of CBP (CREB-binding protein, histone acetyltransferase) → transcriptional dysregulation; impaired axonal transport (huntingtin scaffolds kinesin/dynein); mitochondrial dysfunction (Complex II inhibition — striatal vulnerability because striatal neurons are energy-demanding); excitotoxicity (NMDA receptor hypersensitivity). Trinucleotide repeat disorders: HD (CAG/polyQ, toxic gain), myotonic dystrophy (CTG 3′UTR, RNA-mediated), Fragile X (CGG 5′UTR, loss of FMRP), SBMA (CAG/polyQ in AR). Anticipation: longer repeats in children.` },
      { q:`Parkinson disease is characterized by the presence of Lewy bodies, which are composed primarily of:`, ch:[`Amyloid-β`,`α-synuclein (SNCA) fibrils — misfolded, phosphorylated (S129-pSyn), ubiquitinated aggregates in dopaminergic neurons of the substantia nigra pars compacta`,`Tau paired helical filaments`,`Polyubiquitin chains`], ans:1, exp:`α-synuclein: presynaptic protein, normally regulates SNARE complex. Mutations (A53T, A30P, E46K) or multiplications → misfolding → oligomers (most toxic) → protofibrils → mature fibrils. Lewy bodies: 10–25 μm cytoplasmic inclusions, halo structure (dense fibrillar core + loosely arranged filaments), pSer129-α-syn by IHC. Braak staging: α-syn pathology ascends from olfactory bulb/dorsal motor nucleus (stage 1) → substantia nigra (stage 3) → neocortex (stage 6) → correlation with progression. Parkinson genes: SNCA (PARK1/4), LRRK2 (PARK8, kinase), Parkin (PARK2, E3 ligase, AR), DJ-1 (PARK7), PINK1 (PARK6). Parkin/PINK1 pathway → mitophagy of dysfunctional mitochondria.` },
      { q:`Cystic fibrosis is most commonly caused by the ΔF508 mutation in CFTR, which leads to protein misfolding. The primary defect is at the level of:`, ch:[`Transcription — CFTR mRNA is not produced`,`Protein folding in the ER — ΔF508 CFTR misfolds → retained by calnexin/calreticulin quality control → ERAD degradation → no CFTR reaches the apical membrane`,`CFTR channel gating (the channel reaches the membrane but cannot open)`,`Splice site mutation causing exon skipping`], ans:1, exp:`ΔF508 (deletion of Phe508 in NBD1): misfolding of NBD1 domain → unable to interact properly with MSD2-NBD2 → retained in ER by quality control (calnexin, BiP) → ubiquitinated → ERAD via Hrd1/VCP → proteasomal degradation. Class II mutation (processing/trafficking defect). Some ΔF508 CFTR that escapes to membrane HAS residual gating (Class III component). Lumacaftor/tezacaftor (correctors): pharmacological chaperones that partially correct folding → increased surface expression. Ivacaftor (potentiator): improves gating of CFTR at cell surface. Elexacaftor+tezacaftor+ivacaftor (Trikafta): triple combination — corrects both folding and gating → highly effective for ΔF508 homozygous.` },
      { q:`TDP-43 (TAR DNA-binding protein 43) pathology is found in which neurodegenerative diseases?`, ch:[`Huntington disease and Prion disease`,`ALS (~97% of cases) and frontotemporal dementia (FTD, ~45% of cases) — TDP-43 mislocalizes from nucleus to cytoplasmic inclusions, is hyperphosphorylated and ubiquitinated, and undergoes pathological cleavage to C-terminal fragments`,`Alzheimer disease primarily`,`Multiple sclerosis`], ans:1, exp:`TDP-43 (TARDBP gene): normally nuclear, shuttles nucleus-cytoplasm, regulates pre-mRNA splicing (thousands of targets), mRNA stability, miRNA biogenesis. Pathological: cytoplasmic mislocalization (loss of nuclear TDP-43 → splicing dysregulation; gain of cytoplasmic aggregates → toxic). ~97% sporadic ALS, ~45% FTD-TDP, some AD. TARDBP mutations in familial ALS (1–2%; M337V, A315T, G298S). Related: FUS (ALS/FTD), Matrin 3, hnRNP A1/A2. Cryptic exon derepression: nuclear TDP-43 normally represses cryptic exons in STMN2 and UNC13A; loss → aberrant STMN2/UNC13A isoforms → motor neuron dysfunction. Potential biomarker: neurofilament light chain (NFL) in CSF/blood.` },
      { q:`The signal recognition particle (SRP) pathway is relevant to protein misfolding because:`, ch:[`SRP recognizes misfolded proteins in the ER`,`SRP recognizes the N-terminal signal sequence on nascent polypeptides → arrests translation → docks at the ER membrane (SRP receptor) → cotranslational translocation into the ER lumen, where chaperones assist proper folding`,`SRP is part of the ERAD machinery`,`SRP recognizes KFERQ motifs`], ans:1, exp:`SRP (signal recognition particle): 7SL RNA + 6 proteins (SRP9/14/19/54/68/72). SRP54 (GTPase): recognizes hydrophobic signal sequence as it exits ribosome. Elongation arrest (~40 aa synthesized). SRP docks at SRP receptor (SRα/SRβ) on ER → GTP hydrolysis → ribosome transferred to translocon (Sec61αβγ) → cotranslational translocation. In ER lumen: BiP (HSP70) → prevents premature folding; calnexin/calreticulin (lectin chaperones, bind mono-glucosylated N-glycan); PDI (protein disulfide isomerase) → disulfide bonds. Misfolded: UGGT re-glucosylates → calnexin re-engagement. Irreversible misfolding → ERAD. Co-translational vs. post-translational translocation (TRAP complex for less hydrophobic signals).` },
      { q:`Which statement about amyloid formation is thermodynamically most accurate?`, ch:[`Amyloid fibrils are less stable than natively folded proteins`,`Amyloid fibrils represent a thermodynamically stable β-sheet-rich state — the native fold is kinetically favored under normal conditions, but amyloid represents a global free energy minimum for many proteins once the nucleation barrier is overcome`,`Amyloid formation is always pathological and cannot occur normally`,`Amyloid fibrils are held together by covalent bonds`], ans:1, exp:`Amyloid: cross-β architecture — β-strands perpendicular to fibril axis, H-bonds parallel to axis. Thermodynamics: for many proteins, amyloid is actually the thermodynamic ground state (lower free energy than native fold, possibly even more than random coil). Kinetics: nucleation-dependent polymerization — lag phase (slow nucleus formation), growth phase (rapid elongation), plateau. Seeds (pre-formed fibrils) eliminate lag → seed-dependent growth explains prion-like spread. Congo red birefringence (apple-green under polarized light) — diagnostic. Thioflavin T (ThT) fluorescence assay for amyloid. Functional amyloids: Pmel17 (melanin synthesis), curli fibers (E. coli biofilm), yeast prions [PSI+] (Sup35) — not pathological. Cross-seeding between amyloid types is limited by conformational specificity (transmission barriers).` },
    ]
  },
  { id:`bb65`, cat:`Bio/Biochem`, title:`Warburg Effect & Cancer Metabolism`, diff:`Expert`, qs:[
      { q:`The Warburg effect describes:`, ch:[`Oxidative phosphorylation being the preferred pathway in cancer cells`,`The tendency of cancer cells to preferentially use aerobic glycolysis — converting glucose to lactate even in the presence of sufficient oxygen — a metabolic reprogramming that supports rapid proliferation`,`A complete absence of mitochondria in cancer cells`,`Cancer cells relying exclusively on fatty acid oxidation`], ans:1, exp:`Warburg effect (Otto Warburg, 1956): cancer cells consume glucose at high rates → lactate production even in the presence of O2 (aerobic glycolysis). Not due to mitochondrial dysfunction (mitochondria are often functional); rather, reprogramming for biosynthetic purposes. Benefits: (1) Rapid ATP generation (rate, not yield); (2) Diverts glycolytic intermediates to biosynthesis (nucleotides via PPP, amino acids via serine/one-carbon, lipids via acetyl-CoA); (3) Acidifies tumor microenvironment → immune evasion; (4) Lactate: fuel for OXPHOS in some tumor regions. 18F-FDG PET exploits high glucose uptake. GLUT1, GLUT3 upregulated; HK2 overexpressed.` },
      { q:`Which transcription factor/pathway is the primary driver of metabolic reprogramming in hypoxic tumors?`, ch:[`p53`,`HIF-1α (hypoxia-inducible factor) — stabilized when PHD enzymes are inhibited by low O2 or oncometabolites → transactivates GLUT1, GLUT3, HK2, PGK1, LDHA, PDK1 (inhibits pyruvate dehydrogenase) → shift to glycolysis`,`NRF2`,`PPAR-α`], ans:1, exp:`HIF-1α normally hydroxylated by PHDs (prolyl hydroxylase domain proteins, require O2 and αKG as substrates) → VHL recognition → polyubiquitination → proteasomal degradation. Hypoxia: PHDs inactive → HIF-1α stabilized → translocates to nucleus + HIF-1β (ARNT) → HRE (hypoxia response element) → transcription: GLUT1/3, HK1/2, PGK1, ALDOA, LDHA, PDK1 (blocks pyruvate dehydrogenase → less pyruvate → TCA). Also: VEGF (angiogenesis), EPO (erythropoiesis), carbonic anhydrase IX (pH regulation). Pseudo-hypoxia: oncometabolites (succinate, fumarate, 2-HG from IDH mutation) inhibit PHDs → HIF-1α stabilization even in normoxia. VHL mutations (clear cell RCC): constitutive HIF-1α activation.` },
      { q:`IDH1/IDH2 mutations in glioma and AML produce 2-hydroxyglutarate (2-HG), which causes:`, ch:[`Activation of α-ketoglutarate-dependent dioxygenases`,`Competitive inhibition of α-KG-dependent dioxygenases (TET2, JHDM/KDM family histone demethylases, PHDs) → DNA hypermethylation, histone hypermethylation, HIF stabilization, and a CpG island methylator phenotype (CIMP)`,`Activation of IDH2 wild-type enzyme`,`Increased TCA cycle flux`], ans:1, exp:`IDH1 (cytoplasmic) and IDH2 (mitochondrial) normally: isocitrate → αKG. Neomorphic mutant IDH (R132H for IDH1, R140Q/R172K for IDH2): NADPH + αKG → 2-hydroxyglutarate (R-2-HG, oncometabolite). 2-HG competitively inhibits αKG-dependent enzymes: TET2 (5mC→5hmC demethylation) → DNA hypermethylation (CIMP); KDMs → histone hypermethylation (blocked differentiation); PHDs → HIF-1α stabilization. Net: epigenetic remodeling → differentiation block. IDH1 mutant glioma: IDH1/2 mut + ATRX/TERT → 1p/19q codeletion (oligodendroglioma) or non-codeletion (astrocytoma). IDH inhibitors: enasidenib (IDH2), ivosidenib (IDH1) — approved for AML.` },
      { q:`Glutamine addiction of cancer cells is related to which metabolic need?`, ch:[`Glutamine is needed only as a nitrogen source for amino acid synthesis`,`Glutamine is a major carbon and nitrogen donor — supports TCA anaplerosis (via glutaminolysis: glutamine → glutamate → αKG → TCA), nucleotide synthesis (N9, N3 of purine ring; amide group of asparagine/carbamoyl phosphate), and NADPH production; also supports GSH synthesis`,`Glutamine is used only for glucose synthesis`,`Glutamine is the primary fuel for ATP production only`], ans:1, exp:`Glutamine catabolism (glutaminolysis): GLS (glutaminase): glutamine → glutamate + NH4+; GDH or aminotransferases: glutamate → αKG → enters TCA (anaplerosis). This replenishes TCA intermediates depleted by biosynthetic withdrawal (citrate for lipid synthesis, OAA for aspartate/nucleotides). Glutamine also: N-donor for purine (N3, N9), pyrimidine (CPS-II, N3 of UMP), asparagine (asparagine synthetase), glucosamine-6-P (hexosamine pathway). GSH (γ-Glu-Cys-Gly) synthesis requires glutamate. Glutamine → serine → one-carbon metabolism. MYC oncogene upregulates GLS → drives glutamine addiction. CB-839 (telaglenastat): GLS1 inhibitor in clinical trials.` },
      { q:`The pentose phosphate pathway (PPP) is upregulated in many cancers to provide:`, ch:[`ATP for energy`,`NADPH (for reductive biosynthesis and antioxidant defense via GSH/thioredoxin) and ribose-5-phosphate (for nucleotide synthesis)`,`Acetyl-CoA for fatty acid synthesis`,`Pyruvate for lactate production`], ans:1, exp:`PPP: oxidative branch (irreversible): G6P → 6PGL → 6PG → ribulose-5P; produces 2 NADPH (G6PDH, 6PGDH) per G6P. Non-oxidative branch (reversible): interconverts sugar phosphates → connects PPP with glycolysis (F6P, G3P). In cancer: (1) Nucleotide synthesis (R5P); (2) NADPH for fatty acid/sterol synthesis (FASN, HMGCR); (3) NADPH for GSH/TRX → ROS detoxification (resists oxidative stress from rapid metabolism). G6PD upregulated by KRAS, MYC. TP53 normally suppresses G6PD; p53 loss → PPP upregulation. Transketolase (TKT) and transaldolase link PPP to glycolysis. G6PD deficiency + cancer cells → vulnerability to oxidative stress.` },
      { q:`Oncogene KRAS (Kirsten RAS) promotes the Warburg effect via which downstream pathway?`, ch:[`PI3K/AKT/mTOR only`,`Multiple converging pathways: PI3K/AKT/mTOR (upregulates GLUT1, HIF-1α, HK2), RAF/MEK/ERK (upregulates c-Myc → LDHA, PDK1), and MYC-driven transcriptional reprogramming — together promoting glucose uptake and glycolysis`,`Only by direct phosphorylation of LDHA`,`KRAS does not affect glucose metabolism`], ans:1, exp:`KRAS (GTPase, Gq-type): constitutively active mutants (G12C/D/V, G13D) resist GTPase-activating proteins → locked in GTP-bound (active) state. Downstream: (1) PI3K → PIP3 → AKT → mTORC1 → S6K + 4E-BP1 → protein synthesis, GLUT1 translocation, HIF-1α protein stabilization; (2) RAF → MEK → ERK → c-Myc/c-Jun upregulation → metabolic enzyme transcription; (3) RalGDS → RalA/B → mitochondrial metabolism. KRAS also promotes macropinocytosis (extracellular protein scavenging for amino acids) and autophagy. AMG-510 (sotorasib), MRTX849 (adagrasib): covalent KRASG12C inhibitors — first KRAS-targeted drugs (approved NSCLC, CRC).` },
      { q:`Fatty acid synthesis is upregulated in many cancers. The key lipogenic enzyme is:`, ch:[`Hormone-sensitive lipase (HSL)`,`Fatty acid synthase (FASN) — produces palmitate from acetyl-CoA and malonyl-CoA using NADPH; overexpressed in many cancers (breast, prostate, ovarian) under transcriptional control of SREBP-1c and HER2/PI3K signaling`,`Lipoprotein lipase (LPL)`,`ATGL (adipose triglyceride lipase)`], ans:1, exp:`De novo lipogenesis: acetyl-CoA (from citrate shuttle: mitochondrial citrate → cytoplasm; ATP-citrate lyase/ACLY cleaves) → malonyl-CoA (ACC1) → palmitate (FASN, multifunctional enzyme: KS, AT, DH, ER, KR, ACP, TE domains). NADPH from PPP and malic enzyme (malate → pyruvate). Lipids for: membrane biogenesis (dividing cells need lipids), signaling lipids, protein modification. HER2 → PI3K/AKT → SREBP-1c → FASN. EGFR → FASN. FASN inhibitors: orlistat (FDA-approved lipase inhibitor), TVB-2640 (clinical trials). Citrate synthase (CTP/ACLY) also targeted. SCAP/INSIG/SREBP: sterol regulatory sensing; mTORC1 activates SREBP → lipogenesis.` },
      { q:`The enzyme LDHA (lactate dehydrogenase A) is transcriptionally upregulated in cancer by:`, ch:[`Tumor suppressor p53`,`HIF-1α and c-Myc — both bind promoter elements of LDHA; HIF-1α via HRE; c-Myc via E-box; result: high LDHA activity → pyruvate → lactate → NAD+ regeneration → sustained glycolysis`,`FOXO transcription factors`,`p21 (CDKN1A)`], ans:1, exp:`LDHA: converts pyruvate + NADH → lactate + NAD+. NAD+ regeneration allows continued glycolysis (glyceraldehyde-3-phosphate dehydrogenase step). High LDHA activity is a key Warburg effect effector. Regulation: HIF-1α (hypoxia/pseudo-hypoxia); c-Myc (Myc directly binds E-box on LDHA promoter); NF-κB; STAT3. Serine 88 phosphorylation by FGFR1 → nuclear LDHA → regulates H3 acetylation (moonlighting function). Elevated serum LDH: poor prognosis in lymphoma, melanoma, RCC. LDHA inhibitors: oxalate (competitive), FX11 (NADH competitive). Metformin/IACS-010759 (ETC Complex I inhibitor) indirectly forces cells to rely on LDHA-dependent glycolysis when OXPHOS is impaired.` },
      { q:`Tumor cells in the hypoxic core rely on which metabolic fuel transported from glycolytic cells at the tumor periphery?`, ch:[`Glucose shuttled from aerobic regions`,`Lactate — produced by glycolytic/hypoxic cells, exported via MCT4, taken up by aerobic tumor cells via MCT1 and oxidized in the TCA cycle (reverse Warburg / metabolic symbiosis)`,`Fatty acids via FATP transporters`,`Glucose-6-phosphate`], ans:1, exp:`Metabolic symbiosis / reverse Warburg effect: heterogeneity within tumors — hypoxic core: high HIF-1α → LDHA, MCT4 (exports lactate); aerobic periphery (or stromal cells): MCT1 (imports lactate) → LDH1 (lactate → pyruvate) → TCA/OXPHOS. Shared glucose is conserved for hypoxic cells; lactate fuels aerobic cells. Evidence: Sonveaux et al. 2008 (Nature Medicine) — MCT1 inhibition in oxygenated tumor regions switches cells to glucose → hypoxic core starved. Cancer-associated fibroblasts (CAFs): HIF-1α in CAFs → aerobic glycolysis → lactate/pyruvate secreted → fuel for adjacent tumor cells (paracrine Warburg). AZD3965 (MCT1 inhibitor) in clinical trials.` },
      { q:`The oncometabolite succinate accumulates in SDH-mutant tumors. Its primary pathogenic mechanism is:`, ch:[`Activating oxidative phosphorylation`,`Inhibiting PHD (prolyl hydroxylase domain) enzymes and TET methylcytosine dioxygenases by competitive inhibition at the αKG-binding site → HIF-1α pseudo-hypoxic stabilization + DNA hypermethylation`,`Increasing TCA cycle flux`,`Activating succinate dehydrogenase`], ans:1, exp:`SDH (succinate dehydrogenase) = Complex II. SDHA, SDHB, SDHC, SDHD germline mutations → hereditary paraganglioma/pheochromocytoma syndrome. In tumors: succinate accumulates → exits mitochondria via dicarboxylate transporter → cytoplasm → inhibits PHDs (succinate structurally similar to αKG, acts as product analog — PHDs use αKG → release succinate; accumulated succinate = product inhibitor) → HIF-1α stabilization. Also: succinate inhibits TET2 (αKG-dependent dioxygenase) → 5mC accumulates → DNA hypermethylation → CIMP → epigenetic silencing. Same mechanism for fumarate (fumarate hydratase mutations, hereditary leiomyomatosis/RCC) and 2-HG (IDH mutations). αKG supplementation: potential therapeutic to restore dioxygenase activity.` },
      { q:`mTORC1 acts as a master regulator of anabolic metabolism in cancer. Which of the following is NOT a direct function of mTORC1?`, ch:[`Phosphorylation of S6K1 (ribosomal S6 kinase) → increased protein synthesis`,`Phosphorylation of 4E-BP1 → releases eIF4E → cap-dependent translation`,`Direct phosphorylation of AMPK to inhibit energy sensing`,`Activation of SREBP-1/2 → lipid synthesis; activation of ATF4 → amino acid metabolism; suppression of ULK1 → inhibition of autophagy`], ans:2, exp:`mTORC1 (mTOR + Raptor + mLST8 + PRAS40 + DEPTOR): activated by growth factors (PI3K/AKT), amino acids (Rag GTPases, Ragulator/LYNUS complex on lysosome), energy status (AMPK inhibits mTORC1 by activating TSC2 and phosphorylating Raptor). mTORC1 substrates: S6K1 (ribosome biogenesis, mRNA translation), 4E-BP1 (release eIF4E for cap-dependent translation of HIF-1α, cyclin D1, c-Myc mRNAs), ULK1/2 (autophagy — mTORC1 phosphorylates Ser757 → inhibits ULK1), TFEB (lysosome biogenesis), SRPK2 (splicing), LIPIN1 (SREBP nuclear translocation → lipogenesis). mTORC1 does NOT directly phosphorylate AMPK — it is the reverse (AMPK → mTORC1 inhibition). Rapalogs: rapamycin, everolimus, temsirolimus — partial inhibitors (4E-BP1 not efficiently dephosphorylated); second-gen TOR kinase inhibitors (Torin1, AZD8055) fully block.` },
      { q:`One-carbon metabolism and serine synthesis are upregulated in many cancers. The main functions of one-carbon units are:`, ch:[`One-carbon units are used only for amino acid synthesis`,`Providing methyl groups for DNA/histone methylation, formyl groups for purine ring synthesis (C2, C8), methylene groups for dTMP synthesis, and supporting NADPH production — serine is the primary one-carbon donor via SHMT`,`Carbon source for the TCA cycle only`,`Providing fuel for oxidative phosphorylation`], ans:1, exp:`One-carbon metabolism: folate cycle (cytoplasm) + methionine cycle. Serine → glycine + methylene-THF (SHMT1/2). Methylene-THF: TS (dTMP synthesis); MTHFR → methyl-THF → methionine synthase → methionine → SAM (universal methyl donor: DNA methylation, H3K4me3, H3K9me3, etc.). Formyl-THF (from mitochondria via MTHFD2 → cytoplasm): purine synthesis (C2, C8). PHGDH (phosphoglycerate dehydrogenase): 3-PG → serine (3-PG → 3-phosphohydroxypyruvate → 3-phosphoserine → serine). PHGDH amplified in ER+ breast cancer, melanoma. Serine → one-carbon: supports nucleotide synthesis for proliferating cells. Mitochondrial MTHFD2: produces formate (one-carbon) for cytoplasmic purine synthesis; highly expressed in cancer (oncofetal gene).` },
      { q:`Autophagy can be pro-tumorigenic or anti-tumorigenic depending on context. Which statement is most accurate?`, ch:[`Autophagy always suppresses tumor formation`,`In established tumors, autophagy is predominantly pro-survival — sustains cancer cells under metabolic stress, hypoxia, and therapy; but in early tumorigenesis, autophagy acts as a tumor suppressor by limiting genomic instability and preventing oncogene activation`,`Autophagy only degrades damaged mitochondria (mitophagy)`,`Autophagy activation always correlates with cancer cell death`], ans:1, exp:`Autophagy's dual role: Early: BECN1 (Beclin-1) is a tumor suppressor (monoallelic deletion in ~40–75% of breast/ovarian cancers); autophagy limits: protein aggregates, damaged organelles, p62 accumulation (p62 activates NF-κB), reactive mitochondria → overall restrains oncogenic transformation. Established tumors: autophagy is cytoprotective under: nutrient deprivation (recycling), hypoxia, therapy-induced ER stress; supports RAS-driven tumors (KRAS, BRAF mutants are autophagy-addicted). Mitophagy: PINK1-Parkin pathway removes damaged mitochondria. CQ/HCQ (chloroquine/hydroxychloroquine): block lysosomal acidification → block autophagy → used in cancer trials (+ chemotherapy). ATG proteins: ULK1/2, VPS34, ATG5, ATG7, ATG12, ATG16L1, BECN1.` },
      { q:`The enzyme pyruvate kinase M2 (PKM2) plays a unique role in cancer metabolism by:`, ch:[`Constitutively converting PEP to pyruvate at a high rate`,`Being regulated by allosteric activators (FBP) and inhibitors (phenylalanine, growth factor signaling via tyrosine phosphorylation) — the less active dimeric form slows glycolysis, allowing upstream intermediates to be diverted to biosynthesis; PKM2 also translocates to the nucleus where it acts as a protein kinase and transcriptional coactivator`,`Being completely inactive in cancer cells`,`Promoting OXPHOS over glycolysis`], ans:1, exp:`PK isoforms: PKM1 (constitutively active tetramer, muscle); PKM2 (dimeric/tetrameric interconversion, expressed in fetal tissue and most cancers). Regulation: FBP (fructose-1,6-bisphosphate): allosteric activator → tetramer (active, high Vmax). Tyrosine phosphorylation (EGFR, FGFR signaling) → Y105-P → FBP release → dimer (less active). Less active PKM2 → PEP accumulates → upstream glycolytic intermediates available for biosynthesis. Nuclear PKM2: translocates with HIF-1α → phosphorylates histone H3-T11 → transcriptional activation of c-Myc, cyclin D1. TEPP-46: activates PKM2 tetramer → tumor suppression in animal models. Splice-switch therapy: redirect PKM2 → PKM1 splicing in cancer cells.` },
    ]
  },
  { id:`bb66`, cat:`Bio/Biochem`, title:`Mitochondrial Genetics`, diff:`Expert`, qs:[
      { q:`Maternal inheritance of mitochondrial DNA (mtDNA) is explained by:`, ch:[`Paternal mitochondria are degraded before fertilization`,`Sperm mitochondria are actively eliminated after fertilization — by autophagy (mitophagy) in the fertilized egg; combined with the fact that egg cells contain ~100,000 copies of mtDNA vs. ~100 in sperm → maternal mtDNA vastly predominates`,`All mitochondria are derived from an endosymbiotic event in the mother`,`Father's mitochondria lack mtDNA`], ans:1, exp:`Mitophagy of paternal mitochondria: PINK1-Parkin pathway + p62/LC3 → sperm mitochondria selectively eliminated in zygote. Additionally, egg cytoplasm dilutes paternal mtDNA 1000:1 even if some persists. Heteroplasmya: mix of mutant and normal mtDNA in same cell/tissue. Homoplasmy: all copies identical (mutant or wild-type). Threshold effect: disease manifests when mutant mtDNA exceeds ~60–90% (tissue-dependent — high-energy tissues: brain, muscle, heart, kidney). Sporadic cases: de novo mtDNA mutations. Rare paternal transmission reported in exceptional cases (but not clinically significant for counseling).` },
      { q:`The human mitochondrial genome encodes:`, ch:[`All 13 OXPHOS subunits`,`13 polypeptides (subunits of Complexes I, III, IV, V), 22 tRNAs, and 2 rRNAs — the remaining ~1,500 mitochondrial proteins are nuclear-encoded and imported`,`Only rRNAs and tRNAs`,`The entire mitochondrial proteome`], ans:1, exp:`mtDNA: 16,569 bp circular double-stranded DNA (heavy/light strands). Encodes: 13 polypeptides (ND1-6, ND4L: 7 subunits of Complex I; CYB: Complex III; COX1-3: Complex IV; ATP6, ATP8: Complex V/ATP synthase). 22 tRNAs (sufficient for all 20 amino acids — expanded wobble rules in mitochondria). 2 rRNAs (12S, 16S). D-loop: non-coding control region with replication origin and promoters. Mitochondrial genetic code: differs from universal — UGA = Trp (not stop); AUA = Met; AGA/AGG = stop (not Arg) in vertebrates. Nuclear-encoded mitochondrial proteins (~1,500): imported via TOM/TIM translocases. Mitochondrial disease mutations: both mtDNA (maternal) and nuclear genes (AR or AD).` },
      { q:`Heteroplasmy refers to:`, ch:[`Two different nuclei within the same cell`,`The presence of more than one genotypically distinct mtDNA population within a cell or individual — arises from mtDNA mutation in a subset of molecules; proportion determines phenotype severity (threshold effect)`,`The mixing of paternal and maternal nuclear DNA`,`Equal proportions of wild-type and mutant mtDNA`], ans:1, exp:`Heteroplasmy: cell contains both wild-type and mutant mtDNA. Homoplasmy: all mtDNA copies are identical. Threshold: disease phenotype appears when mutant mtDNA fraction exceeds tissue-specific threshold: CNS/heart/muscle: ~60–90% mutant. Genetic bottleneck: during oogenesis, primary oocytes contain massive mtDNA amplification but only a subset of mtDNA molecules is segregated to each oocyte → rapid drift of heteroplasmy between generations (why same mother can have mildly affected and severely affected children). Replicative segregation: mitotic or meiotic divisions → random partitioning → drift toward homoplasmy. Single-cell sequencing: resolves heteroplasmy levels within individual cells.` },
      { q:`The m.3243A>G mutation (in MT-TL1, tRNALeu) is associated with which syndrome?`, ch:[`Leber hereditary optic neuropathy (LHON)`,`MELAS — Mitochondrial Encephalomyopathy, Lactic Acidosis, and Stroke-like episodes`,`Pearson syndrome`,`Kearns-Sayre syndrome`], ans:1, exp:`m.3243A>G: MT-TL1 gene (tRNALeu UUR). Most common pathogenic mtDNA mutation. MELAS: stroke-like episodes (focal, not following vascular territories), seizures, encephalopathy, lactic acidosis, ragged-red fibers (mitochondrial proliferation, Gomori trichrome stain), elevated CSF lactate, diabetes, hearing loss. MERRF: m.8344A>G (MT-TK, tRNALys) → myoclonus epilepsy with ragged-red fibers. LHON: m.11778G>A (ND4), m.3460G>A (ND1), m.14484T>C (ND6) → bilateral painless visual loss in young males (complex I mutations; >80% males affected due to modifier factors). Kearns-Sayre: large deletions → ophthalmoplegia, retinitis pigmentosa, cardiac block. Pearson: deletions → sideroblastic anemia.` },
      { q:`Leber hereditary optic neuropathy (LHON) is unusual among mitochondrial diseases in its:`, ch:[`Exclusively maternal inheritance`,`Strong male predominance (~4:1 men:women) despite maternal inheritance, suggesting X-linked modifier genes or hormonal factors modulate penetrance`,`Autosomal dominant inheritance pattern`,`Equal prevalence in all ages`], ans:1, exp:`LHON: maternally inherited (mtDNA point mutations), but ~80–90% of mutation carriers are male, only ~10–50% of males who carry a pathogenic mutation develop vision loss. Proposed reasons for male predominance: (1) X-linked nuclear modifier gene (LHON susceptibility locus on Xq25-28 — not yet identified with certainty); (2) Estrogen may be neuroprotective (estrogen upregulates antioxidant pathways); (3) Testosterone may increase mitochondrial ROS sensitivity. LHON mutations affect Complex I subunits → increased ROS → retinal ganglion cell apoptosis → central scotoma → bilateral visual loss (often sequential, days–months apart). Treatment: idebenone (CoQ analog, antioxidant) — modest benefit; gene therapy trials (viral vector with ND4 gene delivered intravitreally).` },
      { q:`In mitochondrial disease, ragged-red fibers seen on muscle biopsy with modified Gomori trichrome stain represent:`, ch:[`Necrotic muscle fibers`,`Subsarcolemmal mitochondrial proliferation — dysfunctional mitochondria attempt to compensate by proliferating, accumulating at the periphery (beneath the sarcolemma) → red-staining aggregates`,`Fiber-type switching`,`Glycogen accumulation`], ans:1, exp:`Ragged-red fibers: characteristic of mitochondrial myopathies with large mtDNA deletions (KSS, Pearson) or tRNA mutations (MELAS: m.3243A>G, MERRF: m.8344A>G). Modified Gomori trichrome: mitochondria stain red against green background. Mechanism: mitochondria lacking functional OXPHOS → energy-deficit signal → PGC-1α activation → mitochondrial biogenesis → compensatory proliferation of dysfunctional mitochondria → subsarcolemmal masses = ragged-red appearance. SDH (succinate dehydrogenase, Complex II, entirely nuclear-encoded) staining: identifies affected fibers even in mtDNA-encoded mutations (COX-deficient fibers by COX/SDH double stain). Electron microscopy: paracrystalline inclusions in mitochondria (parking lot inclusions).` },
      { q:`mtDNA replication is performed by:`, ch:[`RNA polymerase II`,`DNA polymerase gamma (Pol γ, encoded by POLG nuclear gene) — a high-fidelity polymerase with 3′→5′ proofreading; accompanied by mitochondrial single-stranded DNA binding protein (SSBP1) and Twinkle helicase (TWNK)`,`Pol α-primase (same as nuclear)`,`Reverse transcriptase`], ans:1, exp:`Pol γ: catalytic subunit (POLG) + accessory subunit (POLG2). Has 5′→3′ polymerase + 3′→5′ exonuclease (proofreading) + 5′ dRP lyase activities. High fidelity (error rate ~10^-7, 10-fold better than Taq). Twinkle (TWNK): 5′→3′ helicase, unwinds mtDNA. SSBP1: stabilizes ssDNA. TFAM (mitochondrial transcription factor A): compacts mtDNA (histone-like) and also initiates transcription. Mutations: POLG mutations → POLG disease spectrum (POLG-related disorders): Alpers syndrome (childhood hepatocerebral degeneration), progressive external ophthalmoplegia (PEO, AD or AR), SANDO, MNGIE-like; TWNK mutations → PEO. mtDNA replication: displacement-loop (D-loop) model and strand-coupled mechanisms (debated). Initiation at OH (heavy strand origin) in D-loop.` },
      { q:`Mitochondrial import of nuclear-encoded proteins is mediated by:`, ch:[`Signal peptides recognized by the ER translocon`,`N-terminal mitochondrial targeting sequences (MTS) recognized by TOM20/TOM22 on the outer membrane → TOM40 channel → TIM23 complex (inner membrane, matrix-targeted proteins) or TIM22 (inner membrane-integral proteins) → MPP (mitochondrial processing peptidase) cleaves MTS`,`GPI anchoring`,`The nuclear pore complex`], ans:1, exp:`Mitochondrial protein import: ~99% of mitochondrial proteins are nuclear-encoded, translated on cytoplasmic ribosomes, imported post-translationally. MTS (targeting sequence): N-terminal amphipathic helix, net positive charge (basic residues), targets to matrix. TOM complex (translocase of outer membrane): TOM20/22 (receptors), TOM40 (β-barrel pore channel), TOM5/6/7 (assembly). TIM23 pathway (inner membrane, matrix proteins): TIM23 channel + PAM complex (mtHsp70 = HSPA9, drives import by ATP hydrolysis). TIM22 pathway: multi-span inner membrane proteins (e.g., ANT, carriers). TOM40: import of outer membrane β-barrel proteins via SAM complex. Cleaved MTS: MPP (mitochondrial processing peptidase) in matrix. Presequence-containing proteins: also MIA pathway (IMS proteins with twin-Cys motifs).` },
      { q:`MERRF syndrome (myoclonic epilepsy with ragged-red fibers) is caused by which mutation?`, ch:[`m.11778G>A in ND4`,`m.8344A>G in MT-TK (tRNALys) — impairs mitochondrial translation of all mtDNA-encoded proteins → mitochondrial dysfunction`,`Large deletion of mtDNA`,`m.3243A>G in tRNALeu`], ans:1, exp:`MERRF: m.8344A>G (MT-TK, mitochondrial lysine tRNA) — ~80–90% of MERRF cases. Impairs aminoacylation and wobble position reading → general mitochondrial translation deficiency (all 13 proteins affected). Clinical: myoclonus (cortical), epilepsy, ataxia, ragged-red fibers, lactic acidosis, cardiomyopathy, optic atrophy, hearing loss, dementia. Age of onset: childhood–adulthood; severity correlates with heteroplasmy. Other MERRF mutations: m.8356T>C, m.8363G>A (all in MT-TK). Treatment: symptomatic — antiepileptics (valproate avoided: impairs OXPHOS, hepatotoxic in mtDNA disease), CoQ10, riboflavin, L-carnitine. Genetic counseling: maternal inheritance, heteroplasmy complicates penetrance.` },
      { q:`Primary coenzyme Q10 (CoQ10) deficiency causes disease because CoQ10 is:`, ch:[`A cofactor for Complex II only`,`An essential electron carrier linking Complexes I and II to Complex III in the ETC, and an antioxidant in the inner mitochondrial membrane; deficiency causes OXPHOS failure, myopathy, ataxia, and nephropathy`,`A component of the F0 subunit of ATP synthase`,`A fatty acid used for energy`], ans:1, exp:`CoQ10 (ubiquinone, Q): lipid-soluble, mobile electron carrier in inner mitochondrial membrane. Accepts electrons from: Complex I, Complex II, Complex III (in reverse), fatty acid oxidation (ETF:QO), dihydroorotate dehydrogenase (DHODH), choline dehydrogenase, glycerol-3-phosphate dehydrogenase. Transfers electrons to Complex III. Antioxidant: reduced CoQ (QH2) scavenges peroxyl radicals. CoQ10 deficiency syndromes (primary: COQ2-COQ9 gene mutations; secondary: statin therapy, mitochondrial disease): nephropathy (steroid-resistant nephrotic syndrome), ataxia, myopathy, encephalopathy. Treatment: oral CoQ10 supplementation (variable efficacy — limited CNS penetration). Idebenone: short-chain analog, better CNS penetration.` },
      { q:`Why are mitochondrial diseases often multisystemic with predominant involvement of brain, skeletal muscle, heart, and kidneys?`, ch:[`These organs are the only ones with mitochondria`,`These organs have the highest energy demand and greatest reliance on oxidative phosphorylation for ATP production — threshold effect: when mitochondrial function is compromised, high-energy organs reach the threshold for dysfunction first`,`These organs accumulate the most mtDNA mutations`,`Mitochondria in these organs lack compensatory mechanisms`], ans:1, exp:`Energy demand hierarchy (approximate ATP turnover rate): heart > brain ≈ skeletal muscle (during exercise) > kidney. Brain: consumes ~20% of total body energy at rest; neurons are post-mitotic, highly ATP-dependent for ionic gradients (Na/K-ATPase), neurotransmission. Heart: constant activity, >95% ATP from OXPHOS (few glycolytic reserve). Skeletal muscle: large mass, high metabolic flux. Kidney: active transport (proximal tubule — enormous Na/K-ATPase). These tissues are post-mitotic (non-dividing) → less dilution of mutant mtDNA through cell division → accumulate more mutant mtDNA. Tissues with high turnover (intestinal epithelium, blood) have lower mutant heteroplasmy due to continuous cell replacement — rare manifestation.` },
      { q:`Mitochondrial fusion and fission are in dynamic balance. Which statement is correct?`, ch:[`Fission always leads to mitophagy`,`Fusion (MFN1/MFN2 outer membrane; OPA1 inner membrane) promotes complementation of damaged mtDNA/proteins by mixing contents; fission (DRP1 + FIS1/MFF/MiD49/51) is required for mitophagy, apoptosis, and cell division; balance maintains mitochondrial health`,`Fusion is mediated by DRP1`,`OPA1 is required for outer membrane fusion only`], ans:1, exp:`Mitofusins (MFN1/2): GTPases in outer membrane → outer membrane fusion; MFN2 also connects ER and mitochondria (MAM, mitochondria-associated membranes → Ca2+ transfer, lipid synthesis). OPA1: inner membrane GTPase → inner membrane fusion + cristae remodeling (maintain cytochrome c within cristae during apoptosis). DRP1 (dynamin-related protein 1): cytoplasmic GTPase; recruited to mitochondria by adapters (FIS1, MFF, MiD49/51) → forms ring → GTP hydrolysis → constriction → fission. PINK1-Parkin: mitophagy; PINK1 stabilized on depolarized mitochondria → recruits Parkin → ubiquitinates outer membrane proteins → p62/OPTN/NDP52 → LC3 → autophagosome. Disease: OPA1 mutations → Dominant Optic Atrophy; MFN2 mutations → CMT2A; DRP1 mutations → neurodevelopmental (rare).` },
      { q:`The 'm.1555A>G' mutation in the 12S rRNA gene causes:`, ch:[`MELAS`,`Aminoglycoside-induced (and often nonsyndromic) hearing loss — the 12S rRNA mutation changes the ribosome's structure to more closely resemble the bacterial 16S rRNA, making it susceptible to aminoglycoside binding → OXPHOS dysfunction in cochlear hair cells → deafness`,`Leber optic neuropathy`,`Pearson marrow-pancreas syndrome`], ans:1, exp:`m.1555A>G: MT-RNR1 (12S rRNA). Changes the structure of the small ribosomal subunit → mimics bacterial 16S rRNA at the aminoglycoside binding site (decoding A-site). Aminoglycosides (gentamicin, streptomycin, tobramycin, neomycin): bind mitochondrial ribosomes with this mutation → impair mitochondrial protein synthesis → OXPHOS deficiency → cochlear hair cells (metabolically demanding, non-regenerating) → sensorineural hearing loss. Homoplasmic mutation common in certain populations (0.2% of European descent; higher in some Asian populations). Can cause nonsyndromic hearing loss even without aminoglycoside exposure (low penetrance due to modifier genes). Clinical implication: screen mtDNA before using aminoglycosides in patients with family history of deafness.` },
      { q:`Mitochondria-targeted antioxidants (e.g., MitoQ) are designed to:`, ch:[`Inhibit ATP synthase`,`Accumulate in mitochondrial matrix driven by the large negative membrane potential (ΔΨ ≈ −180 mV) — MitoQ = ubiquinone linked to triphenylphosphonium (TPP+) cation; TPP+ concentrates ~1000-fold in mitochondria → brings antioxidant activity directly to the source of mitochondrial ROS`,`Block mitochondrial fission`,`Enhance mitochondrial fusion`], ans:1, exp:`Mitochondria-targeted antioxidants exploit ΔΨ: positively charged (delocalized cation) lipophilic molecules passively accumulate in mitochondrial matrix driven by Nernst equation (180 mV → ~1000-fold enrichment). MitoQ (mitoquinone): TPP+-ubiquinol conjugate; accepted by Complex II → reduced → antioxidant. MitoSOD: TPP+-SOD mimetic. SS-31 (Szeto-Schiller peptide): aromatic-cationic peptide, targets cardiolipin in inner membrane, reduces ROS and preserves cristae. Applications (pre-clinical/clinical): Parkinson, Friedreich's ataxia, heart failure, aging. MitoQ clinical trial for PD: did not slow progression (PROTECT study 2010) — likely insufficient CNS delivery. elamipretide (SS-31): Phase III trials for mitochondrial myopathy and heart failure.` },
      { q:`The Barth syndrome gene (TAZ) encodes which enzyme?`, ch:[`A mitochondrial fusion protein`,`Tafazzin, a transacylase responsible for cardiolipin remodeling — cardiolipin is a unique mitochondrial phospholipid (four acyl chains) critical for ETC complex stability, cristae morphology, and apoptosis; Barth syndrome: cardiomyopathy, skeletal myopathy, neutropenia, 3-methylglutaconic aciduria`,`An OXPHOS Complex I subunit`,`A mitochondrial tRNA synthetase`], ans:1, exp:`Cardiolipin (CL): bis-phosphatidylglycerol (4 acyl chains), exclusively in inner mitochondrial membrane. Roles: (1) Stabilizes ETC supercomplexes (respirasomes); (2) Required for cytochrome c retention in cristae (CL–cytochrome c interaction); (3) Supports OPA1-mediated cristae remodeling; (4) Mitophagy signaling (CL exposed on outer membrane → LC3 recruitment). Tafazzin (TAZ gene, X-linked): transacylase that remodels immature CL (heterogeneous acyl chains) → mature CL (linoleoyl-rich in heart/muscle). Barth syndrome: X-linked, infantile cardiomyopathy, skeletal myopathy, neutropenia, growth retardation, 3-methylglutaconic aciduria (non-specific biomarker), elevated monolysocardiolipin (MLCL:CL ratio). Elamipretide (SS-31) interacts with CL → clinical trials in Barth syndrome.` },
    ]
  },
  { id:`bb67`, cat:`Bio/Biochem`, title:`Autophagy & Ubiquitin-Proteasome`, diff:`Expert`, qs:[
      { q:`The initiation of macroautophagy is regulated by which two key opposing kinase complexes?`, ch:[`PI3K and PTEN`,`mTORC1 (inhibits autophagy) and ULK1/2 complex (initiates autophagy) — AMPK activates ULK1; mTORC1 phosphorylates and inhibits ULK1; nutrient deprivation tips balance toward autophagy`,`PKA and PKC`,`CDK4/6 and CDK2`], ans:1, exp:`Autophagy initiation: Nutrient-replete: mTORC1 active → phosphorylates ULK1 (Ser757) + ATG13 → ULK1 complex inactive. Starvation: mTORC1 inhibited; AMPK activated → phosphorylates ULK1 (Ser317/777) → ULK1 complex (ULK1/2 + ATG13 + FIP200/ATG17 + ATG101) activated → phosphorylates Beclin-1 complex. PI3KC3 complex I (VPS34 + Beclin-1 + ATG14L + VPS15): generates PI3P at ER → phagophore nucleation. PI3P recruits WIPI2 → ATG16L1 → LC3 lipidation machinery. mTORC1 reactivation terminates autophagy when amino acids are regenerated (lysosome-to-cytoplasm amino acid signal via Rag GTPases/LYNUS complex).` },
      { q:`LC3 (microtubule-associated protein 1 light chain 3) is used as a marker of autophagy because:`, ch:[`LC3 is degraded when autophagy is active`,`Pro-LC3 is processed to LC3-I; during autophagy, LC3-I is conjugated to PE (phosphatidylethanolamine) on the phagophore membrane by the ATG5-ATG12-ATG16L1 E3 complex → LC3-II; LC3-II remains on the autophagosome membrane until fusion with lysosome`,`LC3 is a proteasomal subunit`,`LC3 is only found on the inner autophagosomal membrane`], ans:1, exp:`LC3 lipidation pathway: pro-LC3 → ATG4B cleavage → LC3-I (cytosolic) → ATG7 (E1-like) → ATG3 (E2-like) → ATG5-ATG12-ATG16L1 (E3-like) → LC3-II (PE-conjugated). LC3-II: decorates both inner and outer autophagosomal membrane; inner LC3-II is degraded in lysosome; outer LC3-II is cleaved by ATG4B after fusion. LC3 turnover assay: LC3-II/LC3-I ratio; with lysosome inhibitor (bafilomycin A1, CQ) → LC3-II accumulates → confirms autophagic flux. LC3 puncta: fluorescent dots in cells = autophagosomes. FYVE and coiled-coil domain protein ALFY, p62/SQSTM1, NBR1, NDP52, OPTN: cargo receptors that bridge ubiquitinated cargo to LC3.` },
      { q:`p62 (sequestosome 1/SQSTM1) functions as a selective autophagy receptor by:`, ch:[`Directly fusing autophagosomes with lysosomes`,`Binding polyubiquitinated cargo (via UBA domain) and LC3-II on the autophagosome membrane (via LIR motif) — bridges cargo to autophagosome for selective degradation; also activates NF-κB (via TRAF6 binding) and NRF2 (via Keap1 binding/sequestration)`,`Activating mTORC1`,`Phosphorylating ULK1`], ans:1, exp:`p62/SQSTM1 domain structure: PB1 (oligomerization, interaction with other PB1 proteins); ZZ (RhoA); TB (TRAF6, NF-κB activation); LIR (LC3-interacting region — consensus WXXL or FXXL → binds LC3-II, GABARAP); KIR (Keap1-interacting, activates NRF2); UBA (ubiquitin-associated, K63-Ub and K48-Ub binding). p62 accumulation: when autophagy is blocked → used as marker of autophagic flux impairment. p62 aggregates: seen in liver disease (alcoholic hepatitis, NASH), neurodegenerative disease (Lewy bodies contain p62). NRF2: Keap1 normally sequesters/ubiquitinates NRF2 → proteasomal degradation; p62 sequesters Keap1 → NRF2 released → ARE-driven antioxidant genes (HO-1, NQO1, GCLC, GCLM).` },
      { q:`Mitophagy (selective autophagy of mitochondria) in PINK1-Parkin pathway is initiated by:`, ch:[`DRP1 fission alone`,`Mitochondrial membrane depolarization → PINK1 (kinase) accumulates on outer membrane (normally imported and cleaved/degraded) → PINK1 phosphorylates ubiquitin (Ser65) and MFN2 → recruits and activates Parkin (E3 ubiquitin ligase) → Parkin ubiquitinates outer membrane proteins → NDP52/OPTN recruit autophagy machinery → mitophagy`,`Beclin-1 directly binding mitochondria`,`Cytochrome c release triggering autophagy`], ans:1, exp:`PINK1-Parkin pathway: (1) Healthy mitochondria (high ΔΨ): PINK1 is imported into IMM → cleaved by PARL (presenilin-associated rhomboid-like protease) → retrotranslocated to cytoplasm → degraded. (2) Damaged mitochondria (low ΔΨ): PINK1 import halted → accumulates on TOM complex on OMM → kinase activated. (3) PINK1 phosphorylates Ub at Ser65 → recruits Parkin (PhosphoUb binds Parkin RING1 domain) + phosphorylates Parkin Ser65 directly → Parkin activated. (4) Parkin ubiquitinates OMM proteins (VDAC1, TOM20, MFN1/2) → K63+K27 chains. (5) Autophagy receptors (NDP52, OPTN) bind pUb → recruit ULK1 complex and LC3-containing autophagosomes. Parkin/PINK1 mutations → familial Parkinson disease (AR-PARK2/PARK6).` },
      { q:`The ubiquitin E3 ligase APC/C (anaphase-promoting complex/cyclosome) regulates cell cycle by:`, ch:[`Ubiquitinating and stabilizing cyclin B`,`Targeting cyclin B and securin for K11-linked polyubiquitination and 26S proteasomal degradation — allowing mitotic exit and chromatid separation`,`Activating CDK1`,`Inhibiting CDC20`], ans:1, exp:`APC/C: large multi-subunit RING E3 ligase. Activated by co-activators: CDC20 (mitosis, recognizes D-box degrons) and CDH1 (G1, recognizes D-box and KEN-box degrons). APC/C-CDC20 (activated by CDK1): targets cyclin B (CDK1 deactivation → mitotic exit) and securin (cohesin protease separase inhibitor → securin degradation → separase active → cohesin cleaved → chromosome separation → anaphase). APC/C-CDH1 (G1): keeps CDK activity low, targets aurora kinases, CDC20 itself. SAC (spindle assembly checkpoint): BubR1+Mad2 → MCC (mitotic checkpoint complex) → inhibits APC/C-CDC20 until all kinetochores attached to spindle. APC/C uses K11 chains (also K48) — recognized by proteasome via shuttle factors.` },
      { q:`CHIP (C-terminus of HSC70-interacting protein) functions as:`, ch:[`A lysosomal hydrolase`,`A co-chaperone AND E3 ubiquitin ligase — CHIP's TPR domain binds HSP70/HSC70 and HSP90 (C-terminus IEEVD motif); CHIP's U-box E3 domain ubiquitinates misfolded/aggregated chaperone substrates → coupling protein quality control to proteasomal degradation`,`An autophagy receptor`,`A component of the TOM complex`], ans:1, exp:`CHIP (STUB1): molecular link between chaperone and UPS. Mechanism: HSP70 + misfolded client → CHIP-TPR binds HSP70 C-terminus → CHIP U-box ubiquitinates client → proteasome. Also: CHIP binds HSP90 → targets clients for degradation rather than maturation (competition between co-chaperones Hop (folding) and CHIP (degradation)). Substrates: glucocorticoid receptor, HER2/ErbB2, tau (CHIP reduces tau levels — reduced in AD), CFTR (ΔF508), cystic fibrosis. CHIP overexpression: reduces tau/α-syn pathology in animal models. STUB1 mutations: autosomal recessive cerebellar ataxia with cognitive dysfunction (SCAR16) — loss of CHIP → protein quality control failure.` },
      { q:`Deubiquitinases (DUBs) can both promote and oppose proteasomal degradation. The DUB USP14 associated with the 19S proteasome:`, ch:[`Adds ubiquitin chains to substrates`,`Trims ubiquitin chains on proteasome-bound substrates — can prematurely remove chains before translocation, potentially rescuing substrate from degradation; USP14 inhibition (by IU1) → increased proteasomal degradation of ubiquitinated proteins`,`Activates the 20S core particle`,`Delivers substrates to the 26S proteasome`], ans:1, exp:`DUB classes: USP (ubiquitin-specific protease), UCH (ubiquitin C-terminal hydrolase), OTU, MJD/Josephin, JAMM (metalloprotease), MINDY. Proteasome-associated DUBs: USP14 (19S, reversible — can rescue substrates by chain trimming; inhibition → more degradation); UCHL5/UCH37 (19S, similar chain editing); RPN11/POH1 (19S RPT lid, essential — removes chains en bloc as substrate enters translocation channel, enabling efficient degradation). IU1 (USP14 inhibitor): enhances proteasomal degradation of tau, TDP-43, ataxin-3 in animal models — therapeutic potential. UCH-L1: mainly neurons; mutations → autosomal dominant PD (rare). OTUB1: non-canonical DUB — binds E2 UBC13 directly, inhibiting K63 ubiquitination without catalytic deubiquitination.` },
      { q:`The ERAD (ER-associated degradation) pathway uses which unique retrotranslocation machinery?`, ch:[`The Sec61 translocon for reverse transport`,`The HRD1/SEL1L complex as the retrotranslocation channel, with p97/VCP (AAA-ATPase) extracting misfolded proteins from the ER using ATP hydrolysis energy`,`Lysosomal cathepsins`,`The TOM complex`], ans:1, exp:`ERAD substrates: ERAD-L (lumen), ERAD-M (membrane), ERAD-C (cytoplasmic-facing). ERAD-L pathway (Hrd1 branch): EDEM (lectin, recognizes α1,6-mannose) → OS9/XTP3-B → retrotranslocon (HRD1/SEL1L complex: HRD1 is an E3 RING ligase + channel). p97/VCP (valosin-containing protein, mammalian ortholog of Cdc48/yeast): cytoplasmic AAA-ATPase hexamer; cofactors UFD1-NPL4 → extracts substrates from ER membrane into cytoplasm → delivers to 26S proteasome. DerlinDE1/2/3: accessory retrotranslocation components. Substrate modifications: glycan trimming by mannosidases (MAN1B1, EDEM) generates ERAD signal. CFTR ΔF508: model ERAD substrate. VCP mutations → IBM-PDB-FTD (inclusion body myopathy, Paget disease, frontotemporal dementia) — rare autosomal dominant disorder.` },
      { q:`Selective autophagy of ribosomes (ribophagy) is triggered by:`, ch:[`Ribosome overproduction`,`Ribosome stalling during translation`,`Nutritional stress (nitrogen starvation) in yeast — mediated by Ubp3/Bre5 (deubiquitinase complex) that deubiquitinates 60S subunit protein Rpl25 → recognized by Atg19-independent receptor pathway; in mammals, NUFIP1 and Rack1 are implicated in ribophagy under nutrient stress`,`High mTORC1 activity`], ans:2, exp:`Ribophagy: selective autophagy of ribosomes during starvation (recycle amino acids from ribosomal proteins). Yeast: Ubp3 (deubiquitinase) + Bre5 (co-activator) — deubiquitinate 60S Rpl25 → ribophagy receptor function. Mammalian ribophagy: less characterized; NUFIP1 (nuclear fragile X mental retardation protein interacting protein 1): cytoplasmic partner of RACK1 (ribosome-associated); RNF185/BNIP1L/CALCOCO1 also implicated. Ribophagy vs. mRNA quality control: ribophagy degrades entire ribosomes; ribophagy is distinct from ribosome-associated quality control (RQC) which handles stalled ribosomes and produces CAT-tail (alanine-threonine tails on nascent polypeptides to facilitate proteasomal degradation of stalled products via LTN1/listerin E3 ligase and NEMF).` },
      { q:`The proteasome core particle (20S) contains which types of protease activities?`, ch:[`Only serine proteases`,`Caspase-like (β1, cleaves after acidic residues), trypsin-like (β2, cleaves after basic residues), and chymotrypsin-like (β5, cleaves after hydrophobic residues) — all threonine proteases in the β-subunit active sites`,`Aspartate proteases`,`Cysteine proteases only`], ans:1, exp:`20S proteasome: barrel-shaped stack of four heptameric rings: α7-β7-β7-α7. α-rings (α1-α7): gating (19S opens gate via α3 N-terminal insertion). β-rings (β1-β7): three active β-subunits (β1, β2, β5) with N-terminal threonine as nucleophile. Activities: β1 (PSMB6): caspase-like (cleaves Asp/Glu); β2 (PSMB7): trypsin-like (cleaves Arg/Lys); β5 (PSMB5): chymotrypsin-like (cleaves Phe/Leu/Tyr) — most important, rate-limiting, target of bortezomib/carfilzomib. Immunoproteasome: induced by IFN-γ → β1i (LMP2), β2i (MECL1), β5i (LMP7) replace constitutive subunits → altered cleavage specificity → generates peptides optimal for MHC-I loading. Thymoproteasome: β5t → thymic education of T cells.` },
      { q:`Which E3 ubiquitin ligase targets hypoxia-inducible factor 1α (HIF-1α) for proteasomal degradation under normoxia?`, ch:[`MDM2`,`VHL (von Hippel-Lindau) — acts as the substrate recognition component of a CRL2-VHL E3 ligase; recognizes HIF-1α only when it is hydroxylated on Pro402/Pro564 by PHDs (O2-dependent)`,`Parkin`,`CHIP/STUB1`], ans:1, exp:`HIF-1α degradation: normoxia → PHD1/2/3 (prolyl hydroxylase domain proteins; require O2, αKG, Fe2+, ascorbate) → hydroxylates HIF-1α Pro402/Pro564 → VHL recognition (VHL-ElonginC-ElonginB-CUL2-RBX1 = CRL2VHL complex) → K48-polyubiquitination → 26S proteasomal degradation. HIF-1α half-life ~5 min in normoxia; hypoxia → PHDs inactive → HIF-1α stable. FIH (factor inhibiting HIF): hydroxylates Asn803 on HIF-1α → blocks p300/CBP coactivator interaction → additional transcriptional repression. VHL mutations: clear cell RCC (biallelic VHL loss → constitutive HIF-1α → VEGF, EPO, GLUT1). Hereditary: Von Hippel-Lindau syndrome (hemangioblastomas, ccRCC, pheochromocytoma). VHL loss: PHD2 inhibitors (daprodustat, roxadustat) used in anemia of CKD.` },
      { q:`Aggrephagy refers to:`, ch:[`Autophagy of aggregated RNA`,`Selective autophagy of protein aggregates — mediated by cargo receptors p62, NBR1, and ALFY that recognize polyubiquitinated aggregates and bridge them to LC3/GABARAP on autophagosomes; key for clearance of huntingtin, α-synuclein, and tau aggregates`,`Lysosomal storage disease`,`Proteasomal degradation of aggregates`], ans:1, exp:`Aggrephagy: substrate aggregates are first collected at the aggresome (perinuclear, HDAC6-dependent: HDAC6 binds polyUb via BUZ domain + dynein → retrograde transport on microtubules → aggresome at MTOC). Aggresome markers: vimentin cage, ubiquitin+. Then autophagic receptors (p62, NBR1 via PB1-mediated oligomerization; ALFY/WDFY3 bridges p62-LC3) recruit autophagy machinery. Also: nuclear aggregates cleared by NPC (nuclear pore-associated autophagy) or proteasome. Failure: neurodegenerative diseases (HD, PD, ALS). HSP90 inhibitors (geldanamycin) → reroute aggregates to autophagy. VCP/p97 mutations → impair aggresome-autophagy flux → IBM-PDB-FTD. HDAC6: also deacetylates tubulin and HSP90 — multiple roles in quality control.` },
      { q:`Ubiquitin chains linked via K63 serve primarily which cellular functions?`, ch:[`Proteasomal degradation of short-lived proteins`,`DNA double-strand break repair (recruitment of RNF8/RNF168 → H2A-K63ub → MDC1/53BP1 signaling), endosomal sorting (ESCRT pathway), NF-κB signaling (TRAF6/RIP1 → IKK activation), and autophagy receptor-mediated cargo capture`,`Cell cycle arrest`,`Splicing regulation`], ans:1, exp:`Ubiquitin chain linkage codes: K48 → proteasomal degradation (canonical); K63 → non-proteolytic signaling: (1) DNA DSB: RNF8 (E3, recognizes γH2AX/MDC1) → H1-K63ub → RNF168 amplification → H2A-K13/15ub → 53BP1 (K20me2 on H4) + BRCA1 recruitment → DNA repair pathway choice; (2) NEMO (IKKγ) binds K63-Ub chains → IKK complex activation → NF-κB; (3) TRAF6 autoubiquitination (K63) → signaling platform; (4) Autophagy receptors (OPTN, NDP52) prefer K63-Ub or phospho-Ub on mitochondria for mitophagy; (5) ESCRT-0 (Hrs/STAM) binds K63-Ub monoUb → endosomal sorting. K27-Ub: Parkin-mediated mitophagy. Linear/M1-Ub: LUBAC complex → NF-κB. K11-Ub: APC/C substrates.` },
      { q:`The Nrf2-Keap1 pathway is regulated by the ubiquitin-proteasome system. Under homeostatic conditions:`, ch:[`Nrf2 is constitutively active in the nucleus`,`Keap1 (substrate adapter for CRL3 E3 ligase containing Cullin3-RBX1) constitutively ubiquitinates Nrf2 (K48) → rapid proteasomal degradation; oxidative stress or electrophiles modify Keap1 cysteine sensors → Keap1 conformational change → Nrf2 not ubiquitinated → accumulates → nucleus → ARE-driven cytoprotective genes`,`Nrf2 is only activated by inflammation`,`Keap1 is nuclear`], ans:1, exp:`Keap1: BTB-Kelch domain protein. Kelch domain: binds Nrf2 ETGE and DLG motifs (two-site binding). BTB domain: interfaces with Cullin3 → CRL3Keap1 E3 ligase. Normally: Nrf2 continuously ubiquitinated → short half-life (~10–20 min). Activated: Cys151, Cys273, Cys288 on Keap1 modified by ROS, electrophiles, p62/SQSTM1, NIKEAp → Keap1 trapped in closed conformation → cannot release Nrf2 → Nrf2 accumulates → Maf heterodimerization → ARE binding → HO-1, NQO1, GCLM, GCLC, ferritin, thioredoxin, GPx2. Cancer: KEAP1 and NFE2L2 (Nrf2) are commonly mutated in NSCLC, HNSCC, liver cancer → constitutively active Nrf2 → chemotherapy resistance, metabolic reprogramming. Bardoxolone: Nrf2 activator, clinical trials for CKD.` },
    ]
  },
  { id:`bb68`, cat:`Bio/Biochem`, title:`Serine Proteases & Zymogens`, diff:`Expert`, qs:[
      { q:`The catalytic mechanism of serine proteases involves which arrangement of active site residues?`, ch:[`Lys-His-Ser (KHS) triad`,`Ser-His-Asp catalytic triad — Asp orients His; His acts as general base to deprotonate Ser OH → nucleophilic attack on peptide carbonyl → tetrahedral intermediate → acyl-enzyme → His reprotonates leaving amine → water attacks acyl-enzyme → product released`,`Cys-His-Asn`,`Two His residues and one Cys`], ans:1, exp:`Serine proteases: chymotrypsin, trypsin, elastase, thrombin, factor Xa, plasmin, subtilisin (bacterial, convergent evolution). Catalytic triad: Ser195-His57-Asp102 (chymotrypsin numbering). Mechanism: (1) Asp102-His57 hydrogen bond stabilizes His57 protonation state; (2) His57 deprotonates Ser195 OH → nucleophile; (3) Ser attacks carbonyl → oxyanion tetrahedral intermediate → oxyanion hole (Gly193-NH, Ser195-NH) stabilizes negative charge; (4) Amide bond cleaved → acyl-enzyme + amino product (first product leaves); (5) His57 deprotonates water → hydroxide attacks acyl-enzyme → second tetrahedral intermediate → carboxyl product released. Specificity pocket: S1 pocket. Chymotrypsin: large hydrophobic; Trypsin: Asp189 in S1 → Arg/Lys; Elastase: Val216/Thr226 occlude pocket → small residues (Ala, Val).` },
      { q:`Trypsinogen is activated to trypsin by:`, ch:[`Autocatalytic activation by trypsin only`,`Enteropeptidase (enterokinase) in the duodenum — cleaves the Lys6-Ile7 peptide bond in trypsinogen → releasing the activation hexapeptide → active trypsin; trypsin then activates other zymogens (chymotrypsinogen, proelastase, procarboxypeptidases, prophospholipase)`,`Pepsin in the stomach`,`Bile salts`], ans:1, exp:`Pancreatic zymogen activation cascade: enteropeptidase (brush border membrane enzyme, encoded by TMPRSS15, trypsinogen → trypsin) → trypsin activates all other pancreatic zymogens. Trypsinogen → trypsin: Lys6-Ile7 bond cleaved; Ile7 inserts into activation pocket → conformational change → active site forms (Asp189 in S1 pocket now accessible). The activation peptide (Val-Asp-Asp-Asp-Asp-Lys) is released. Trypsin is autocatalytic (amplification loop). Acute pancreatitis: premature trypsinogen activation within pancreatic acinar cells → autodigestion. SPINK1: pancreatic secretory trypsin inhibitor (Kazal type 1) → inhibits intrapancreatic trypsin. PRSS1 mutations → hereditary pancreatitis (gain-of-function → easier trypsinogen autoactivation).` },
      { q:`α1-antitrypsin (α1-AT, SERPINA1) inhibits which protease, and how does its mechanism work?`, ch:[`Pepsin, by competitive inhibition`,`Elastase (and other serine proteases) — α1-AT is a suicide substrate: its reactive center loop (RCL, Met358-Ser359) mimics an elastase substrate → elastase forms a covalent acyl-enzyme intermediate → RCL inserts into β-sheet A → distorts elastase active site → forms stable 1:1 covalent complex (serpin-enzyme complex)`,`Trypsin, by binding the S1 pocket non-covalently`,`Collagenase, by chelating zinc`], ans:1, exp:`Serpins (serine protease inhibitors): structural mechanism — conformational change irreversibly inhibits enzyme. α1-AT (M allele: normal; S allele: moderate deficiency; Z allele: severe deficiency → polymerization in hepatocytes → accumulation → liver disease; also low serum levels → insufficient neutrophil elastase inhibition → emphysema). RCL cleavage → massive conformational change → N-terminus of cleaved RCL inserts into central β-sheet A of serpin as strand 4A → enzyme active site is contorted → irreversible inhibition. Clinical: α1-AT deficiency → panacinar emphysema (lower lobes), liver cirrhosis. Treatment: weekly IV augmentation therapy (purified α1-AT), liver transplant, FDA-approved AAV gene therapy.` },
      { q:`The coagulation cascade involves serine proteases. Which factor is the common pathway junction point?`, ch:[`Factor VII`,`Factor X (Stuart-Prower factor) — activated by either the extrinsic pathway (TF-VIIa) or intrinsic pathway (IXa-VIIIa) → Factor Xa forms prothrombinase complex with Factor Va, phospholipid, and Ca2+ → cleaves prothrombin (Factor II) → thrombin (Factor IIa)`,`Fibrinogen (Factor I)`,`Factor XIII`], ans:1, exp:`Coagulation cascade: Extrinsic: TF-VIIa → activates X (and IX). Intrinsic: XII → XI → IX → IXa-VIIIa (tenase complex) → X. Common: Xa + Va + PL + Ca2+ (prothrombinase) → prothrombin → thrombin. Thrombin: cleaves fibrinogen → fibrin; activates XIII → XIIIa (cross-links fibrin); activates V, VIII, XI (positive feedback); activates protein C (negative feedback on Va/VIIIa). TFPI: inhibits TF-VIIa-Xa complex. Antithrombin III: inhibits thrombin, Xa (accelerated by heparin). Protein C/S: inactivates Va and VIIIa. Direct oral anticoagulants: rivaroxaban/apixaban (Xa inhibitors), dabigatran (thrombin inhibitor).` },
      { q:`Hemostasis involves plasminogen activation to plasmin for fibrinolysis. tPA (tissue plasminogen activator) is most active:`, ch:[`In free solution with circulating plasminogen`,`On the surface of fibrin clots — fibrin acts as a cofactor that co-localizes tPA and plasminogen → dramatically increases local plasmin generation; this ensures fibrinolysis is targeted to clots rather than systemic fibrinogen degradation`,`Inside platelets`,`In the absence of fibrin`], ans:1, exp:`tPA (serine protease): secreted by endothelium. Plasminogen: zymogen → plasmin (serine protease) by cleavage of Arg560-Val561. Free tPA: low activity (Km for plasminogen is high). Fibrin binding: tPA has kringle domains + fibrin-binding domain; fibrin provides template → co-localization of tPA + plasminogen → 1000-fold increase in plasminogen activation efficiency. Plasmin: degrades fibrin → D-dimer + FDPs. Streptokinase, urokinase: non-fibrin-specific plasminogen activators → systemic fibrinolysis → higher bleeding risk. Alteplase (recombinant tPA): STEMI, ischemic stroke (within 4.5h), PE. α2-antiplasmin: rapidly inactivates free plasmin but not fibrin-bound plasmin. PAI-1 (plasminogen activator inhibitor 1): inhibits tPA; elevated in obesity/metabolic syndrome → prothrombotic.` },
      { q:`Complement component C3 is activated by which of the three pathways, and what is the shared amplification step?`, ch:[`C3 is only activated by antibody-dependent mechanisms`,`Classical (antigen-antibody-C1qrs), lectin (MBL/ficolins-MASP1/2), and alternative (spontaneous C3 hydrolysis + factor B/D) pathways all generate C3 convertases (C4b2a for classical/lectin; C3bBb for alternative) that cleave C3 → C3a (anaphylatoxin) + C3b (opsonin)`,`Complement is a serine protease cascade but is independent of C3`,`Only IgM triggers C3 activation`], ans:1, exp:`Complement: classical (IgM/IgG immune complexes → C1q binding → C1r/C1s serine proteases → C4a,b → C4b binds surface → C2 → C2a,b → C3 convertase C4b2a); lectin (MBL or ficolins bind PAMPs → MASPs activate → same as classical → C4b2a); alternative (spontaneous C3 hydrolysis → C3(H2O)Bb = initial C3 convertase → C3b deposited → factor B → factor D cleaves Bb → C3bBb on surface → amplification loop). C5 convertases: C4b2a3b (classical/lectin) or C3b2Bb (alternative) → C5 → C5a (potent anaphylatoxin, chemotaxis) + C5b → MAC (C5b-9) → membrane attack complex → lysis. Regulators: DAF, MCP, CR1 — accelerate convertase decay; Factor I (serine protease) + cofactors (Factor H) cleave C3b/C4b.` },
      { q:`Prostate-specific antigen (PSA) is a serine protease in the kallikrein family. Its clinical use is:`, ch:[`It is 100% specific for prostate cancer`,`PSA (KLK3) cleaves semenogelin I/II in seminal fluid (liquefaction); serum PSA is elevated in prostate cancer, benign prostatic hyperplasia (BPH), and prostatitis — used as a screening/monitoring biomarker but lacks specificity`,`PSA enzymatic activity is used to activate prodrugs in the prostate`,`PSA is only secreted by cancerous prostate cells`], ans:1, exp:`KLK3 (kallikrein 3, PSA): secreted by prostatic epithelium → seminal plasma; cleaves semenogelin I/II → semen liquefaction. Serum PSA: normal <4 ng/mL; PSA 4–10 ng/mL = "gray zone" (25% chance cancer); PSA >10 ng/mL higher risk. Free/total PSA ratio: low ratio (<15%) favors cancer. PSA velocity (rate of rise) and PSA density also used. Limitations: BPH, prostatitis, ejaculation, prostate manipulation can elevate PSA → high false positive rate → overdiagnosis/overtreatment controversy. Current guidelines: shared decision-making for PSA screening (ages 55–69). Monitoring: post-prostatectomy PSA should be undetectable; rising PSA (PSA relapse) suggests recurrence. PSMA (prostate-specific membrane antigen): separate biomarker, target for PET imaging and targeted therapy (177Lu-PSMA).` },
      { q:`The serine protease inhibitor aprotinin (Trasylol) was historically used in cardiac surgery to:`, ch:[`Prevent platelet aggregation`,`Inhibit kallikrein, plasmin, and trypsin → reduce fibrinolysis and contact activation → decrease perioperative bleeding; withdrawn from market in 2007 due to increased mortality (renal failure, MI, stroke) vs. lysine analogs`,`Block thrombin directly`,`Activate protein C`], ans:1, exp:`Aprotinin: bovine-derived Kunitz-type serine protease inhibitor. Inhibits: plasmin (anti-fibrinolytic), kallikrein (anti-inflammatory, reduces contact activation), trypsin. Used in CABG to reduce blood loss. BART trial (2007): aprotinin → increased 30-day mortality vs. tranexamic acid and aminocaproic acid (lysine analogues that block plasminogen binding to fibrin) → withdrawn worldwide. Partial re-approval in some countries for specific uses. Lysine analogues (tranexamic acid = TXA, ε-aminocaproic acid): competitive inhibitors of plasminogen lysine-binding sites → prevent plasminogen binding to fibrin → anti-fibrinolytic. TXA: widely used now for trauma, postpartum hemorrhage (CRASH-2, WOMAN trials), cardiac surgery.` },
      { q:`Granzyme B (GzmB) is a serine protease secreted by cytotoxic T lymphocytes (CTLs) and NK cells. Its mechanism of target cell killing involves:`, ch:[`Direct activation of complement`,`Entry into target cell (facilitated by perforin pore) → cleaves substrates after Asp residues (caspase-like specificity) → directly activates caspase-3/7 and BID (tBID → mitochondrial apoptosis)`,`Blocking mTOR in target cells`,`Inhibiting NF-κB in target cells`], ans:1, exp:`CTL/NK killing: immunological synapse → degranulation of lytic granules (secretory lysosomes). Perforin (PFN): polymerizes in Ca2+-dependent manner → pores in target cell membrane → facilitates granzyme entry (debated: endocytic pathway + direct pore entry). GzmB: serine protease (chymotrypsin fold); aspartyl specificity (ASP in P1 position) → unlike other serine proteases (Arg/Lys or hydrophobic). GzmB substrates: caspase-3 (Asp175 → directly activates executioner caspase), caspase-7, BID → tBID → MOMP → cytochrome c → apoptosome. Also directly cleaves ICAD (inhibitor of caspase-activated DNase) → CAD activated → DNA fragmentation. Granule exocytosis pathway: perforin deficiency → hemophagocytic lymphohistiocytosis (HLH). Granzyme A: tryptase, activates caspase-independent pathway via SET complex.` },
      { q:`Dipeptidyl peptidase 4 (DPP-4) is a serine protease targeted by gliptins. Its mechanism of action in type 2 diabetes involves:`, ch:[`Blocking insulin secretion`,`DPP-4 rapidly inactivates GLP-1 and GIP (incretin hormones) by cleaving the N-terminal dipeptide (His-Ala in GLP-1); DPP-4 inhibitors (sitagliptin, saxagliptin) prevent incretin degradation → prolonged GLP-1/GIP activity → glucose-dependent insulin secretion increase + glucagon suppression`,`Enhancing glucagon action`,`Activating hepatic gluconeogenesis`], ans:1, exp:`Incretins: GLP-1 (glucagon-like peptide 1) and GIP (glucose-dependent insulinotropic polypeptide) — released from gut L and K cells after meals. Mechanisms: stimulate glucose-dependent insulin secretion (β cells); suppress glucagon (α cells, GLP-1 only); slow gastric emptying; promote β-cell mass. DPP-4 (CD26): membrane-bound serine protease (prolyl oligopeptidase family); cleaves penultimate Pro or Ala after N-terminal residue → inactivates GLP-1 (half-life < 2 min without DPP-4 inhibition). Gliptins: sitagliptin, vildagliptin, saxagliptin, alogliptin, linagliptin — oral, weight-neutral, low hypoglycemia risk. GLP-1 receptor agonists (liraglutide, semaglutide, tirzepatide): more potent GLP-1 signaling; cause weight loss; cardioprotective.` },
      { q:`Matriptase (ST14) is a type II transmembrane serine protease implicated in:`, ch:[`Blood coagulation only`,`Epithelial barrier integrity, cancer invasion (activates HGF/proHGF, urokinase, prostasin), and skin/gut homeostasis — balanced by HAI-1 (hepatocyte growth factor activator inhibitor 1); dysregulation → invasion and metastasis`,`Complement activation`,`Pancreatic zymogen activation`], ans:1, exp:`Matriptase (MT-SP1, ST14): type II transmembrane serine protease, expressed on epithelial cell surfaces. Substrates: proHGF/SF (→ HGF → Met activation → invasion); urokinase/pro-uPA (→ uPA → plasminogen → plasmin → MMP activation → ECM degradation); prostasin (PRSS8, activates matriptase in epithelium); protease-activated receptor 2 (PAR2). HAI-1 (SPINT1): major membrane-bound inhibitor of matriptase; HAI-1/matriptase ratio critical for barrier function. St14-null mice: neonatal lethality, hair follicle defects, ichthyosis. Matriptase overexpression: breast, prostate, colorectal cancers → invasion, MET pathway activation. TMPRSS2 (another type II TTSP): cleaves SARS-CoV-2 spike → viral entry; also cleaves prostasin, matriptase.` },
      { q:`Neprilysin (NEP, CD10) is a zinc metallopeptidase, not a serine protease, but is relevant to Alzheimer therapy because:`, ch:[`It synthesizes amyloid-β`,`It is the principal enzyme for degrading amyloid-β (Aβ) in the brain — reduced NEP activity with aging contributes to Aβ accumulation; NEP gene transfer or pharmacological stimulation represents a therapeutic approach`,`It activates tau kinases`,`It cleaves presenilin`], ans:1, exp:`Neprilysin (neutral endopeptidase, enkephalinase): membrane-bound zinc endopeptidase (M13 metallopeptidase family). Substrates: ANP (atrial natriuretic peptide — NEP inhibition → more ANP → natriuresis, used in HF treatment), BNP, enkephalins, substance P, Aβ. In brain: NEP is the primary Aβ-degrading enzyme. NEP activity declines with age and in AD → Aβ accumulation. Sacubitril (LCZ696/Entresto): NEP inhibitor + valsartan (ARB) → increases ANP/BNP → vasodilation, natriuresis → approved for HFrEF. Concern for AD: sacubitril might increase CNS Aβ (controversial in clinical data). IDE (insulin-degrading enzyme): also degrades Aβ. Complement: NEP + IDE + plasmin are main Aβ-clearing enzymes. BACE1 inhibitors: block Aβ production (upstream).` },
      { q:`Kallikrein-kinin system: tissue kallikrein cleaves kininogen to produce which vasoactive peptide, and what is its mechanism?`, ch:[`Angiotensin II from renin`,`Bradykinin (nonapeptide) — bradykinin binds B2 receptors (constitutive) on endothelium → Gq → PLC → IP3/DAG → Ca2+ → eNOS + COX → NO + PGI2 → vasodilation, vascular permeability, pain; B1 receptors (inducible) respond to des-Arg9-bradykinin`,`Substance P from pro-substance P`,`Endothelin-1 from big-endothelin`], ans:1, exp:`Kallikrein-kinin system: Prekallikrein + HMWK (high molecular weight kininogen) contact activates on surfaces → factor XII activates prekallikrein → plasma kallikrein cleaves HMWK → bradykinin. Tissue kallikrein cleaves LMW or HMW kininogen → kallidin (Lys-bradykinin) → BK by aminopeptidases. Bradykinin: B2R (Gq/Gi, constitutive; all tissues) → NO (eNOS/nNOS activation), PGI2, EDHF → vasodilation, edema, pain (nociceptors). Degradation: ACE (kininase II) cleaves BK (C-terminal dipeptide removal) → inactive. ACE inhibitors → BK accumulates → cough (bradykinin-stimulated airway C-fibers) + angioedema (rare but dangerous, especially in C1-INH deficiency). ACE inhibitor angioedema: bradykinin-mediated (not mast cell). Icatibant: B2R antagonist, approved for hereditary angioedema.` },
    ]
  },
  { id:`bb69`, cat:`Bio/Biochem`, title:`Bioenergetics Integration`, diff:`Expert`, qs:[
      { q:`The maximum theoretical ATP yield from one mole of glucose under complete aerobic oxidation is approximately:`, ch:[`38 ATP (classic textbook value)`,`30–32 ATP (modern measured value) — revised from older estimates based on actual P/O ratios (NADH → ~2.5 ATP; FADH2 → ~1.5 ATP) and accounting for the cost of ATP/ADP and Pi transport across the inner mitochondrial membrane`,`100 ATP`,`10 ATP`], ans:1, exp:`Updated accounting: Glycolysis: 2 ATP (net) + 2 NADH (cytoplasmic) → malate-aspartate shuttle: 2×2.5=5 ATP OR glycerol-3-P shuttle: 2×1.5=3 ATP. PDH: 2 NADH × 2.5 = 5 ATP. TCA (per acetyl-CoA × 2): 3 NADH → 7.5 ATP; 1 FADH2 → 1.5 ATP; 1 GTP → 1 ATP = 10 per acetyl-CoA × 2 = 20 ATP. Glycolysis NADH via malate-aspartate: 5. Total: 2 + 2 + 5 + 20 = 30 (glycerol-3-P) to 32 (malate-aspartate). Classic 36–38 used older P/O ratios of 3 (NADH) and 2 (FADH2) without accounting for proton cost of Pi and ATP transport (~2.5 ATP per transported ATP/ADP pair costs ~1 H+).` },
      { q:`AMPK (AMP-activated protein kinase) is the cellular energy sensor. It is activated by:`, ch:[`High ATP:AMP ratio`,`Low energy state — AMP binds γ subunit → allosteric activation + prevents dephosphorylation of Thr172 on α subunit (phosphorylated by LKB1 or CaMKKβ); ADP also activates; ratio AMP:ATP (or AMP:ADP) rises when energy is depleted → AMPK switches on ATP-producing and off ATP-consuming pathways`,`mTORC1 activation`,`Insulin signaling via AKT`], ans:1, exp:`AMPK (heterotrimer α+β+γ): α (catalytic, Thr172 phosphorylation = active); β (scaffold, contains glycogen-sensing module); γ (regulatory, binds AMP/ADP/ATP via CBS domains). Activation: AMP/ADP bind γ → (1) allosteric activation; (2) inhibit PP2C from dephosphorylating αThr172; (3) promote LKB1-mediated phosphorylation (LKB1 = STK11 = Peutz-Jeghers tumor suppressor). CaMKKβ: activates AMPK via Ca2+ (muscle contraction). AMPK targets: ACC1/2 (phospho-inhibits → less malonyl-CoA → less FA synthesis, more FAO); mTORC1 (phospho-inhibits raptor + activates TSC2) → autophagy; GLUT4 translocation; PGC-1α → mitochondrial biogenesis. Metformin: activates AMPK (via Complex I inhibition → AMP:ATP rise + direct AMPK activation).` },
      { q:`Substrate cycles (also called futile cycles) in metabolism serve what physiological purpose?`, ch:[`They waste energy with no benefit`,`They allow fine-tuned bidirectional control of metabolic flux — by simultaneously running opposing reactions at low levels, small changes in enzyme activities can produce large changes in net flux; they also generate heat (non-shivering thermogenesis) and increase metabolic sensitivity`,`They only occur in cancerous cells`,`They are errors in metabolic regulation`], ans:1, exp:`Substrate cycles: e.g., fructose-6-P ↔ fructose-1,6-bisphosphate (PFK-1 forward; FBPase backward); phosphoenolpyruvate/pyruvate/OAA (PK forward; PEPCK+PC backward); glucose/glucose-6-P (HK forward; G6Pase backward). At rest: both directions operate → net flux is small but can be quickly amplified by allosteric modulation. Heat generation: each cycle burns ATP → energy → heat. In muscle/liver: cycles are important for rapid metabolic switching (e.g., exercise onset). Thermogenesis: in insects (e.g., bumblebee thorax) — substrate cycling + mitochondrial uncoupling → rapid heat generation. Signal amplification: a 10% change in PFK-1 + FBPase activities can produce 100% change in net flux (sensitivity amplification).` },
      { q:`The Cori cycle describes:`, ch:[`Lactate recycling between liver and red blood cells`,`Lactate produced by anaerobic muscle glycolysis is transported to the liver → gluconeogenesis → glucose exported back to muscle; net: transfers metabolic work from muscle to liver at the cost of 6 ATP (gluconeogenesis) vs 2 ATP produced (muscle glycolysis)`,`Lactate being converted to ketone bodies in the liver`,`The recycling of amino acids between organs`], ans:1, exp:`Cori cycle: muscle (anaerobic) → lactate + 2 ATP; blood lactate → liver; liver gluconeogenesis: lactate → pyruvate → OAA → PEP → F1,6BP → glucose + 6 ATP consumed; glucose back to blood → muscle. Net energetics: liver spends 6 ATP, muscle gains 2 ATP → net loss of 4 ATP per cycle (oxidized in liver mitochondria). Physiological role: regenerates muscle glucose supply; removes lactic acid from blood. Glucose-alanine cycle (Cahill cycle): muscle → alanine → liver; liver: alanine → pyruvate + NH3 → glucose + urea. Both cycles contribute to fasted-state glucose homeostasis.` },
      { q:`Which enzyme catalyzes the committed, regulated step of fatty acid synthesis, and how is it regulated?`, ch:[`Fatty acid synthase (FASN)`,`Acetyl-CoA carboxylase (ACC1/2) — carboxylates acetyl-CoA → malonyl-CoA using biotin; regulated by citrate (allosteric activator), palmitoyl-CoA (allosteric inhibitor), AMPK phosphorylation (inhibition), and insulin (dephosphorylation → activation)`,`Malonyl-CoA decarboxylase`,`ATP-citrate lyase`], ans:1, exp:`ACC1 (cytoplasm, lipogenesis) + ACC2 (OMM, malonyl-CoA inhibits CPT1 → blocks FAO). Regulation: Citrate (high energy/biosynthetic signal): allosteric activator (promotes ACC polymerization → active filaments). Palmitoyl-CoA (end product): allosteric inhibitor. AMPK: phosphorylates Ser79 (ACC1)/Ser212 (ACC2) → inactivation. Insulin → PP2A/PP2B → dephosphorylates ACC → activation. Glucagon → PKA → phosphorylates ACC → inhibition. Transcription: SREBP-1c (insulin-activated) → transcribes ACC1, FASN, G6PD. Malonyl-CoA: dual function — substrate for FASN (cytoplasm); inhibitor of CPT-I (outer mitochondrial membrane) → prevents simultaneous FA synthesis and oxidation (metabolic coordination).` },
      { q:`The glucose-fatty acid (Randle) cycle describes the competition between glucose and fatty acids for oxidation in muscle and heart. When fatty acid oxidation is high:`, ch:[`Glucose uptake increases`,`Acetyl-CoA from FA oxidation inhibits PDH complex → reduced pyruvate oxidation; citrate inhibits PFK-1 → reduced glycolysis; elevated NADH/NAD+ ratio further inhibits PDH; net: FA oxidation suppresses glucose oxidation`,`Lactate production increases`,`Glycogen synthesis increases`], ans:1, exp:`Randle cycle: (1) FA oxidation → acetyl-CoA → citrate + NAD+ (limited) → TCA; excess acetyl-CoA + excess NADH from β-oxidation: (2) Acetyl-CoA inhibits PDH (product inhibition) and activates pyruvate carboxylase → OAA → citrate → cytoplasm → inhibits PFK-1; (3) High NADH/NAD+ → PDH complex inhibited (by PDK1/2 which phosphorylate E1α); (4) Citrate accumulates → PFK-1 inhibited → F6P/G6P accumulate → HK inhibited → less glucose uptake. Physiological: during fasting (high FFA) → muscle/heart uses FAs, spares glucose for brain/RBCs. Insulin resistance: excess lipids in muscle → chronic Randle cycle suppression of glucose uptake + ceramide/DAG → IRS-1 serine phosphorylation → impairs PI3K/AKT signaling.` },
      { q:`During prolonged fasting (>48 hours), which tissues shift to ketone body utilization, and which cannot?`, ch:[`All tissues can use ketone bodies equally`,`Brain (after adaptation — normally glucose-dependent, adapts over 5–7 days to use β-hydroxybutyrate/acetoacetate as 60–70% of fuel); heart, skeletal muscle, kidney cortex (readily use ketones); liver and red blood cells CANNOT use ketones (liver lacks succinyl-CoA transferase/SCOT; RBCs lack mitochondria)`,`Only muscle uses ketone bodies`,`Liver is the primary ketone consumer`], ans:1, exp:`Ketone utilization: β-hydroxybutyrate → acetoacetate (by BHB dehydrogenase, mitochondria) → acetoacetyl-CoA (by SCOT/succinyl-CoA:3-oxoacid CoA transferase — requires succinyl-CoA → succinate, so liver lacks SCOT → cannot oxidize ketones) → 2 acetyl-CoA → TCA. Brain adaptation: requires several days; reduces gluconeogenic demand (glucose-sparing during starvation). Heart: prefers ketones over glucose and FAs during starvation. RBCs: no mitochondria → cannot use ketones. Liver: produces ketones but lacks SCOT → exporter not consumer. Diabetic ketoacidosis vs. starvation ketosis: DKA much higher ketonemia due to combination of excess glucagon + insulin deficiency → maximal lipolysis + maximal ketogenesis + impaired ketone utilization.` },
      { q:`PGC-1α (PPAR-γ coactivator 1 alpha) is a master regulator of:`, ch:[`Glycolysis`,`Mitochondrial biogenesis and oxidative metabolism — activated by exercise, cold, fasting (via AMPK and SIRT1); PGC-1α coactivates NRF1/NRF2 (nuclear respiratory factors) → TFAM → mtDNA replication/transcription; PPARα → FAO genes; ERRα → OXPHOS genes`,`Purine synthesis`,`Cholesterol synthesis`], ans:1, exp:`PGC-1α: transcriptional coactivator (no DNA-binding domain, no enzymatic activity). Activation post-translational: AMPK phosphorylation (Thr177, Ser538) → activates PGC-1α; SIRT1 deacetylation (removes Lys acetyl groups added by GCN5) → activates PGC-1α. Both AMPK and SIRT1 are activated by energy deficit. Targets: NRF1/2 → TFAM → mtDNA transcription/replication → more mitochondria; PPARα → CPT-1, medium-chain acyl-CoA dehydrogenase → FAO; ERRα → OXPHOS subunits; GLUT4 (skeletal muscle); UCP1 (BAT). Exercise → AMPK + Ca2+/CaMKII → PGC-1α in muscle → mitochondrial biogenesis (training effect). PGC-1α reduced in T2D, aging muscle; PGC-1β: similar role. PGC-1α in cancer: complex (can suppress or promote depending on context).` },
      { q:`Gluconeogenesis is restricted to the liver and kidney cortex primarily because:`, ch:[`These organs have higher glucose demand`,`They uniquely express glucose-6-phosphatase (G6Pase, in ER membrane) which catalyzes the final step (G6P → glucose + Pi), enabling glucose release into blood; other gluconeogenic enzymes (PEPCK, PC, FBPase-1) are also highly expressed`,`Lactate is only produced by liver and kidney`,`Glycogen is not present in other tissues`], ans:1, exp:`Gluconeogenic key enzymes (bypass glycolytic irreversible steps): (1) PC (pyruvate → OAA, mitochondria); (2) PEPCK (OAA → PEP, cytoplasm); (3) FBPase-1 (F1,6BP → F6P; regulated by AMP inhibition, fructose-2,6-bisphosphate inhibition — reciprocal to PFK-1); (4) G6Pase (G6P → glucose, ER lumen, hepatic + kidney cortex only). Muscle lacks G6Pase → cannot release free glucose; can release G6P → glycogen or continue glycolysis. Brain lacks significant gluconeogenesis. Kidney cortex: important in prolonged fasting (up to 40% of total glucose output). Alanine (from muscle) → liver → pyruvate → gluconeogenesis (alanine cycle). Regulation: glucagon → PKA → activates PC/PEPCK, FBPase-2 (lowers F2,6BP → relieves FBPase-1 inhibition) → gluconeogenesis up. Insulin: opposes all of the above.` },
      { q:`The anaplerotic reaction catalyzed by pyruvate carboxylase is essential for TCA cycle maintenance. Which cofactor is required, and when is this reaction most active?`, ch:[`Thiamine pyrophosphate; active during fasting`,`Biotin (covalently attached to the enzyme via Lys residue); most active when acetyl-CoA is high (e.g., fasting, high FA oxidation) — acetyl-CoA is the allosteric activator that activates PC to replenish OAA for TCA and gluconeogenesis`,`Pyridoxal phosphate; active post-meal`,`Cobalamin (B12); active in nitrogen excess`], ans:1, exp:`Pyruvate carboxylase (PC): biotin-dependent (covalently bound). Reaction: pyruvate + CO2 + ATP → oxaloacetate + ADP + Pi (mitochondrial). Allosteric: acetyl-CoA = obligate allosteric activator (without AcCoA, enzyme is essentially inactive). Logic: high acetyl-CoA (from FAO or glycolysis overflow) signals TCA is running fast and needs OAA replenishment → PC activated. OAA from PC: (1) TCA anaplerosis → citrate synthase; (2) Gluconeogenesis substrate (PEPCK converts OAA → PEP). Biotin-dependent enzymes: PC, ACC (acetyl-CoA carboxylase), propionyl-CoA carboxylase, 3-methylcrotonyl-CoA carboxylase. Biotin deficiency (raw egg avidin, rare): multiple carboxylase deficiency → lactic acidosis, skin rash, neurological symptoms. Holocarboxylase synthetase or biotinidase deficiency: multiple carboxylase deficiency disorders.` },
      { q:`Which best describes the thermodynamic relationship between catabolism and anabolism in living cells?`, ch:[`Anabolism and catabolism are in thermodynamic equilibrium`,`Catabolism is coupled to anabolism via intermediary energy currencies (ATP, NADPH, acetyl-CoA, and reduced cofactors) — catabolism liberates free energy that is captured in these currencies, which then drive thermodynamically unfavorable biosynthetic reactions; the overall system is maintained far from equilibrium by continuous energy input`,`Anabolism produces ATP directly from nutrient oxidation`,`All metabolic reactions proceed spontaneously without energy coupling`], ans:1, exp:`Thermodynamic coupling: spontaneous reactions (ΔG < 0) drive non-spontaneous reactions (ΔG > 0) through shared intermediates. ATP hydrolysis (ΔG ≈ −30 to −60 kJ/mol in vivo, depending on [ATP]/[ADP][Pi]) powers: biosynthesis (peptide bonds, glycosidic bonds, phospholipid assembly), active transport, motility. NADPH vs. NADH: structurally similar but functionally distinct — NADH primarily catabolic (oxidized by ETC); NADPH primarily anabolic (from PPP, ICDH2/ICDH1, malic enzyme) → used by FASN, reductases, glutathione reductase, thioredoxin reductase. Acetyl-CoA: central metabolite linking catabolism (β-oxidation, pyruvate decarboxylation) to anabolism (FA synthesis, cholesterol synthesis, ketogenesis). Non-equilibrium: cells maintain [ATP]/[ADP] far above equilibrium → large negative ΔG for hydrolysis → thermodynamic driving force for coupled processes.` },
      { q:`The Q10 effect in biochemistry refers to:`, ch:[`The fact that ubiquinone (CoQ10) carries 10 electrons`,`The temperature coefficient — for most biochemical reactions, a 10°C rise doubles or triples reaction rate (Q10 ≈ 2–3); this affects metabolic rate and enzyme kinetics in organisms across different thermal environments`,`The 10-step pathway of glycolysis`,`A 10:1 ratio of NAD+ to NADH`], ans:1, exp:`Q10 (temperature coefficient): Q10 = (rate at T+10°C)/(rate at T°C). Most enzymes: Q10 ≈ 2–3. Implications: (1) Hypothermia (surgical) → reduces O2 demand, allows longer ischemia tolerance; (2) Fever → increases metabolic rate (+13% per 1°C); (3) Ectotherms: metabolic rate varies with environment; thermal acclimation involves enzyme adaptation. Arrhenius relationship: lnk = lnA − Ea/(RT) → linear plot of lnk vs 1/T → slope = −Ea/R. Above Tm (melting temperature of enzyme): denaturation → rate decreases. Cold adaptation in fish: produce more enzyme (Km remains similar) or isoforms with lower activation energy. Warm adaptation: higher Km enzymes that remain stable at high temperatures. Clinical: targeted hypothermia → ↓metabolic rate → neuroprotection post-cardiac arrest.` },
      { q:`The pentose phosphate pathway and glycolysis interact at which metabolic nodes?`, ch:[`Glucose-6-phosphate and lactate`,`Glucose-6-phosphate (G6P enters PPP oxidative branch), fructose-6-phosphate (F6P), and glyceraldehyde-3-phosphate (G3P) — the non-oxidative branch converts ribulose-5-P → F6P + G3P which re-enter glycolysis at these points`,`Pyruvate and acetyl-CoA`,`Only at the level of ATP production`], ans:1, exp:`PPP-glycolysis connections: G6P: direct entry point into PPP oxidative branch (G6PD) OR glycolysis (PGI → F6P). Non-oxidative branch interconversions: ribose-5P + xylulose-5P → sedoheptulose-7P + G3P (transketolase); sedoheptulose-7P + G3P → erythrose-4P + F6P (transaldolase); xylulose-5P + erythrose-4P → F6P + G3P (transketolase). Net non-oxidative: 3 pentose-5P → 2 F6P + G3P → glycolysis. Flux balance: proliferating cells (high nucleotide demand) → PPP non-oxidative branch dominant; oxidative stress (high NADPH demand) → oxidative branch. G6PD is rate-limiting for NADPH production; G6PD deficiency → hemolytic anemia (RBCs lack nuclei → cannot regenerate G6PD protein → ROS-sensitive). Transketolase: requires thiamine pyrophosphate (TPP).` },
      { q:`Glucokinase (hexokinase IV) in the liver behaves differently from hexokinases I–III in muscle because:`, ch:[`Glucokinase has lower Km for glucose and is inhibited by glucose-6-phosphate`,`Glucokinase has high Km (~10 mM, sigmoid kinetics/cooperative-like behavior), is not inhibited by product glucose-6-phosphate, and is induced by insulin — acts as a glucose sensor: only active when portal glucose concentrations are high after a meal`,`Glucokinase is expressed in neurons only`,`Glucokinase produces fructose-6-phosphate directly`], ans:1, exp:`Hexokinase I–III (HK1–3): Km ~0.1 mM (well below physiological blood glucose); constitutively active; strongly inhibited by G6P → product inhibition → prevents overconsumption of glucose when G6P accumulates. Glucokinase (GK, HK4, liver + pancreatic β cells): Km ~10 mM (above fasting glucose ~5 mM); sigmoidal kinetics (Hill coefficient ~1.7); no product inhibition by G6P; transcriptionally regulated by insulin/FOXO1. Liver GK: sequesters postprandial glucose → glycogen, glycolysis. Pancreatic β-cell GK: glucose sensor → rate of glucokinase reaction determines rate of glycolysis → ATP rise → KATP closure → depolarization → Ca2+ → insulin secretion. Activating GK mutations → congenital hyperinsulinism; inactivating → MODY2 (maturity-onset diabetes of the young, mild fasting hyperglycemia). GK activators: in development for T2D.` },
    ]
  },
  { id:`bb70`, cat:`Bio/Biochem`, title:`Pharmacokinetics & CYP450`, diff:`Expert`, qs:[
      { q:`Bioavailability (F) of an orally administered drug is determined by:`, ch:[`The dose administered`,`The fraction of the dose that reaches the systemic circulation unchanged — reduced by incomplete absorption, gut-wall metabolism (intestinal CYP3A4, P-gp efflux), and first-pass hepatic metabolism; F = AUCoral/AUCiv × (doseiv/doseoral)`,`Half-life only`,`Volume of distribution`], ans:1, exp:`Bioavailability = fraction reaching systemic circulation unchanged. Determinants: absorption (solubility, permeability — BCS classification); gut wall metabolism (CYP3A4 in enterocytes — e.g., cyclosporine, midazolam, felodipine); P-glycoprotein efflux (intestinal, returns drug to gut lumen); first-pass liver metabolism (high extraction ratio drugs: morphine, propranolol, lidocaine, nitroglycerin — near-zero oral bioavailability). Extraction ratio (E) = (CA − CV)/CA; F = 1 − E (hepatic). AUC (area under the curve): total drug exposure. AUCoral/AUCiv ratio with dose correction = F. Routes with 100% F: IV. Routes avoiding first-pass: sublingual, transdermal, rectal, inhaled, IV.` },
      { q:`Volume of distribution (Vd) relates drug dose to plasma concentration. A drug with Vd = 500 L (for a 70 kg person) suggests:`, ch:[`The drug is restricted to the plasma compartment`,`The drug is extensively distributed to peripheral tissues (Vd >> total body water ≈ 42 L) — likely highly lipophilic or protein-bound in tissues; Vd = dose/C0; large Vd → long half-life; drugs with large Vd are harder to remove by dialysis`,`The drug is exclusively renal`,`Vd equals the total body weight in liters`], ans:1, exp:`Vd (apparent volume): not a real physiological volume — conceptual volume that drug appears to occupy at plasma concentration. Vd = dose/C0 (C0 = plasma concentration at time 0). Interpretation: Vd ≈ 5 L → restricted to plasma (heparin, large proteins); Vd ≈ 15 L → extracellular fluid (aminoglycosides — hydrophilic); Vd ≈ 42 L → total body water; Vd > 200 L → extensive tissue sequestration (chloroquine: Vd ≈ 200–800 L; amiodarone: Vd ≈ 5,000 L). Large Vd: (1) Lipophilic drugs (cross membranes); (2) High tissue protein binding; (3) Basic drugs (partition into intracellular acidic compartments — lysosomes: chloroquine). Large Vd drugs not removed by hemodialysis (too little in blood to dialyze). Relationship: t½ = 0.693 × Vd / CL; large Vd → long half-life even if clearance is high.` },
      { q:`First-order kinetics versus zero-order kinetics in drug elimination: which statement is correct?`, ch:[`Zero-order: constant fraction eliminated per unit time`,`First-order: a constant fraction of the remaining drug is eliminated per unit time (rate proportional to concentration → exponential decay); zero-order: a constant amount is eliminated per unit time regardless of concentration (saturation kinetics — e.g., ethanol, high-dose aspirin, phenytoin at high doses)`,`Both produce linear plots on standard concentration vs. time graphs`,`Half-life is not defined for first-order kinetics`], ans:1, exp:`First-order kinetics: most drugs at therapeutic doses. Rate = k × C → C(t) = C0 × e^(−kt). Half-life constant (independent of concentration). Log-linear plot: straight line. Clearance constant, Vd constant → half-life constant. Zero-order (capacity-limited): rate = k (constant); C(t) = C0 − kt. Linear plot. Occurs when eliminating enzyme is saturated (e.g., CYP2E1 saturated by ethanol: ~1 drink/hour eliminated regardless of BAC; phenytoin at therapeutic doses — near Km of CYP2C9; aspirin in overdose). Michaelis-Menten kinetics: at low [drug] << Km → first-order; at high [drug] >> Km → zero-order. Clinical importance: zero-order drugs (phenytoin, warfarin at high doses, theophylline) → small dose changes → disproportionately large plasma level changes → narrow therapeutic window.` },
      { q:`Cytochrome P450 enzymes (CYPs) are most concentrated in which subcellular location and primarily catalyze which reactions?`, ch:[`Mitochondria; amino acid hydroxylation`,`Smooth endoplasmic reticulum (liver, intestine, lung); monooxygenation reactions (oxidative metabolism) — insert one oxygen atom into substrate, reduce other O atom to water: drug + NADPH + O2 → drug-OH + NADP+ + H2O; also N-dealkylation, O-dealkylation, sulfoxidation, epoxidation`,`Lysosome; hydrolysis`,`Nucleus; phase II conjugation`], ans:1, exp:`CYP450 enzymes: heme-containing monooxygenases. Mechanism: NADPH + H+ + O2 + R-H → NADP+ + H2O + R-OH. Require: NADPH-CYP reductase (electron donor) + cytochrome b5 (can donate second electron). Located: ER membrane (liver >> intestine, lung, kidney, adrenal). Major drug-metabolizing CYPs: CYP3A4 (>50% of marketed drugs), CYP2D6 (25% of drugs; genetic polymorphism — PMs, IMs, EMs, UMs), CYP2C9 (warfarin, phenytoin, NSAIDs), CYP2C19 (proton pump inhibitors, clopidogrel), CYP1A2 (caffeine, clozapine, theophylline), CYP2E1 (ethanol, acetaminophen). Phase II reactions: glucuronidation (UGT), sulfation (SULT), glutathione conjugation (GST), acetylation (NAT) — occur in cytoplasm/ER.` },
      { q:`CYP2D6 genetic polymorphisms are clinically important because CYP2D6 metabolizes:`, ch:[`Only antibiotics`,`Many psychiatric drugs (tricyclics, SSRIs, antipsychotics), beta-blockers (metoprolol, carvedilol), opioids (codeine, tramadol), and tamoxifen — poor metabolizers (PMs) have toxicity risk with standard doses; ultra-rapid metabolizers (UMs) may have inadequate response or, for prodrugs (codeine), dangerous accumulation of active metabolite`,`Warfarin exclusively`,`Only steroid hormones`], ans:1, exp:`CYP2D6 phenotypes: PM (poor metabolizer: 2 non-functional alleles, ~7% Caucasians, ~1% Asians); IM (intermediate); EM (extensive, most common); UM (ultrarapid, gene duplication, ~1–2% Caucasians, ~29% Ethiopians). Codeine (prodrug) → morphine (by CYP2D6): PM = no analgesia; UM = morphine toxicity (deaths reported; FDA black box for UM nursing mothers). Tamoxifen → endoxifen (active) by CYP2D6: PM = lower endoxifen → worse breast cancer outcomes. Metoprolol: PM → 5-fold higher AUC → bradycardia, hypotension. SSRIs (fluoxetine, paroxetine): potent CYP2D6 inhibitors → convert EMs to phenotypic PMs. Pharmacogenomics: CPIC guidelines recommend dose adjustments based on CYP2D6 genotype.` },
      { q:`CYP3A4 induction by rifampin can cause:`, ch:[`Increased plasma levels of coadministered CYP3A4 substrates`,`Dramatically reduced plasma levels of CYP3A4 substrates — oral contraceptives (OCP failure → pregnancy), cyclosporine (transplant rejection), HIV PIs, statins, warfarin → bleeding risk if dose not adjusted, benzodiazepines → reduced sedation`,`Increased toxicity of substrates`,`No clinically significant effect`], ans:1, exp:`Rifampin: powerful CYP3A4 inducer (via pregnane X receptor/PXR → transcriptional upregulation of CYP3A4 + P-glycoprotein). Effect onset: 2–3 days; offset: 2 weeks after stopping. Important interactions: OCPs (ethinyl estradiol + levonorgestrel) → therapeutic failure → unintended pregnancy; cyclosporine → rejection in transplant patients; antiretrovirals (most PIs, NNRTIs); azole antifungals (metabolized by CYP3A4); warfarin → need higher dose during rifampin, dangerous drop when stopped. Other inducers: carbamazepine, phenytoin, phenobarbital, St. John's Wort (Hypericum perforatum), chronic ethanol. Other CYP3A4 inhibitors (increase levels of substrates): ketoconazole, itraconazole, erythromycin, clarithromycin, grapefruit juice (furanocoumarins: intestinal CYP3A4 irreversible inhibition), ritonavir.` },
      { q:`The concept of hepatic clearance is described by the well-stirred model as:`, ch:[`CL = Vd × t1/2`,`CL = Q × E = Q × (fu × CLint) / (Q + fu × CLint) — where Q = hepatic blood flow, E = extraction ratio, fu = unbound fraction, CLint = intrinsic clearance; for high E drugs (E > 0.7): CL ≈ Q (flow-limited); for low E drugs (E < 0.3): CL ≈ fu × CLint (capacity-limited)`,`CL = dose × AUC`,`CL = Km / Vmax`], ans:1, exp:`Hepatic clearance models: Well-stirred (venous equilibration model): CL_H = Q_H × E_H. E_H = fu × CLint / (Q_H + fu × CLint). High E (extraction ratio > 0.7): CL ≈ Q_H — primarily flow-dependent; protein binding changes have minimal effect (since free drug rapidly cleared); enzyme induction/inhibition has minimal effect on CL but affects bioavailability of oral drugs greatly. Low E (< 0.3): CL ≈ fu × CLint — capacity-limited, primarily dependent on protein binding and intrinsic metabolic capacity; enzyme inhibitors (e.g., CYP inhibitors) greatly affect CL. Examples: high E: lidocaine, morphine, propranolol (Vd also large); low E: warfarin, phenytoin, theophylline. t½ = 0.693 × Vd/CL.` },
      { q:`Grapefruit juice drug interactions are due to:`, ch:[`Inhibiting intestinal P-glycoprotein only`,`Irreversible inactivation of intestinal CYP3A4 by furanocoumarins (bergamottin, 6′,7′-dihydroxybergamottin) — mechanism-based inhibition that cannot be overcome by increasing CYP3A4 expression during the meal; effect lasts 24–72 hours after one glass → dramatically increases oral bioavailability of CYP3A4 substrates`,`Inducing CYP3A4 in the liver`,`Chelating divalent cations to prevent drug absorption`], ans:1, exp:`Grapefruit furanocoumarins: mechanism-based (irreversible, suicide) inhibitors of CYP3A4. Specifically inhibit INTESTINAL CYP3A4 (not significantly hepatic CYP3A4 due to first-pass metabolism of furanocoumarins themselves before reaching liver). Effect: increases oral bioavailability of drugs with significant intestinal first-pass extraction. Duration: 24–72 h per glass (must regenerate new CYP3A4 protein). Affected drugs: felodipine (prototype), simvastatin (myopathy risk), atorvastatin, cyclosporine, tacrolimus, saquinavir, midazolam, buspirone, amiodarone. Note: Seville oranges, pomelos, tangelos also contain furanocoumarins; regular oranges do not. P-gp efflux is also inhibited (some furanocoumarins) but CYP3A4 effect dominates.` },
      { q:`Which pharmacokinetic parameter determines how often a drug must be dosed to maintain steady-state plasma levels?`, ch:[`Volume of distribution (Vd)`,`Half-life (t½) — it takes ~4–5 half-lives to reach steady state (Css) and ~4–5 half-lives to be eliminated; dosing interval should typically be ≤1–2 half-lives for drugs requiring continuous therapeutic levels`,`Bioavailability (F)`,`Protein binding percentage`], ans:1, exp:`Half-life determines: (1) Time to steady state (4–5 × t½ regardless of dose or dosing frequency); (2) Elimination time after stopping drug (4–5 × t½); (3) Dosing interval guidelines. Css (steady state): achieved when rate in = rate out. Css(avg) = (F × dose) / (CL × τ) where τ = dosing interval. Loading dose: LD = Vd × Css_target (bypasses accumulation time). Fluctuation at steady state: determined by dosing interval relative to t½; small τ/t½ ratio → less fluctuation. Aminoglycosides: long t½ relative to dosing interval → accumulate → ototoxicity/nephrotoxicity → drug monitoring. Vancomycin: AUC/MIC target-based monitoring. t½ = 0.693 × Vd/CL.` },
      { q:`Non-linear (saturable) pharmacokinetics in phenytoin is a major clinical problem because:`, ch:[`Phenytoin is completely absorbed only at low doses`,`Phenytoin's CYP2C9/2C19 metabolism is saturated near therapeutic plasma levels — small dose increases can cause disproportionate (supralinear) rises in plasma concentration → toxicity (nystagmus, ataxia, CNS depression); Km ≈ 5 mg/L (within or below therapeutic range of 10–20 mg/L)`,`Phenytoin's half-life is less than one hour`,`Phenytoin induces its own metabolism`], ans:1, exp:`Phenytoin Michaelis-Menten kinetics: rate of elimination = Vmax × C / (Km + C). At low C << Km: first-order (elimination proportional to C). At C near or > Km (~5 mg/L): mixed/zero-order → small dose increase → large C increase → narrow therapeutic window. Therapeutic range 10–20 mg/L; toxic >20 mg/L. Clinical: for a patient at 10 mg/L, a 10% dose increase might raise levels to 15–20 mg/L; another 10% might cause toxicity at >30 mg/L. Variable Km/Vmax due to CYP2C9/2C19 polymorphisms. Other zero-order drugs at therapeutic doses: ethanol (social doses), high-dose aspirin (salicylate), fluoxetine (at some levels). TDM (therapeutic drug monitoring) essential for phenytoin. Maintenance dose = Vmax × Css / (Km + Css); solving for Css given dose requires iterative calculation.` },
      { q:`CYP2C9 poor metabolizers on warfarin therapy require:`, ch:[`Higher doses to achieve anticoagulation`,`Lower doses — CYP2C9 is responsible for ~90% of S-warfarin (more potent enantiomer) metabolism; PMs have greatly reduced S-warfarin clearance → accumulate to toxic levels → bleeding risk at standard doses; VKORC1 polymorphisms also affect warfarin sensitivity`,`No dose adjustment`,`Only INR monitoring without dose change`], ans:1, exp:`Warfarin pharmacogenomics: S-warfarin (3–5× more potent than R-warfarin) metabolized primarily by CYP2C9. R-warfarin: CYP1A2, CYP3A4. CYP2C9*2 (Arg144Cys, ~11% Caucasians): ~30% reduced activity. CYP2C9*3 (Ile359Leu, ~7% Caucasians): ~90% reduced activity. CYP2C9*3 PMs: need ~3-fold lower warfarin dose. VKORC1: vitamin K epoxide reductase; VKORC1 −1639 G>A (haplotype A) → reduced VKORC1 expression → warfarin sensitivity (lower dose needed). FDA: warfarin label includes CYP2C9/VKORC1 genotype dosing table. CYP2C19: clopidogrel (prodrug → active thienopyridine); PMs (~14% Asians, 2% Caucasians) have inadequate platelet inhibition → increased MACE risk → FDA black box warning.` },
      { q:`The acetylation polymorphism (NAT2 — N-acetyltransferase 2) affects the metabolism of which commonly used drugs?`, ch:[`Beta-blockers`,`Isoniazid (INH), hydralazine, procainamide, sulfamethazine, dapsone — rapid acetylators clear these drugs faster (may require higher doses or more frequent dosing); slow acetylators (50% of Caucasians/African Americans) accumulate drug → increased toxicity risk (INH neuropathy, drug-induced lupus with hydralazine/procainamide)`,`Statins`,`ACE inhibitors`], ans:1, exp:`NAT2: cytoplasmic enzyme, acetyl-CoA as co-substrate. Slow acetylators: bimodal distribution (AR trait); prevalent alleles *5B (481C>T), *6A (590G>A), *7B (857G>A). Slow acetylators: ~50% Caucasians + African Americans; ~10% Asians. INH: fast acetylators → acetylisoniazid → acetylhydrazine → hepatotoxicity (paradoxically); slow acetylators → higher INH levels → peripheral neuropathy (pyridoxine depletion), but possibly better bactericidal at standard doses. Hydralazine/procainamide: slow acetylators → drug-induced SLE (anti-histone antibodies). Dapsone: slow acetylators → methemoglobinemia risk. Sulfasalazine: slow acetylators → higher 5-aminosalicylate (active) levels but also higher sulfapyridine → toxicity. NAT1: separate enzyme; some overlap in substrates.` },
      { q:`The 'prodrug' concept is used in which clinical scenario and involves what pharmacological principle?`, ch:[`Prodrugs are used when a drug has no effect on its own`,`Prodrugs are pharmacologically inactive (or weakly active) compounds that are enzymatically converted to active drug in vivo — used to: improve bioavailability (enalapril → enalaprilat, ACE inhibitor; oseltamivir → oseltamivir carboxylate), improve permeability (valacyclovir → acyclovir), target specific tissues (codeine → morphine by CYP2D6), or reduce toxicity (5-fluorouracil prodrugs: capecitabine)`,`Prodrugs are always more toxic than the active drug`,`Prodrugs cannot be converted if CYP enzymes are absent`], ans:1, exp:`Prodrug examples by activation mechanism: Ester hydrolysis: enalapril (enalaprilat by esterases), valacyclovir (acyclovir by valacyclovirase), oseltamivir (ester hydrolysis in liver), aspirin (no prodrug, but rapidly hydrolyzed to salicylate). CYP-mediated: codeine → morphine (CYP2D6, ~10%); clopidogrel → active thiolactone (CYP2C19, CYP3A4); tamoxifen → endoxifen (CYP2D6). Bacteria/tumor-specific activation: 5-fluorouracil (FUDR) activated in rapidly dividing cells; capecitabine → 5-FU by thymidine phosphorylase (higher in tumor tissue). Phosphatase activation: tenofovir disoproxil fumarate → tenofovir diphosphate. Classic prodrug failure: clopidogrel in CYP2C19 PMs → inadequate platelet inhibition (FDA black box). Prodrug advantage: overcome poor solubility, irritation, instability, poor absorption.` },
    ]
  },
];
